pub const Runtime = union(BackendKind) {
    none,
    native,
    markdown: MarkdownAgentMemory,
    memory_lru: MemoryAgentMemory,
    redis: RedisAgentMemory,
    clickhouse: ClickHouseAgentMemory,
    api: ApiAgentMemory,
    supermemory: ApiAgentMemory,
    openviking: ApiAgentMemory,
    honcho: ApiAgentMemory,
    mem0: ApiAgentMemory,
    hindsight: ApiAgentMemory,
    retaindb: ApiAgentMemory,
    byterover: ApiAgentMemory,
    holographic: holographic.Engine,
    zep: ApiAgentMemory,
    falkordb: ApiAgentMemory,

    pub fn init(allocator: std.mem.Allocator, config: Config) !Runtime {
        try config.validateUsable();
        return switch (config.backend) {
            .none => .none,
            .native => .native,
            .markdown => .{ .markdown = try MarkdownAgentMemory.init(allocator, config.markdown) },
            .memory_lru => .{ .memory_lru = MemoryAgentMemory.init(allocator, config.memory) },
            .redis => .{ .redis = RedisAgentMemory.init(allocator, config.redis) },
            .clickhouse => .{ .clickhouse = try ClickHouseAgentMemory.init(allocator, config.clickhouse) },
            .api => .{ .api = try ApiAgentMemory.init(allocator, config.api) },
            .supermemory => blk: {
                var api_config = config.api;
                api_config.profile = .supermemory;
                if (api_config.base_url == null) api_config.base_url = api_config.profile.defaultBaseUrl();
                break :blk .{ .supermemory = try ApiAgentMemory.init(allocator, api_config) };
            },
            .openviking => blk: {
                var api_config = config.api;
                api_config.profile = .openviking;
                if (api_config.base_url == null) api_config.base_url = api_config.profile.defaultBaseUrl();
                break :blk .{ .openviking = try ApiAgentMemory.init(allocator, api_config) };
            },
            .honcho => blk: {
                var api_config = config.api;
                api_config.profile = .honcho;
                if (api_config.base_url == null) api_config.base_url = api_config.profile.defaultBaseUrl();
                break :blk .{ .honcho = try ApiAgentMemory.init(allocator, api_config) };
            },
            .mem0 => blk: {
                var api_config = config.api;
                api_config.profile = .mem0;
                if (api_config.base_url == null) api_config.base_url = api_config.profile.defaultBaseUrl();
                break :blk .{ .mem0 = try ApiAgentMemory.init(allocator, api_config) };
            },
            .hindsight => blk: {
                var api_config = config.api;
                api_config.profile = .hindsight;
                if (api_config.base_url == null) api_config.base_url = api_config.profile.defaultBaseUrl();
                break :blk .{ .hindsight = try ApiAgentMemory.init(allocator, api_config) };
            },
            .retaindb => blk: {
                var api_config = config.api;
                api_config.profile = .retaindb;
                if (api_config.base_url == null) api_config.base_url = api_config.profile.defaultBaseUrl();
                break :blk .{ .retaindb = try ApiAgentMemory.init(allocator, api_config) };
            },
            .byterover => blk: {
                var api_config = config.api;
                api_config.profile = .byterover;
                break :blk .{ .byterover = try ApiAgentMemory.init(allocator, api_config) };
            },
            .zep => blk: {
                var api_config = config.api;
                api_config.profile = .zep;
                if (api_config.base_url == null) api_config.base_url = api_config.profile.defaultBaseUrl();
                break :blk .{ .zep = try ApiAgentMemory.init(allocator, api_config) };
            },
            .falkordb => blk: {
                var api_config = config.api;
                api_config.profile = .falkordb;
                if (api_config.base_url == null) api_config.base_url = api_config.profile.defaultBaseUrl();
                break :blk .{ .falkordb = try ApiAgentMemory.init(allocator, api_config) };
            },
            .holographic => .{ .holographic = try holographic.Engine.init(allocator, config.holographic) },
        };
    }

    pub fn deinit(self: *Runtime) void {
        switch (self.*) {
            .none => {},
            .native => {},
            .markdown => |*engine| engine.deinit(),
            .memory_lru => |*engine| engine.deinit(),
            .redis => |*engine| engine.deinit(),
            .clickhouse => |*engine| engine.deinit(),
            .api, .supermemory, .openviking, .honcho, .mem0, .hindsight, .retaindb, .byterover, .zep, .falkordb => |*engine| engine.deinit(),
            .holographic => |*engine| engine.deinit(),
        }
    }

    pub fn isExternal(self: *const Runtime) bool {
        return self.* != .native;
    }

    pub fn backendName(self: *const Runtime) []const u8 {
        return switch (self.*) {
            .none => "none",
            .native => "native",
            .markdown => "markdown",
            .memory_lru => "memory_lru",
            .redis => "redis",
            .clickhouse => "clickhouse",
            .api => "api",
            .supermemory => "supermemory",
            .openviking => "openviking",
            .honcho => "honcho",
            .mem0 => "mem0",
            .hindsight => "hindsight",
            .retaindb => "retaindb",
            .byterover => "byterover",
            .zep => "zep",
            .falkordb => "falkordb",
            .holographic => "holographic",
        };
    }

    pub fn supportsFeed(self: *const Runtime) bool {
        return switch (self.*) {
            .memory_lru => true,
            .redis => true,
            .api => true,
            .clickhouse => true,
            else => false,
        };
    }

    pub fn delegatesMissingLifecycleTarget(self: *const Runtime) bool {
        return self.* == .api;
    }

    pub fn isNoop(self: *const Runtime) bool {
        return self.* == .none;
    }

    fn MemoryMethodReturn(comptime method: []const u8) type {
        return @typeInfo(@TypeOf(@field(MemoryAgentMemory, method))).@"fn".return_type.?;
    }

    fn callMemoryLocked(engine: *MemoryAgentMemory, comptime method: []const u8, args: anytype) MemoryMethodReturn(method) {
        engine.mutex.lockUncancelable(compat.io());
        defer engine.mutex.unlock(compat.io());
        return @call(.auto, @field(MemoryAgentMemory, method), .{engine} ++ args);
    }

    pub fn store(self: *Runtime, allocator: std.mem.Allocator, input: Input) !domain.AgentMemory {
        const normalized = normalizeInput(input);
        return switch (self.*) {
            .none => noopAgentMemory(allocator, normalized),
            .native => error.NativeAgentMemoryRuntime,
            .markdown => |*engine| engine.store(allocator, normalized),
            .memory_lru => |*engine| callMemoryLocked(engine, "store", .{ allocator, normalized }),
            .redis => |*engine| engine.store(allocator, normalized),
            .clickhouse => |*engine| engine.store(allocator, normalized),
            .holographic => |*engine| storeHolographic(engine, allocator, normalized),
            .api, .supermemory, .openviking, .honcho, .mem0, .hindsight, .retaindb, .byterover, .zep, .falkordb => |*engine| engine.store(allocator, normalized),
        };
    }

