            .holographic => |*engine| engine.listSessionsByInput(allocator, input),
            .api, .supermemory, .openviking, .honcho, .mem0, .hindsight, .retaindb, .byterover, .zep, .falkordb => |*engine| engine.listSessionsByInput(allocator, input),
        };
    }

    pub fn historyByInput(self: *Runtime, allocator: std.mem.Allocator, input: HistoryInput) !HistoryShow {
        return switch (self.*) {
            .none => .{ .total = 0, .messages = try allocator.alloc(Message, 0) },
            .native => error.NativeAgentMemoryRuntime,
            .markdown => |*engine| engine.historyByInput(allocator, input),
            .memory_lru => |*engine| callMemoryLocked(engine, "historyByInput", .{ allocator, input }),
            .redis => |*engine| engine.historyByInput(allocator, input),
            .clickhouse => |*engine| engine.historyByInput(allocator, input),
            .holographic => |*engine| engine.historyByInput(allocator, input),
