fn noopAgentMemory(allocator: std.mem.Allocator, input: Input) !domain.AgentMemory {
    const request_actor = try access.requiredActorId(input.actor_id);
    const owner_actor = try access.agentMemoryOwner(allocator, request_actor, input.scope);
    defer allocator.free(owner_actor);
    const writer_actor = input.writer_actor_id orelse request_actor;
    const scope = try access.agentMemoryScope(allocator, owner_actor, input.session_id, input.scope);
    defer allocator.free(scope);
    const permissions = try access.agentMemoryPermissions(allocator, owner_actor, input.scope, input.permissions_json);
    defer allocator.free(permissions);
    const status = domain.defaultMemoryStatus("agent", scope);
    const content = try agent_memory_reducer.reduceContent(allocator, input.operation, null, input.content);
    defer allocator.free(content);

    return .{
        .id = try memoryEntryId(allocator, owner_actor, input.session_id, input.key),
        .key = try allocator.dupe(u8, input.key),
        .content = try allocator.dupe(u8, content),
        .category = try allocator.dupe(u8, input.category),
        .timestamp = try std.fmt.allocPrint(allocator, "{d}", .{ids.nowMs()}),
        .session_id = if (input.session_id) |sid| try allocator.dupe(u8, sid) else null,
        .actor_id = try allocator.dupe(u8, owner_actor),
        .writer_actor_id = try allocator.dupe(u8, writer_actor),
        .scope = try allocator.dupe(u8, scope),
        .permissions_json = try allocator.dupe(u8, permissions),
        .status = try allocator.dupe(u8, status),
        .store = try allocator.dupe(u8, "none"),
    };
}

fn storeHolographic(engine: *holographic.Engine, allocator: std.mem.Allocator, input: Input) !domain.AgentMemory {
    const request_actor = try access.requiredActorId(input.actor_id);
    const owner_actor = try access.agentMemoryOwner(allocator, request_actor, input.scope);
    defer allocator.free(owner_actor);
    const writer_actor = input.writer_actor_id orelse request_actor;
    return engine.store(allocator, .{
        .key = input.key,
        .content = input.content,
        .category = input.category,
        .session_id = input.session_id,
        .owner_actor_id = owner_actor,
        .writer_actor_id = writer_actor,
        .requested_scope = input.scope,
        .requested_permissions_json = input.permissions_json,
        .metadata_json = input.metadata_json,
        .operation = input.operation,
        .timestamp_ms = eventTimestampMs(input),
    });
}

fn markdownEntryId(allocator: std.mem.Allocator, filename: []const u8, line_idx: usize, key: []const u8, content: []const u8) ![]u8 {
    var hash_value = std.hash.Wyhash.hash(0, filename);
    hash_value = std.hash.Wyhash.hash(hash_value, std.mem.asBytes(&line_idx));
    hash_value = std.hash.Wyhash.hash(hash_value, key);
    hash_value = std.hash.Wyhash.hash(hash_value, content);
    return std.fmt.allocPrint(allocator, "md_{x}", .{hash_value});
}

fn markdownTimestamp(allocator: std.mem.Allocator, filename: []const u8) ![]u8 {
    if (filename.len >= "YYYY-MM-DD".len and
        std.ascii.isDigit(filename[0]) and std.ascii.isDigit(filename[1]) and
        std.ascii.isDigit(filename[2]) and std.ascii.isDigit(filename[3]) and
        filename[4] == '-' and
        std.ascii.isDigit(filename[5]) and std.ascii.isDigit(filename[6]) and
        filename[7] == '-' and
        std.ascii.isDigit(filename[8]) and std.ascii.isDigit(filename[9]))
    {
        return std.fmt.allocPrint(allocator, "{s}{s}{s}000000", .{ filename[0..4], filename[5..7], filename[8..10] });
    }
    return allocator.dupe(u8, "0");
}

fn markdownEntryMatchesKey(entry: domain.AgentMemory, key: []const u8) bool {
    if (std.mem.eql(u8, entry.key, key)) return true;
    if (domain.extractMarkdownMemoryKey(entry.content)) |extracted| {
        if (std.mem.eql(u8, extracted, key)) return true;
    }
    return std.mem.indexOf(u8, entry.content, key) != null;
}

fn markdownEndsWithIgnoreCase(value: []const u8, suffix: []const u8) bool {
    if (value.len < suffix.len) return false;
    return std.ascii.eqlIgnoreCase(value[value.len - suffix.len ..], suffix);
}

pub const MarkdownAgentMemory = struct {
    allocator: std.mem.Allocator,
    workspace_dir: []const u8,
    max_file_bytes: usize,
    default_scope: []const u8,
    permissions_json: []const u8,

    pub fn init(allocator: std.mem.Allocator, config: MarkdownConfig) !MarkdownAgentMemory {
        try config.validateUsable();
        return .{
            .allocator = allocator,
            .workspace_dir = try allocator.dupe(u8, config.workspace_dir),
            .max_file_bytes = config.max_file_bytes,
            .default_scope = try allocator.dupe(u8, config.default_scope),
            .permissions_json = try allocator.dupe(u8, config.permissions_json),
        };
    }

    pub fn deinit(self: *MarkdownAgentMemory) void {
        self.allocator.free(self.workspace_dir);
        self.allocator.free(self.default_scope);
        self.allocator.free(self.permissions_json);
    }

    pub fn store(self: *MarkdownAgentMemory, allocator: std.mem.Allocator, input: Input) !domain.AgentMemory {
        const request_actor = try access.requiredActorId(input.actor_id);
        const owner_actor = try access.agentMemoryOwner(allocator, request_actor, input.scope);
        defer allocator.free(owner_actor);
        const writer_actor = input.writer_actor_id orelse request_actor;
        const scope = try access.agentMemoryScope(allocator, owner_actor, input.session_id, input.scope);
        defer allocator.free(scope);
        const permissions = try access.agentMemoryPermissions(allocator, owner_actor, input.scope, input.permissions_json);
        defer allocator.free(permissions);

        var existing = try self.get(allocator, input.key, input.session_id, input.actor_id);
        defer if (existing) |*entry| freeAgentMemory(allocator, entry);
        const existing_content = if (existing) |entry| entry.content else null;
        const reduced_content = try agent_memory_reducer.reduceContent(allocator, input.operation, existing_content, input.content);
        defer allocator.free(reduced_content);

        const entry_text = try std.fmt.allocPrint(allocator, "- **{s}**: {s}", .{ input.key, reduced_content });
        defer allocator.free(entry_text);
        const path = if (std.mem.eql(u8, input.category, "core"))
            try self.rootPath(allocator, "MEMORY.md")
        else
            try self.dailyPath(allocator);
        defer allocator.free(path);
        try self.appendLine(path, entry_text);

        const timestamp = eventTimestampMs(input);
        const id = try markdownEntryId(allocator, "write", 0, input.key, reduced_content);
        errdefer allocator.free(id);
        const status = domain.defaultMemoryStatus("agent", scope);
        return .{
            .id = id,
            .key = try allocator.dupe(u8, input.key),
            .content = try allocator.dupe(u8, reduced_content),
            .category = try allocator.dupe(u8, input.category),
            .timestamp = try std.fmt.allocPrint(allocator, "{d}", .{timestamp}),
            .session_id = if (input.session_id) |sid| try allocator.dupe(u8, sid) else null,
            .actor_id = try allocator.dupe(u8, owner_actor),
            .writer_actor_id = try allocator.dupe(u8, writer_actor),
            .scope = try allocator.dupe(u8, scope),
            .permissions_json = try allocator.dupe(u8, permissions),
            .status = try allocator.dupe(u8, status),
            .store = try allocator.dupe(u8, "markdown"),
        };
    }

    pub fn getByInput(self: *MarkdownAgentMemory, allocator: std.mem.Allocator, input: GetInput) !?domain.AgentMemory {
        const normalized_session_id = access.normalizeSessionId(input.session_id);
        if (input.scopes_json) |scopes_json| {
            const actor_id = input.actor_id orelse return error.InvalidAgentMemoryRuntimeRequest;
            if (input.any_session) return self.getAnyVisible(allocator, input.key, actor_id, scopes_json);
            return self.getVisible(allocator, input.key, normalized_session_id, actor_id, scopes_json);
        }
        return self.get(allocator, input.key, normalized_session_id, input.actor_id);
    }

    fn get(self: *MarkdownAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8) !?domain.AgentMemory {
        _ = session_id;
        _ = actor_id;
        const all = try self.readAllEntries(allocator);
        defer allocator.free(all);
        var found: ?domain.AgentMemory = null;
        for (all) |*entry_ptr| {
            const entry = entry_ptr.*;
            if (markdownEntryMatchesKey(entry, key)) {
                if (found) |*prev| freeAgentMemory(allocator, prev);
                found = entry;
                detachAgentMemory(entry_ptr);
            }
            freeAgentMemory(allocator, entry_ptr);
        }
        return found;
    }

    fn getVisible(self: *MarkdownAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8) !?domain.AgentMemory {
        _ = session_id;
        const all = try self.readAllEntries(allocator);
        defer allocator.free(all);
        var matches: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        defer matches.deinit(allocator);
        errdefer for (matches.items) |*entry| freeAgentMemory(allocator, entry);
        for (all) |*entry_ptr| {
            const entry = entry_ptr.*;
            if (markdownEntryMatchesKey(entry, key) and try entryVisible(allocator, entry, actor_id, scopes_json)) {
                try matches.append(allocator, entry);
                detachAgentMemory(entry_ptr);
            }
            freeAgentMemory(allocator, entry_ptr);
        }
        sortAgentMemoryForVisibleGet(matches.items, actor_id);
        if (matches.items.len == 0) return null;
        const result = matches.items[0];
        for (matches.items[1..]) |*entry| freeAgentMemory(allocator, entry);
        return result;
    }

    fn getAnyVisible(self: *MarkdownAgentMemory, allocator: std.mem.Allocator, key: []const u8, actor_id: []const u8, scopes_json: []const u8) !?domain.AgentMemory {
        return self.getVisible(allocator, key, null, actor_id, scopes_json);
    }

    pub fn listByInput(self: *MarkdownAgentMemory, allocator: std.mem.Allocator, input: ListInput) ![]domain.AgentMemory {
        const normalized_session_id = access.normalizeSessionId(input.session_id);
        if (input.limit) |limit| {
            if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
            if (input.scopes_json) |scopes_json| {
                const actor_id = input.actor_id orelse return error.InvalidAgentMemoryRuntimeRequest;
                if (input.any_session) return self.listAnyVisibleWindow(allocator, input.category, actor_id, scopes_json, limit, input.offset);
                return self.listVisibleWindow(allocator, input.category, normalized_session_id, actor_id, scopes_json, limit, input.offset);
            }
            return self.listWindow(allocator, input.category, normalized_session_id, input.actor_id, limit, input.offset);
        }
        if (input.scopes_json) |scopes_json| {
            const actor_id = input.actor_id orelse return error.InvalidAgentMemoryRuntimeRequest;
            if (input.any_session) return self.listAnyVisible(allocator, input.category, actor_id, scopes_json);
            return self.listVisible(allocator, input.category, normalized_session_id, actor_id, scopes_json);
        }
        return self.list(allocator, input.category, normalized_session_id, input.actor_id);
    }

    fn list(self: *MarkdownAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: ?[]const u8) ![]domain.AgentMemory {
        _ = session_id;
        _ = actor_id;
        return self.listInternal(allocator, category, null, null, 0, 0);
    }

    fn listWindow(self: *MarkdownAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: ?[]const u8, limit: usize, offset: usize) ![]domain.AgentMemory {
        _ = session_id;
        _ = actor_id;
        return self.listInternal(allocator, category, null, null, limit, offset);
    }

    fn listVisible(self: *MarkdownAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8) ![]domain.AgentMemory {
        _ = session_id;
        return self.listInternal(allocator, category, actor_id, scopes_json, 0, 0);
    }

    fn listVisibleWindow(self: *MarkdownAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, limit: usize, offset: usize) ![]domain.AgentMemory {
        _ = session_id;
        return self.listInternal(allocator, category, actor_id, scopes_json, limit, offset);
    }

    fn listAnyVisible(self: *MarkdownAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, actor_id: []const u8, scopes_json: []const u8) ![]domain.AgentMemory {
        return self.listInternal(allocator, category, actor_id, scopes_json, 0, 0);
    }

    fn listAnyVisibleWindow(self: *MarkdownAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, limit: usize, offset: usize) ![]domain.AgentMemory {
        return self.listInternal(allocator, category, actor_id, scopes_json, limit, offset);
    }

    pub fn searchByInput(self: *MarkdownAgentMemory, allocator: std.mem.Allocator, input: SearchInput) ![]domain.AgentMemory {
        if (input.limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        const normalized_session_id = access.normalizeSessionId(input.session_id);
        if (input.any_session) return self.searchAnyVisible(allocator, input.query, input.limit, input.scopes_json, input.actor_id);
        return self.search(allocator, input.query, input.limit, normalized_session_id, input.scopes_json, input.actor_id);
    }

    fn search(self: *MarkdownAgentMemory, allocator: std.mem.Allocator, query: []const u8, limit: usize, session_id: ?[]const u8, scopes_json: []const u8, actor_id: ?[]const u8) ![]domain.AgentMemory {
        _ = session_id;
        const actor = actor_id orelse return allocator.alloc(domain.AgentMemory, 0);
        return self.searchInternal(allocator, query, limit, actor, scopes_json);
    }

    fn searchAnyVisible(self: *MarkdownAgentMemory, allocator: std.mem.Allocator, query: []const u8, limit: usize, scopes_json: []const u8, actor_id: ?[]const u8) ![]domain.AgentMemory {
        const actor = actor_id orelse return allocator.alloc(domain.AgentMemory, 0);
        return self.searchInternal(allocator, query, limit, actor, scopes_json);
    }

    pub fn deleteByInput(self: *MarkdownAgentMemory, input: DeleteInput) !bool {
        const normalized_session_id = access.normalizeSessionId(input.session_id);
        if (input.all_owners) return self.deleteAll(input.key, input.actor_id, input.writer_actor_id);
        return self.delete(input.key, normalized_session_id, input.actor_id, input.writer_actor_id);
    }

    fn delete(_: *MarkdownAgentMemory, _: []const u8, _: ?[]const u8, _: ?[]const u8, _: ?[]const u8) !bool {
        return false;
    }

    fn deleteAll(_: *MarkdownAgentMemory, _: []const u8, _: ?[]const u8, _: ?[]const u8) !bool {
        return false;
    }

    pub fn patchStatusByInput(self: *MarkdownAgentMemory, allocator: std.mem.Allocator, input: PatchStatusInput) !bool {
        return self.patchStatus(allocator, input.key, access.normalizeSessionId(input.session_id), input.actor_id, input.status, input.writer_actor_id);
    }

    fn patchStatus(_: *MarkdownAgentMemory, _: std.mem.Allocator, _: []const u8, _: ?[]const u8, _: ?[]const u8, _: []const u8, _: ?[]const u8) !bool {
        return false;
    }

    pub fn countByInput(self: *MarkdownAgentMemory, input: CountInput) !usize {
        return self.count(input.actor_id, input.scopes_json);
    }

    fn count(self: *MarkdownAgentMemory, actor_id: ?[]const u8, scopes_json: []const u8) !usize {
        const entries = try self.readAllEntries(self.allocator);
        defer {
            for (entries) |*entry| freeAgentMemory(self.allocator, entry);
            self.allocator.free(entries);
        }
        if (actor_id) |actor| {
            var visible_count: usize = 0;
            for (entries) |entry| {
                if (try entryVisible(self.allocator, entry, actor, scopes_json)) visible_count = runtimeCountIncrement(visible_count);
            }
            return visible_count;
        }
        return entries.len;
    }

