    pub fn listSessionsByInput(_: *MarkdownAgentMemory, allocator: std.mem.Allocator, _: ListSessionsInput) !HistoryList {
        return .{ .total = 0, .sessions = try allocator.alloc(SessionInfo, 0) };
    }

