    fn listInternal(self: *MarkdownAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, actor_id: ?[]const u8, scopes_json: ?[]const u8, limit: usize, offset: usize) ![]domain.AgentMemory {
        if (limit == 0 and offset > 0) return allocator.alloc(domain.AgentMemory, 0);
        const all = try self.readAllEntries(allocator);
        defer allocator.free(all);
        var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (out.items) |*entry| freeAgentMemory(allocator, entry);
            out.deinit(allocator);
        }
        for (all) |*entry_ptr| {
            const entry = entry_ptr.*;
            if (category) |cat| if (!std.mem.eql(u8, entry.category, cat)) {
                freeAgentMemory(allocator, entry_ptr);
                continue;
            };
            if (actor_id) |actor| {
                const scopes = scopes_json orelse "[]";
                if (!try entryVisible(allocator, entry, actor, scopes)) {
                    freeAgentMemory(allocator, entry_ptr);
                    continue;
                }
            }
            try out.append(allocator, entry);
            detachAgentMemory(entry_ptr);
            freeAgentMemory(allocator, entry_ptr);
        }
        sortAgentMemory(out.items);
        const owned = try out.toOwnedSlice(allocator);
        out = .empty;
        if (limit == 0) return owned;
        return pageAgentMemorySlice(allocator, owned, limit, offset);
    }

    fn searchInternal(self: *MarkdownAgentMemory, allocator: std.mem.Allocator, query: []const u8, limit: usize, actor_id: []const u8, scopes_json: []const u8) ![]domain.AgentMemory {
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        const all = try self.readAllEntries(allocator);
        defer allocator.free(all);
        var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (out.items) |*entry| freeAgentMemory(allocator, entry);
            out.deinit(allocator);
        }
        for (all) |*entry_ptr| {
            var entry = entry_ptr.*;
            if (!try entryVisible(allocator, entry, actor_id, scopes_json)) {
                freeAgentMemory(allocator, entry_ptr);
                continue;
            }
            const score = scoreText(query, entry.key) + scoreText(query, entry.content);
            if (score <= 0 and query.len > 0) {
                freeAgentMemory(allocator, entry_ptr);
                continue;
            }
            entry.score = score + 0.5;
            try out.append(allocator, entry);
            detachAgentMemory(entry_ptr);
            freeAgentMemory(allocator, entry_ptr);
            sortAgentMemory(out.items);
            trimAgentMemorySearchResults(allocator, &out, limit);
        }
        return out.toOwnedSlice(allocator);
    }

    fn readAllEntries(self: *MarkdownAgentMemory, allocator: std.mem.Allocator) ![]domain.AgentMemory {
        var all: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (all.items) |*entry| freeAgentMemory(allocator, entry);
            all.deinit(allocator);
        }

        const root_candidates = [_]struct { filename: []const u8, label: []const u8 }{
            .{ .filename = "MEMORY.md", .label = "MEMORY" },
            .{ .filename = "memory.md", .label = "memory" },
        };
        for (root_candidates) |candidate| {
            const path = try self.rootPath(allocator, candidate.filename);
            defer allocator.free(path);
            const content = std.Io.Dir.cwd().readFileAlloc(compat.io(), path, allocator, .limited(self.max_file_bytes)) catch |err| switch (err) {
                error.FileNotFound => continue,
                else => return err,
            };
            defer allocator.free(content);
            const entries = try self.parseEntries(allocator, content, candidate.label, "core");
            defer allocator.free(entries);
            for (entries) |entry| try all.append(allocator, entry);
        }

        const dir_path = try self.memoryDir(allocator);
        defer allocator.free(dir_path);
        var dir = std.Io.Dir.cwd().openDir(compat.io(), dir_path, .{ .iterate = true }) catch |err| switch (err) {
            error.FileNotFound => return all.toOwnedSlice(allocator),
            error.NotDir => return all.toOwnedSlice(allocator),
            else => return err,
        };
        defer dir.close(compat.io());
        var walker = try dir.walk(allocator);
        defer walker.deinit();
        while (try walker.next(compat.io())) |entry| {
            if (entry.kind != .file) continue;
            if (!markdownEndsWithIgnoreCase(entry.path, ".md")) continue;
            const full_path = try std.fs.path.join(allocator, &.{ dir_path, entry.path });
            defer allocator.free(full_path);
            const content = std.Io.Dir.cwd().readFileAlloc(compat.io(), full_path, allocator, .limited(self.max_file_bytes)) catch continue;
            defer allocator.free(content);
            const label = entry.basename[0 .. entry.basename.len - ".md".len];
            const entries = try self.parseEntries(allocator, content, label, "daily");
            defer allocator.free(entries);
            for (entries) |parsed_entry| try all.append(allocator, parsed_entry);
        }
        sortAgentMemory(all.items);
        return all.toOwnedSlice(allocator);
    }

    fn parseEntries(self: *MarkdownAgentMemory, allocator: std.mem.Allocator, text: []const u8, filename: []const u8, category: []const u8) ![]domain.AgentMemory {
        var entries: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (entries.items) |*entry| freeAgentMemory(allocator, entry);
            entries.deinit(allocator);
        }
        const owner = try access.sharedAgentMemoryOwner(allocator, self.default_scope);
        defer allocator.free(owner);
        var line_idx: usize = 0;
        var iter = std.mem.splitScalar(u8, text, '\n');
        while (iter.next()) |line| {
            const trimmed = std.mem.trim(u8, line, " \t\r");
            if (trimmed.len == 0 or trimmed[0] == '#') continue;
            if (std.mem.eql(u8, trimmed, "---")) continue;
            const clean = if (std.mem.startsWith(u8, trimmed, "- ")) trimmed[2..] else trimmed;
            var generated_key: ?[]u8 = null;
            defer if (generated_key) |generated| allocator.free(generated);
            const key = domain.extractMarkdownMemoryKey(clean) orelse blk: {
                generated_key = try std.fmt.allocPrint(allocator, "{s}:{d}", .{ filename, line_idx });
                break :blk generated_key.?;
            };
            const id = try markdownEntryId(allocator, filename, line_idx, key, clean);
            errdefer allocator.free(id);
            const timestamp = try markdownTimestamp(allocator, filename);
            errdefer allocator.free(timestamp);
            try entries.append(allocator, .{
                .id = id,
                .key = try allocator.dupe(u8, key),
                .content = try allocator.dupe(u8, clean),
                .category = try allocator.dupe(u8, category),
                .timestamp = timestamp,
                .session_id = null,
                .actor_id = try allocator.dupe(u8, owner),
                .writer_actor_id = try allocator.dupe(u8, owner),
                .scope = try allocator.dupe(u8, self.default_scope),
                .permissions_json = try allocator.dupe(u8, self.permissions_json),
                .status = try allocator.dupe(u8, "proposed"),
                .store = try allocator.dupe(u8, "markdown"),
            });
            line_idx += 1;
        }
        return entries.toOwnedSlice(allocator);
    }

    fn rootPath(self: *MarkdownAgentMemory, allocator: std.mem.Allocator, filename: []const u8) ![]u8 {
        return std.fs.path.join(allocator, &.{ self.workspace_dir, filename });
    }

    fn memoryDir(self: *MarkdownAgentMemory, allocator: std.mem.Allocator) ![]u8 {
        return std.fs.path.join(allocator, &.{ self.workspace_dir, "memory" });
    }

    fn dailyPath(self: *MarkdownAgentMemory, allocator: std.mem.Allocator) ![]u8 {
        const now_ms = ids.nowMs();
        const epoch: u64 = if (now_ms <= 0) 0 else @intCast(@divTrunc(now_ms, 1000));
        const es = std.time.epoch.EpochSeconds{ .secs = epoch };
        const day = es.getEpochDay().calculateYearDay();
        const md = day.calculateMonthDay();
        const filename = try std.fmt.allocPrint(allocator, "{d:0>4}-{d:0>2}-{d:0>2}.md", .{ day.year, @intFromEnum(md.month), md.day_index + 1 });
        defer allocator.free(filename);
        return std.fs.path.join(allocator, &.{ self.workspace_dir, "memory", filename });
    }

    fn appendLine(self: *MarkdownAgentMemory, path: []const u8, line: []const u8) !void {
        if (std.fs.path.dirname(path)) |parent| {
            if (parent.len > 0) try std.Io.Dir.cwd().createDirPath(compat.io(), parent);
        }
        const existing = std.Io.Dir.cwd().readFileAlloc(compat.io(), path, self.allocator, .limited(self.max_file_bytes)) catch |err| switch (err) {
            error.FileNotFound => null,
            else => return err,
        };
        defer if (existing) |bytes| self.allocator.free(bytes);
        var out: std.ArrayListUnmanaged(u8) = .empty;
        defer out.deinit(self.allocator);
        if (existing) |bytes| {
            try out.appendSlice(self.allocator, bytes);
            if (bytes.len > 0 and bytes[bytes.len - 1] != '\n') try out.append(self.allocator, '\n');
        }
        try out.appendSlice(self.allocator, line);
        try out.append(self.allocator, '\n');
        try std.Io.Dir.cwd().writeFile(compat.io(), .{
            .sub_path = path,
            .data = out.items,
            .flags = .{ .truncate = true },
        });
    }
};

test "markdown agent memory reads and appends live workspace files" {
    const allocator = std.testing.allocator;
    var tmp = std.testing.tmpDir(.{ .iterate = true });
    defer tmp.cleanup();

    const root_path = try std.fmt.allocPrint(allocator, ".zig-cache/tmp/{s}/markdown-runtime", .{tmp.sub_path});
    defer allocator.free(root_path);
    const memory_dir = try std.fs.path.join(allocator, &.{ root_path, "memory" });
    defer allocator.free(memory_dir);
    try std.Io.Dir.cwd().createDirPath(compat.io(), memory_dir);

    const memory_path = try std.fs.path.join(allocator, &.{ root_path, "MEMORY.md" });
    defer allocator.free(memory_path);
    const daily_path = try std.fs.path.join(allocator, &.{ memory_dir, "2026-06-04.md" });
    defer allocator.free(daily_path);
    try std.Io.Dir.cwd().writeFile(compat.io(), .{ .sub_path = memory_path, .data = "- **project.name**: NullPantry live markdown\n" });
    try std.Io.Dir.cwd().writeFile(compat.io(), .{ .sub_path = daily_path, .data = "- **decision**: Keep markdown live\n" });

    var runtime = try Runtime.init(allocator, .{ .backend = .markdown, .markdown = .{ .workspace_dir = root_path } });
    defer runtime.deinit();
    try std.testing.expectEqualStrings("markdown", runtime.backendName());

    var existing = (try testRuntimeGet(&runtime, allocator, "project.name", null, "agent:test")).?;
    defer freeAgentMemory(allocator, &existing);
    try std.testing.expect(std.mem.indexOf(u8, existing.content, "NullPantry live markdown") != null);

    const listed = try testRuntimeList(&runtime, allocator, null, null, null);
    defer {
        for (listed) |*entry| freeAgentMemory(allocator, entry);
        allocator.free(listed);
    }
    var saw_project = false;
    var saw_decision = false;
    for (listed) |entry| {
        if (std.mem.eql(u8, entry.key, "project.name")) saw_project = true;
        if (std.mem.eql(u8, entry.key, "decision")) saw_decision = true;
    }
    try std.testing.expect(saw_project);
    try std.testing.expect(saw_decision);

    const stored = try runtime.store(allocator, .{
        .key = "pref.lang",
        .content = "Russian",
        .actor_id = "agent:test",
        .scope = "public",
    });
    defer {
        var owned = stored;
        freeAgentMemory(allocator, &owned);
    }

    const updated = try std.Io.Dir.cwd().readFileAlloc(compat.io(), memory_path, allocator, .limited(1024 * 1024));
    defer allocator.free(updated);
    try std.testing.expect(std.mem.indexOf(u8, updated, "- **pref.lang**: Russian") != null);

    var reread = (try testRuntimeGet(&runtime, allocator, "pref.lang", null, "agent:test")).?;
    defer freeAgentMemory(allocator, &reread);
    try std.testing.expectEqualStrings("Russian", reread.content["**pref.lang**: ".len..]);
}

pub const MemoryAgentMemory = struct {
    allocator: std.mem.Allocator,
    mutex: std.Io.Mutex = .init,
    config: MemoryConfig = .{},
    entries: std.ArrayListUnmanaged(MemoryEntry) = .empty,
    tombstones: std.ArrayListUnmanaged(MemoryTombstone) = .empty,
    message_tombstones: std.ArrayListUnmanaged(MessageTombstone) = .empty,
    usage_tombstones: std.ArrayListUnmanaged(UsageTombstone) = .empty,
    messages: std.ArrayListUnmanaged(MemorySessionMessage) = .empty,
    usage: std.ArrayListUnmanaged(MemoryUsage) = .empty,
    feed_events: std.ArrayListUnmanaged(FeedEvent) = .empty,
    origin_frontiers: std.StringHashMapUnmanaged(i64) = .{},
    feed_cursor_floor: i64 = 0,
    feed_next_sequence: i64 = 1,
    test_now_ms: ?i64 = null,

    pub fn init(allocator: std.mem.Allocator, config: MemoryConfig) MemoryAgentMemory {
        return .{ .allocator = allocator, .config = config };
    }

    pub fn setTestNowMs(self: *MemoryAgentMemory, now_ms: ?i64) void {
        self.test_now_ms = now_ms;
    }

    fn nowMs(self: *MemoryAgentMemory) i64 {
        return self.test_now_ms orelse ids.nowMs();
    }

    fn inputTimestampMs(self: *MemoryAgentMemory, input: Input) i64 {
        if (input.event_order) |order| return order.timestamp_ms;
        return self.nowMs();
    }

    pub fn deinit(self: *MemoryAgentMemory) void {
        for (self.entries.items) |*entry| self.freeMemoryEntry(entry);
        self.entries.deinit(self.allocator);
        for (self.tombstones.items) |*tombstone| self.freeTombstone(tombstone);
        self.tombstones.deinit(self.allocator);
        for (self.message_tombstones.items) |*tombstone| self.freeMessageTombstone(tombstone);
        self.message_tombstones.deinit(self.allocator);
        for (self.usage_tombstones.items) |*tombstone| self.freeUsageTombstone(tombstone);
        self.usage_tombstones.deinit(self.allocator);
        for (self.messages.items) |*message| freeMemorySessionMessage(self.allocator, message);
        self.messages.deinit(self.allocator);
        for (self.usage.items) |*item| freeMemoryUsage(self.allocator, item);
        self.usage.deinit(self.allocator);
        for (self.feed_events.items) |*event| event.deinit(self.allocator);
        self.feed_events.deinit(self.allocator);
        var frontier_it = self.origin_frontiers.iterator();
        while (frontier_it.next()) |kv| self.allocator.free(kv.key_ptr.*);
        self.origin_frontiers.deinit(self.allocator);
    }

    fn cloneForCheckpointRestore(self: *MemoryAgentMemory) !MemoryAgentMemory {
        var out = MemoryAgentMemory.init(self.allocator, self.config);
        out.test_now_ms = self.test_now_ms;
        errdefer out.deinit();

        try out.entries.ensureTotalCapacity(self.allocator, self.entries.items.len);
        for (self.entries.items) |entry| {
            out.entries.appendAssumeCapacity(try cloneMemoryEntry(self.allocator, entry));
        }

        try out.tombstones.ensureTotalCapacity(self.allocator, self.tombstones.items.len);
        for (self.tombstones.items) |tombstone| {
            out.tombstones.appendAssumeCapacity(try cloneMemoryTombstone(self.allocator, tombstone));
        }

        try out.message_tombstones.ensureTotalCapacity(self.allocator, self.message_tombstones.items.len);
        for (self.message_tombstones.items) |tombstone| {
            out.message_tombstones.appendAssumeCapacity(try cloneMessageTombstone(self.allocator, tombstone));
        }

        try out.usage_tombstones.ensureTotalCapacity(self.allocator, self.usage_tombstones.items.len);
        for (self.usage_tombstones.items) |tombstone| {
            out.usage_tombstones.appendAssumeCapacity(try cloneUsageTombstone(self.allocator, tombstone));
        }

        try out.messages.ensureTotalCapacity(self.allocator, self.messages.items.len);
        for (self.messages.items) |message| {
            out.messages.appendAssumeCapacity(try cloneMemorySessionMessage(self.allocator, message));
        }

        try out.usage.ensureTotalCapacity(self.allocator, self.usage.items.len);
        for (self.usage.items) |usage| {
            out.usage.appendAssumeCapacity(try cloneMemoryUsage(self.allocator, usage));
        }

        try out.feed_events.ensureTotalCapacity(self.allocator, self.feed_events.items.len);
        for (self.feed_events.items) |event| {
            out.feed_events.appendAssumeCapacity(try event.clone(self.allocator));
        }

        var frontier_it = self.origin_frontiers.iterator();
        while (frontier_it.next()) |kv| {
            var owned_key: ?[]u8 = try self.allocator.dupe(u8, kv.key_ptr.*);
            errdefer if (owned_key) |key| self.allocator.free(key);
            try out.origin_frontiers.put(self.allocator, owned_key.?, kv.value_ptr.*);
            owned_key = null;
        }

        out.feed_cursor_floor = self.feed_cursor_floor;
        out.feed_next_sequence = self.feed_next_sequence;
        return out;
    }

    pub fn store(self: *MemoryAgentMemory, allocator: std.mem.Allocator, input: Input) !domain.AgentMemory {
        self.purgeExpired();
        const request_actor = try access.requiredActorId(input.actor_id);
        const owner_actor = try access.agentMemoryOwner(allocator, request_actor, input.scope);
        defer allocator.free(owner_actor);
        const writer_actor = input.writer_actor_id orelse request_actor;
        const scope = try access.agentMemoryScope(allocator, owner_actor, input.session_id, input.scope);
        defer allocator.free(scope);
        const permissions = try access.agentMemoryPermissions(allocator, owner_actor, input.scope, input.permissions_json);
        defer allocator.free(permissions);
        const status = domain.defaultMemoryStatus("agent", scope);
        const existing_idx = self.findEntryIndex(owner_actor, input.session_id, input.key);
        if (input.event_order) |order| {
            if (try self.tombstoneBlocksPut(input.key, input.session_id, owner_actor, order)) {
                if (existing_idx) |idx| return cloneAgentMemory(allocator, self.entries.items[idx].entry);
                return ignoredAgentMemory(allocator, input, owner_actor, writer_actor);
            }
            if (existing_idx) |idx| {
                if (compareEventOrderToMemoryEntry(order, self.entries.items[idx]) <= 0) {
                    return cloneAgentMemory(allocator, self.entries.items[idx].entry);
                }
            }
        }
        const existing_content = if (existing_idx) |idx| self.entries.items[idx].entry.content else null;
        const reduced_content = try agent_memory_reducer.reduceContent(allocator, input.operation, existing_content, input.content);
        defer allocator.free(reduced_content);
        _ = try self.deleteInternal(input.key, input.session_id, owner_actor, writer_actor, false, null);

        const timestamp = self.inputTimestampMs(input);
        const timestamp_text = try std.fmt.allocPrint(self.allocator, "{d}", .{timestamp});
        var timestamp_owned = true;
        errdefer if (timestamp_owned) self.allocator.free(timestamp_text);
        const entry_id = try memoryEntryId(self.allocator, owner_actor, input.session_id, input.key);
        var entry_id_owned = true;
        errdefer if (entry_id_owned) self.allocator.free(entry_id);
        var stored = domain.AgentMemory{
            .id = entry_id,
            .key = try self.allocator.dupe(u8, input.key),
            .content = try self.allocator.dupe(u8, reduced_content),
            .category = try self.allocator.dupe(u8, input.category),
            .timestamp = timestamp_text,
            .session_id = if (input.session_id) |sid| try self.allocator.dupe(u8, sid) else null,
            .actor_id = try self.allocator.dupe(u8, owner_actor),
            .writer_actor_id = try self.allocator.dupe(u8, writer_actor),
            .scope = try self.allocator.dupe(u8, scope),
            .permissions_json = try self.allocator.dupe(u8, permissions),
            .status = try self.allocator.dupe(u8, status),
        };
        timestamp_owned = false;
        entry_id_owned = false;
        var stored_owned = true;
        errdefer {
            if (stored_owned) freeAgentMemory(self.allocator, &stored);
        }
        var stored_order = if (input.event_order) |order| try cloneEventOrder(self.allocator, order) else null;
        errdefer if (stored_order) |*order| freeEventOrder(self.allocator, order);
        try self.entries.append(self.allocator, .{ .entry = stored, .event_order = stored_order, .last_access_ms = timestamp });
        stored_owned = false;
        errdefer {
            var removed = self.entries.orderedRemove(self.entries.items.len - 1);
            self.freeMemoryEntry(&removed);
        }
        var result = try cloneAgentMemory(allocator, stored);
        errdefer freeAgentMemory(allocator, &result);
        if (!input.suppress_feed and !domain.isInternalMemoryEntryKeyOrContent(stored.key, stored.content)) {
            try self.appendAgentMemoryFeedEvent(stored, input.operation, input.content, input.event_order);
        }
        self.enforceLimits();
        return result;
    }

    pub fn getByInput(self: *MemoryAgentMemory, allocator: std.mem.Allocator, input: GetInput) !?domain.AgentMemory {
        const normalized_session_id = access.normalizeSessionId(input.session_id);
        if (input.scopes_json) |scopes_json| {
            const actor_id = input.actor_id orelse return error.InvalidAgentMemoryRuntimeRequest;
            if (input.any_session) return self.getAnyVisible(allocator, input.key, actor_id, scopes_json);
            return self.getVisible(allocator, input.key, normalized_session_id, actor_id, scopes_json);
        }
        return self.get(allocator, input.key, normalized_session_id, input.actor_id);
    }

    fn get(self: *MemoryAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8) !?domain.AgentMemory {
        self.purgeExpired();
        const owner = actor_id orelse return null;
        const idx = self.findEntryIndex(owner, session_id, key) orelse return null;
        self.entries.items[idx].last_access_ms = self.nowMs();
        return try cloneAgentMemory(allocator, self.entries.items[idx].entry);
    }

    fn getVisible(self: *MemoryAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8) !?domain.AgentMemory {
        return self.getVisibleInternal(allocator, key, session_id, false, actor_id, scopes_json);
    }

    fn getAnyVisible(self: *MemoryAgentMemory, allocator: std.mem.Allocator, key: []const u8, actor_id: []const u8, scopes_json: []const u8) !?domain.AgentMemory {
        return self.getVisibleInternal(allocator, key, null, true, actor_id, scopes_json);
    }

    fn getVisibleInternal(self: *MemoryAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, include_sessions: bool, actor_id: []const u8, scopes_json: []const u8) !?domain.AgentMemory {
        self.purgeExpired();
        var matches: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        defer matches.deinit(allocator);
        errdefer for (matches.items) |*entry| freeAgentMemory(allocator, entry);
        for (self.entries.items) |wrapped| {
            const entry = wrapped.entry;
            if (!std.mem.eql(u8, entry.key, key)) continue;
            if (session_id) |sid| {
                if (entry.session_id == null or !std.mem.eql(u8, entry.session_id.?, sid)) continue;
            } else if (entry.session_id != null and !include_sessions) continue;
            if (!try entryVisible(allocator, entry, actor_id, scopes_json)) continue;
            try matches.append(allocator, try cloneAgentMemory(allocator, entry));
        }
        sortAgentMemoryForVisibleGet(matches.items, actor_id);
        if (matches.items.len == 0) return null;
        const result = matches.items[0];
        for (matches.items[1..]) |*entry| freeAgentMemory(allocator, entry);
        self.touchEntryById(result.id, self.nowMs());
        return result;
    }

    pub fn listByInput(self: *MemoryAgentMemory, allocator: std.mem.Allocator, input: ListInput) ![]domain.AgentMemory {
        const normalized_session_id = access.normalizeSessionId(input.session_id);
        if (input.limit) |limit| {
            if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
            if (input.scopes_json) |scopes_json| {
                const actor_id = input.actor_id orelse return error.InvalidAgentMemoryRuntimeRequest;
                if (input.any_session) return self.listAnyVisibleWindow(allocator, input.category, actor_id, scopes_json, limit, input.offset);
                return self.listVisibleWindow(allocator, input.category, normalized_session_id, actor_id, scopes_json, limit, input.offset);
            }
            return self.listWindow(allocator, input.category, normalized_session_id, input.actor_id, limit, input.offset);
        }
        if (input.scopes_json) |scopes_json| {
            const actor_id = input.actor_id orelse return error.InvalidAgentMemoryRuntimeRequest;
            if (input.any_session) return self.listAnyVisible(allocator, input.category, actor_id, scopes_json);
            return self.listVisible(allocator, input.category, normalized_session_id, actor_id, scopes_json);
        }
        return self.list(allocator, input.category, normalized_session_id, input.actor_id);
    }

    fn list(self: *MemoryAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: ?[]const u8) ![]domain.AgentMemory {
        return self.listInternal(allocator, category, session_id, false, actor_id, null, false);
    }

    fn listWindow(self: *MemoryAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: ?[]const u8, limit: usize, offset: usize) ![]domain.AgentMemory {
        return self.listInternalWindow(allocator, category, session_id, false, actor_id, null, false, limit, offset);
    }

    fn listVisible(self: *MemoryAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8) ![]domain.AgentMemory {
        return self.listInternal(allocator, category, session_id, false, null, .{ .actor_id = actor_id, .scopes_json = scopes_json }, true);
    }

    fn listVisibleWindow(self: *MemoryAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, limit: usize, offset: usize) ![]domain.AgentMemory {
        return self.listInternalWindow(allocator, category, session_id, false, null, .{ .actor_id = actor_id, .scopes_json = scopes_json }, true, limit, offset);
    }

    fn listAnyVisible(self: *MemoryAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, actor_id: []const u8, scopes_json: []const u8) ![]domain.AgentMemory {
        return self.listInternal(allocator, category, null, true, null, .{ .actor_id = actor_id, .scopes_json = scopes_json }, true);
    }

    fn listAnyVisibleWindow(self: *MemoryAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, limit: usize, offset: usize) ![]domain.AgentMemory {
        return self.listInternalWindow(allocator, category, null, true, null, .{ .actor_id = actor_id, .scopes_json = scopes_json }, true, limit, offset);
    }

    pub fn searchByInput(self: *MemoryAgentMemory, allocator: std.mem.Allocator, input: SearchInput) ![]domain.AgentMemory {
        if (input.limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        const normalized_session_id = access.normalizeSessionId(input.session_id);
        if (input.any_session) return self.searchAnyVisible(allocator, input.query, input.limit, input.scopes_json, input.actor_id);
        return self.search(allocator, input.query, input.limit, normalized_session_id, input.scopes_json, input.actor_id);
    }

    fn search(self: *MemoryAgentMemory, allocator: std.mem.Allocator, query: []const u8, limit: usize, session_id: ?[]const u8, scopes_json: []const u8, actor_id: ?[]const u8) ![]domain.AgentMemory {
        const actor = actor_id orelse return allocator.alloc(domain.AgentMemory, 0);
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        return self.searchInternal(allocator, query, limit, session_id, false, .{ .actor_id = actor, .scopes_json = scopes_json });
    }

    fn searchAnyVisible(self: *MemoryAgentMemory, allocator: std.mem.Allocator, query: []const u8, limit: usize, scopes_json: []const u8, actor_id: ?[]const u8) ![]domain.AgentMemory {
        const actor = actor_id orelse return allocator.alloc(domain.AgentMemory, 0);
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        return self.searchInternal(allocator, query, limit, null, true, .{ .actor_id = actor, .scopes_json = scopes_json });
    }

    fn searchInternal(self: *MemoryAgentMemory, allocator: std.mem.Allocator, query: []const u8, limit: usize, session_id: ?[]const u8, include_sessions: bool, visible: VisibleFilter) ![]domain.AgentMemory {
        self.purgeExpired();
        var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (out.items) |*entry| freeAgentMemory(allocator, entry);
            out.deinit(allocator);
        }
        for (self.entries.items) |wrapped| {
            const entry = wrapped.entry;
            if (session_id) |sid| {
                if (entry.session_id == null or !std.mem.eql(u8, entry.session_id.?, sid)) continue;
            } else if (entry.session_id != null and !include_sessions) continue;
            if (!try entryVisible(allocator, entry, visible.actor_id, visible.scopes_json)) continue;
            const score = scoreText(query, entry.key) + scoreText(query, entry.content);
            if (score <= 0 and query.len > 0) continue;
            var copy = try cloneAgentMemory(allocator, entry);
            var copy_owned = true;
            errdefer if (copy_owned) freeAgentMemory(allocator, &copy);
            copy.score = score + 0.5;
            try out.append(allocator, copy);
            copy_owned = false;
            sortAgentMemory(out.items);
            trimAgentMemorySearchResults(allocator, &out, limit);
        }
        const access_time = self.nowMs();
        for (out.items) |entry| self.touchEntryById(entry.id, access_time);
        return out.toOwnedSlice(allocator);
    }

    pub fn deleteByInput(self: *MemoryAgentMemory, input: DeleteInput) !bool {
        const normalized_session_id = access.normalizeSessionId(input.session_id);
        const log_feed = !input.suppress_feed;
        if (input.all_owners) {
            if (input.event_order != null) return self.deleteAllOrderedInternal(input.key, input.actor_id, input.writer_actor_id, input.event_order, log_feed);
            return self.deleteAllInternal(input.key, input.actor_id, input.writer_actor_id, log_feed, null);
        }
        if (input.event_order != null) return self.deleteOrderedInternal(input.key, normalized_session_id, input.actor_id, input.writer_actor_id, input.event_order, log_feed);
        return self.deleteInternal(input.key, normalized_session_id, input.actor_id, input.writer_actor_id, log_feed, null);
    }

    fn deleteInternal(self: *MemoryAgentMemory, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, log_feed: bool, event_order: ?EventOrder) !bool {
        self.purgeExpired();
        const owner = actor_id orelse return false;
        const idx = self.findEntryIndex(owner, session_id, key) orelse return false;
        const existing = self.entries.items[idx].entry;
        const scope = try self.allocator.dupe(u8, existing.scope);
        defer self.allocator.free(scope);
        const permissions = try self.allocator.dupe(u8, existing.permissions_json);
        defer self.allocator.free(permissions);
        var removed = self.entries.orderedRemove(idx);
        self.freeMemoryEntry(&removed);
        if (log_feed) try self.appendAgentMemoryDeleteFeedEvent(key, session_id, owner, writer_actor_id orelse owner, scope, permissions, "delete", event_order);
        return true;
    }

    fn deleteOrderedInternal(self: *MemoryAgentMemory, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, event_order: ?EventOrder, log_feed: bool) !bool {
        const order = event_order orelse return self.deleteInternal(key, session_id, actor_id, writer_actor_id, log_feed, null);
        self.purgeExpired();
        const owner = actor_id orelse return false;
        try self.upsertTombstone(key, owner, .scoped, session_id, order);
        const idx = self.findEntryIndex(owner, session_id, key) orelse return false;
        if (compareEventOrderToMemoryEntry(order, self.entries.items[idx]) < 0) return false;
        const existing = self.entries.items[idx].entry;
        const scope = try self.allocator.dupe(u8, existing.scope);
        defer self.allocator.free(scope);
        const permissions = try self.allocator.dupe(u8, existing.permissions_json);
        defer self.allocator.free(permissions);
        var removed = self.entries.orderedRemove(idx);
        self.freeMemoryEntry(&removed);
        if (log_feed) try self.appendAgentMemoryDeleteFeedEvent(key, session_id, owner, writer_actor_id orelse owner, scope, permissions, "delete", event_order);
        return true;
    }

    fn deleteAllInternal(self: *MemoryAgentMemory, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, log_feed: bool, event_order: ?EventOrder) !bool {
        self.purgeExpired();
        const owner = actor_id orelse return false;
        var changed = false;
        var first_scope: ?[]u8 = null;
        defer if (first_scope) |scope| self.allocator.free(scope);
        var first_permissions: ?[]u8 = null;
        defer if (first_permissions) |permissions| self.allocator.free(permissions);
        var i: usize = 0;
        while (i < self.entries.items.len) {
            const entry = self.entries.items[i].entry;
            if (std.mem.eql(u8, entry.actor_id, owner) and std.mem.eql(u8, entry.key, key)) {
                if (first_scope == null) first_scope = try self.allocator.dupe(u8, entry.scope);
                if (first_permissions == null) first_permissions = try self.allocator.dupe(u8, entry.permissions_json);
                var removed = self.entries.orderedRemove(i);
                self.freeMemoryEntry(&removed);
                changed = true;
                continue;
            }
            i += 1;
        }
        if (changed and log_feed) {
            const fallback_scope = if (first_scope == null) try self.fallbackAgentMemoryScope(owner, null) else null;
            defer if (fallback_scope) |scope| self.allocator.free(scope);
            const fallback_permissions = if (first_permissions == null) try domain.actorGrantJson(self.allocator, owner) else null;
            defer if (fallback_permissions) |permissions| self.allocator.free(permissions);
            try self.appendAgentMemoryDeleteFeedEvent(key, null, owner, writer_actor_id orelse owner, first_scope orelse fallback_scope.?, first_permissions orelse fallback_permissions.?, "delete_all", event_order);
        }
        return changed;
    }

    fn deleteAllOrderedInternal(self: *MemoryAgentMemory, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, event_order: ?EventOrder, log_feed: bool) !bool {
        const order = event_order orelse return self.deleteAllInternal(key, actor_id, writer_actor_id, log_feed, null);
        self.purgeExpired();
        const owner = actor_id orelse return false;
        try self.upsertTombstone(key, owner, .all, null, order);
        var changed = false;
        var first_scope: ?[]u8 = null;
        defer if (first_scope) |scope| self.allocator.free(scope);
        var first_permissions: ?[]u8 = null;
        defer if (first_permissions) |permissions| self.allocator.free(permissions);
        var i: usize = 0;
        while (i < self.entries.items.len) {
            const entry = self.entries.items[i].entry;
            if (std.mem.eql(u8, entry.actor_id, owner) and std.mem.eql(u8, entry.key, key)) {
                if (compareEventOrderToMemoryEntry(order, self.entries.items[i]) < 0) {
                    i += 1;
                    continue;
                }
                if (first_scope == null) first_scope = try self.allocator.dupe(u8, entry.scope);
                if (first_permissions == null) first_permissions = try self.allocator.dupe(u8, entry.permissions_json);
                var removed = self.entries.orderedRemove(i);
                self.freeMemoryEntry(&removed);
                changed = true;
                continue;
            }
            i += 1;
        }
        if (changed and log_feed) {
            const fallback_scope = if (first_scope == null) try self.fallbackAgentMemoryScope(owner, null) else null;
            defer if (fallback_scope) |scope| self.allocator.free(scope);
            const fallback_permissions = if (first_permissions == null) try domain.actorGrantJson(self.allocator, owner) else null;
            defer if (fallback_permissions) |permissions| self.allocator.free(permissions);
            try self.appendAgentMemoryDeleteFeedEvent(key, null, owner, writer_actor_id orelse owner, first_scope orelse fallback_scope.?, first_permissions orelse fallback_permissions.?, "delete_all", event_order);
        }
        return changed;
    }

    pub fn patchStatusByInput(self: *MemoryAgentMemory, input: PatchStatusInput) !bool {
        return self.patchStatusOrdered(input.key, access.normalizeSessionId(input.session_id), input.actor_id, input.status, input.writer_actor_id, input.event_order);
    }

    fn patchStatus(self: *MemoryAgentMemory, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, status: []const u8, writer_actor_id: ?[]const u8) !bool {
        return self.patchStatusInternal(key, session_id, actor_id, writer_actor_id, status, true, null);
    }

    fn patchStatusOrdered(self: *MemoryAgentMemory, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, status: []const u8, writer_actor_id: ?[]const u8, event_order: ?EventOrder) !bool {
