    pub fn tombstoneBlocksReplayByInput(self: *MemoryAgentMemory, allocator: std.mem.Allocator, input: TombstoneBlocksReplayInput) !bool {
        _ = allocator;
        return self.tombstoneBlocksReplay(input.key, input.session_id, input.actor_id, input.event_order);
    }

    fn tombstoneBlocksReplay(self: *MemoryAgentMemory, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, event_order: EventOrder) !bool {
        self.purgeExpired();
        const owner = actor_id orelse return false;
        return self.tombstoneBlocksPut(key, session_id, owner, event_order);
    }

    fn patchStatusInternal(self: *MemoryAgentMemory, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, status: []const u8, log_feed: bool, event_order: ?EventOrder) !bool {
        self.purgeExpired();
        const owner = actor_id orelse return false;
        const idx = self.findEntryIndex(owner, session_id, key) orelse return false;
        var next_order: ?EventOrder = null;
        errdefer if (next_order) |*order| freeEventOrder(self.allocator, order);
        if (event_order) |order| {
            if (compareEventOrderToMemoryEntry(order, self.entries.items[idx]) <= 0) return false;
            if (!domain.isDefaultVisibleStatus(status)) {
                try self.upsertTombstone(key, owner, .scoped, session_id, order);
                const entry = self.entries.items[idx].entry;
                const scope = try self.allocator.dupe(u8, entry.scope);
                defer self.allocator.free(scope);
                const permissions = try self.allocator.dupe(u8, entry.permissions_json);
                defer self.allocator.free(permissions);
                if (log_feed) try self.appendAgentMemoryLifecycleFeedEvent(entry, writer_actor_id orelse owner, status, event_order);
                var removed = self.entries.orderedRemove(idx);
                self.freeMemoryEntry(&removed);
                return true;
            }
            next_order = try cloneEventOrder(self.allocator, order);
        }
        const updated = try self.allocator.dupe(u8, status);
        if (next_order) |order| {
            if (self.entries.items[idx].event_order) |*existing_order| freeEventOrder(self.allocator, existing_order);
            self.entries.items[idx].event_order = order;
            next_order = null;
        }
        if (self.entries.items[idx].entry.status.len > 0) self.allocator.free(self.entries.items[idx].entry.status);
        self.entries.items[idx].entry.status = updated;
        self.entries.items[idx].last_access_ms = self.nowMs();
        if (log_feed) try self.appendAgentMemoryLifecycleFeedEvent(self.entries.items[idx].entry, writer_actor_id orelse owner, status, event_order);
        return true;
    }

    pub fn countByInput(self: *MemoryAgentMemory, input: CountInput) !usize {
        return self.count(input.actor_id, input.scopes_json);
    }

    fn count(self: *MemoryAgentMemory, actor_id: ?[]const u8, scopes_json: []const u8) !usize {
        self.purgeExpired();
        if (actor_id) |actor| {
            var visible_count: usize = 0;
            for (self.entries.items) |wrapped| {
                if (!try entryVisible(self.allocator, wrapped.entry, actor, scopes_json)) continue;
                visible_count = runtimeCountIncrement(visible_count);
            }
            return visible_count;
        }
        return self.entries.items.len;
    }

    pub fn saveMessageByInput(self: *MemoryAgentMemory, input: SaveMessageInput) !void {
        return self.saveMessageAtOrderedInternal(input.session_id, input.role, input.content, input.created_at_ms, input.actor_id, input.event_order, !input.suppress_feed);
    }

    fn saveMessage(self: *MemoryAgentMemory, session_id: []const u8, role: []const u8, content: []const u8, actor_id: ?[]const u8) !void {
        return self.saveMessageAt(session_id, role, content, self.nowMs(), actor_id);
    }

    fn saveMessageAt(self: *MemoryAgentMemory, session_id: []const u8, role: []const u8, content: []const u8, created_at_ms: i64, actor_id: ?[]const u8) !void {
        return self.saveMessageAtOrdered(session_id, role, content, created_at_ms, actor_id, null);
    }

    fn saveMessageAtOrdered(self: *MemoryAgentMemory, session_id: []const u8, role: []const u8, content: []const u8, created_at_ms: i64, actor_id: ?[]const u8, event_order: ?EventOrder) !void {
        return self.saveMessageAtOrderedInternal(session_id, role, content, created_at_ms, actor_id, event_order, true);
    }

    fn saveMessageAtOrderedInternal(self: *MemoryAgentMemory, session_id: []const u8, role: []const u8, content: []const u8, created_at_ms: i64, actor_id: ?[]const u8, event_order: ?EventOrder, log_feed: bool) !void {
        self.purgeExpired();
        const actor = try access.requiredActorId(actor_id);
        if (event_order) |order| {
            if (try self.messageTombstoneBlocksPut(actor, session_id, order)) return;
        }
        var stored_order = if (event_order) |order| try cloneEventOrder(self.allocator, order) else null;
        errdefer if (stored_order) |*order| freeEventOrder(self.allocator, order);
        const stored = MemorySessionMessage{
            .actor_id = try self.allocator.dupe(u8, actor),
            .session_id = try self.allocator.dupe(u8, session_id),
            .role = try self.allocator.dupe(u8, role),
            .content = try self.allocator.dupe(u8, content),
            .created_at_ms = created_at_ms,
            .event_order = stored_order,
            .last_access_ms = self.nowMs(),
        };
        stored_order = null;
        errdefer {
            var cleanup = stored;
            freeMemorySessionMessage(self.allocator, &cleanup);
        }
        try self.messages.append(self.allocator, stored);
        if (log_feed and sessionMessageShouldEmitFeed(role)) try self.appendSessionMessageFeedEvent(session_id, role, content, created_at_ms, actor, event_order);
        self.enforceLimits();
    }

    pub fn loadMessagesByInput(self: *MemoryAgentMemory, allocator: std.mem.Allocator, input: LoadMessagesInput) ![]Message {
        return self.loadMessages(allocator, input.session_id, input.actor_id);
    }

    fn loadMessages(self: *MemoryAgentMemory, allocator: std.mem.Allocator, session_id: []const u8, actor_id: ?[]const u8) ![]Message {
        self.purgeExpired();
        const actor = actor_id orelse return allocator.alloc(Message, 0);
        var out: std.ArrayListUnmanaged(Message) = .empty;
        errdefer {
            for (out.items) |*message| freeMessage(allocator, message);
            out.deinit(allocator);
        }
        const access_time = self.nowMs();
        for (self.messages.items) |*message| {
            if (!std.mem.eql(u8, message.actor_id, actor) or !std.mem.eql(u8, message.session_id, session_id)) continue;
            message.last_access_ms = access_time;
            try out.append(allocator, .{
                .role = try allocator.dupe(u8, message.role),
                .content = try allocator.dupe(u8, message.content),
                .created_at_ms = message.created_at_ms,
            });
        }
        const messages = try out.toOwnedSlice(allocator);
        sortMessages(messages);
        return messages;
    }

    pub fn clearMessagesByInput(self: *MemoryAgentMemory, input: ClearMessagesInput) !void {
        return self.clearMessagesOrderedInternal(input.session_id, input.actor_id, input.event_order, !input.suppress_feed);
    }

    fn clearMessages(self: *MemoryAgentMemory, session_id: []const u8, actor_id: ?[]const u8) !void {
        return self.clearMessagesOrdered(session_id, actor_id, null);
    }

    fn clearMessagesOrdered(self: *MemoryAgentMemory, session_id: []const u8, actor_id: ?[]const u8, event_order: ?EventOrder) !void {
        return self.clearMessagesOrderedInternal(session_id, actor_id, event_order, true);
    }

    fn clearMessagesOrderedInternal(self: *MemoryAgentMemory, session_id: []const u8, actor_id: ?[]const u8, event_order: ?EventOrder, log_feed: bool) !void {
        self.purgeExpired();
        const actor = actor_id orelse return;
        var changed = false;
        if (event_order) |order| {
            try self.upsertMessageTombstone(actor, session_id, order);
        }
        var i: usize = 0;
        while (i < self.messages.items.len) {
            if (std.mem.eql(u8, self.messages.items[i].actor_id, actor) and std.mem.eql(u8, self.messages.items[i].session_id, session_id)) {
                if (event_order) |order| {
                    const existing = self.messages.items[i];
                    const existing_timestamp = if (existing.event_order) |stored| stored.timestamp_ms else existing.created_at_ms;
                    const existing_origin = if (existing.event_order) |stored| stored.origin_instance_id else "";
                    const existing_sequence = if (existing.event_order) |stored| stored.origin_sequence else 0;
                    if (compareEventOrder(order, existing_timestamp, existing_origin, existing_sequence) < 0) {
                        i += 1;
                        continue;
                    }
                }
                var removed = self.messages.orderedRemove(i);
                freeMemorySessionMessage(self.allocator, &removed);
                changed = true;
                continue;
            }
            i += 1;
        }
        _ = try self.deleteUsageOrderedInternal(session_id, actor, event_order, log_feed);
        if (changed and log_feed) try self.appendSessionMessageDeleteFeedEvent(session_id, actor, "delete", event_order);
    }

    pub fn clearAutoSavedByInput(self: *MemoryAgentMemory, input: ClearAutoSavedInput) !void {
        return self.clearAutoSavedInternal(input.session_id, input.actor_id, !input.suppress_feed);
    }

    fn clearAutoSaved(self: *MemoryAgentMemory, session_id: ?[]const u8, actor_id: ?[]const u8) !void {
        return self.clearAutoSavedInternal(session_id, actor_id, true);
    }

    fn clearAutoSavedInternal(self: *MemoryAgentMemory, session_id: ?[]const u8, actor_id: ?[]const u8, log_feed: bool) !void {
        self.purgeExpired();
        const actor = actor_id orelse return;
        var changed = false;
        var i: usize = 0;
        while (i < self.messages.items.len) {
            const message = self.messages.items[i];
            const same_actor = std.mem.eql(u8, message.actor_id, actor);
            const same_session = if (session_id) |sid| std.mem.eql(u8, message.session_id, sid) else true;
            if (same_actor and same_session and domain.isAutosaveSessionRole(message.role)) {
                var removed = self.messages.orderedRemove(i);
                freeMemorySessionMessage(self.allocator, &removed);
                changed = true;
                continue;
            }
            i += 1;
        }
        if (changed and log_feed) try self.appendSessionAutosaveDeleteFeedEvent(session_id, actor);
    }

    pub fn saveUsageByInput(self: *MemoryAgentMemory, input: SaveUsageInput) !void {
        return self.saveUsageOrderedInternal(input.session_id, input.total_tokens, input.actor_id, input.event_order, !input.suppress_feed);
    }

    fn saveUsage(self: *MemoryAgentMemory, session_id: []const u8, total_tokens: u64, actor_id: ?[]const u8) !void {
        return self.saveUsageOrdered(session_id, total_tokens, actor_id, null);
    }

    fn saveUsageOrdered(self: *MemoryAgentMemory, session_id: []const u8, total_tokens: u64, actor_id: ?[]const u8, event_order: ?EventOrder) !void {
        return self.saveUsageOrderedInternal(session_id, total_tokens, actor_id, event_order, true);
    }

    fn saveUsageOrderedInternal(self: *MemoryAgentMemory, session_id: []const u8, total_tokens: u64, actor_id: ?[]const u8, event_order: ?EventOrder, log_feed: bool) !void {
        self.purgeExpired();
        const actor = try access.requiredActorId(actor_id);
        const now = if (event_order) |order| order.timestamp_ms else self.nowMs();
        if (event_order) |order| {
            if (try self.usageTombstoneBlocksPut(actor, session_id, order)) return;
            if (self.findUsageIndex(actor, session_id)) |idx| {
                const existing = self.usage.items[idx];
                const existing_timestamp = if (existing.event_order) |stored| stored.timestamp_ms else existing.updated_at_ms;
                const existing_origin = if (existing.event_order) |stored| stored.origin_instance_id else "";
                const existing_sequence = if (existing.event_order) |stored| stored.origin_sequence else 0;
                if (compareEventOrder(order, existing_timestamp, existing_origin, existing_sequence) <= 0) return;
            }
        }
        if (self.findUsageIndex(actor, session_id)) |idx| {
            if (self.usage.items[idx].event_order) |*stored| freeEventOrder(self.allocator, stored);
            self.usage.items[idx].event_order = if (event_order) |order| try cloneEventOrder(self.allocator, order) else null;
            self.usage.items[idx].total_tokens = total_tokens;
            self.usage.items[idx].updated_at_ms = now;
            self.usage.items[idx].last_access_ms = now;
            if (log_feed) try self.appendSessionUsagePutFeedEvent(session_id, total_tokens, actor, event_order);
            return;
        }
        var stored_order = if (event_order) |order| try cloneEventOrder(self.allocator, order) else null;
        errdefer if (stored_order) |*order| freeEventOrder(self.allocator, order);
        const stored = MemoryUsage{
            .actor_id = try self.allocator.dupe(u8, actor),
            .session_id = try self.allocator.dupe(u8, session_id),
            .total_tokens = total_tokens,
            .updated_at_ms = now,
            .event_order = stored_order,
            .last_access_ms = now,
        };
        stored_order = null;
        errdefer {
            var cleanup = stored;
            freeMemoryUsage(self.allocator, &cleanup);
        }
        try self.usage.append(self.allocator, stored);
        if (log_feed) try self.appendSessionUsagePutFeedEvent(session_id, total_tokens, actor, event_order);
        self.enforceLimits();
    }

    pub fn deleteUsageByInput(self: *MemoryAgentMemory, input: DeleteUsageInput) !bool {
        return self.deleteUsageOrderedInternal(input.session_id, input.actor_id, input.event_order, !input.suppress_feed);
    }

    fn deleteUsage(self: *MemoryAgentMemory, session_id: []const u8, actor_id: ?[]const u8) !bool {
        return self.deleteUsageOrdered(session_id, actor_id, null);
    }

    fn deleteUsageOrdered(self: *MemoryAgentMemory, session_id: []const u8, actor_id: ?[]const u8, event_order: ?EventOrder) !bool {
        return self.deleteUsageOrderedInternal(session_id, actor_id, event_order, true);
    }

    fn deleteUsageOrderedInternal(self: *MemoryAgentMemory, session_id: []const u8, actor_id: ?[]const u8, event_order: ?EventOrder, log_feed: bool) !bool {
        self.purgeExpired();
        const actor = actor_id orelse return false;
        if (event_order) |order| {
            try self.upsertUsageTombstone(actor, session_id, order);
        }
        const idx = self.findUsageIndex(actor, session_id) orelse return false;
        if (event_order) |order| {
            const existing = self.usage.items[idx];
            const existing_timestamp = if (existing.event_order) |stored| stored.timestamp_ms else existing.updated_at_ms;
            const existing_origin = if (existing.event_order) |stored| stored.origin_instance_id else "";
            const existing_sequence = if (existing.event_order) |stored| stored.origin_sequence else 0;
            if (compareEventOrder(order, existing_timestamp, existing_origin, existing_sequence) < 0) return false;
        }
        var removed = self.usage.orderedRemove(idx);
        freeMemoryUsage(self.allocator, &removed);
        if (log_feed) try self.appendSessionUsageDeleteFeedEvent(session_id, actor, event_order);
        return true;
    }

    pub fn loadUsageByInput(self: *MemoryAgentMemory, input: LoadUsageInput) !?u64 {
        return self.loadUsage(input.session_id, input.actor_id);
    }

    fn loadUsage(self: *MemoryAgentMemory, session_id: []const u8, actor_id: ?[]const u8) !?u64 {
        self.purgeExpired();
        const actor = actor_id orelse return null;
        const idx = self.findUsageIndex(actor, session_id) orelse return null;
        self.usage.items[idx].last_access_ms = self.nowMs();
        return self.usage.items[idx].total_tokens;
    }

    pub fn listSessionsByInput(self: *MemoryAgentMemory, allocator: std.mem.Allocator, input: ListSessionsInput) !HistoryList {
        return self.listSessions(allocator, input.limit, input.offset, input.actor_id);
    }

    fn listSessions(self: *MemoryAgentMemory, allocator: std.mem.Allocator, limit: usize, offset: usize, actor_id: ?[]const u8) !HistoryList {
        self.purgeExpired();
        const actor = actor_id orelse return .{ .total = 0, .sessions = try allocator.alloc(SessionInfo, 0) };
        var all_sessions: std.ArrayListUnmanaged(SessionInfo) = .empty;
        var session_index = std.StringHashMap(usize).init(allocator);
        errdefer {
            for (all_sessions.items) |*info| freeSessionInfo(allocator, info);
            all_sessions.deinit(allocator);
        }
        defer session_index.deinit();
        for (self.messages.items) |message| {
            if (!std.mem.eql(u8, message.actor_id, actor)) continue;
            if (!domain.sessionMessageVisibleInHistory(message.role)) continue;
            if (session_index.get(message.session_id)) |idx| {
                all_sessions.items[idx].message_count += 1;
                all_sessions.items[idx].first_message_at = @min(all_sessions.items[idx].first_message_at, message.created_at_ms);
                all_sessions.items[idx].last_message_at = @max(all_sessions.items[idx].last_message_at, message.created_at_ms);
            } else {
                try session_index.ensureUnusedCapacity(1);
                const session_id = try allocator.dupe(u8, message.session_id);
                errdefer allocator.free(session_id);
                const idx = all_sessions.items.len;
                try all_sessions.append(allocator, .{
                    .session_id = session_id,
                    .message_count = 1,
                    .first_message_at = message.created_at_ms,
                    .last_message_at = message.created_at_ms,
                });
                session_index.putAssumeCapacityNoClobber(all_sessions.items[idx].session_id, idx);
            }
        }
        sortSessions(all_sessions.items);
        const total = all_sessions.items.len;
        const window = runtimePageWindow(limit, total, offset);
        var sessions = try allocator.alloc(SessionInfo, window.len);
        for (all_sessions.items, 0..) |*info, i| {
            if (i >= window.start and i < window.end) {
                sessions[i - window.start] = info.*;
                detachSessionInfo(info);
            } else {
                freeSessionInfo(allocator, info);
            }
        }
        all_sessions.deinit(allocator);
        return .{ .total = runtimeCountToU64(total), .sessions = sessions };
    }

    pub fn historyByInput(self: *MemoryAgentMemory, allocator: std.mem.Allocator, input: HistoryInput) !HistoryShow {
        return self.history(allocator, input.session_id, input.limit, input.offset, input.actor_id);
    }

    fn history(self: *MemoryAgentMemory, allocator: std.mem.Allocator, session_id: []const u8, limit: usize, offset: usize, actor_id: ?[]const u8) !HistoryShow {
        const messages = try self.loadMessages(allocator, session_id, actor_id);
        defer {
            for (messages) |*message| freeMessage(allocator, message);
            allocator.free(messages);
        }
        var total: usize = 0;
        var out: std.ArrayListUnmanaged(Message) = .empty;
        errdefer {
            for (out.items) |*message| freeMessage(allocator, message);
            out.deinit(allocator);
        }
        for (messages) |*message| {
            if (!domain.sessionMessageVisibleInHistory(message.role)) continue;
            if (total >= offset and out.items.len < limit) {
                try out.append(allocator, message.*);
                detachMessage(message);
            }
            total = runtimeCountIncrement(total);
        }
        return .{ .total = runtimeCountToU64(total), .messages = try out.toOwnedSlice(allocator) };
    }

    pub fn listFeedEventsByInput(self: *MemoryAgentMemory, allocator: std.mem.Allocator, input: ListFeedEventsInput) ![]FeedEvent {
        return self.listFeedEvents(allocator, input.since_id, input.limit, input.actor_id, input.scopes_json);
    }

    fn listFeedEvents(self: *MemoryAgentMemory, allocator: std.mem.Allocator, since_id: i64, limit: usize, actor_id: ?[]const u8, scopes_json: []const u8) ![]FeedEvent {
        self.purgeExpired();
        if (since_id < self.feed_cursor_floor) return error.CursorExpired;
        const target_limit = runtimeFeedEventTargetLimit(limit);
        var out: std.ArrayListUnmanaged(FeedEvent) = .empty;
        errdefer {
            for (out.items) |*event| event.deinit(allocator);
            out.deinit(allocator);
        }
        for (self.feed_events.items) |event| {
            if (event.id <= since_id) continue;
            if (event.compacted_at_ms != null) continue;
            if (!self.feedEventVisible(event, actor_id, scopes_json)) continue;
            try out.append(allocator, try event.clone(allocator));
            if (out.items.len >= target_limit) break;
        }
        return out.toOwnedSlice(allocator);
    }

    pub fn feedStatusByInput(self: *MemoryAgentMemory, allocator: std.mem.Allocator, input: FeedStatusInput) !FeedStatus {
        return self.feedStatus(allocator, input.actor_id, input.scopes_json);
    }

    fn feedStatus(self: *MemoryAgentMemory, allocator: std.mem.Allocator, actor_id: ?[]const u8, scopes_json: []const u8) !FeedStatus {
        self.purgeExpired();
        var visible: usize = 0;
        var pending: usize = 0;
        var applying: usize = 0;
        var applied: usize = 0;
        for (self.feed_events.items) |event| {
            if (event.compacted_at_ms != null) continue;
            if (!self.feedEventVisible(event, actor_id, scopes_json)) continue;
            visible = runtimeCountIncrement(visible);
            if (std.mem.eql(u8, event.status, "pending")) {
                pending = runtimeCountIncrement(pending);
            } else if (std.mem.eql(u8, event.status, "applying")) {
                applying = runtimeCountIncrement(applying);
            } else if (std.mem.eql(u8, event.status, "applied")) {
                applied = runtimeCountIncrement(applied);
            }
        }
        const max_event_id = self.lastFeedEventId();
        const local_frontier_next = runtimeFeedSequenceAfter(self.originFrontier("memory_lru"));
        const next_local_origin_sequence = runtimeNextLocalOriginSequence(@max(self.feed_next_sequence, local_frontier_next), max_event_id);
        return .{
            .instance_id = try allocator.dupe(u8, "memory_lru"),
            .storage_kind = try allocator.dupe(u8, "memory_lru"),
            .supports_compaction = true,
            .cursor_floor = self.feed_cursor_floor,
            .compacted_through_sequence = self.feed_cursor_floor,
            .oldest_available_sequence = runtimeFeedSequenceAfter(self.feed_cursor_floor),
            .max_event_id = max_event_id,
            .last_sequence = max_event_id,
            .next_local_origin_sequence = next_local_origin_sequence,
            .visible_events = visible,
            .pending_events = pending,
            .applying_events = applying,
            .applied_events = applied,
        };
    }

    pub fn compactFeedByInput(self: *MemoryAgentMemory, allocator: std.mem.Allocator, input: CompactFeedInput) !FeedCompactResult {
        return self.compactFeed(allocator, input.actor_id, input.scopes_json, input.before_id);
    }

    fn compactFeed(self: *MemoryAgentMemory, allocator: std.mem.Allocator, actor_id: ?[]const u8, scopes_json: []const u8, before_id: ?i64) !FeedCompactResult {
        _ = actor_id;
        _ = scopes_json;
        _ = allocator;
        const before = before_id orelse self.lastFeedEventId();
        var compacted: usize = 0;
        const now = self.nowMs();
        for (self.feed_events.items) |*event| {
            if (event.id <= before and event.compacted_at_ms == null) {
                event.compacted_at_ms = now;
                compacted += 1;
            }
        }
        self.feed_cursor_floor = @max(self.feed_cursor_floor, before);
        const max_event_id = self.lastFeedEventId();
        return .{
            .cursor_floor = self.feed_cursor_floor,
            .compacted_through_sequence = self.feed_cursor_floor,
            .max_event_id = max_event_id,
            .compacted_events = compacted,
        };
    }

    pub fn exportFeedCheckpointByInput(self: *MemoryAgentMemory, allocator: std.mem.Allocator, input: ExportFeedCheckpointInput) ![]u8 {
        return self.exportFeedCheckpoint(allocator, input.since_id, input.limit, input.actor_id, input.scopes_json);
    }

    fn exportFeedCheckpoint(self: *MemoryAgentMemory, allocator: std.mem.Allocator, since_id: ?i64, limit: ?usize, actor_id: ?[]const u8, scopes_json: []const u8) ![]u8 {
        const after = since_id orelse 0;
        const target_limit = @max(@as(usize, 1), @min(limit orelse 500, 1000));
        const events = try self.listFeedEvents(allocator, after, target_limit, actor_id, scopes_json);
        defer {
            for (events) |*event| event.deinit(allocator);
            allocator.free(events);
        }
        var out: std.ArrayListUnmanaged(u8) = .empty;
        errdefer out.deinit(allocator);
        try out.appendSlice(allocator, "{\"instance_id\":\"memory_lru\",\"feed_object_types\":");
        try out.appendSlice(allocator, feed_object_types_json);
        try out.appendSlice(allocator, ",\"lifecycle_object_types\":");
        try out.appendSlice(allocator, lifecycle_object_types_json);
        try out.appendSlice(allocator, ",\"cursor_floor\":");
        try out.print(allocator, "{d},\"compacted_through_sequence\":{d},\"max_event_id\":{d},\"last_sequence\":{d},\"frontiers\":[", .{ self.feed_cursor_floor, self.feed_cursor_floor, self.lastFeedEventId(), self.lastFeedEventId() });
        try self.appendCheckpointFrontiersJson(allocator, &out);
        try out.appendSlice(allocator, "],\"events\":[");
        for (events, 0..) |event, i| {
            if (i > 0) try out.append(allocator, ',');
            try event.writeJson(allocator, &out);
        }
        try out.appendSlice(allocator, "]}");
        return out.toOwnedSlice(allocator);
    }

    pub fn restoreFeedCheckpointByInput(self: *MemoryAgentMemory, allocator: std.mem.Allocator, input: RestoreFeedCheckpointInput) !void {
        return self.restoreFeedCheckpoint(allocator, input.checkpoint_json, input.actor_id, input.scopes_json);
    }

    fn restoreFeedCheckpoint(self: *MemoryAgentMemory, allocator: std.mem.Allocator, checkpoint_json: []const u8, actor_id: ?[]const u8, scopes_json: []const u8) !void {
        var parsed = std.json.parseFromSlice(std.json.Value, allocator, checkpoint_json, .{}) catch return error.AgentMemoryStorageUnavailable;
        defer parsed.deinit();
        if (parsed.value != .object) return error.AgentMemoryStorageUnavailable;
        const events_value = runtimeCheckpointEventsValue(parsed.value.object) orelse return error.AgentMemoryStorageUnavailable;
        if (events_value != .array) return error.AgentMemoryStorageUnavailable;
        try validateRuntimeCheckpointShape(allocator, parsed.value.object, actor_id, scopes_json);
        var staged = try self.cloneForCheckpointRestore();
        var committed = false;
        errdefer if (!committed) staged.deinit();
        for (events_value.array.items) |item| {
            if (item != .object) return error.AgentMemoryStorageUnavailable;
            try staged.applyFeedEventObject(allocator, item.object, actor_id, scopes_json);
        }
        try staged.restoreCheckpointFrontiers(parsed.value.object);
        const floor = try runtimeCheckpointCompactedThrough(parsed.value.object);
        if (floor > 0) {
            staged.feed_cursor_floor = @max(staged.feed_cursor_floor, floor);
            if (staged.feed_next_sequence <= staged.feed_cursor_floor) staged.feed_next_sequence = runtimeFeedSequenceAfter(staged.feed_cursor_floor);
        }
        self.deinit();
        self.allocator = staged.allocator;
        self.config = staged.config;
        self.entries = staged.entries;
        self.tombstones = staged.tombstones;
        self.message_tombstones = staged.message_tombstones;
        self.usage_tombstones = staged.usage_tombstones;
        self.messages = staged.messages;
        self.usage = staged.usage;
        self.feed_events = staged.feed_events;
        self.origin_frontiers = staged.origin_frontiers;
        self.feed_cursor_floor = staged.feed_cursor_floor;
        self.feed_next_sequence = staged.feed_next_sequence;
        committed = true;
    }

    pub fn applyFeedEventByInput(self: *MemoryAgentMemory, allocator: std.mem.Allocator, input: ApplyFeedEventInput) !void {
        return self.applyFeedEventJson(allocator, input.event_json, input.actor_id, input.scopes_json);
    }

    fn applyFeedEventJson(self: *MemoryAgentMemory, allocator: std.mem.Allocator, event_json: []const u8, actor_id: ?[]const u8, scopes_json: []const u8) !void {
        var parsed = std.json.parseFromSlice(std.json.Value, allocator, event_json, .{}) catch return error.AgentMemoryStorageUnavailable;
        defer parsed.deinit();
        if (parsed.value != .object) return error.AgentMemoryStorageUnavailable;
        if (runtimeCheckpointEventsValue(parsed.value.object) != null) return self.restoreFeedCheckpoint(allocator, event_json, actor_id, scopes_json);
        return self.applyFeedEventObject(allocator, parsed.value.object, actor_id, scopes_json);
    }

    const VisibleFilter = struct {
        actor_id: []const u8,
        scopes_json: []const u8,
    };

    fn listInternal(self: *MemoryAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, include_sessions: bool, actor_id: ?[]const u8, visible: ?VisibleFilter, visible_only: bool) ![]domain.AgentMemory {
        self.purgeExpired();
        var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (out.items) |*entry| freeAgentMemory(allocator, entry);
            out.deinit(allocator);
        }
        for (self.entries.items) |wrapped| {
            const entry = wrapped.entry;
            if (actor_id) |actor| if (!std.mem.eql(u8, entry.actor_id, actor)) continue;
            if (category) |cat| if (!std.mem.eql(u8, entry.category, cat)) continue;
            if (session_id) |sid| {
                if (entry.session_id == null or !std.mem.eql(u8, entry.session_id.?, sid)) continue;
            } else if (entry.session_id != null and !include_sessions) continue;
            if (visible_only) {
                const filter = visible orelse continue;
                if (!try entryVisible(allocator, entry, filter.actor_id, filter.scopes_json)) continue;
            }
            try out.append(allocator, try cloneAgentMemory(allocator, entry));
        }
        sortAgentMemory(out.items);
        return out.toOwnedSlice(allocator);
    }

    fn listInternalWindow(self: *MemoryAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, include_sessions: bool, actor_id: ?[]const u8, visible: ?VisibleFilter, visible_only: bool, limit: usize, offset: usize) ![]domain.AgentMemory {
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        self.purgeExpired();
        const keep = agentMemoryWindowKeepLimit(limit, offset);
        var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (out.items) |*entry| freeAgentMemory(allocator, entry);
            out.deinit(allocator);
        }
        for (self.entries.items) |wrapped| {
            const entry = wrapped.entry;
            if (actor_id) |actor| if (!std.mem.eql(u8, entry.actor_id, actor)) continue;
            if (category) |cat| if (!std.mem.eql(u8, entry.category, cat)) continue;
            if (session_id) |sid| {
                if (entry.session_id == null or !std.mem.eql(u8, entry.session_id.?, sid)) continue;
            } else if (entry.session_id != null and !include_sessions) continue;
            if (visible_only) {
                const filter = visible orelse continue;
                if (!try entryVisible(allocator, entry, filter.actor_id, filter.scopes_json)) continue;
            }
            var cloned = try cloneAgentMemory(allocator, entry);
            var cloned_owned = true;
            errdefer if (cloned_owned) freeAgentMemory(allocator, &cloned);
            try out.append(allocator, cloned);
            cloned_owned = false;
            sortAgentMemory(out.items);
            if (out.items.len > keep) {
                var removed = out.pop().?;
                freeAgentMemory(allocator, &removed);
            }
        }
        const owned = try out.toOwnedSlice(allocator);
        out = .empty;
        return pageAgentMemorySlice(allocator, owned, limit, offset);
    }

    fn findEntryIndex(self: *MemoryAgentMemory, actor_id: []const u8, session_id: ?[]const u8, key: []const u8) ?usize {
        for (self.entries.items, 0..) |wrapped, i| {
            const entry = wrapped.entry;
            if (!std.mem.eql(u8, entry.actor_id, actor_id)) continue;
            if (!std.mem.eql(u8, entry.key, key)) continue;
            if (!sameOptionalString(entry.session_id, session_id)) continue;
            return i;
        }
        return null;
    }

    fn tombstoneBlocksPut(self: *MemoryAgentMemory, key: []const u8, session_id: ?[]const u8, owner_actor: []const u8, event_order: EventOrder) !bool {
        const session_key = tombstoneSessionKey(session_id);
        for (self.tombstones.items) |tombstone| {
            if (!std.mem.eql(u8, tombstone.key, key)) continue;
            if (!std.mem.eql(u8, tombstone.actor_id, owner_actor)) continue;
            const matches_scope = switch (tombstone.scope) {
                .scoped => std.mem.eql(u8, tombstone.session_key, session_key),
                .all => std.mem.eql(u8, tombstone.session_key, "*"),
            };
            if (!matches_scope) continue;
            if (compareEventOrder(event_order, tombstone.event_order.timestamp_ms, tombstone.event_order.origin_instance_id, tombstone.event_order.origin_sequence) <= 0) return true;
        }
        return false;
    }

    fn upsertTombstone(self: *MemoryAgentMemory, key: []const u8, owner_actor: []const u8, scope: MemoryTombstoneScope, session_id: ?[]const u8, event_order: EventOrder) !void {
        const session_key = if (scope == .all) "*" else tombstoneSessionKey(session_id);
        for (self.tombstones.items) |*tombstone| {
            if (!std.mem.eql(u8, tombstone.key, key)) continue;
            if (!std.mem.eql(u8, tombstone.actor_id, owner_actor)) continue;
            if (tombstone.scope != scope) continue;
            if (!std.mem.eql(u8, tombstone.session_key, session_key)) continue;
            if (compareEventOrder(event_order, tombstone.event_order.timestamp_ms, tombstone.event_order.origin_instance_id, tombstone.event_order.origin_sequence) <= 0) return;
            freeEventOrder(self.allocator, &tombstone.event_order);
            tombstone.event_order = try cloneEventOrder(self.allocator, event_order);
            if (tombstone.session_id) |sid| self.allocator.free(sid);
            tombstone.session_id = if (session_id) |sid| try self.allocator.dupe(u8, sid) else null;
            return;
        }
        var tombstone = MemoryTombstone{
            .key = try self.allocator.dupe(u8, key),
            .actor_id = try self.allocator.dupe(u8, owner_actor),
            .scope = scope,
            .session_key = try self.allocator.dupe(u8, session_key),
            .session_id = if (session_id) |sid| try self.allocator.dupe(u8, sid) else null,
            .event_order = try cloneEventOrder(self.allocator, event_order),
        };
        errdefer self.freeTombstone(&tombstone);
        try self.tombstones.append(self.allocator, tombstone);
    }

    fn messageTombstoneBlocksPut(self: *MemoryAgentMemory, actor_id: []const u8, session_id: []const u8, event_order: EventOrder) !bool {
        for (self.message_tombstones.items) |tombstone| {
            if (!std.mem.eql(u8, tombstone.actor_id, actor_id)) continue;
            if (!std.mem.eql(u8, tombstone.session_id, session_id)) continue;
            if (compareEventOrder(event_order, tombstone.event_order.timestamp_ms, tombstone.event_order.origin_instance_id, tombstone.event_order.origin_sequence) <= 0) return true;
        }
        return false;
    }

    fn upsertMessageTombstone(self: *MemoryAgentMemory, actor_id: []const u8, session_id: []const u8, event_order: EventOrder) !void {
        for (self.message_tombstones.items) |*tombstone| {
