    fn freeMemoryEntry(self: *MemoryAgentMemory, entry: *MemoryEntry) void {
        freeAgentMemory(self.allocator, &entry.entry);
        if (entry.event_order) |*order| freeEventOrder(self.allocator, order);
    }

    fn freeTombstone(self: *MemoryAgentMemory, tombstone: *MemoryTombstone) void {
        self.allocator.free(tombstone.key);
        self.allocator.free(tombstone.actor_id);
        self.allocator.free(tombstone.session_key);
        if (tombstone.session_id) |sid| self.allocator.free(sid);
        freeEventOrder(self.allocator, &tombstone.event_order);
    }

    fn freeMessageTombstone(self: *MemoryAgentMemory, tombstone: *MessageTombstone) void {
        self.allocator.free(tombstone.actor_id);
        self.allocator.free(tombstone.session_id);
        freeEventOrder(self.allocator, &tombstone.event_order);
    }

    fn freeUsageTombstone(self: *MemoryAgentMemory, tombstone: *UsageTombstone) void {
        self.allocator.free(tombstone.actor_id);
        self.allocator.free(tombstone.session_id);
        freeEventOrder(self.allocator, &tombstone.event_order);
    }

    fn touchEntryById(self: *MemoryAgentMemory, id: []const u8, at_ms: i64) void {
        for (self.entries.items) |*wrapped| {
            if (std.mem.eql(u8, wrapped.entry.id, id)) {
                wrapped.last_access_ms = at_ms;
                return;
            }
        }
    }

    fn purgeExpired(self: *MemoryAgentMemory) void {
        const ttl = self.config.ttl_seconds orelse return;
        if (ttl == 0) return;
        const cutoff = memoryTtlCutoffMs(self.nowMs(), ttl);
        var i: usize = 0;
        while (i < self.entries.items.len) {
            if (parseMemoryTimestamp(self.entries.items[i].entry.timestamp) <= cutoff) {
                var removed = self.entries.orderedRemove(i);
                self.freeMemoryEntry(&removed);
                continue;
            }
            i += 1;
        }
        i = 0;
        while (i < self.messages.items.len) {
            if (self.messages.items[i].created_at_ms <= cutoff) {
                var removed = self.messages.orderedRemove(i);
                freeMemorySessionMessage(self.allocator, &removed);
                continue;
            }
            i += 1;
        }
        i = 0;
        while (i < self.usage.items.len) {
            if (self.usage.items[i].updated_at_ms <= cutoff) {
                var removed = self.usage.orderedRemove(i);
                freeMemoryUsage(self.allocator, &removed);
                continue;
            }
            i += 1;
        }
    }

    fn enforceLimits(self: *MemoryAgentMemory) void {
        self.purgeExpired();
        while (self.config.max_entries > 0 and self.entries.items.len > self.config.max_entries) {
            if (!self.evictLeastRecentEntry()) break;
        }
        while (self.config.max_messages > 0 and self.messages.items.len > self.config.max_messages) {
            if (!self.evictLeastRecentMessage()) break;
        }
        while (self.config.max_usage_entries > 0 and self.usage.items.len > self.config.max_usage_entries) {
            if (!self.evictLeastRecentUsage()) break;
        }
        while (self.config.max_bytes > 0 and self.approxMemoryBytes() > self.config.max_bytes) {
            if (!self.evictLeastRecentAny()) break;
        }
    }

    fn evictLeastRecentEntry(self: *MemoryAgentMemory) bool {
        if (self.entries.items.len == 0) return false;
        var idx: usize = 0;
        var oldest = self.entries.items[0].last_access_ms;
        for (self.entries.items[1..], 1..) |entry, i| {
            if (entry.last_access_ms < oldest) {
                oldest = entry.last_access_ms;
                idx = i;
            }
        }
        var removed = self.entries.orderedRemove(idx);
        self.freeMemoryEntry(&removed);
        return true;
    }

    fn evictLeastRecentMessage(self: *MemoryAgentMemory) bool {
        if (self.messages.items.len == 0) return false;
        var idx: usize = 0;
        var oldest = self.messages.items[0].last_access_ms;
        for (self.messages.items[1..], 1..) |message, i| {
            if (message.last_access_ms < oldest) {
                oldest = message.last_access_ms;
                idx = i;
            }
        }
        var removed = self.messages.orderedRemove(idx);
        freeMemorySessionMessage(self.allocator, &removed);
        return true;
    }

    fn evictLeastRecentUsage(self: *MemoryAgentMemory) bool {
        if (self.usage.items.len == 0) return false;
        var idx: usize = 0;
        var oldest = self.usage.items[0].last_access_ms;
        for (self.usage.items[1..], 1..) |item, i| {
            if (item.last_access_ms < oldest) {
                oldest = item.last_access_ms;
                idx = i;
            }
        }
        var removed = self.usage.orderedRemove(idx);
        freeMemoryUsage(self.allocator, &removed);
        return true;
    }

    fn evictLeastRecentAny(self: *MemoryAgentMemory) bool {
        var kind: enum { none, entry, message, usage } = .none;
        var oldest: i64 = 0;
        for (self.entries.items) |entry| {
            if (kind == .none or entry.last_access_ms < oldest) {
                kind = .entry;
                oldest = entry.last_access_ms;
            }
        }
        for (self.messages.items) |message| {
            if (kind == .none or message.last_access_ms < oldest) {
                kind = .message;
                oldest = message.last_access_ms;
            }
        }
        for (self.usage.items) |item| {
            if (kind == .none or item.last_access_ms < oldest) {
                kind = .usage;
                oldest = item.last_access_ms;
            }
        }
        return switch (kind) {
            .none => false,
            .entry => self.evictLeastRecentEntry(),
            .message => self.evictLeastRecentMessage(),
            .usage => self.evictLeastRecentUsage(),
        };
    }

    fn approxMemoryBytes(self: *MemoryAgentMemory) usize {
        var total: usize = 0;
        for (self.entries.items) |entry| total = memoryByteSizeAdd(total, agentMemoryByteSize(entry.entry));
        for (self.messages.items) |message| total = memoryByteSizeAdd(total, messageByteSize(message));
        for (self.usage.items) |item| total = memoryByteSizeAdd(total, usageByteSize(item));
        return total;
    }

    fn findUsageIndex(self: *MemoryAgentMemory, actor_id: []const u8, session_id: []const u8) ?usize {
        for (self.usage.items, 0..) |item, i| {
            if (std.mem.eql(u8, item.actor_id, actor_id) and std.mem.eql(u8, item.session_id, session_id)) return i;
        }
        return null;
    }

    fn lastFeedEventId(self: *MemoryAgentMemory) i64 {
        var last: i64 = if (self.feed_events.items.len == 0) 0 else self.feed_events.items[self.feed_events.items.len - 1].id;
        last = @max(last, self.feed_cursor_floor);
        if (self.feed_next_sequence > 1) last = @max(last, self.feed_next_sequence - 1);
        return last;
    }

    fn originFrontier(self: *MemoryAgentMemory, origin_instance_id: []const u8) i64 {
        return self.origin_frontiers.get(origin_instance_id) orelse 0;
    }

    fn originAlreadyApplied(self: *MemoryAgentMemory, origin_instance_id: []const u8, origin_sequence: i64) bool {
        return origin_sequence > 0 and origin_sequence <= self.originFrontier(origin_instance_id);
    }

    fn advanceOriginFrontier(self: *MemoryAgentMemory, origin_instance_id: []const u8, origin_sequence: i64) !void {
        if (origin_instance_id.len == 0 or origin_sequence <= 0) return;
        if (self.origin_frontiers.getPtr(origin_instance_id)) |existing| {
            existing.* = @max(existing.*, origin_sequence);
            return;
        }
        try self.origin_frontiers.put(self.allocator, try self.allocator.dupe(u8, origin_instance_id), origin_sequence);
    }

    fn appendCheckpointFrontiersJson(self: *MemoryAgentMemory, allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8)) !void {
        var written: usize = 0;
        var it = self.origin_frontiers.iterator();
        while (it.next()) |kv| {
            if (written > 0) try out.append(allocator, ',');
            try appendRuntimeCheckpointFrontierJson(allocator, out, kv.key_ptr.*, kv.value_ptr.*);
            written += 1;
        }
    }

    fn restoreCheckpointFrontiers(self: *MemoryAgentMemory, obj: std.json.ObjectMap) !void {
        const frontiers = runtimeCheckpointFrontiersValue(obj) orelse return;
        if (frontiers != .array) return error.AgentMemoryStorageUnavailable;
        for (frontiers.array.items) |frontier_value| {
            if (frontier_value != .object) return error.AgentMemoryStorageUnavailable;
            const frontier = try runtimeCheckpointFrontierFields(frontier_value.object);
            try self.advanceOriginFrontier(frontier.origin_instance_id, frontier.origin_sequence);
            if (std.mem.eql(u8, frontier.origin_instance_id, "memory_lru") and self.feed_next_sequence <= frontier.origin_sequence) self.feed_next_sequence = runtimeFeedSequenceAfter(frontier.origin_sequence);
        }
    }

    fn feedEventVisible(self: *MemoryAgentMemory, event: FeedEvent, actor_id: ?[]const u8, scopes_json: []const u8) bool {
        return runtimeFeedEventVisible(self.allocator, event, actor_id, scopes_json);
    }

    fn appendLocalFeedEvent(
        self: *MemoryAgentMemory,
        event_type: []const u8,
        operation: []const u8,
        object_type: []const u8,
        object_id: []const u8,
        scope: []const u8,
        permissions_json: []const u8,
        actor_id: ?[]const u8,
        payload_json: []const u8,
        event_order: ?EventOrder,
    ) !void {
        if (event_order) |order| {
            if (self.findFeedEventByOrigin(order.origin_instance_id, order.origin_sequence, event_type, object_type, object_id) != null) return;
        }
        const id = self.feed_next_sequence;
        const next_id = try runtimeAdvanceFeedSequence(id);
        const created_at_ms = if (event_order) |order| order.timestamp_ms else self.nowMs();
        var event = FeedEvent{
            .id = id,
            .sequence = id,
            .event_type = try self.allocator.dupe(u8, event_type),
            .origin_instance_id = if (event_order) |order| try self.allocator.dupe(u8, order.origin_instance_id) else try self.allocator.dupe(u8, "memory_lru"),
            .origin_sequence = if (event_order) |order| order.origin_sequence else id,
            .operation = try self.allocator.dupe(u8, operation),
            .object_type = try self.allocator.dupe(u8, object_type),
            .object_id = try self.allocator.dupe(u8, object_id),
            .scope = try self.allocator.dupe(u8, scope),
            .permissions_json = try self.allocator.dupe(u8, permissions_json),
            .actor_id = if (actor_id) |actor| try self.allocator.dupe(u8, actor) else null,
            .dedupe_key = null,
            .causality_json = try self.allocator.dupe(u8, "{}"),
            .payload_json = try self.allocator.dupe(u8, payload_json),
            .status = try self.allocator.dupe(u8, "applied"),
            .created_at_ms = created_at_ms,
            .applied_at_ms = created_at_ms,
            .compacted_at_ms = null,
        };
        var event_owned = true;
        errdefer if (event_owned) event.deinit(self.allocator);
        try self.feed_events.append(self.allocator, event);
        event_owned = false;
        var event_committed = false;
        errdefer {
            if (!event_committed) {
                var removed = self.feed_events.orderedRemove(self.feed_events.items.len - 1);
                removed.deinit(self.allocator);
            }
        }
        self.feed_next_sequence = next_id;
        errdefer {
            if (!event_committed) self.feed_next_sequence = id;
        }
        try self.advanceOriginFrontier(self.feed_events.items[self.feed_events.items.len - 1].origin_instance_id, self.feed_events.items[self.feed_events.items.len - 1].origin_sequence);
        event_committed = true;
    }

    fn appendAgentMemoryFeedEvent(self: *MemoryAgentMemory, entry: domain.AgentMemory, operation: domain.AgentMemoryOperation, operation_content: []const u8, event_order: ?EventOrder) !void {
        const payload = try self.agentMemoryPayloadJson(entry, operation, operation_content);
        defer self.allocator.free(payload);
        const event_type = switch (operation) {
            .put => "agent_memory.put",
            .merge_object => "agent_memory.merge_object",
            .merge_string_set => "agent_memory.merge_string_set",
        };
        try self.appendLocalFeedEvent(
            event_type,
            operation.name(),
            "agent_memory",
            entry.id,
            entry.scope,
            entry.permissions_json,
            if (entry.writer_actor_id.len > 0) entry.writer_actor_id else entry.actor_id,
            payload,
            event_order,
        );
    }

    fn appendAgentMemoryDeleteFeedEvent(self: *MemoryAgentMemory, key: []const u8, session_id: ?[]const u8, owner_actor_id: []const u8, writer_actor_id: []const u8, scope: []const u8, permissions_json: []const u8, operation: []const u8, event_order: ?EventOrder) !void {
        const payload = try self.agentMemoryDeletePayloadJson(key, session_id, owner_actor_id, scope, permissions_json);
        defer self.allocator.free(payload);
        const event_type = if (std.mem.eql(u8, operation, "delete_all")) "agent_memory.delete_all" else "agent_memory.delete";
        try self.appendLocalFeedEvent(event_type, operation, "agent_memory", key, scope, permissions_json, writer_actor_id, payload, event_order);
    }

    fn appendAgentMemoryLifecycleFeedEvent(self: *MemoryAgentMemory, entry: domain.AgentMemory, writer_actor_id: []const u8, status: []const u8, event_order: ?EventOrder) !void {
        const operation = feed_contract.agentMemoryLifecycleOperationForStatus(status);
        const payload = try self.agentMemoryLifecyclePayloadJson(entry, status);
        defer self.allocator.free(payload);
        const event_type = try std.fmt.allocPrint(self.allocator, "agent_memory.{s}", .{operation});
        defer self.allocator.free(event_type);
        try self.appendLocalFeedEvent(event_type, operation, "agent_memory", entry.id, entry.scope, entry.permissions_json, writer_actor_id, payload, event_order);
    }

    fn findFeedEventByOrigin(self: *MemoryAgentMemory, origin_instance_id: []const u8, origin_sequence: i64, event_type: []const u8, object_type: []const u8, object_id: []const u8) ?usize {
        if (origin_instance_id.len == 0 or origin_sequence <= 0) return null;
        for (self.feed_events.items, 0..) |event, i| {
            if (!std.mem.eql(u8, event.origin_instance_id, origin_instance_id)) continue;
            if (event.origin_sequence != origin_sequence) continue;
            if (!std.mem.eql(u8, event.event_type, event_type)) continue;
            if (!std.mem.eql(u8, event.object_type, object_type)) continue;
            if (!std.mem.eql(u8, event.object_id, object_id)) continue;
            return i;
        }
        return null;
    }

    fn fallbackAgentMemoryScope(self: *MemoryAgentMemory, owner_actor_id: []const u8, session_id: ?[]const u8) ![]const u8 {
        return access.agentMemoryScope(self.allocator, owner_actor_id, session_id, null);
