    fn agentMemoryPayloadJson(self: *MemoryAgentMemory, entry: domain.AgentMemory, operation: domain.AgentMemoryOperation, operation_content: []const u8) ![]u8 {
        var out: std.ArrayListUnmanaged(u8) = .empty;
        errdefer out.deinit(self.allocator);
        try out.appendSlice(self.allocator, "{\"key\":");
        try json.appendString(&out, self.allocator, entry.key);
        try out.appendSlice(self.allocator, ",\"content\":");
        try json.appendString(&out, self.allocator, entry.content);
        try out.appendSlice(self.allocator, ",\"category\":");
        try json.appendString(&out, self.allocator, entry.category);
        try out.appendSlice(self.allocator, ",\"session_id\":");
        try json.appendNullableString(&out, self.allocator, entry.session_id);
        try out.appendSlice(self.allocator, ",\"scope\":");
        try json.appendString(&out, self.allocator, entry.scope);
        try out.appendSlice(self.allocator, ",\"permissions\":");
        try json.appendRawJsonArray(&out, self.allocator, entry.permissions_json);
        try out.appendSlice(self.allocator, ",\"owner_id\":");
        try json.appendString(&out, self.allocator, entry.actor_id);
        try out.appendSlice(self.allocator, ",\"writer_actor_id\":");
        try json.appendString(&out, self.allocator, if (entry.writer_actor_id.len > 0) entry.writer_actor_id else entry.actor_id);
        switch (operation) {
            .put => {},
            .merge_string_set => {
                try out.appendSlice(self.allocator, ",\"values\":");
                try json.appendRawJsonArray(&out, self.allocator, operation_content);
            },
            .merge_object => {
                try out.appendSlice(self.allocator, ",\"object\":");
                try json.appendRawJsonObject(&out, self.allocator, operation_content);
            },
        }
        try out.append(self.allocator, '}');
        return out.toOwnedSlice(self.allocator);
    }

