    fn applyFeedEventObject(self: *MemoryAgentMemory, allocator: std.mem.Allocator, obj: std.json.ObjectMap, actor_id: ?[]const u8, scopes_json: []const u8) !void {
        var event = try parseLooseFeedEventValue(allocator, obj, actor_id);
        defer event.deinit(allocator);
        if (!self.feedEventVisible(event, actor_id, scopes_json)) return error.Forbidden;
        if (self.originAlreadyApplied(event.origin_instance_id, event.origin_sequence)) return;
        if (self.findFeedEventByOrigin(event.origin_instance_id, event.origin_sequence, event.event_type, event.object_type, event.object_id) != null) {
            try self.advanceOriginFrontier(event.origin_instance_id, event.origin_sequence);
            return;
        }
        const suppress_feed = json.boolField(obj, "suppress_feed") orelse false;
        const order = EventOrder{
            .timestamp_ms = event.created_at_ms,
            .origin_instance_id = event.origin_instance_id,
            .origin_sequence = event.origin_sequence,
        };
        if (std.mem.eql(u8, event.object_type, "agent_memory")) {
            try self.applyAgentMemoryFeedEvent(allocator, event, order, actor_id, suppress_feed);
        } else if (std.mem.eql(u8, event.object_type, "agent_session_message")) {
            try self.applySessionMessageFeedEvent(allocator, event, order, actor_id, suppress_feed);
        } else if (std.mem.eql(u8, event.object_type, "agent_session_usage")) {
            try self.applySessionUsageFeedEvent(allocator, event, order, actor_id, suppress_feed);
        } else {
            return error.NotSupported;
        }
        try self.advanceOriginFrontier(event.origin_instance_id, event.origin_sequence);
    }

    fn applyAgentMemoryFeedEvent(self: *MemoryAgentMemory, allocator: std.mem.Allocator, event: FeedEvent, order: EventOrder, fallback_actor_id: ?[]const u8, suppress_feed: bool) !void {
        var payload = try std.json.parseFromSlice(std.json.Value, allocator, event.payload_json, .{});
        defer payload.deinit();
        if (payload.value != .object) return error.AgentMemoryStorageUnavailable;
        const obj = payload.value.object;
        const key = jsonStringishField(obj, &.{"key"}) orelse event.object_id;
        const session_id = access.normalizeSessionId(jsonStringishField(obj, &.{ "session_id", "session" }));
        const owner_actor = jsonStringishField(obj, &.{ "owner_id", "actor_id" }) orelse event.actor_id orelse fallback_actor_id orelse return error.MissingActorId;
        if (feed_contract.isDeleteAllOperation(event.operation)) {
            _ = try self.deleteByInput(.{
                .key = key,
                .actor_id = owner_actor,
                .writer_actor_id = event.actor_id orelse owner_actor,
                .event_order = order,
                .all_owners = true,
                .suppress_feed = suppress_feed,
            });
            return;
        }
        if (feed_contract.isDeleteOperation(event.operation) or feed_contract.isDeleteScopedOperation(event.operation)) {
            _ = try self.deleteByInput(.{
                .key = key,
                .session_id = session_id,
                .actor_id = owner_actor,
                .writer_actor_id = event.actor_id orelse owner_actor,
                .event_order = order,
                .suppress_feed = suppress_feed,
            });
            return;
        }
        if (feed_contract.isLifecycleOperation(event.operation)) {
            const status = feed_contract.statusFromLifecycleOperation(event.operation, obj);
            _ = try self.patchStatusInternal(key, session_id, owner_actor, event.actor_id orelse owner_actor, status, !suppress_feed, order);
            return;
        }
        const memory_operation = domain.AgentMemoryOperation.parse(event.operation);
        const content = try runtimeAgentMemoryOperationContent(allocator, obj, memory_operation);
        defer allocator.free(content);
        const permissions_json = try jsonRawArrayField(allocator, obj, &.{ "permissions", "permissions_json" }, "[]");
        defer allocator.free(permissions_json);
        var entry = try self.store(allocator, .{
            .key = key,
            .content = content,
            .category = jsonStringishField(obj, &.{"category"}) orelse "core",
            .session_id = session_id,
            .scope = jsonStringishField(obj, &.{"scope"}),
            .permissions_json = permissions_json,
            .actor_id = owner_actor,
            .writer_actor_id = event.actor_id orelse owner_actor,
            .operation = memory_operation,
            .suppress_feed = suppress_feed,
            .event_order = order,
        });
        defer freeAgentMemory(allocator, &entry);
    }

    fn applySessionMessageFeedEvent(self: *MemoryAgentMemory, allocator: std.mem.Allocator, event: FeedEvent, order: EventOrder, fallback_actor_id: ?[]const u8, suppress_feed: bool) !void {
        var payload = try std.json.parseFromSlice(std.json.Value, allocator, event.payload_json, .{});
        defer payload.deinit();
        if (payload.value != .object) return error.AgentMemoryStorageUnavailable;
        const obj = payload.value.object;
        const actor = jsonStringishField(obj, &.{"actor_id"}) orelse event.actor_id orelse fallback_actor_id orelse return error.MissingActorId;
        if (std.mem.eql(u8, event.operation, "delete_autosaved")) {
            try self.clearAutoSavedByInput(.{
                .session_id = try optionalJsonNullableStringField(obj, "session_id"),
                .actor_id = actor,
                .suppress_feed = suppress_feed,
            });
            return;
        }
        const session_id = try requiredJsonStringField(obj, "session_id");
        if (feed_contract.isAgentSessionDeleteOperation(event.operation)) {
            try self.clearMessagesByInput(.{
                .session_id = session_id,
                .actor_id = actor,
                .event_order = order,
                .suppress_feed = suppress_feed,
            });
            return;
        }
        const message = try runtimeSessionMessagePayload(obj, event, fallback_actor_id);
        try self.saveMessageByInput(.{
            .session_id = message.session_id,
            .role = message.role,
            .content = message.content,
            .created_at_ms = message.created_at_ms,
            .actor_id = message.actor_id,
            .event_order = order,
            .suppress_feed = suppress_feed,
        });
    }

    fn applySessionUsageFeedEvent(self: *MemoryAgentMemory, allocator: std.mem.Allocator, event: FeedEvent, order: EventOrder, fallback_actor_id: ?[]const u8, suppress_feed: bool) !void {
        var payload = try std.json.parseFromSlice(std.json.Value, allocator, event.payload_json, .{});
        defer payload.deinit();
        if (payload.value != .object) return error.AgentMemoryStorageUnavailable;
        const obj = payload.value.object;
        const actor = jsonStringishField(obj, &.{"actor_id"}) orelse event.actor_id orelse fallback_actor_id orelse return error.MissingActorId;
        const session_id = try requiredJsonStringField(obj, "session_id");
        if (feed_contract.isAgentSessionDeleteOperation(event.operation)) {
            _ = try self.deleteUsageByInput(.{
                .session_id = session_id,
                .actor_id = actor,
                .event_order = order,
                .suppress_feed = suppress_feed,
            });
            return;
        }
        const usage = try runtimeSessionUsagePayload(obj, event, fallback_actor_id);
        try self.saveUsageByInput(.{
            .session_id = usage.session_id,
            .total_tokens = usage.total_tokens,
            .actor_id = usage.actor_id,
            .event_order = order,
            .suppress_feed = suppress_feed,
        });
    }
};

fn memoryTtlCutoffMs(now_ms: i64, ttl_seconds: u32) i64 {
    if (ttl_seconds == 0) return now_ms;
    const ttl_ms = time_math.secondsToMs(ttl_seconds);
    return time_math.saturatingAddMs(now_ms, -ttl_ms);
}

pub const RedisAgentMemory = struct {
    allocator: std.mem.Allocator,
    client: redis.Client,
    prefix: []const u8,
    ttl_seconds: ?u32,

    const DeleteAllCandidate = struct {
        redis_key: []u8,
        entry: domain.AgentMemory,
    };

    pub fn init(allocator: std.mem.Allocator, config: redis.Config) RedisAgentMemory {
        return .{
            .allocator = allocator,
            .client = redis.Client.init(allocator, config),
            .prefix = config.key_prefix,
            .ttl_seconds = config.ttl_seconds,
        };
    }

    pub fn deinit(self: *RedisAgentMemory) void {
        self.client.deinit();
    }

    pub fn store(self: *RedisAgentMemory, allocator: std.mem.Allocator, input: Input) !domain.AgentMemory {
        const request_actor = try access.requiredActorId(input.actor_id);
        const owner_actor = try access.agentMemoryOwner(allocator, request_actor, input.scope);
        defer allocator.free(owner_actor);
        const writer_actor = input.writer_actor_id orelse request_actor;
        const scope = try access.agentMemoryScope(allocator, owner_actor, input.session_id, input.scope);
        defer allocator.free(scope);
        const permissions = try access.agentMemoryPermissions(allocator, owner_actor, input.scope, input.permissions_json);
        defer allocator.free(permissions);
        const status = domain.defaultMemoryStatus("agent", scope);
        const timestamp = eventTimestampMs(input);
        const timestamp_text = try std.fmt.allocPrint(allocator, "{d}", .{timestamp});
        defer allocator.free(timestamp_text);
        const origin_instance_id = if (input.event_order) |order| order.origin_instance_id else "";
        const origin_sequence = if (input.event_order) |order| order.origin_sequence else 0;
        const origin_sequence_text = try std.fmt.allocPrint(allocator, "{d}", .{origin_sequence});
        defer allocator.free(origin_sequence_text);
        const entry_key = try self.entryKey(allocator, owner_actor, input.session_id, input.key);
        defer allocator.free(entry_key);
        const entry_id = try self.entryId(allocator, owner_actor, input.session_id, input.key);
        defer allocator.free(entry_id);
        var old_hash = try self.client.command(&.{ "HGETALL", entry_key });
        defer old_hash.deinit(self.allocator);
        var old_entry = try self.agentMemoryFromHash(self.allocator, old_hash);
        defer if (old_entry) |*entry| freeAgentMemory(self.allocator, entry);
        if (input.event_order) |order| {
            if (try self.tombstoneBlocksPut(allocator, input.key, input.session_id, owner_actor, order)) {
                if (old_entry) |entry| return cloneAgentMemory(allocator, entry);
                return ignoredAgentMemory(allocator, input, owner_actor, writer_actor);
            }
            if (try redisEventOrderFromHash(old_hash)) |stored_order| {
                if (compareEventOrder(order, stored_order.timestamp_ms, stored_order.origin_instance_id, stored_order.origin_sequence) <= 0) {
                    if (old_entry) |entry| return cloneAgentMemory(allocator, entry);
                    return ignoredAgentMemory(allocator, input, owner_actor, writer_actor);
                }
            }
        }
        const reduced_content = try agent_memory_reducer.reduceContent(allocator, input.operation, if (old_entry) |entry| entry.content else null, input.content);
        defer allocator.free(reduced_content);

        const global = try self.globalIndexKey(allocator);
        defer allocator.free(global);
        const owner = try self.ownerIndexKey(allocator, owner_actor);
        defer allocator.free(owner);
        const cat = try self.categoryIndexKey(allocator, input.category);
        defer allocator.free(cat);
        const key_index = try self.keyIndexKey(allocator, input.key);
        defer allocator.free(key_index);
        const owner_key_index = try self.ownerKeyIndexKey(allocator, owner_actor, input.key);
        defer allocator.free(owner_key_index);
        const session_index = if (input.session_id) |sid| try self.agentSessionIndexKey(allocator, owner_actor, sid) else null;
        defer if (session_index) |key_value| allocator.free(key_value);

        try self.beginTransaction();
        var committed = false;
        defer if (!committed) self.discardTransaction();

        if (old_entry) |entry| try self.queueRemoveEntryIndexes(entry_key, entry);
        try self.queueCommand(&.{
            "HSET",               entry_key,
            "id",                 entry_id,
            "key",                input.key,
            "content",            reduced_content,
            "category",           input.category,
            "timestamp",          timestamp_text,
            "session_id",         input.session_id orelse "",
            "actor_id",           owner_actor,
            "writer_actor_id",    writer_actor,
            "scope",              scope,
            "permissions_json",   permissions,
            "status",             status,
            "event_timestamp_ms", timestamp_text,
            "origin_instance_id", origin_instance_id,
            "origin_sequence",    origin_sequence_text,
        });
        try self.queueCommand(&.{ "ZADD", global, timestamp_text, entry_key });
        try self.queueCommand(&.{ "ZADD", owner, timestamp_text, entry_key });
        try self.queueCommand(&.{ "ZADD", cat, timestamp_text, entry_key });
        try self.queueCommand(&.{ "ZADD", key_index, timestamp_text, entry_key });
        try self.queueCommand(&.{ "ZADD", owner_key_index, timestamp_text, entry_key });
        if (session_index) |key_value| try self.queueCommand(&.{ "ZADD", key_value, timestamp_text, entry_key });
        try self.queueExpireKey(entry_key);
        try self.queueExpireKey(global);
        try self.queueExpireKey(owner);
        try self.queueExpireKey(cat);
        try self.queueExpireKey(key_index);
        try self.queueExpireKey(owner_key_index);
        if (session_index) |key_value| try self.queueExpireKey(key_value);
        var exec = try self.execTransaction();
        exec.deinit(self.allocator);
        committed = true;

        const result = (try self.get(allocator, input.key, input.session_id, owner_actor)).?;
        errdefer {
            var cleanup = result;
            freeAgentMemory(allocator, &cleanup);
        }
        if (!input.suppress_feed and !domain.isInternalMemoryEntryKeyOrContent(result.key, result.content)) {
            try self.appendAgentMemoryFeedEvent(result, input.operation, input.content, input.event_order);
        }
        return result;
    }

    pub fn getByInput(self: *RedisAgentMemory, allocator: std.mem.Allocator, input: GetInput) !?domain.AgentMemory {
        const normalized_session_id = access.normalizeSessionId(input.session_id);
        if (input.scopes_json) |scopes_json| {
            const actor_id = input.actor_id orelse return error.InvalidAgentMemoryRuntimeRequest;
            if (input.any_session) return self.getAnyVisible(allocator, input.key, actor_id, scopes_json);
            return self.getVisible(allocator, input.key, normalized_session_id, actor_id, scopes_json);
        }
        return self.get(allocator, input.key, normalized_session_id, input.actor_id);
    }

    fn get(self: *RedisAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8) !?domain.AgentMemory {
        const owner = actor_id orelse return null;
        const entry_key = try self.entryKey(allocator, owner, session_id, key);
        defer allocator.free(entry_key);
        var resp = try self.client.command(&.{ "HGETALL", entry_key });
        defer resp.deinit(self.allocator);
        return self.agentMemoryFromHash(allocator, resp);
    }

    fn getVisible(self: *RedisAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8) !?domain.AgentMemory {
        var candidates = try visibleOwnerCandidatesFromScopes(allocator, actor_id, scopes_json);
        defer candidates.deinit(allocator);
        if (!candidates.requires_global_scan) return self.getVisibleFromOwnerKeyCandidates(allocator, &candidates, key, session_id, false, actor_id, scopes_json);

        const index_key = try self.keyIndexKey(allocator, key);
        defer allocator.free(index_key);
        return self.getVisibleFromKeyIndex(allocator, index_key, key, session_id, false, actor_id, scopes_json, false);
    }

    pub fn listByInput(self: *RedisAgentMemory, allocator: std.mem.Allocator, input: ListInput) ![]domain.AgentMemory {
        const normalized_session_id = access.normalizeSessionId(input.session_id);
        if (input.limit) |limit| {
            if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
            if (input.scopes_json) |scopes_json| {
                const actor_id = input.actor_id orelse return error.InvalidAgentMemoryRuntimeRequest;
                if (input.any_session) return self.listAnyVisibleWindow(allocator, input.category, actor_id, scopes_json, limit, input.offset);
                return self.listVisibleWindow(allocator, input.category, normalized_session_id, actor_id, scopes_json, limit, input.offset);
            }
            return self.listWindow(allocator, input.category, normalized_session_id, input.actor_id, limit, input.offset);
        }
        if (input.scopes_json) |scopes_json| {
            const actor_id = input.actor_id orelse return error.InvalidAgentMemoryRuntimeRequest;
            if (input.any_session) return self.listAnyVisible(allocator, input.category, actor_id, scopes_json);
            return self.listVisible(allocator, input.category, normalized_session_id, actor_id, scopes_json);
        }
        return self.list(allocator, input.category, normalized_session_id, input.actor_id);
    }

    fn list(self: *RedisAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: ?[]const u8) ![]domain.AgentMemory {
        const index_key = try self.listIndexKey(allocator, category, session_id, actor_id);
        defer allocator.free(index_key);
        return self.listFromIndex(allocator, index_key, category, session_id, false, null, "[]", false);
    }

    fn listWindow(self: *RedisAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: ?[]const u8, limit: usize, offset: usize) ![]domain.AgentMemory {
        const index_key = try self.listIndexKey(allocator, category, session_id, actor_id);
        defer allocator.free(index_key);
        return self.listFromIndexWindow(allocator, index_key, category, session_id, false, null, "[]", false, limit, offset);
    }

    fn listVisible(self: *RedisAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8) ![]domain.AgentMemory {
        var candidates = try visibleOwnerCandidatesFromScopes(allocator, actor_id, scopes_json);
        defer candidates.deinit(allocator);
        if (!candidates.requires_global_scan) return self.listVisibleFromOwnerCandidatesWindow(allocator, &candidates, category, session_id, false, actor_id, scopes_json, std.math.maxInt(usize), 0);

        const index_key = try self.visibleListIndexKey(allocator, category);
        defer allocator.free(index_key);
        return self.listFromIndex(allocator, index_key, category, session_id, false, actor_id, scopes_json, true);
    }

    fn listVisibleWindow(self: *RedisAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, limit: usize, offset: usize) ![]domain.AgentMemory {
        var candidates = try visibleOwnerCandidatesFromScopes(allocator, actor_id, scopes_json);
        defer candidates.deinit(allocator);
        if (!candidates.requires_global_scan) return self.listVisibleFromOwnerCandidatesWindow(allocator, &candidates, category, session_id, false, actor_id, scopes_json, limit, offset);

        const index_key = try self.visibleListIndexKey(allocator, category);
        defer allocator.free(index_key);
        return self.listFromIndexWindow(allocator, index_key, category, session_id, false, actor_id, scopes_json, true, limit, offset);
    }

    fn listAnyVisible(self: *RedisAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, actor_id: []const u8, scopes_json: []const u8) ![]domain.AgentMemory {
        var candidates = try visibleOwnerCandidatesFromScopes(allocator, actor_id, scopes_json);
        defer candidates.deinit(allocator);
        if (!candidates.requires_global_scan) return self.listVisibleFromOwnerCandidatesWindow(allocator, &candidates, category, null, true, actor_id, scopes_json, std.math.maxInt(usize), 0);

        const index_key = try self.visibleListIndexKey(allocator, category);
        defer allocator.free(index_key);
        return self.listFromIndex(allocator, index_key, category, null, true, actor_id, scopes_json, true);
    }

    fn listAnyVisibleWindow(self: *RedisAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, limit: usize, offset: usize) ![]domain.AgentMemory {
        var candidates = try visibleOwnerCandidatesFromScopes(allocator, actor_id, scopes_json);
        defer candidates.deinit(allocator);
        if (!candidates.requires_global_scan) return self.listVisibleFromOwnerCandidatesWindow(allocator, &candidates, category, null, true, actor_id, scopes_json, limit, offset);

        const index_key = try self.visibleListIndexKey(allocator, category);
        defer allocator.free(index_key);
        return self.listFromIndexWindow(allocator, index_key, category, null, true, actor_id, scopes_json, true, limit, offset);
    }

    fn getAnyVisible(self: *RedisAgentMemory, allocator: std.mem.Allocator, key: []const u8, actor_id: []const u8, scopes_json: []const u8) !?domain.AgentMemory {
        var candidates = try visibleOwnerCandidatesFromScopes(allocator, actor_id, scopes_json);
        defer candidates.deinit(allocator);
        if (!candidates.requires_global_scan) return self.getVisibleFromOwnerKeyCandidates(allocator, &candidates, key, null, true, actor_id, scopes_json);

        const index_key = try self.keyIndexKey(allocator, key);
        defer allocator.free(index_key);
        return self.getVisibleFromKeyIndex(allocator, index_key, key, null, true, actor_id, scopes_json, false);
    }

    fn getVisibleFromOwnerKeyCandidates(self: *RedisAgentMemory, allocator: std.mem.Allocator, candidates: *const VisibleOwnerCandidates, key: []const u8, session_id: ?[]const u8, include_sessions: bool, actor_id: []const u8, scopes_json: []const u8) !?domain.AgentMemory {
        if (!include_sessions) return self.getVisibleFromOwnerDirectCandidates(allocator, candidates, key, session_id, actor_id, scopes_json);

        var matches: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        defer matches.deinit(allocator);
        errdefer for (matches.items) |*entry| freeAgentMemory(allocator, entry);

        for (candidates.owners.items) |owner| {
            const index_key = try self.ownerKeyIndexKey(allocator, owner, key);
            defer allocator.free(index_key);
            var maybe_entry = try self.getVisibleFromKeyIndex(allocator, index_key, key, session_id, include_sessions, actor_id, scopes_json, true);
            if (maybe_entry) |*entry| {
                var entry_owned = true;
                errdefer if (entry_owned) freeAgentMemory(allocator, entry);
                try matches.append(allocator, entry.*);
                entry_owned = false;
            }
        }

        sortAgentMemoryForVisibleGet(matches.items, actor_id);
        if (matches.items.len == 0) return null;
        const result = matches.items[0];
        for (matches.items[1..]) |*entry| freeAgentMemory(allocator, entry);
        return result;
    }

    fn getVisibleFromOwnerDirectCandidates(self: *RedisAgentMemory, allocator: std.mem.Allocator, candidates: *const VisibleOwnerCandidates, key: []const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8) !?domain.AgentMemory {
        var matches: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        defer matches.deinit(allocator);
        errdefer for (matches.items) |*entry| freeAgentMemory(allocator, entry);

        for (candidates.owners.items) |owner| {
            var maybe_entry = try self.get(allocator, key, session_id, owner);
            if (maybe_entry) |*entry| {
                var entry_owned = true;
                errdefer if (entry_owned) freeAgentMemory(allocator, entry);
                if (!try entryVisible(allocator, entry.*, actor_id, scopes_json)) {
                    freeAgentMemory(allocator, entry);
                    entry_owned = false;
                    continue;
                }
                try matches.append(allocator, entry.*);
                entry_owned = false;
            }
        }

        sortAgentMemoryForVisibleGet(matches.items, actor_id);
        if (matches.items.len == 0) return null;
        const result = matches.items[0];
        for (matches.items[1..]) |*entry| freeAgentMemory(allocator, entry);
        return result;
    }

    fn getVisibleFromKeyIndex(self: *RedisAgentMemory, allocator: std.mem.Allocator, index_key: []const u8, key: []const u8, session_id: ?[]const u8, include_sessions: bool, actor_id: []const u8, scopes_json: []const u8, stop_after_first_visible: bool) !?domain.AgentMemory {
        var matches: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        defer matches.deinit(allocator);
        errdefer for (matches.items) |*entry| freeAgentMemory(allocator, entry);
        const scan_limit = redisVisibleKeyScanLimit();
        const fetch_limit = redisMemoryWindowFetchLimit(1);
        var raw_offset: usize = 0;
        var scanned: usize = 0;
        while (scanned < scan_limit) {
            const remaining = scan_limit - scanned;
            const batch_limit = @min(fetch_limit, remaining);
            var fetched: usize = 0;
            {
                const start_text = try std.fmt.allocPrint(allocator, "{d}", .{raw_offset});
                defer allocator.free(start_text);
                const stop_text = try std.fmt.allocPrint(allocator, "{d}", .{runtimePageStopOffset(raw_offset, batch_limit)});
                defer allocator.free(stop_text);
                var resp = try self.client.command(&.{ "ZREVRANGE", index_key, start_text, stop_text });
                defer resp.deinit(self.allocator);
                const members = try redisRequiredStringArrayFromResp(resp);
                fetched = members.len;
                if (fetched == 0) break;
                for (members) |member| {
                    scanned += 1;
                    const redis_key = try redisRequiredStringFromResp(member);
                    var hash = try self.client.command(&.{ "HGETALL", redis_key });
                    const maybe_entry = try self.agentMemoryFromHash(allocator, hash);
                    hash.deinit(self.allocator);
                    var entry = maybe_entry orelse {
                        try self.removeIndexMember(index_key, redis_key);
                        continue;
                    };
                    var entry_owned = true;
                    errdefer if (entry_owned) freeAgentMemory(allocator, &entry);
                    if (!std.mem.eql(u8, entry.key, key)) {
                        freeAgentMemory(allocator, &entry);
                        entry_owned = false;
                        continue;
                    }
                    if (session_id) |sid| {
                        if (entry.session_id == null or !std.mem.eql(u8, entry.session_id.?, sid)) {
                            freeAgentMemory(allocator, &entry);
                            entry_owned = false;
                            continue;
                        }
                    } else if (entry.session_id != null and !include_sessions) {
                        freeAgentMemory(allocator, &entry);
                        entry_owned = false;
                        continue;
                    }
                    if (!try entryVisible(allocator, entry, actor_id, scopes_json)) {
                        freeAgentMemory(allocator, &entry);
                        entry_owned = false;
                        continue;
                    }
                    try matches.append(allocator, entry);
                    entry_owned = false;
                }
            }
            if ((stop_after_first_visible and matches.items.len > 0) or fetched < batch_limit) break;
            raw_offset = runtimePageOffsetAfterFetch(raw_offset, fetched);
        }
        sortAgentMemoryForVisibleGet(matches.items, actor_id);
        if (matches.items.len == 0) return null;
        const result = matches.items[0];
        for (matches.items[1..]) |*entry| freeAgentMemory(allocator, entry);
        return result;
    }

    pub fn searchByInput(self: *RedisAgentMemory, allocator: std.mem.Allocator, input: SearchInput) ![]domain.AgentMemory {
        if (input.limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        const normalized_session_id = access.normalizeSessionId(input.session_id);
        if (input.any_session) return self.searchAnyVisible(allocator, input.query, input.limit, input.scopes_json, input.actor_id);
        return self.search(allocator, input.query, input.limit, normalized_session_id, input.scopes_json, input.actor_id);
    }

    fn search(self: *RedisAgentMemory, allocator: std.mem.Allocator, query: []const u8, limit: usize, session_id: ?[]const u8, scopes_json: []const u8, actor_id: ?[]const u8) ![]domain.AgentMemory {
        const actor = actor_id orelse return allocator.alloc(domain.AgentMemory, 0);
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        var candidates = try visibleOwnerCandidatesFromScopes(allocator, actor, scopes_json);
        defer candidates.deinit(allocator);
        if (!candidates.requires_global_scan) return self.searchVisibleOwnerCandidates(allocator, &candidates, null, session_id, false, actor, scopes_json, query, limit);

        const index_key = try self.visibleListIndexKey(allocator, null);
        defer allocator.free(index_key);
        return self.searchFromIndex(allocator, index_key, null, session_id, false, actor, scopes_json, query, limit);
    }

    fn searchAnyVisible(self: *RedisAgentMemory, allocator: std.mem.Allocator, query: []const u8, limit: usize, scopes_json: []const u8, actor_id: ?[]const u8) ![]domain.AgentMemory {
        const actor = actor_id orelse return allocator.alloc(domain.AgentMemory, 0);
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        var candidates = try visibleOwnerCandidatesFromScopes(allocator, actor, scopes_json);
        defer candidates.deinit(allocator);
        if (!candidates.requires_global_scan) return self.searchVisibleOwnerCandidates(allocator, &candidates, null, null, true, actor, scopes_json, query, limit);

        const index_key = try self.visibleListIndexKey(allocator, null);
        defer allocator.free(index_key);
        return self.searchFromIndex(allocator, index_key, null, null, true, actor, scopes_json, query, limit);
    }

    fn listVisibleFromOwnerCandidatesWindow(self: *RedisAgentMemory, allocator: std.mem.Allocator, candidates: *const VisibleOwnerCandidates, category: ?[]const u8, session_id: ?[]const u8, include_sessions: bool, actor_id: []const u8, scopes_json: []const u8, limit: usize, offset: usize) ![]domain.AgentMemory {
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        const keep_limit = agentMemoryWindowKeepLimit(limit, offset);
        var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (out.items) |*entry| freeAgentMemory(allocator, entry);
            out.deinit(allocator);
        }
        for (candidates.owners.items) |owner| {
            const owner_index = try self.ownerIndexKey(allocator, owner);
            defer allocator.free(owner_index);
            const entries = try self.listFromIndexWindow(allocator, owner_index, category, session_id, include_sessions, actor_id, scopes_json, true, keep_limit, 0);
            defer {
                for (entries) |*entry| freeAgentMemory(allocator, entry);
                allocator.free(entries);
            }
            for (entries) |*entry| {
                try out.append(allocator, entry.*);
                detachAgentMemory(entry);
            }
        }
        sortAgentMemory(out.items);
        const owned = try out.toOwnedSlice(allocator);
        return pageAgentMemorySlice(allocator, owned, limit, offset);
    }

    fn searchVisibleOwnerCandidates(self: *RedisAgentMemory, allocator: std.mem.Allocator, candidates: *const VisibleOwnerCandidates, category: ?[]const u8, session_id: ?[]const u8, include_sessions: bool, actor_id: []const u8, scopes_json: []const u8, query: []const u8, limit: usize) ![]domain.AgentMemory {
        const capped = runtimeAgentMemorySearchResultLimit(limit);
        var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (out.items) |*entry| freeAgentMemory(allocator, entry);
            out.deinit(allocator);
        }
        for (candidates.owners.items) |owner| {
            const owner_index = try self.ownerIndexKey(allocator, owner);
            defer allocator.free(owner_index);
            const entries = try self.searchFromIndex(allocator, owner_index, category, session_id, include_sessions, actor_id, scopes_json, query, capped);
            defer {
                for (entries) |*entry| freeAgentMemory(allocator, entry);
                allocator.free(entries);
            }
            for (entries) |*entry| {
                try out.append(allocator, entry.*);
                detachAgentMemory(entry);
                sortAgentMemory(out.items);
                trimAgentMemorySearchResults(allocator, &out, capped);
            }
        }
        return out.toOwnedSlice(allocator);
    }

    fn searchFromIndex(self: *RedisAgentMemory, allocator: std.mem.Allocator, index_key: []const u8, category: ?[]const u8, session_id: ?[]const u8, include_sessions: bool, actor_id: []const u8, scopes_json: []const u8, query: []const u8, limit: usize) ![]domain.AgentMemory {
        const capped = runtimeAgentMemorySearchResultLimit(limit);
        const scan_limit = runtimeAgentMemorySearchScanLimit(capped);
        const fetch_limit = redisMemoryWindowFetchLimit(capped);
        var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (out.items) |*entry| freeAgentMemory(allocator, entry);
            out.deinit(allocator);
        }
        var raw_offset: usize = 0;
        var scanned: usize = 0;
        while (scanned < scan_limit) {
            const remaining = scan_limit - scanned;
            const batch_limit = @min(fetch_limit, remaining);
            var fetched: usize = 0;
            {
                const start_text = try std.fmt.allocPrint(allocator, "{d}", .{raw_offset});
                defer allocator.free(start_text);
                const stop_text = try std.fmt.allocPrint(allocator, "{d}", .{runtimePageStopOffset(raw_offset, batch_limit)});
                defer allocator.free(stop_text);
                var resp = try self.client.command(&.{ "ZREVRANGE", index_key, start_text, stop_text });
                defer resp.deinit(self.allocator);
                const members = try redisRequiredStringArrayFromResp(resp);
                fetched = members.len;
                if (fetched == 0) break;
                for (members) |member| {
                    scanned += 1;
                    const redis_key = try redisRequiredStringFromResp(member);
                    var hash = try self.client.command(&.{ "HGETALL", redis_key });
                    const maybe_entry = try self.agentMemoryFromHash(allocator, hash);
                    hash.deinit(self.allocator);
                    var entry = maybe_entry orelse {
                        try self.removeIndexMember(index_key, redis_key);
                        continue;
                    };
                    var entry_owned = true;
                    errdefer if (entry_owned) freeAgentMemory(allocator, &entry);
                    if (category) |cat| {
                        if (!std.mem.eql(u8, entry.category, cat)) {
                            freeAgentMemory(allocator, &entry);
                            entry_owned = false;
                            continue;
                        }
                    }
                    if (session_id) |sid| {
                        if (entry.session_id == null or !std.mem.eql(u8, entry.session_id.?, sid)) {
                            freeAgentMemory(allocator, &entry);
                            entry_owned = false;
                            continue;
                        }
                    } else if (entry.session_id != null and !include_sessions) {
                        freeAgentMemory(allocator, &entry);
                        entry_owned = false;
                        continue;
                    }
                    if (!try entryVisible(allocator, entry, actor_id, scopes_json)) {
                        freeAgentMemory(allocator, &entry);
                        entry_owned = false;
                        continue;
                    }
                    const score = scoreText(query, entry.key) + scoreText(query, entry.content);
                    try appendRuntimeScoredAgentMemoryCandidate(allocator, &out, query, capped, entry, score);
                    entry_owned = false;
                }
            }
            if ((query.len == 0 and out.items.len >= capped) or fetched < batch_limit) break;
            raw_offset = runtimePageOffsetAfterFetch(raw_offset, fetched);
        }
        return out.toOwnedSlice(allocator);
    }

    pub fn deleteByInput(self: *RedisAgentMemory, input: DeleteInput) !bool {
        const normalized_session_id = access.normalizeSessionId(input.session_id);
        const log_feed = !input.suppress_feed;
        if (input.all_owners) {
            if (input.event_order != null) return self.deleteAllOrderedInternal(input.key, input.actor_id, input.writer_actor_id, input.event_order, log_feed);
            return self.deleteAllInternal(input.key, input.actor_id, input.writer_actor_id, log_feed, null);
        }
        if (input.event_order != null) return self.deleteOrderedInternal(input.key, normalized_session_id, input.actor_id, input.writer_actor_id, input.event_order, log_feed);
        return self.deleteInternal(input.key, normalized_session_id, input.actor_id, input.writer_actor_id, log_feed, null);
    }

    fn deleteInternal(self: *RedisAgentMemory, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, log_feed: bool, event_order: ?EventOrder) !bool {
        const owner = actor_id orelse return false;
        const entry_key = try self.entryKey(self.allocator, owner, session_id, key);
        defer self.allocator.free(entry_key);
        var existing_hash = try self.client.command(&.{ "HGETALL", entry_key });
        defer existing_hash.deinit(self.allocator);
        var existing = try self.agentMemoryFromHash(self.allocator, existing_hash);
        defer if (existing) |*entry| freeAgentMemory(self.allocator, entry);
        if (existing == null) return false;
        try self.beginTransaction();
        var committed = false;
        defer if (!committed) self.discardTransaction();
        try self.queueRemoveEntryIndexes(entry_key, existing.?);
        try self.queueCommand(&.{ "DEL", entry_key });
        var resp = try self.execTransaction();
        committed = true;
        defer resp.deinit(self.allocator);
        const changed = try redisExecLastIntegerChanged(resp);
        if (changed and log_feed) {
            const entry = existing.?;
            try self.appendAgentMemoryDeleteFeedEvent(key, session_id, owner, writer_actor_id orelse owner, entry.scope, entry.permissions_json, "delete", event_order);
        }
        return changed;
    }

    fn deleteOrderedInternal(self: *RedisAgentMemory, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, event_order: ?EventOrder, log_feed: bool) !bool {
        const order = event_order orelse return self.deleteInternal(key, session_id, actor_id, writer_actor_id, log_feed, null);
        const owner = actor_id orelse return false;
        try self.upsertTombstone(key, owner, .scoped, session_id, order);
        const entry_key = try self.entryKey(self.allocator, owner, session_id, key);
        defer self.allocator.free(entry_key);
        var existing_hash = try self.client.command(&.{ "HGETALL", entry_key });
        defer existing_hash.deinit(self.allocator);
        if (try redisEventOrderFromHash(existing_hash)) |stored_order| {
            if (compareEventOrder(order, stored_order.timestamp_ms, stored_order.origin_instance_id, stored_order.origin_sequence) < 0) return false;
        }
        return self.deleteInternal(key, session_id, owner, writer_actor_id, log_feed, order);
    }

    fn deleteAllInternal(self: *RedisAgentMemory, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, log_feed: bool, event_order: ?EventOrder) !bool {
        const owner = actor_id orelse return false;
        const candidates = try self.collectDeleteAllCandidates(key, owner, null);
        defer self.freeDeleteAllCandidates(candidates);
        if (candidates.len == 0) return false;

        try self.beginTransaction();
        var committed = false;
        defer if (!committed) self.discardTransaction();
        for (candidates) |candidate| {
            try self.queueRemoveEntryIndexes(candidate.redis_key, candidate.entry);
            try self.queueCommand(&.{ "DEL", candidate.redis_key });
        }
        var resp = try self.execTransaction();
        committed = true;
        defer resp.deinit(self.allocator);
        const changed_any = try redisExecAnyIntegerChanged(resp);
        if (changed_any and log_feed) {
            const entry = candidates[0].entry;
            try self.appendAgentMemoryDeleteFeedEvent(key, null, owner, writer_actor_id orelse owner, entry.scope, entry.permissions_json, "delete_all", event_order);
        }
        return changed_any;
    }

    fn deleteAllOrderedInternal(self: *RedisAgentMemory, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, event_order: ?EventOrder, log_feed: bool) !bool {
        const order = event_order orelse return self.deleteAllInternal(key, actor_id, writer_actor_id, log_feed, null);
        const owner = actor_id orelse return false;
        try self.upsertTombstone(key, owner, .all, null, order);
        const candidates = try self.collectDeleteAllCandidates(key, owner, order);
        defer self.freeDeleteAllCandidates(candidates);
        if (candidates.len == 0) return false;

        try self.beginTransaction();
        var committed = false;
        defer if (!committed) self.discardTransaction();
        for (candidates) |candidate| {
            try self.queueRemoveEntryIndexes(candidate.redis_key, candidate.entry);
            try self.queueCommand(&.{ "DEL", candidate.redis_key });
        }
        var resp = try self.execTransaction();
        committed = true;
        defer resp.deinit(self.allocator);
        const changed_any = try redisExecAnyIntegerChanged(resp);
        if (changed_any and log_feed) {
            const entry = candidates[0].entry;
            try self.appendAgentMemoryDeleteFeedEvent(key, null, owner, writer_actor_id orelse owner, entry.scope, entry.permissions_json, "delete_all", event_order);
        }
        return changed_any;
    }

    fn collectDeleteAllCandidates(self: *RedisAgentMemory, key: []const u8, owner: []const u8, event_order: ?EventOrder) ![]DeleteAllCandidate {
        const owner_key_index = try self.ownerKeyIndexKey(self.allocator, owner, key);
        defer self.allocator.free(owner_key_index);

        var candidates: std.ArrayListUnmanaged(DeleteAllCandidate) = .empty;
        errdefer {
            for (candidates.items) |*candidate| {
                self.allocator.free(candidate.redis_key);
                freeAgentMemory(self.allocator, &candidate.entry);
            }
            candidates.deinit(self.allocator);
        }
        var stale_members: std.ArrayListUnmanaged([]u8) = .empty;
        defer {
            for (stale_members.items) |member| self.allocator.free(member);
            stale_members.deinit(self.allocator);
        }

        const fetch_limit = redisDeleteAllFetchLimit();
        var raw_offset: usize = 0;
        while (true) {
            const start_text = try std.fmt.allocPrint(self.allocator, "{d}", .{raw_offset});
            defer self.allocator.free(start_text);
            const stop_text = try std.fmt.allocPrint(self.allocator, "{d}", .{runtimePageStopOffset(raw_offset, fetch_limit)});
            defer self.allocator.free(stop_text);
            var members_resp = try self.client.command(&.{ "ZREVRANGE", owner_key_index, start_text, stop_text });
            defer members_resp.deinit(self.allocator);
            const members = try redisRequiredStringArrayFromResp(members_resp);
            if (members.len == 0) break;

            for (members) |member| {
                const redis_key = try redisRequiredStringFromResp(member);
                var hash = try self.client.command(&.{ "HGETALL", redis_key });
                const maybe_entry = self.agentMemoryFromHash(self.allocator, hash) catch |err| {
                    hash.deinit(self.allocator);
                    return err;
                };
                const is_newer_than_delete = if (event_order) |order| blk: {
                    break :blk if (try redisEventOrderFromHash(hash)) |existing|
                        compareEventOrder(order, existing.timestamp_ms, existing.origin_instance_id, existing.origin_sequence) < 0
                    else
                        false;
                } else false;
                hash.deinit(self.allocator);
                var entry = maybe_entry orelse {
                    try stale_members.append(self.allocator, try self.allocator.dupe(u8, redis_key));
                    continue;
                };
                if (!std.mem.eql(u8, entry.actor_id, owner) or !std.mem.eql(u8, entry.key, key) or is_newer_than_delete) {
                    freeAgentMemory(self.allocator, &entry);
                    continue;
                }
                const redis_key_copy = try self.allocator.dupe(u8, redis_key);
                var appended = false;
                errdefer if (!appended) {
                    self.allocator.free(redis_key_copy);
                    freeAgentMemory(self.allocator, &entry);
                };
                try candidates.append(self.allocator, .{ .redis_key = redis_key_copy, .entry = entry });
                appended = true;
            }

            if (members.len < fetch_limit) break;
            raw_offset = runtimePageOffsetAfterFetch(raw_offset, members.len);
        }

        for (stale_members.items) |member| try self.removeIndexMember(owner_key_index, member);
        return candidates.toOwnedSlice(self.allocator);
    }

    fn freeDeleteAllCandidates(self: *RedisAgentMemory, candidates: []DeleteAllCandidate) void {
        for (candidates) |*candidate| {
            self.allocator.free(candidate.redis_key);
            freeAgentMemory(self.allocator, &candidate.entry);
        }
        self.allocator.free(candidates);
    }

