    }

    fn patchStatusOrdered(self: *RedisAgentMemory, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, status: []const u8, writer_actor_id: ?[]const u8, event_order: ?EventOrder) !bool {
