    fn tombstoneBlocksReplay(self: *RedisAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, event_order: EventOrder) !bool {
        const owner = actor_id orelse return false;
        return self.tombstoneBlocksPut(allocator, key, session_id, owner, event_order);
    }

    fn patchStatusInternal(self: *RedisAgentMemory, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, status: []const u8, log_feed: bool, event_order: ?EventOrder) !bool {
        const owner = actor_id orelse return false;
        const entry_key = try self.entryKey(self.allocator, owner, session_id, key);
        defer self.allocator.free(entry_key);
        var existing_hash = try self.client.command(&.{ "HGETALL", entry_key });
        defer existing_hash.deinit(self.allocator);
        var existing = try self.agentMemoryFromHash(self.allocator, existing_hash);
        defer if (existing) |*entry| freeAgentMemory(self.allocator, entry);
        if (existing == null) return false;
        if (event_order) |order| {
            if (try redisEventOrderFromHash(existing_hash)) |stored_order| {
                if (compareEventOrder(order, stored_order.timestamp_ms, stored_order.origin_instance_id, stored_order.origin_sequence) <= 0) return false;
            }
            if (!domain.isDefaultVisibleStatus(status)) {
                try self.upsertTombstone(key, owner, .scoped, session_id, order);
                try self.beginTransaction();
                var committed = false;
                defer if (!committed) self.discardTransaction();
                try self.queueRemoveEntryIndexes(entry_key, existing.?);
                try self.queueCommand(&.{ "DEL", entry_key });
                var del_response = try self.execTransaction();
                committed = true;
                defer del_response.deinit(self.allocator);
                const changed = try redisExecLastIntegerChanged(del_response);
                if (changed and log_feed) try self.appendAgentMemoryLifecycleFeedEvent(existing.?, writer_actor_id orelse owner, status, event_order);
                return changed;
            }
        }
        var response = if (event_order) |order| blk: {
            const timestamp_text = try std.fmt.allocPrint(self.allocator, "{d}", .{order.timestamp_ms});
            defer self.allocator.free(timestamp_text);
            const sequence_text = try std.fmt.allocPrint(self.allocator, "{d}", .{order.origin_sequence});
            defer self.allocator.free(sequence_text);
            break :blk try self.client.command(&.{ "HSET", entry_key, "status", status, "event_timestamp_ms", timestamp_text, "origin_instance_id", order.origin_instance_id, "origin_sequence", sequence_text });
        } else try self.client.command(&.{ "HSET", entry_key, "status", status });
        defer response.deinit(self.allocator);
        if (log_feed) {
            var updated = try self.get(self.allocator, key, session_id, owner);
            defer if (updated) |*entry| freeAgentMemory(self.allocator, entry);
            if (updated) |entry| try self.appendAgentMemoryLifecycleFeedEvent(entry, writer_actor_id orelse owner, status, event_order);
        }
        return true;
    }

    pub fn countByInput(self: *RedisAgentMemory, input: CountInput) !usize {
        return self.count(input.actor_id, input.scopes_json);
    }

    fn count(self: *RedisAgentMemory, actor_id: ?[]const u8, scopes_json: []const u8) !usize {
        const index_key = try self.globalIndexKey(self.allocator);
        defer self.allocator.free(index_key);
        if (actor_id) |actor| {
            var candidates = try visibleOwnerCandidatesFromScopes(self.allocator, actor, scopes_json);
            defer candidates.deinit(self.allocator);
            if (candidates.requires_global_scan) return self.countVisibleFromIndex(index_key, actor, scopes_json);

            var visible_count: usize = 0;
            for (candidates.owners.items) |owner| {
                const owner_index = try self.ownerIndexKey(self.allocator, owner);
                defer self.allocator.free(owner_index);
                visible_count = runtimeCountAdd(visible_count, try self.countVisibleFromIndex(owner_index, actor, scopes_json));
            }
            return visible_count;
        }
        var resp = try self.client.command(&.{ "ZCARD", index_key });
        defer resp.deinit(self.allocator);
        return redisRequiredCountFromResp(resp);
    }

    fn countVisibleFromIndex(self: *RedisAgentMemory, index_key: []const u8, actor_id: []const u8, scopes_json: []const u8) !usize {
        const batch_limit: usize = 1000;
        var raw_offset: usize = 0;
        var visible_count: usize = 0;
        while (true) {
            const start_text = try std.fmt.allocPrint(self.allocator, "{d}", .{raw_offset});
            defer self.allocator.free(start_text);
            const stop_text = try std.fmt.allocPrint(self.allocator, "{d}", .{runtimePageStopOffset(raw_offset, batch_limit)});
            defer self.allocator.free(stop_text);
            var resp = try self.client.command(&.{ "ZREVRANGE", index_key, start_text, stop_text });
            defer resp.deinit(self.allocator);
            const members = try redisRequiredStringArrayFromResp(resp);
            if (members.len == 0) break;
            for (members) |member| {
                const redis_key = try redisRequiredStringFromResp(member);
                var hash = try self.client.command(&.{ "HGETALL", redis_key });
                const maybe_entry = try self.agentMemoryFromHash(self.allocator, hash);
                hash.deinit(self.allocator);
                var entry = maybe_entry orelse {
                    try self.removeIndexMember(index_key, redis_key);
                    continue;
                };
                const visible = try entryVisible(self.allocator, entry, actor_id, scopes_json);
                freeAgentMemory(self.allocator, &entry);
                if (visible) visible_count = runtimeCountIncrement(visible_count);
            }
            if (members.len < batch_limit) break;
            raw_offset = runtimePageOffsetAfterFetch(raw_offset, members.len);
        }
        return visible_count;
    }

    pub fn saveMessageByInput(self: *RedisAgentMemory, input: SaveMessageInput) !void {
        return self.saveMessageAtOrderedInternal(input.session_id, input.role, input.content, input.created_at_ms, input.actor_id, input.event_order, !input.suppress_feed);
    }

    fn saveMessage(self: *RedisAgentMemory, session_id: []const u8, role: []const u8, content: []const u8, actor_id: ?[]const u8) !void {
        return self.saveMessageAt(session_id, role, content, ids.nowMs(), actor_id);
    }

    fn saveMessageAt(self: *RedisAgentMemory, session_id: []const u8, role: []const u8, content: []const u8, created_at: i64, actor_id: ?[]const u8) !void {
        return self.saveMessageAtOrdered(session_id, role, content, created_at, actor_id, null);
    }

    fn saveMessageAtOrdered(self: *RedisAgentMemory, session_id: []const u8, role: []const u8, content: []const u8, created_at: i64, actor_id: ?[]const u8, event_order: ?EventOrder) !void {
        return self.saveMessageAtOrderedInternal(session_id, role, content, created_at, actor_id, event_order, true);
    }

    fn saveMessageAtOrderedInternal(self: *RedisAgentMemory, session_id: []const u8, role: []const u8, content: []const u8, created_at: i64, actor_id: ?[]const u8, event_order: ?EventOrder, log_feed: bool) !void {
        const actor = try access.requiredActorId(actor_id);
        if (event_order) |order| {
            if (try self.messageTombstoneBlocksPut(actor, session_id, order)) return;
        }
        const meta_key = try self.sessionMetaKey(self.allocator, actor, session_id);
        defer self.allocator.free(meta_key);
        const sessions_key = try self.sessionsIndexKey(self.allocator, actor);
        defer self.allocator.free(sessions_key);
        const autosave_sessions_key = try self.autosaveSessionsIndexKey(self.allocator, actor);
        defer self.allocator.free(autosave_sessions_key);
        const message_index_key = try self.sessionMessageIndexKey(self.allocator, actor, session_id);
        defer self.allocator.free(message_index_key);
        const history_index_key = try self.sessionHistoryIndexKey(self.allocator, actor, session_id);
        defer self.allocator.free(history_index_key);
        const autosave_index_key = try self.sessionAutosaveIndexKey(self.allocator, actor, session_id);
        defer self.allocator.free(autosave_index_key);
        const payloads_key = try self.sessionMessagePayloadsKey(self.allocator, actor, session_id);
        defer self.allocator.free(payloads_key);
        const sequence_key = try self.sessionMessageSequenceKey(self.allocator, actor, session_id);
        defer self.allocator.free(sequence_key);
        const payload = try messagePayloadOrdered(self.allocator, role, content, created_at, event_order);
        defer self.allocator.free(payload);
        const created_text = try std.fmt.allocPrint(self.allocator, "{d}", .{created_at});
        defer self.allocator.free(created_text);
        const message_id = try self.redisSessionMessageId(role, content, created_at, event_order, sequence_key);
        defer self.allocator.free(message_id);

        try self.beginTransaction();
        var committed = false;
        defer if (!committed) self.discardTransaction();
        try self.queueCommand(&.{ "HSET", payloads_key, message_id, payload });
        try self.queueCommand(&.{ "ZADD", message_index_key, created_text, message_id });
        if (domain.sessionMessageVisibleInHistory(role)) {
            try self.queueCommand(&.{ "ZADD", history_index_key, created_text, message_id });
        }
        if (domain.isAutosaveSessionRole(role)) {
            try self.queueCommand(&.{ "ZADD", autosave_index_key, created_text, message_id });
            try self.queueCommand(&.{ "ZADD", autosave_sessions_key, created_text, session_id });
        }
        try self.queueExpireKey(message_index_key);
        try self.queueExpireKey(history_index_key);
        try self.queueExpireKey(autosave_index_key);
        try self.queueExpireKey(payloads_key);
        try self.queueExpireKey(sequence_key);
        try self.queueExpireKey(meta_key);
        try self.queueExpireKey(sessions_key);
        if (domain.isAutosaveSessionRole(role)) try self.queueExpireKey(autosave_sessions_key);
        var exec = try self.execTransaction();
        exec.deinit(self.allocator);
        committed = true;
        if (domain.sessionMessageVisibleInHistory(role)) try self.refreshSessionHistoryMeta(actor, session_id);
        if (log_feed and sessionMessageShouldEmitFeed(role)) try self.appendSessionMessageFeedEvent(session_id, role, content, created_at, actor, event_order);
    }

    pub fn loadMessagesByInput(self: *RedisAgentMemory, allocator: std.mem.Allocator, input: LoadMessagesInput) ![]Message {
        return self.loadMessages(allocator, input.session_id, input.actor_id);
    }

    fn loadMessages(self: *RedisAgentMemory, allocator: std.mem.Allocator, session_id: []const u8, actor_id: ?[]const u8) ![]Message {
        const actor = actor_id orelse return allocator.alloc(Message, 0);
        const message_index_key = try self.sessionMessageIndexKey(allocator, actor, session_id);
        defer allocator.free(message_index_key);
        const payloads_key = try self.sessionMessagePayloadsKey(allocator, actor, session_id);
        defer allocator.free(payloads_key);
        var resp = try self.client.command(&.{ "ZRANGE", message_index_key, "0", "-1" });
        defer resp.deinit(self.allocator);
        return self.messagesFromRedisIds(allocator, payloads_key, resp);
    }

    pub fn clearMessagesByInput(self: *RedisAgentMemory, input: ClearMessagesInput) !void {
        return self.clearMessagesOrderedInternal(input.session_id, input.actor_id, input.event_order, !input.suppress_feed);
    }

    fn clearMessages(self: *RedisAgentMemory, session_id: []const u8, actor_id: ?[]const u8) !void {
        return self.clearMessagesOrdered(session_id, actor_id, null);
    }

    fn clearMessagesOrdered(self: *RedisAgentMemory, session_id: []const u8, actor_id: ?[]const u8, event_order: ?EventOrder) !void {
        return self.clearMessagesOrderedInternal(session_id, actor_id, event_order, true);
    }

    fn clearMessagesOrderedInternal(self: *RedisAgentMemory, session_id: []const u8, actor_id: ?[]const u8, event_order: ?EventOrder, log_feed: bool) !void {
        const actor = actor_id orelse return;
        const order = event_order orelse {
            const had_usage = (try self.loadUsage(session_id, actor)) != null;
            const changed = try self.clearMessagesInner(session_id, actor, true);
            if (changed and log_feed) try self.appendSessionMessageDeleteFeedEvent(session_id, actor, "delete", null);
            if (had_usage and log_feed) try self.appendSessionUsageDeleteFeedEvent(session_id, actor, null);
            return;
        };
        try self.upsertMessageTombstone(actor, session_id, order);
        const message_index_key = try self.sessionMessageIndexKey(self.allocator, actor, session_id);
        defer self.allocator.free(message_index_key);
        const history_index_key = try self.sessionHistoryIndexKey(self.allocator, actor, session_id);
        defer self.allocator.free(history_index_key);
        const autosave_index_key = try self.sessionAutosaveIndexKey(self.allocator, actor, session_id);
        defer self.allocator.free(autosave_index_key);
        const payloads_key = try self.sessionMessagePayloadsKey(self.allocator, actor, session_id);
        defer self.allocator.free(payloads_key);
        var response = try self.client.command(&.{ "ZRANGE", message_index_key, "0", "-1" });
        defer response.deinit(self.allocator);
        var delete_ids: std.ArrayListUnmanaged([]u8) = .empty;
        defer {
            for (delete_ids.items) |id| self.allocator.free(id);
            delete_ids.deinit(self.allocator);
        }
        var original_count: usize = 0;
        const values = try redisRequiredStringArrayFromResp(response);
        for (values) |item| {
            const message_id = try redisRequiredStringFromResp(item);
            original_count += 1;
            var payload_resp = try self.client.command(&.{ "HGET", payloads_key, message_id });
            defer payload_resp.deinit(self.allocator);
            const payload = (try redisOptionalStringFromResp(payload_resp)) orelse {
                try delete_ids.append(self.allocator, try self.allocator.dupe(u8, message_id));
                continue;
            };
            if (try redisMessagePayloadNewerThanOrder(self.allocator, payload, order)) continue;
            const owned_id = try self.allocator.dupe(u8, message_id);
            errdefer self.allocator.free(owned_id);
            try delete_ids.append(self.allocator, owned_id);
        }
        if (delete_ids.items.len == 0) {
            _ = try self.deleteUsageOrderedInternal(session_id, actor, event_order, log_feed);
            return;
        }
        try self.beginTransaction();
        var committed = false;
        defer if (!committed) self.discardTransaction();
        try self.queueRedisVariadic("HDEL", payloads_key, delete_ids.items);
        try self.queueRedisVariadic("ZREM", message_index_key, delete_ids.items);
        try self.queueRedisVariadic("ZREM", history_index_key, delete_ids.items);
        try self.queueRedisVariadic("ZREM", autosave_index_key, delete_ids.items);
        var exec = try self.execTransaction();
        exec.deinit(self.allocator);
        committed = true;
        try self.refreshSessionHistoryMeta(actor, session_id);
        try self.refreshSessionAutosaveIndex(actor, session_id);
        _ = try self.deleteUsageOrderedInternal(session_id, actor, event_order, log_feed);
        if (original_count > 0 and log_feed) try self.appendSessionMessageDeleteFeedEvent(session_id, actor, "delete", event_order);
    }

    fn clearMessagesInner(self: *RedisAgentMemory, session_id: []const u8, actor: []const u8, delete_usage: bool) !bool {
        const list_key = try self.sessionListKey(self.allocator, actor, session_id);
        defer self.allocator.free(list_key);
        const meta_key = try self.sessionMetaKey(self.allocator, actor, session_id);
        defer self.allocator.free(meta_key);
        const sessions_key = try self.sessionsIndexKey(self.allocator, actor);
        defer self.allocator.free(sessions_key);
        const autosave_sessions_key = try self.autosaveSessionsIndexKey(self.allocator, actor);
        defer self.allocator.free(autosave_sessions_key);
        const message_index_key = try self.sessionMessageIndexKey(self.allocator, actor, session_id);
        defer self.allocator.free(message_index_key);
        const history_index_key = try self.sessionHistoryIndexKey(self.allocator, actor, session_id);
        defer self.allocator.free(history_index_key);
        const autosave_index_key = try self.sessionAutosaveIndexKey(self.allocator, actor, session_id);
        defer self.allocator.free(autosave_index_key);
        const payloads_key = try self.sessionMessagePayloadsKey(self.allocator, actor, session_id);
        defer self.allocator.free(payloads_key);
        const sequence_key = try self.sessionMessageSequenceKey(self.allocator, actor, session_id);
        defer self.allocator.free(sequence_key);
        const usage_key = if (delete_usage) try self.usageKey(self.allocator, actor, session_id) else null;
        defer if (usage_key) |key| self.allocator.free(key);
        var exists_resp = if (usage_key) |key|
            try self.client.command(&.{ "EXISTS", list_key, meta_key, message_index_key, history_index_key, autosave_index_key, payloads_key, key })
        else
            try self.client.command(&.{ "EXISTS", list_key, meta_key, message_index_key, history_index_key, autosave_index_key, payloads_key });
        defer exists_resp.deinit(self.allocator);
        const changed = try redisRequiredIntegerChangedFromResp(exists_resp);
        try self.beginTransaction();
        var committed = false;
        defer if (!committed) self.discardTransaction();
        if (usage_key) |key| {
            try self.queueCommand(&.{ "DEL", list_key, meta_key, message_index_key, history_index_key, autosave_index_key, payloads_key, sequence_key, key });
        } else {
            try self.queueCommand(&.{ "DEL", list_key, meta_key, message_index_key, history_index_key, autosave_index_key, payloads_key, sequence_key });
        }
        try self.queueCommand(&.{ "ZREM", sessions_key, session_id });
        try self.queueCommand(&.{ "ZREM", autosave_sessions_key, session_id });
        var exec = try self.execTransaction();
        exec.deinit(self.allocator);
        committed = true;
        return changed;
    }

    pub fn clearAutoSavedByInput(self: *RedisAgentMemory, input: ClearAutoSavedInput) !void {
        return self.clearAutoSavedInternal(input.session_id, input.actor_id, !input.suppress_feed);
    }

    fn clearAutoSaved(self: *RedisAgentMemory, session_id: ?[]const u8, actor_id: ?[]const u8) !void {
        return self.clearAutoSavedInternal(session_id, actor_id, true);
    }

    fn clearAutoSavedInternal(self: *RedisAgentMemory, session_id: ?[]const u8, actor_id: ?[]const u8, log_feed: bool) !void {
        const actor = actor_id orelse return;
        if (session_id) |sid| {
            return self.clearAutoSavedSession(sid, actor, log_feed);
        }
        const autosave_sessions_key = try self.autosaveSessionsIndexKey(self.allocator, actor);
        defer self.allocator.free(autosave_sessions_key);
        const stop_text = try std.fmt.allocPrint(self.allocator, "{d}", .{redisAutosaveSessionFetchLimit() - 1});
        defer self.allocator.free(stop_text);
        while (true) {
            var resp = try self.client.command(&.{ "ZRANGE", autosave_sessions_key, "0", stop_text });
            defer resp.deinit(self.allocator);
            var session_ids: std.ArrayListUnmanaged([]u8) = .empty;
            defer {
                for (session_ids.items) |sid| self.allocator.free(sid);
                session_ids.deinit(self.allocator);
            }
            const values = try redisRequiredStringArrayFromResp(resp);
            if (values.len == 0) return;
            for (values) |value| {
                const sid = try redisRequiredStringFromResp(value);
                try session_ids.append(self.allocator, try self.allocator.dupe(u8, sid));
            }
            for (session_ids.items) |sid| try self.clearAutoSavedSession(sid, actor, log_feed);
        }
    }

    fn clearAutoSavedSession(self: *RedisAgentMemory, session_id: []const u8, actor: []const u8, log_feed: bool) !void {
        const autosave_index_key = try self.sessionAutosaveIndexKey(self.allocator, actor, session_id);
        defer self.allocator.free(autosave_index_key);
        const autosave_sessions_key = try self.autosaveSessionsIndexKey(self.allocator, actor);
        defer self.allocator.free(autosave_sessions_key);
        const message_index_key = try self.sessionMessageIndexKey(self.allocator, actor, session_id);
        defer self.allocator.free(message_index_key);
        const history_index_key = try self.sessionHistoryIndexKey(self.allocator, actor, session_id);
        defer self.allocator.free(history_index_key);
        const payloads_key = try self.sessionMessagePayloadsKey(self.allocator, actor, session_id);
        defer self.allocator.free(payloads_key);

        var autosave_resp = try self.client.command(&.{ "ZRANGE", autosave_index_key, "0", "-1" });
        defer autosave_resp.deinit(self.allocator);
        const values = try redisRequiredStringArrayFromResp(autosave_resp);
        if (values.len == 0) {
            try self.removeAutosaveSessionIndex(actor, session_id);
            return;
        }

        var delete_ids: std.ArrayListUnmanaged([]u8) = .empty;
        defer {
            for (delete_ids.items) |id| self.allocator.free(id);
            delete_ids.deinit(self.allocator);
        }
        for (values) |value| {
            const message_id = try redisRequiredStringFromResp(value);
            try delete_ids.append(self.allocator, try self.allocator.dupe(u8, message_id));
        }

        try self.beginTransaction();
        var committed = false;
        defer if (!committed) self.discardTransaction();
        try self.queueRedisVariadic("HDEL", payloads_key, delete_ids.items);
        try self.queueRedisVariadic("ZREM", message_index_key, delete_ids.items);
        try self.queueRedisVariadic("ZREM", history_index_key, delete_ids.items);
        try self.queueRedisVariadic("ZREM", autosave_index_key, delete_ids.items);
        try self.queueCommand(&.{ "ZREM", autosave_sessions_key, session_id });
        var exec = try self.execTransaction();
        exec.deinit(self.allocator);
        committed = true;

        try self.refreshSessionHistoryMeta(actor, session_id);
        if (log_feed) try self.appendSessionAutosaveDeleteFeedEvent(session_id, actor);
    }

    pub fn saveUsageByInput(self: *RedisAgentMemory, input: SaveUsageInput) !void {
        return self.saveUsageOrderedInternal(input.session_id, input.total_tokens, input.actor_id, input.event_order, !input.suppress_feed);
    }

    fn saveUsage(self: *RedisAgentMemory, session_id: []const u8, total_tokens: u64, actor_id: ?[]const u8) !void {
        return self.saveUsageOrdered(session_id, total_tokens, actor_id, null);
    }

    fn saveUsageOrdered(self: *RedisAgentMemory, session_id: []const u8, total_tokens: u64, actor_id: ?[]const u8, event_order: ?EventOrder) !void {
        return self.saveUsageOrderedInternal(session_id, total_tokens, actor_id, event_order, true);
    }

    fn saveUsageOrderedInternal(self: *RedisAgentMemory, session_id: []const u8, total_tokens: u64, actor_id: ?[]const u8, event_order: ?EventOrder, log_feed: bool) !void {
        const actor = try access.requiredActorId(actor_id);
        const key = try self.usageKey(self.allocator, actor, session_id);
        defer self.allocator.free(key);
        const timestamp = if (event_order) |order| order.timestamp_ms else ids.nowMs();
        const timestamp_text = try std.fmt.allocPrint(self.allocator, "{d}", .{timestamp});
        defer self.allocator.free(timestamp_text);
        const value = try std.fmt.allocPrint(self.allocator, "{d}", .{total_tokens});
        defer self.allocator.free(value);
        const origin_instance_id = if (event_order) |order| order.origin_instance_id else "";
        const origin_sequence = if (event_order) |order| order.origin_sequence else 0;
        const origin_sequence_text = try std.fmt.allocPrint(self.allocator, "{d}", .{origin_sequence});
        defer self.allocator.free(origin_sequence_text);
        if (event_order) |order| {
            if (try self.usageTombstoneBlocksPut(actor, session_id, order)) return;
            var existing_hash = try self.client.command(&.{ "HGETALL", key });
            defer existing_hash.deinit(self.allocator);
            if (try redisEventOrderFromHash(existing_hash)) |stored_order| {
                if (compareEventOrder(order, stored_order.timestamp_ms, stored_order.origin_instance_id, stored_order.origin_sequence) <= 0) return;
            }
        }
        try self.beginTransaction();
        var committed = false;
        defer if (!committed) self.discardTransaction();
        try self.queueCommand(&.{
            "HSET",               key,
            "total_tokens",       value,
            "updated_at_ms",      timestamp_text,
            "event_timestamp_ms", timestamp_text,
            "origin_instance_id", origin_instance_id,
            "origin_sequence",    origin_sequence_text,
        });
        try self.queueExpireKey(key);
        var exec = try self.execTransaction();
        exec.deinit(self.allocator);
        committed = true;
        if (log_feed) try self.appendSessionUsagePutFeedEvent(session_id, total_tokens, actor, event_order);
    }

    pub fn deleteUsageByInput(self: *RedisAgentMemory, input: DeleteUsageInput) !bool {
        return self.deleteUsageOrderedInternal(input.session_id, input.actor_id, input.event_order, !input.suppress_feed);
    }

    fn deleteUsage(self: *RedisAgentMemory, session_id: []const u8, actor_id: ?[]const u8) !bool {
        return self.deleteUsageOrdered(session_id, actor_id, null);
    }

    fn deleteUsageOrdered(self: *RedisAgentMemory, session_id: []const u8, actor_id: ?[]const u8, event_order: ?EventOrder) !bool {
        return self.deleteUsageOrderedInternal(session_id, actor_id, event_order, true);
    }

    fn deleteUsageOrderedInternal(self: *RedisAgentMemory, session_id: []const u8, actor_id: ?[]const u8, event_order: ?EventOrder, log_feed: bool) !bool {
        const actor = actor_id orelse return false;
        const key = try self.usageKey(self.allocator, actor, session_id);
        defer self.allocator.free(key);
        if (event_order) |order| {
            try self.upsertUsageTombstone(actor, session_id, order);
            var existing_hash = try self.client.command(&.{ "HGETALL", key });
            defer existing_hash.deinit(self.allocator);
            if (try redisEventOrderFromHash(existing_hash)) |stored_order| {
                if (compareEventOrder(order, stored_order.timestamp_ms, stored_order.origin_instance_id, stored_order.origin_sequence) < 0) return false;
            }
        }
        var del = try self.client.command(&.{ "DEL", key });
        defer del.deinit(self.allocator);
        const changed = try redisRequiredIntegerChangedFromResp(del);
        if (changed and log_feed) try self.appendSessionUsageDeleteFeedEvent(session_id, actor, event_order);
        return changed;
    }

    pub fn loadUsageByInput(self: *RedisAgentMemory, input: LoadUsageInput) !?u64 {
        return self.loadUsage(input.session_id, input.actor_id);
    }

    fn loadUsage(self: *RedisAgentMemory, session_id: []const u8, actor_id: ?[]const u8) !?u64 {
        const actor = actor_id orelse return null;
        const key = try self.usageKey(self.allocator, actor, session_id);
        defer self.allocator.free(key);
        var response = try self.client.command(&.{ "HGET", key, "total_tokens" });
        defer response.deinit(self.allocator);
        return redisUsageTotalFromResp(response);
    }

    pub fn listSessionsByInput(self: *RedisAgentMemory, allocator: std.mem.Allocator, input: ListSessionsInput) !HistoryList {
        return self.listSessions(allocator, input.limit, input.offset, input.actor_id);
    }

    fn listSessions(self: *RedisAgentMemory, allocator: std.mem.Allocator, limit: usize, offset: usize, actor_id: ?[]const u8) !HistoryList {
        const actor = actor_id orelse return .{ .total = 0, .sessions = try allocator.alloc(SessionInfo, 0) };
        const index_key = try self.sessionsIndexKey(allocator, actor);
        defer allocator.free(index_key);
        var total_resp = try self.client.command(&.{ "ZCARD", index_key });
        defer total_resp.deinit(self.allocator);
        const total = try redisRequiredCountFromResp(total_resp);
        const page_size = runtimePageSize(limit, total, offset);
        if (page_size == 0) return .{ .total = runtimeCountToU64(total), .sessions = try allocator.alloc(SessionInfo, 0) };
        const stop = runtimePageStopOffset(offset, page_size);
        const start_text = try std.fmt.allocPrint(allocator, "{d}", .{offset});
        defer allocator.free(start_text);
        const stop_text = try std.fmt.allocPrint(allocator, "{d}", .{stop});
        defer allocator.free(stop_text);
        var resp = try self.client.command(&.{ "ZREVRANGE", index_key, start_text, stop_text });
        defer resp.deinit(self.allocator);
        const values = try redisRequiredStringArrayFromResp(resp);
        var sessions: std.ArrayListUnmanaged(SessionInfo) = .empty;
        errdefer {
            for (sessions.items) |*info| freeSessionInfo(allocator, info);
            sessions.deinit(allocator);
        }
        for (values) |value| {
            const sid = try redisRequiredStringFromResp(value);
            if (try self.visibleSessionInfo(allocator, actor, sid)) |info| {
                try sessions.append(allocator, info);
            }
        }
        return .{ .total = runtimeCountToU64(total), .sessions = try sessions.toOwnedSlice(allocator) };
    }

    pub fn historyByInput(self: *RedisAgentMemory, allocator: std.mem.Allocator, input: HistoryInput) !HistoryShow {
        return self.history(allocator, input.session_id, input.limit, input.offset, input.actor_id);
    }

    fn history(self: *RedisAgentMemory, allocator: std.mem.Allocator, session_id: []const u8, limit: usize, offset: usize, actor_id: ?[]const u8) !HistoryShow {
        const actor = actor_id orelse return .{ .total = 0, .messages = try allocator.alloc(Message, 0) };
        const history_index_key = try self.sessionHistoryIndexKey(allocator, actor, session_id);
        defer allocator.free(history_index_key);
        const payloads_key = try self.sessionMessagePayloadsKey(allocator, actor, session_id);
        defer allocator.free(payloads_key);
        var total_resp = try self.client.command(&.{ "ZCARD", history_index_key });
        defer total_resp.deinit(self.allocator);
        const total = try redisRequiredCountFromResp(total_resp);
        const page_size = runtimePageSize(limit, total, offset);
        if (page_size == 0) return .{ .total = runtimeCountToU64(total), .messages = try allocator.alloc(Message, 0) };
        const stop = runtimePageStopOffset(offset, page_size);
        const start_text = try std.fmt.allocPrint(allocator, "{d}", .{offset});
        defer allocator.free(start_text);
        const stop_text = try std.fmt.allocPrint(allocator, "{d}", .{stop});
        defer allocator.free(stop_text);
        var ids_resp = try self.client.command(&.{ "ZRANGE", history_index_key, start_text, stop_text });
        defer ids_resp.deinit(self.allocator);
        const messages = try self.messagesFromRedisIds(allocator, payloads_key, ids_resp);
        return .{ .total = runtimeCountToU64(total), .messages = messages };
    }

    pub fn listFeedEventsByInput(self: *RedisAgentMemory, allocator: std.mem.Allocator, input: ListFeedEventsInput) ![]FeedEvent {
        return self.listFeedEvents(allocator, input.since_id, input.limit, input.actor_id, input.scopes_json);
    }

    fn listFeedEvents(self: *RedisAgentMemory, allocator: std.mem.Allocator, since_id: i64, limit: usize, actor_id: ?[]const u8, scopes_json: []const u8) ![]FeedEvent {
        const floor = try self.feedCursorFloor();
        if (since_id < floor) return error.CursorExpired;
        const target_limit = runtimeFeedEventTargetLimit(limit);
        const fetch_limit = runtimeFeedEventFetchLimit(target_limit);
        const index_key = try self.feedIndexKey(allocator);
        defer allocator.free(index_key);
        const min_text = try std.fmt.allocPrint(allocator, "({d}", .{since_id});
        defer allocator.free(min_text);
        const fetch_text = try std.fmt.allocPrint(allocator, "{d}", .{fetch_limit});
        defer allocator.free(fetch_text);
        var resp = try self.client.command(&.{ "ZRANGEBYSCORE", index_key, min_text, "+inf", "LIMIT", "0", fetch_text });
        defer resp.deinit(self.allocator);
        const keys = try redisRequiredArrayFromResp(resp);
        var out: std.ArrayListUnmanaged(FeedEvent) = .empty;
        errdefer {
            for (out.items) |*event| event.deinit(allocator);
            out.deinit(allocator);
        }
        for (keys) |key_value| {
            const event_key = try redisRequiredStringFromResp(key_value);
            const maybe_event = try self.feedEventFromRedisKey(allocator, event_key);
            var event = maybe_event orelse continue;
            if (event.compacted_at_ms != null or !self.feedEventVisible(event, actor_id, scopes_json)) {
                event.deinit(allocator);
                continue;
            }
            try out.append(allocator, event);
            if (out.items.len >= target_limit) break;
        }
        return out.toOwnedSlice(allocator);
    }

    pub fn feedStatusByInput(self: *RedisAgentMemory, allocator: std.mem.Allocator, input: FeedStatusInput) !FeedStatus {
        return self.feedStatus(allocator, input.actor_id, input.scopes_json);
    }

    fn feedStatus(self: *RedisAgentMemory, allocator: std.mem.Allocator, actor_id: ?[]const u8, scopes_json: []const u8) !FeedStatus {
        const floor = try self.feedCursorFloor();
        const max_event_id = try self.lastFeedEventId();
        const index_key = try self.feedIndexKey(allocator);
        defer allocator.free(index_key);
        var resp = try self.client.command(&.{ "ZRANGE", index_key, "0", "-1" });
        defer resp.deinit(self.allocator);
        const keys = try redisRequiredArrayFromResp(resp);
        var visible: usize = 0;
        var pending: usize = 0;
        var applying: usize = 0;
        var applied: usize = 0;
        for (keys) |key_value| {
            const event_key = try redisRequiredStringFromResp(key_value);
            const maybe_event = try self.feedEventFromRedisKey(allocator, event_key);
            var event = maybe_event orelse continue;
            if (event.compacted_at_ms != null or !self.feedEventVisible(event, actor_id, scopes_json)) {
                event.deinit(allocator);
                continue;
            }
            visible = runtimeCountIncrement(visible);
            if (std.mem.eql(u8, event.status, "pending")) {
                pending = runtimeCountIncrement(pending);
            } else if (std.mem.eql(u8, event.status, "applying")) {
                applying = runtimeCountIncrement(applying);
            } else if (std.mem.eql(u8, event.status, "applied")) {
                applied = runtimeCountIncrement(applied);
            }
            event.deinit(allocator);
        }
        const instance_id = try self.feedInstanceId(allocator);
        errdefer allocator.free(instance_id);
        const next_local_origin_sequence = runtimeNextLocalOriginSequenceFromFrontier(try self.originFrontier(instance_id), max_event_id);
        return .{
            .instance_id = instance_id,
            .storage_kind = try allocator.dupe(u8, "redis"),
            .supports_compaction = true,
            .cursor_floor = floor,
            .compacted_through_sequence = floor,
            .oldest_available_sequence = runtimeFeedSequenceAfter(floor),
            .max_event_id = max_event_id,
            .last_sequence = max_event_id,
            .next_local_origin_sequence = next_local_origin_sequence,
            .visible_events = visible,
            .pending_events = pending,
            .applying_events = applying,
            .applied_events = applied,
        };
    }

    pub fn compactFeedByInput(self: *RedisAgentMemory, allocator: std.mem.Allocator, input: CompactFeedInput) !FeedCompactResult {
        return self.compactFeed(allocator, input.actor_id, input.scopes_json, input.before_id);
    }

    fn compactFeed(self: *RedisAgentMemory, allocator: std.mem.Allocator, actor_id: ?[]const u8, scopes_json: []const u8, before_id: ?i64) !FeedCompactResult {
        _ = actor_id;
        _ = scopes_json;
        const before = before_id orelse try self.lastFeedEventId();
        const index_key = try self.feedIndexKey(allocator);
        defer allocator.free(index_key);
        const before_text = try std.fmt.allocPrint(allocator, "{d}", .{before});
        defer allocator.free(before_text);
        var resp = try self.client.command(&.{ "ZRANGEBYSCORE", index_key, "-inf", before_text });
        defer resp.deinit(self.allocator);
        const keys = try redisRequiredArrayFromResp(resp);
        const floor_key = try self.feedCursorFloorKey(allocator);
        defer allocator.free(floor_key);
        var floor_resp = try self.client.command(&.{ "GET", floor_key });
        defer floor_resp.deinit(self.allocator);
        const current_floor = try redisStoredNonNegativeI64OrDefault(floor_resp, 0);
        const next_floor = @max(current_floor, before);
        const floor_text = try std.fmt.allocPrint(allocator, "{d}", .{next_floor});
        defer allocator.free(floor_text);

        try self.beginTransaction();
        var committed = false;
        defer if (!committed) self.discardTransaction();
        var compacted: usize = 0;
        for (keys) |key_value| {
            const event_key = try redisRequiredStringFromResp(key_value);
            try self.queueCommand(&.{ "DEL", event_key });
            try self.queueCommand(&.{ "ZREM", index_key, event_key });
            compacted += 1;
        }
        try self.queueCommand(&.{ "SET", floor_key, floor_text });
        var exec = try self.execTransaction();
        exec.deinit(self.allocator);
        committed = true;
        const max_event_id = try self.lastFeedEventId();
        return .{
            .cursor_floor = next_floor,
            .compacted_through_sequence = next_floor,
            .max_event_id = max_event_id,
            .compacted_events = compacted,
        };
    }

    pub fn exportFeedCheckpointByInput(self: *RedisAgentMemory, allocator: std.mem.Allocator, input: ExportFeedCheckpointInput) ![]u8 {
        return self.exportFeedCheckpoint(allocator, input.since_id, input.limit, input.actor_id, input.scopes_json);
    }

    fn exportFeedCheckpoint(self: *RedisAgentMemory, allocator: std.mem.Allocator, since_id: ?i64, limit: ?usize, actor_id: ?[]const u8, scopes_json: []const u8) ![]u8 {
        const after = since_id orelse 0;
        const target_limit = @max(@as(usize, 1), @min(limit orelse 500, 1000));
        const events = try self.listFeedEvents(allocator, after, target_limit, actor_id, scopes_json);
        defer {
            for (events) |*event| event.deinit(allocator);
            allocator.free(events);
        }
        const floor = try self.feedCursorFloor();
        const max_event_id = try self.lastFeedEventId();
        const instance_id = try self.feedInstanceId(allocator);
        defer allocator.free(instance_id);
        var out: std.ArrayListUnmanaged(u8) = .empty;
        errdefer out.deinit(allocator);
        try out.appendSlice(allocator, "{\"instance_id\":");
        try json.appendString(&out, allocator, instance_id);
        try out.appendSlice(allocator, ",\"feed_object_types\":");
        try out.appendSlice(allocator, feed_object_types_json);
        try out.appendSlice(allocator, ",\"lifecycle_object_types\":");
        try out.appendSlice(allocator, lifecycle_object_types_json);
        try out.appendSlice(allocator, ",\"cursor_floor\":");
        try out.print(allocator, "{d},\"compacted_through_sequence\":{d},\"max_event_id\":{d},\"last_sequence\":{d},\"frontiers\":[", .{ floor, floor, max_event_id, max_event_id });
        try self.appendCheckpointFrontiersJson(allocator, &out);
        try out.appendSlice(allocator, "],\"events\":[");
        for (events, 0..) |event, i| {
            if (i > 0) try out.append(allocator, ',');
            try event.writeJson(allocator, &out);
        }
        try out.appendSlice(allocator, "]}");
        return out.toOwnedSlice(allocator);
    }

    pub fn restoreFeedCheckpointByInput(self: *RedisAgentMemory, allocator: std.mem.Allocator, input: RestoreFeedCheckpointInput) !void {
        return self.restoreFeedCheckpoint(allocator, input.checkpoint_json, input.actor_id, input.scopes_json);
    }

    fn restoreFeedCheckpoint(self: *RedisAgentMemory, allocator: std.mem.Allocator, checkpoint_json: []const u8, actor_id: ?[]const u8, scopes_json: []const u8) !void {
        var parsed = std.json.parseFromSlice(std.json.Value, allocator, checkpoint_json, .{}) catch return error.AgentMemoryStorageUnavailable;
        defer parsed.deinit();
        if (parsed.value != .object) return error.AgentMemoryStorageUnavailable;
        const events_value = runtimeCheckpointEventsValue(parsed.value.object) orelse return error.AgentMemoryStorageUnavailable;
        if (events_value != .array) return error.AgentMemoryStorageUnavailable;
        try validateRuntimeCheckpointShape(allocator, parsed.value.object, actor_id, scopes_json);
        for (events_value.array.items) |item| {
            if (item != .object) return error.AgentMemoryStorageUnavailable;
            try self.applyFeedEventObject(allocator, item.object, actor_id, scopes_json);
        }
        try self.restoreCheckpointFrontiers(allocator, parsed.value.object);
        const floor = try runtimeCheckpointCompactedThrough(parsed.value.object);
        if (floor > 0) {
            try self.setFeedCursorFloor(floor);
            try self.setFeedSequenceAtLeast(floor);
        }
    }

    pub fn applyFeedEventByInput(self: *RedisAgentMemory, allocator: std.mem.Allocator, input: ApplyFeedEventInput) !void {
        return self.applyFeedEventJson(allocator, input.event_json, input.actor_id, input.scopes_json);
    }

    fn applyFeedEventJson(self: *RedisAgentMemory, allocator: std.mem.Allocator, event_json: []const u8, actor_id: ?[]const u8, scopes_json: []const u8) !void {
        var parsed = std.json.parseFromSlice(std.json.Value, allocator, event_json, .{}) catch return error.AgentMemoryStorageUnavailable;
        defer parsed.deinit();
        if (parsed.value != .object) return error.AgentMemoryStorageUnavailable;
        if (runtimeCheckpointEventsValue(parsed.value.object) != null) return self.restoreFeedCheckpoint(allocator, event_json, actor_id, scopes_json);
        return self.applyFeedEventObject(allocator, parsed.value.object, actor_id, scopes_json);
    }

    fn lastFeedEventId(self: *RedisAgentMemory) !i64 {
        const key = try self.feedSequenceKey(self.allocator);
        defer self.allocator.free(key);
