    fn setFeedCursorFloor(self: *RedisAgentMemory, value: i64) !void {
        const key = try self.feedCursorFloorKey(self.allocator);
        defer self.allocator.free(key);
        var existing_resp = try self.client.command(&.{ "GET", key });
        defer existing_resp.deinit(self.allocator);
        const current = try redisStoredNonNegativeI64OrDefault(existing_resp, 0);
        if (value <= current) return;
        const text = try std.fmt.allocPrint(self.allocator, "{d}", .{value});
        defer self.allocator.free(text);
        var resp = try self.client.command(&.{ "SET", key, text });
        defer resp.deinit(self.allocator);
        try expectRedisSimple(resp, "OK");
    }

