    fn feedEventFromRedisKey(self: *RedisAgentMemory, allocator: std.mem.Allocator, event_key: []const u8) !?FeedEvent {
        var resp = try self.client.command(&.{ "GET", event_key });
        defer resp.deinit(self.allocator);
        const body = (try redisOptionalStringFromResp(resp)) orelse return null;
        var parsed = std.json.parseFromSlice(std.json.Value, allocator, body, .{}) catch return error.AgentMemoryStorageUnavailable;
        defer parsed.deinit();
        if (parsed.value != .object) return error.AgentMemoryStorageUnavailable;
        return try parseFeedEventValue(allocator, parsed.value.object);
    }

    fn appendLocalFeedEvent(
        self: *RedisAgentMemory,
        event_type: []const u8,
        operation: []const u8,
        object_type: []const u8,
        object_id: []const u8,
        scope: []const u8,
        permissions_json: []const u8,
        actor_id: ?[]const u8,
        payload_json: []const u8,
        event_order: ?EventOrder,
    ) !void {
        const origin_key = if (event_order) |order| try self.feedOriginKey(self.allocator, order.origin_instance_id, order.origin_sequence, event_type, object_type, object_id) else null;
        defer if (origin_key) |key| self.allocator.free(key);
        var origin_reserved = false;
        if (origin_key) |key| {
            var reserved = try self.client.command(&.{ "SETNX", key, "pending" });
            defer reserved.deinit(self.allocator);
            const inserted = switch (reserved) {
                .integer => |value| value == 1,
                else => return error.UnexpectedRedisResponse,
            };
            if (!inserted) return;
            origin_reserved = true;
        }
        errdefer if (origin_reserved) if (origin_key) |key| {
            var cleanup = self.client.command(&.{ "DEL", key }) catch null;
            if (cleanup) |*resp| resp.deinit(self.allocator);
        };

        const seq_key = try self.feedSequenceKey(self.allocator);
        defer self.allocator.free(seq_key);
        var seq_resp = try self.client.command(&.{ "INCR", seq_key });
        defer seq_resp.deinit(self.allocator);
        const id = switch (seq_resp) {
            .integer => |value| value,
            else => return error.UnexpectedRedisResponse,
        };
        const created_at_ms = if (event_order) |order| order.timestamp_ms else ids.nowMs();
        const local_origin_instance_id = if (event_order == null) try self.feedInstanceId(self.allocator) else null;
        var event = FeedEvent{
            .id = id,
            .sequence = id,
            .event_type = try self.allocator.dupe(u8, event_type),
            .origin_instance_id = if (event_order) |order| try self.allocator.dupe(u8, order.origin_instance_id) else local_origin_instance_id.?,
            .origin_sequence = if (event_order) |order| order.origin_sequence else id,
            .operation = try self.allocator.dupe(u8, operation),
            .object_type = try self.allocator.dupe(u8, object_type),
            .object_id = try self.allocator.dupe(u8, object_id),
            .scope = try self.allocator.dupe(u8, scope),
            .permissions_json = try self.allocator.dupe(u8, permissions_json),
            .actor_id = if (actor_id) |actor| try self.allocator.dupe(u8, actor) else null,
            .dedupe_key = null,
            .causality_json = try self.allocator.dupe(u8, "{}"),
            .payload_json = try self.allocator.dupe(u8, payload_json),
            .status = try self.allocator.dupe(u8, "applied"),
            .created_at_ms = created_at_ms,
            .applied_at_ms = created_at_ms,
            .compacted_at_ms = null,
        };
        defer event.deinit(self.allocator);
        var event_json: std.ArrayListUnmanaged(u8) = .empty;
        defer event_json.deinit(self.allocator);
        try event.writeJson(self.allocator, &event_json);
        const event_body = try event_json.toOwnedSlice(self.allocator);
        defer self.allocator.free(event_body);
        const event_key = try self.feedEventKey(self.allocator, id);
        defer self.allocator.free(event_key);
        const index_key = try self.feedIndexKey(self.allocator);
        defer self.allocator.free(index_key);
        const id_text = try std.fmt.allocPrint(self.allocator, "{d}", .{id});
        defer self.allocator.free(id_text);

        try self.beginTransaction();
        var committed = false;
        defer if (!committed) self.discardTransaction();
        try self.queueCommand(&.{ "SET", event_key, event_body });
        try self.queueCommand(&.{ "ZADD", index_key, id_text, event_key });
        if (origin_key) |key| try self.queueCommand(&.{ "SET", key, id_text });
        var exec = try self.execTransaction();
        exec.deinit(self.allocator);
        committed = true;
        try self.advanceOriginFrontier(event.origin_instance_id, event.origin_sequence);
    }

    fn appendAgentMemoryFeedEvent(self: *RedisAgentMemory, entry: domain.AgentMemory, operation: domain.AgentMemoryOperation, operation_content: []const u8, event_order: ?EventOrder) !void {
        const payload = try feed_contract.agentMemoryWrite(self.allocator, "redis", entry, operation, operation_content);
        defer self.allocator.free(payload);
        const event_type = switch (operation) {
            .put => "agent_memory.put",
            .merge_object => "agent_memory.merge_object",
            .merge_string_set => "agent_memory.merge_string_set",
        };
        try self.appendLocalFeedEvent(
            event_type,
            operation.name(),
            "agent_memory",
            entry.id,
            entry.scope,
            entry.permissions_json,
            if (entry.writer_actor_id.len > 0) entry.writer_actor_id else entry.actor_id,
            payload,
            event_order,
        );
    }

    fn appendAgentMemoryDeleteFeedEvent(self: *RedisAgentMemory, key: []const u8, session_id: ?[]const u8, owner_actor_id: []const u8, writer_actor_id: []const u8, scope: []const u8, permissions_json: []const u8, operation: []const u8, event_order: ?EventOrder) !void {
        const payload = try feed_contract.agentMemoryDelete(self.allocator, "redis", key, session_id, owner_actor_id, scope, permissions_json);
        defer self.allocator.free(payload);
        const event_type = if (std.mem.eql(u8, operation, "delete_all")) "agent_memory.delete_all" else "agent_memory.delete";
        try self.appendLocalFeedEvent(event_type, operation, "agent_memory", key, scope, permissions_json, writer_actor_id, payload, event_order);
    }

