    fn applyFeedEventObject(self: *RedisAgentMemory, allocator: std.mem.Allocator, obj: std.json.ObjectMap, actor_id: ?[]const u8, scopes_json: []const u8) !void {
        var event = try parseLooseFeedEventValue(allocator, obj, actor_id);
        defer event.deinit(allocator);
        if (!self.feedEventVisible(event, actor_id, scopes_json)) return error.Forbidden;
        if (try self.originAlreadyApplied(event.origin_instance_id, event.origin_sequence)) return;
        if (try self.feedEventOriginExists(event.origin_instance_id, event.origin_sequence, event.event_type, event.object_type, event.object_id)) {
            try self.advanceOriginFrontier(event.origin_instance_id, event.origin_sequence);
            return;
        }
        const suppress_feed = json.boolField(obj, "suppress_feed") orelse false;
        const order = EventOrder{
            .timestamp_ms = event.created_at_ms,
            .origin_instance_id = event.origin_instance_id,
            .origin_sequence = event.origin_sequence,
        };
        if (std.mem.eql(u8, event.object_type, "agent_memory")) {
            try self.applyAgentMemoryFeedEvent(allocator, event, order, actor_id, suppress_feed);
        } else if (std.mem.eql(u8, event.object_type, "agent_session_message")) {
            try self.applySessionMessageFeedEvent(allocator, event, order, actor_id, suppress_feed);
        } else if (std.mem.eql(u8, event.object_type, "agent_session_usage")) {
            try self.applySessionUsageFeedEvent(allocator, event, order, actor_id, suppress_feed);
        } else {
            return error.NotSupported;
        }
        try self.advanceOriginFrontier(event.origin_instance_id, event.origin_sequence);
    }

    fn applyAgentMemoryFeedEvent(self: *RedisAgentMemory, allocator: std.mem.Allocator, event: FeedEvent, order: EventOrder, fallback_actor_id: ?[]const u8, suppress_feed: bool) !void {
        var payload = try std.json.parseFromSlice(std.json.Value, allocator, event.payload_json, .{});
        defer payload.deinit();
        if (payload.value != .object) return error.AgentMemoryStorageUnavailable;
        const obj = payload.value.object;
        const key = jsonStringishField(obj, &.{"key"}) orelse event.object_id;
        const session_id = access.normalizeSessionId(jsonStringishField(obj, &.{ "session_id", "session" }));
        const owner_actor = jsonStringishField(obj, &.{ "owner_id", "actor_id" }) orelse event.actor_id orelse fallback_actor_id orelse return error.MissingActorId;
        if (feed_contract.isDeleteAllOperation(event.operation)) {
            _ = try self.deleteByInput(.{
                .key = key,
                .actor_id = owner_actor,
                .writer_actor_id = event.actor_id orelse owner_actor,
                .event_order = order,
                .all_owners = true,
                .suppress_feed = suppress_feed,
            });
            return;
        }
        if (feed_contract.isDeleteOperation(event.operation) or feed_contract.isDeleteScopedOperation(event.operation)) {
            _ = try self.deleteByInput(.{
                .key = key,
                .session_id = session_id,
                .actor_id = owner_actor,
                .writer_actor_id = event.actor_id orelse owner_actor,
                .event_order = order,
                .suppress_feed = suppress_feed,
            });
            return;
        }
        if (feed_contract.isLifecycleOperation(event.operation)) {
            const status = feed_contract.statusFromLifecycleOperation(event.operation, obj);
            _ = try self.patchStatusInternal(key, session_id, owner_actor, event.actor_id orelse owner_actor, status, !suppress_feed, order);
            return;
        }
        const memory_operation = domain.AgentMemoryOperation.parse(event.operation);
        const content = try runtimeAgentMemoryOperationContent(allocator, obj, memory_operation);
        defer allocator.free(content);
        const permissions_json = try jsonRawArrayField(allocator, obj, &.{ "permissions", "permissions_json" }, "[]");
        defer allocator.free(permissions_json);
        var entry = try self.store(allocator, .{
            .key = key,
            .content = content,
            .category = jsonStringishField(obj, &.{"category"}) orelse "core",
            .session_id = session_id,
            .scope = jsonStringishField(obj, &.{"scope"}),
            .permissions_json = permissions_json,
            .actor_id = owner_actor,
            .writer_actor_id = event.actor_id orelse owner_actor,
            .operation = memory_operation,
            .suppress_feed = suppress_feed,
            .event_order = order,
        });
        defer freeAgentMemory(allocator, &entry);
    }

    fn applySessionMessageFeedEvent(self: *RedisAgentMemory, allocator: std.mem.Allocator, event: FeedEvent, order: EventOrder, fallback_actor_id: ?[]const u8, suppress_feed: bool) !void {
        var payload = try std.json.parseFromSlice(std.json.Value, allocator, event.payload_json, .{});
        defer payload.deinit();
        if (payload.value != .object) return error.AgentMemoryStorageUnavailable;
        const obj = payload.value.object;
        const actor = jsonStringishField(obj, &.{"actor_id"}) orelse event.actor_id orelse fallback_actor_id orelse return error.MissingActorId;
        if (std.mem.eql(u8, event.operation, "delete_autosaved")) {
            try self.clearAutoSavedByInput(.{
                .session_id = try optionalJsonNullableStringField(obj, "session_id"),
                .actor_id = actor,
                .suppress_feed = suppress_feed,
            });
            return;
        }
        const session_id = try requiredJsonStringField(obj, "session_id");
        if (feed_contract.isAgentSessionDeleteOperation(event.operation)) {
            try self.clearMessagesByInput(.{
                .session_id = session_id,
                .actor_id = actor,
                .event_order = order,
                .suppress_feed = suppress_feed,
            });
            return;
        }
        const message = try runtimeSessionMessagePayload(obj, event, fallback_actor_id);
        try self.saveMessageByInput(.{
            .session_id = message.session_id,
            .role = message.role,
            .content = message.content,
            .created_at_ms = message.created_at_ms,
            .actor_id = message.actor_id,
            .event_order = order,
            .suppress_feed = suppress_feed,
        });
    }

    fn applySessionUsageFeedEvent(self: *RedisAgentMemory, allocator: std.mem.Allocator, event: FeedEvent, order: EventOrder, fallback_actor_id: ?[]const u8, suppress_feed: bool) !void {
        var payload = try std.json.parseFromSlice(std.json.Value, allocator, event.payload_json, .{});
        defer payload.deinit();
        if (payload.value != .object) return error.AgentMemoryStorageUnavailable;
        const obj = payload.value.object;
        const actor = jsonStringishField(obj, &.{"actor_id"}) orelse event.actor_id orelse fallback_actor_id orelse return error.MissingActorId;
        const session_id = try requiredJsonStringField(obj, "session_id");
        if (feed_contract.isAgentSessionDeleteOperation(event.operation)) {
            _ = try self.deleteUsageByInput(.{
                .session_id = session_id,
                .actor_id = actor,
                .event_order = order,
                .suppress_feed = suppress_feed,
            });
            return;
        }
        const usage = try runtimeSessionUsagePayload(obj, event, fallback_actor_id);
        try self.saveUsageByInput(.{
            .session_id = usage.session_id,
            .total_tokens = usage.total_tokens,
            .actor_id = usage.actor_id,
            .event_order = order,
            .suppress_feed = suppress_feed,
        });
    }

    fn feedEventOriginExists(self: *RedisAgentMemory, origin_instance_id: []const u8, origin_sequence: i64, event_type: []const u8, object_type: []const u8, object_id: []const u8) !bool {
        if (origin_instance_id.len == 0 or origin_sequence <= 0) return false;
        const key = try self.feedOriginKey(self.allocator, origin_instance_id, origin_sequence, event_type, object_type, object_id);
        defer self.allocator.free(key);
        var resp = try self.client.command(&.{ "GET", key });
        defer resp.deinit(self.allocator);
        return redisOptionalStringExistsFromResp(resp);
    }

    fn feedIndexKey(self: *RedisAgentMemory, allocator: std.mem.Allocator) ![]u8 {
        return std.fmt.allocPrint(allocator, "{s}:agent-memory:feed:index", .{self.prefix});
    }

    fn feedInstanceId(self: *RedisAgentMemory, allocator: std.mem.Allocator) ![]u8 {
        return std.fmt.allocPrint(allocator, "redis:{s}", .{self.prefix});
    }

    fn feedSequenceKey(self: *RedisAgentMemory, allocator: std.mem.Allocator) ![]u8 {
        return std.fmt.allocPrint(allocator, "{s}:agent-memory:feed:seq", .{self.prefix});
    }

    fn feedCursorFloorKey(self: *RedisAgentMemory, allocator: std.mem.Allocator) ![]u8 {
        return std.fmt.allocPrint(allocator, "{s}:agent-memory:feed:cursor_floor", .{self.prefix});
    }

    fn feedFrontiersKey(self: *RedisAgentMemory, allocator: std.mem.Allocator) ![]u8 {
        return std.fmt.allocPrint(allocator, "{s}:agent-memory:feed:frontiers", .{self.prefix});
    }

    fn feedEventKey(self: *RedisAgentMemory, allocator: std.mem.Allocator, id: i64) ![]u8 {
        return std.fmt.allocPrint(allocator, "{s}:agent-memory:feed:event:{d}", .{ self.prefix, id });
    }

    fn originFrontier(self: *RedisAgentMemory, origin_instance_id: []const u8) !i64 {
        const key = try self.feedFrontiersKey(self.allocator);
        defer self.allocator.free(key);
        var resp = try self.client.command(&.{ "HGET", key, origin_instance_id });
        defer resp.deinit(self.allocator);
        return redisStoredNonNegativeI64OrDefault(resp, 0);
    }

    fn originAlreadyApplied(self: *RedisAgentMemory, origin_instance_id: []const u8, origin_sequence: i64) !bool {
        return origin_sequence > 0 and origin_sequence <= try self.originFrontier(origin_instance_id);
    }

    fn advanceOriginFrontier(self: *RedisAgentMemory, origin_instance_id: []const u8, origin_sequence: i64) !void {
        if (origin_instance_id.len == 0 or origin_sequence <= 0) return;
        const current = try self.originFrontier(origin_instance_id);
        if (origin_sequence <= current) return;
        const key = try self.feedFrontiersKey(self.allocator);
        defer self.allocator.free(key);
        const sequence_text = try std.fmt.allocPrint(self.allocator, "{d}", .{origin_sequence});
        defer self.allocator.free(sequence_text);
        var resp = try self.client.command(&.{ "HSET", key, origin_instance_id, sequence_text });
        defer resp.deinit(self.allocator);
        switch (resp) {
            .integer => {},
            else => return error.UnexpectedRedisResponse,
        }
        try self.expireKey(key);
    }

    fn appendCheckpointFrontiersJson(self: *RedisAgentMemory, allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8)) !void {
        const key = try self.feedFrontiersKey(allocator);
        defer allocator.free(key);
        var resp = try self.client.command(&.{ "HGETALL", key });
        defer resp.deinit(self.allocator);
        try appendRedisCheckpointFrontiersJson(allocator, out, resp);
    }

    fn restoreCheckpointFrontiers(self: *RedisAgentMemory, allocator: std.mem.Allocator, obj: std.json.ObjectMap) !void {
        const frontiers = runtimeCheckpointFrontiersValue(obj) orelse return;
        if (frontiers != .array) return error.AgentMemoryStorageUnavailable;
        const instance_id = try self.feedInstanceId(allocator);
        defer allocator.free(instance_id);
        for (frontiers.array.items) |frontier_value| {
            if (frontier_value != .object) return error.AgentMemoryStorageUnavailable;
            const frontier = try runtimeCheckpointFrontierFields(frontier_value.object);
            try self.advanceOriginFrontier(frontier.origin_instance_id, frontier.origin_sequence);
            if (std.mem.eql(u8, frontier.origin_instance_id, instance_id)) try self.setFeedSequenceAtLeast(frontier.origin_sequence);
        }
    }

    fn feedOriginKey(self: *RedisAgentMemory, allocator: std.mem.Allocator, origin_instance_id: []const u8, origin_sequence: i64, event_type: []const u8, object_type: []const u8, object_id: []const u8) ![]u8 {
        var hasher = std.hash.Wyhash.init(0);
        hasher.update(origin_instance_id);
        hasher.update("\x00");
        var sequence_buf: [32]u8 = undefined;
        const sequence_text = try std.fmt.bufPrint(&sequence_buf, "{d}", .{origin_sequence});
        hasher.update(sequence_text);
        hasher.update("\x00");
        hasher.update(event_type);
        hasher.update("\x00");
        hasher.update(object_type);
        hasher.update("\x00");
        hasher.update(object_id);
        return std.fmt.allocPrint(allocator, "{s}:agent-memory:feed:origin:{x}", .{ self.prefix, hasher.final() });
    }

    fn beginTransaction(self: *RedisAgentMemory) !void {
        var resp = try self.client.command(&.{"MULTI"});
        defer resp.deinit(self.allocator);
        try expectRedisSimple(resp, "OK");
    }

    fn queueCommand(self: *RedisAgentMemory, args: []const []const u8) !void {
        var resp = try self.client.command(args);
        defer resp.deinit(self.allocator);
        try expectRedisSimple(resp, "QUEUED");
    }

    fn queueRedisVariadic(self: *RedisAgentMemory, command: []const u8, key: []const u8, values: []const []u8) !void {
        if (values.len == 0) return;
        const arg_count = try redisCommandArgCount(values.len);
        var args = try self.allocator.alloc([]const u8, arg_count);
        defer self.allocator.free(args);
        args[0] = command;
        args[1] = key;
        for (values, 0..) |value, i| args[redis_command_header_args + i] = value;
        try self.queueCommand(args);
    }

    fn execTransaction(self: *RedisAgentMemory) !redis.RespValue {
        var resp = try self.client.command(&.{"EXEC"});
        errdefer resp.deinit(self.allocator);
        switch (resp) {
            .array => |maybe_items| {
                if (maybe_items) |items| {
                    for (items) |item| {
                        if (item == .err) return error.RedisTransactionFailed;
                    }
                }
                return resp;
            },
            .err => return error.RedisTransactionFailed,
            else => return error.UnexpectedRedisResponse,
        }
    }

    fn discardTransaction(self: *RedisAgentMemory) void {
        var resp = self.client.command(&.{"DISCARD"}) catch return;
        resp.deinit(self.allocator);
    }

    fn queueExpireKey(self: *RedisAgentMemory, key: []const u8) !void {
        const ttl = self.ttl_seconds orelse return;
        if (ttl == 0) return;
        var ttl_buf: [16]u8 = undefined;
        const ttl_text = try std.fmt.bufPrint(&ttl_buf, "{d}", .{ttl});
        try self.queueCommand(&.{ "EXPIRE", key, ttl_text });
    }

    fn expireKey(self: *RedisAgentMemory, key: []const u8) !void {
        const ttl = self.ttl_seconds orelse return;
        if (ttl == 0) return;
        var ttl_buf: [16]u8 = undefined;
        const ttl_text = try std.fmt.bufPrint(&ttl_buf, "{d}", .{ttl});
        var resp = try self.client.command(&.{ "EXPIRE", key, ttl_text });
        defer resp.deinit(self.allocator);
    }

    fn tombstoneBlocksPut(self: *RedisAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, owner_actor: []const u8, event_order: EventOrder) !bool {
        const scoped_key = try self.tombstoneKey(allocator, owner_actor, key, .scoped, tombstoneSessionKey(session_id));
        defer allocator.free(scoped_key);
        if (try self.tombstoneKeyBlocksPut(scoped_key, event_order)) return true;
        const all_key = try self.tombstoneKey(allocator, owner_actor, key, .all, "*");
        defer allocator.free(all_key);
        return self.tombstoneKeyBlocksPut(all_key, event_order);
    }

    fn tombstoneKeyBlocksPut(self: *RedisAgentMemory, redis_key: []const u8, event_order: EventOrder) !bool {
        var hash = try self.client.command(&.{ "HGETALL", redis_key });
        defer hash.deinit(self.allocator);
        const stored_order = (try redisEventOrderFromHash(hash)) orelse return false;
        return compareEventOrder(event_order, stored_order.timestamp_ms, stored_order.origin_instance_id, stored_order.origin_sequence) <= 0;
    }

    fn upsertTombstone(self: *RedisAgentMemory, key: []const u8, owner_actor: []const u8, scope: MemoryTombstoneScope, session_id: ?[]const u8, event_order: EventOrder) !void {
        const session_key = if (scope == .all) "*" else tombstoneSessionKey(session_id);
        const redis_key = try self.tombstoneKey(self.allocator, owner_actor, key, scope, session_key);
        defer self.allocator.free(redis_key);
        if (try self.tombstoneKeyBlocksPut(redis_key, event_order)) return;
        const timestamp_text = try std.fmt.allocPrint(self.allocator, "{d}", .{event_order.timestamp_ms});
        defer self.allocator.free(timestamp_text);
        const sequence_text = try std.fmt.allocPrint(self.allocator, "{d}", .{event_order.origin_sequence});
        defer self.allocator.free(sequence_text);
        var resp = try self.client.command(&.{
            "HSET",               redis_key,
            "key",                key,
            "actor_id",           owner_actor,
            "scope",              if (scope == .all) "all" else "scoped",
            "session_key",        session_key,
            "session_id",         session_id orelse "",
            "event_timestamp_ms", timestamp_text,
            "origin_instance_id", event_order.origin_instance_id,
            "origin_sequence",    sequence_text,
        });
        defer resp.deinit(self.allocator);
        try self.expireKey(redis_key);
    }

    fn usageTombstoneBlocksPut(self: *RedisAgentMemory, actor: []const u8, session_id: []const u8, event_order: EventOrder) !bool {
        const redis_key = try self.usageTombstoneKey(self.allocator, actor, session_id);
