    fn queueRemoveEntryIndexes(self: *RedisAgentMemory, entry_key: []const u8, entry: domain.AgentMemory) !void {
        const global = try self.globalIndexKey(self.allocator);
        defer self.allocator.free(global);
        const owner = try self.ownerIndexKey(self.allocator, entry.actor_id);
        defer self.allocator.free(owner);
        const cat = try self.categoryIndexKey(self.allocator, entry.category);
        defer self.allocator.free(cat);
        const key_index = try self.keyIndexKey(self.allocator, entry.key);
        defer self.allocator.free(key_index);
        const owner_key_index = try self.ownerKeyIndexKey(self.allocator, entry.actor_id, entry.key);
        defer self.allocator.free(owner_key_index);
        try self.queueCommand(&.{ "ZREM", global, entry_key });
        try self.queueCommand(&.{ "ZREM", owner, entry_key });
        try self.queueCommand(&.{ "ZREM", cat, entry_key });
        try self.queueCommand(&.{ "ZREM", key_index, entry_key });
        try self.queueCommand(&.{ "ZREM", owner_key_index, entry_key });
        if (entry.session_id) |sid| {
            const session = try self.agentSessionIndexKey(self.allocator, entry.actor_id, sid);
            defer self.allocator.free(session);
            try self.queueCommand(&.{ "ZREM", session, entry_key });
        }
    }

    fn removeEntryIndexes(self: *RedisAgentMemory, entry_key: []const u8, entry: domain.AgentMemory) !void {
        const global = try self.globalIndexKey(self.allocator);
        defer self.allocator.free(global);
        const owner = try self.ownerIndexKey(self.allocator, entry.actor_id);
        defer self.allocator.free(owner);
        const cat = try self.categoryIndexKey(self.allocator, entry.category);
        defer self.allocator.free(cat);
        const key_index = try self.keyIndexKey(self.allocator, entry.key);
        defer self.allocator.free(key_index);
        const owner_key_index = try self.ownerKeyIndexKey(self.allocator, entry.actor_id, entry.key);
        defer self.allocator.free(owner_key_index);
        try self.removeIndexMember(global, entry_key);
        try self.removeIndexMember(owner, entry_key);
        try self.removeIndexMember(cat, entry_key);
        try self.removeIndexMember(key_index, entry_key);
        try self.removeIndexMember(owner_key_index, entry_key);
        if (entry.session_id) |sid| {
            const session = try self.agentSessionIndexKey(self.allocator, entry.actor_id, sid);
            defer self.allocator.free(session);
            try self.removeIndexMember(session, entry_key);
        }
    }

    fn removeIndexMember(self: *RedisAgentMemory, index_key: []const u8, entry_key: []const u8) !void {
        var zrem = try self.client.command(&.{ "ZREM", index_key, entry_key });
        zrem.deinit(self.allocator);
    }

    fn listFromIndex(self: *RedisAgentMemory, allocator: std.mem.Allocator, index_key: []const u8, category: ?[]const u8, session_id: ?[]const u8, include_sessions: bool, actor_id: ?[]const u8, scopes_json: []const u8, visible_only: bool) ![]domain.AgentMemory {
        return self.listFromIndexWindow(allocator, index_key, category, session_id, include_sessions, actor_id, scopes_json, visible_only, std.math.maxInt(usize), 0);
    }

    fn listFromIndexWindow(self: *RedisAgentMemory, allocator: std.mem.Allocator, index_key: []const u8, category: ?[]const u8, session_id: ?[]const u8, include_sessions: bool, actor_id: ?[]const u8, scopes_json: []const u8, visible_only: bool, limit: usize, offset: usize) ![]domain.AgentMemory {
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (out.items) |*entry| freeAgentMemory(allocator, entry);
            out.deinit(allocator);
        }

        const fetch_limit = redisMemoryWindowFetchLimit(limit);
        var raw_offset: usize = 0;
        var visible_offset_seen: usize = 0;
        while (true) {
            const start_text = try std.fmt.allocPrint(allocator, "{d}", .{raw_offset});
            defer allocator.free(start_text);
            const stop_text = try std.fmt.allocPrint(allocator, "{d}", .{runtimePageStopOffset(raw_offset, fetch_limit)});
            defer allocator.free(stop_text);
            var resp = try self.client.command(&.{ "ZREVRANGE", index_key, start_text, stop_text });
            defer resp.deinit(self.allocator);
            const members = try redisRequiredStringArrayFromResp(resp);
            if (members.len == 0) break;

            for (members) |member| {
                const redis_key = try redisRequiredStringFromResp(member);
                var hash = try self.client.command(&.{ "HGETALL", redis_key });
                const maybe_entry = try self.agentMemoryFromHash(allocator, hash);
                hash.deinit(self.allocator);
                var entry = maybe_entry orelse {
                    try self.removeIndexMember(index_key, redis_key);
                    continue;
                };
                if (category) |cat| {
                    if (!std.mem.eql(u8, entry.category, cat)) {
                        freeAgentMemory(allocator, &entry);
                        continue;
                    }
                }
                if (session_id) |sid| {
                    if (entry.session_id == null or !std.mem.eql(u8, entry.session_id.?, sid)) {
                        freeAgentMemory(allocator, &entry);
                        continue;
                    }
                } else if (entry.session_id != null and !include_sessions) {
                    freeAgentMemory(allocator, &entry);
                    continue;
                }
                if (visible_only) {
                    const actor = actor_id orelse {
                        freeAgentMemory(allocator, &entry);
                        continue;
                    };
                    if (!try entryVisible(allocator, entry, actor, scopes_json)) {
                        freeAgentMemory(allocator, &entry);
                        continue;
                    }
                }
                if (visible_offset_seen < offset) {
                    visible_offset_seen += 1;
                    freeAgentMemory(allocator, &entry);
                    continue;
                }
                if (out.items.len >= limit) {
                    freeAgentMemory(allocator, &entry);
                    continue;
                }
                try out.append(allocator, entry);
            }

            if (out.items.len >= limit or members.len < fetch_limit) break;
            raw_offset = runtimePageOffsetAfterFetch(raw_offset, members.len);
        }
        return out.toOwnedSlice(allocator);
    }

    fn agentMemoryFromHash(self: *RedisAgentMemory, allocator: std.mem.Allocator, resp: redis.RespValue) !?domain.AgentMemory {
        _ = self;
        const fields = (try redisOptionalHashFieldsFromResp(resp)) orelse return null;
        const id_value = try requiredHashField(fields, "id");
        const key = try requiredHashField(fields, "key");
        const content = try requiredHashField(fields, "content");
        const category = try requiredHashField(fields, "category");
        const timestamp = try requiredHashField(fields, "timestamp");
        const session = try requiredHashField(fields, "session_id");
        const owner = try requiredHashField(fields, "actor_id");
        const writer = try requiredHashField(fields, "writer_actor_id");
        const scope = try requiredHashField(fields, "scope");
        const permissions = try requiredHashField(fields, "permissions_json");
        const status = try requiredHashField(fields, "status");
        const store_name = (try redisHashField(fields, "store")) orelse "";
        const out_id = try allocator.dupe(u8, id_value);
        errdefer allocator.free(out_id);
        const out_key = try allocator.dupe(u8, key);
        errdefer allocator.free(out_key);
        const out_content = try allocator.dupe(u8, content);
        errdefer allocator.free(out_content);
        const out_category = try allocator.dupe(u8, category);
        errdefer allocator.free(out_category);
        const out_timestamp = try allocator.dupe(u8, timestamp);
        errdefer allocator.free(out_timestamp);
        const out_session = if (session.len > 0) try allocator.dupe(u8, session) else null;
        errdefer if (out_session) |sid| allocator.free(sid);
        const out_actor = try allocator.dupe(u8, owner);
        errdefer allocator.free(out_actor);
        const out_writer = try allocator.dupe(u8, writer);
        errdefer allocator.free(out_writer);
        const out_scope = try allocator.dupe(u8, scope);
        errdefer allocator.free(out_scope);
        const out_permissions = try allocator.dupe(u8, permissions);
        errdefer allocator.free(out_permissions);
        const out_status = try allocator.dupe(u8, status);
        errdefer allocator.free(out_status);
        const out_store = try allocator.dupe(u8, store_name);
        errdefer allocator.free(out_store);
        return .{
            .id = out_id,
            .key = out_key,
            .content = out_content,
            .category = out_category,
            .timestamp = out_timestamp,
            .session_id = out_session,
            .actor_id = out_actor,
            .writer_actor_id = out_writer,
            .scope = out_scope,
            .permissions_json = out_permissions,
            .status = out_status,
            .store = out_store,
        };
    }

    fn visibleSessionInfo(self: *RedisAgentMemory, allocator: std.mem.Allocator, actor: []const u8, session_id: []const u8) !?SessionInfo {
        const meta_key = try self.sessionMetaKey(allocator, actor, session_id);
        defer allocator.free(meta_key);
        var resp = try self.client.command(&.{ "HMGET", meta_key, "message_count", "first_message_at", "last_message_at" });
        defer resp.deinit(self.allocator);
        const values = try redisRequiredArrayFromResp(resp);
        return redisSessionInfoFromMetaValues(allocator, session_id, values);
    }

    fn refreshSessionHistoryMeta(self: *RedisAgentMemory, actor: []const u8, session_id: []const u8) !void {
        const history_index_key = try self.sessionHistoryIndexKey(self.allocator, actor, session_id);
        defer self.allocator.free(history_index_key);
        const meta_key = try self.sessionMetaKey(self.allocator, actor, session_id);
        defer self.allocator.free(meta_key);
        const sessions_key = try self.sessionsIndexKey(self.allocator, actor);
        defer self.allocator.free(sessions_key);

        var count_resp = try self.client.command(&.{ "ZCARD", history_index_key });
        defer count_resp.deinit(self.allocator);
        const history_count = try redisRequiredCountFromResp(count_resp);
        if (history_count == 0) {
            try self.beginTransaction();
            var committed = false;
            defer if (!committed) self.discardTransaction();
            try self.queueCommand(&.{ "DEL", meta_key });
            try self.queueCommand(&.{ "ZREM", sessions_key, session_id });
            var exec = try self.execTransaction();
            exec.deinit(self.allocator);
            committed = true;
            return;
        }

        var first_resp = try self.client.command(&.{ "ZRANGE", history_index_key, "0", "0", "WITHSCORES" });
        defer first_resp.deinit(self.allocator);
        var last_resp = try self.client.command(&.{ "ZREVRANGE", history_index_key, "0", "0", "WITHSCORES" });
        defer last_resp.deinit(self.allocator);
        const first = try redisRequiredSingleZsetScore(first_resp);
        const last = try redisRequiredSingleZsetScore(last_resp);
        const count_text = try std.fmt.allocPrint(self.allocator, "{d}", .{history_count});
        defer self.allocator.free(count_text);
        const first_text = try std.fmt.allocPrint(self.allocator, "{d}", .{first});
        defer self.allocator.free(first_text);
        const last_text = try std.fmt.allocPrint(self.allocator, "{d}", .{last});
        defer self.allocator.free(last_text);

        try self.beginTransaction();
        var committed = false;
        defer if (!committed) self.discardTransaction();
        try self.queueCommand(&.{ "HSET", meta_key, "session_id", session_id, "message_count", count_text, "first_message_at", first_text, "last_message_at", last_text });
        try self.queueCommand(&.{ "ZADD", sessions_key, last_text, session_id });
        try self.queueExpireKey(history_index_key);
        try self.queueExpireKey(meta_key);
        try self.queueExpireKey(sessions_key);
        var exec = try self.execTransaction();
        exec.deinit(self.allocator);
        committed = true;
    }

    fn refreshSessionAutosaveIndex(self: *RedisAgentMemory, actor: []const u8, session_id: []const u8) !void {
        const autosave_index_key = try self.sessionAutosaveIndexKey(self.allocator, actor, session_id);
        defer self.allocator.free(autosave_index_key);
        const autosave_sessions_key = try self.autosaveSessionsIndexKey(self.allocator, actor);
        defer self.allocator.free(autosave_sessions_key);

        var count_resp = try self.client.command(&.{ "ZCARD", autosave_index_key });
        defer count_resp.deinit(self.allocator);
        const autosave_count = try redisRequiredCountFromResp(count_resp);
        if (autosave_count == 0) {
            try self.removeAutosaveSessionIndex(actor, session_id);
            return;
        }

        var last_resp = try self.client.command(&.{ "ZREVRANGE", autosave_index_key, "0", "0", "WITHSCORES" });
        defer last_resp.deinit(self.allocator);
        const last = try redisRequiredSingleZsetScore(last_resp);
        const last_text = try std.fmt.allocPrint(self.allocator, "{d}", .{last});
        defer self.allocator.free(last_text);

        try self.beginTransaction();
        var committed = false;
        defer if (!committed) self.discardTransaction();
        try self.queueCommand(&.{ "ZADD", autosave_sessions_key, last_text, session_id });
        try self.queueExpireKey(autosave_index_key);
        try self.queueExpireKey(autosave_sessions_key);
        var exec = try self.execTransaction();
        exec.deinit(self.allocator);
        committed = true;
    }

    fn removeAutosaveSessionIndex(self: *RedisAgentMemory, actor: []const u8, session_id: []const u8) !void {
        const autosave_sessions_key = try self.autosaveSessionsIndexKey(self.allocator, actor);
        defer self.allocator.free(autosave_sessions_key);
        var resp = try self.client.command(&.{ "ZREM", autosave_sessions_key, session_id });
        defer resp.deinit(self.allocator);
    }

    fn messagesFromRedisIds(self: *RedisAgentMemory, allocator: std.mem.Allocator, payloads_key: []const u8, ids_resp: redis.RespValue) ![]Message {
        const ids_values = try redisRequiredArrayFromResp(ids_resp);
        if (ids_values.len == 0) return allocator.alloc(Message, 0);
        const arg_count = try redisCommandArgCount(ids_values.len);
        var args = try allocator.alloc([]const u8, arg_count);
        defer allocator.free(args);
        args[0] = "HMGET";
        args[1] = payloads_key;
        for (ids_values, 0..) |value, i| {
            const message_id = try redisRequiredStringFromResp(value);
            args[redis_command_header_args + i] = message_id;
        }
        var payloads_resp = try self.client.command(args[0..arg_count]);
        defer payloads_resp.deinit(self.allocator);
        return messagesFromResp(allocator, payloads_resp);
    }

    fn globalIndexKey(self: *RedisAgentMemory, allocator: std.mem.Allocator) ![]u8 {
        return std.fmt.allocPrint(allocator, "{s}:agent-memory:index", .{self.prefix});
    }

    fn ownerIndexKey(self: *RedisAgentMemory, allocator: std.mem.Allocator, actor: []const u8) ![]u8 {
        const encoded = try hex(allocator, actor);
        defer allocator.free(encoded);
        return std.fmt.allocPrint(allocator, "{s}:agent-memory:owner:{s}", .{ self.prefix, encoded });
