    }

    fn listIndexKey(self: *RedisAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: ?[]const u8) ![]u8 {
        if (actor_id) |actor| {
            if (session_id) |sid| return self.agentSessionIndexKey(allocator, actor, sid);
            return self.ownerIndexKey(allocator, actor);
        }
        if (category) |cat| return self.categoryIndexKey(allocator, cat);
        return self.globalIndexKey(allocator);
    }

    fn visibleListIndexKey(self: *RedisAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8) ![]u8 {
        if (category) |cat| return self.categoryIndexKey(allocator, cat);
        return self.globalIndexKey(allocator);
    }

    fn redisMemoryWindowFetchLimit(limit: usize) usize {
        if (limit == 0) return 0;
        if (limit == std.math.maxInt(usize)) return 1000;
        return @min(@as(usize, 1000), @max(@as(usize, 128), limit));
    }

    fn redisVisibleKeyScanLimit() usize {
        return 5000;
    }

    fn redisDeleteAllFetchLimit() usize {
        return 128;
    }

    fn redisAutosaveSessionFetchLimit() usize {
        return 128;
    }

    fn redisSessionMessageId(self: *RedisAgentMemory, role: []const u8, content: []const u8, created_at_ms: i64, event_order: ?EventOrder, sequence_key: []const u8) ![]u8 {
        var hash_value = std.hash.Wyhash.hash(0, role);
        hash_value = std.hash.Wyhash.hash(hash_value, content);
        var created_buf: [32]u8 = undefined;
        const created_text = try std.fmt.bufPrint(&created_buf, "{d}", .{created_at_ms});
        hash_value = std.hash.Wyhash.hash(hash_value, created_text);

        const role_hex = try hex(self.allocator, role);
        defer self.allocator.free(role_hex);
        const content_hash = std.hash.Wyhash.hash(0, content);
        if (event_order) |order| {
            hash_value = std.hash.Wyhash.hash(hash_value, order.origin_instance_id);
            var event_buf: [32]u8 = undefined;
            const event_text = try std.fmt.bufPrint(&event_buf, "{d}:{d}", .{ order.timestamp_ms, order.origin_sequence });
            hash_value = std.hash.Wyhash.hash(hash_value, event_text);
            return std.fmt.allocPrint(self.allocator, "msg:{d}:{s}:{x}:{x}", .{ created_at_ms, role_hex, content_hash, hash_value });
        }

        var seq_resp = try self.client.command(&.{ "INCR", sequence_key });
        defer seq_resp.deinit(self.allocator);
        const sequence = switch (seq_resp) {
            .integer => |value| value,
            else => return error.RedisInvalidResponse,
        };
        return std.fmt.allocPrint(self.allocator, "msg:{d}:{s}:{x}:{d}", .{ created_at_ms, role_hex, content_hash, sequence });
    }

    fn entryKey(self: *RedisAgentMemory, allocator: std.mem.Allocator, actor: []const u8, session_id: ?[]const u8, key: []const u8) ![]u8 {
        const actor_hex = try hex(allocator, actor);
        defer allocator.free(actor_hex);
        const session_hex = try hex(allocator, session_id orelse "");
        defer allocator.free(session_hex);
        const key_hex = try hex(allocator, key);
        defer allocator.free(key_hex);
        return std.fmt.allocPrint(allocator, "{s}:agent-memory:item:{s}:{s}:{s}", .{ self.prefix, actor_hex, session_hex, key_hex });
    }

    fn tombstoneKey(self: *RedisAgentMemory, allocator: std.mem.Allocator, actor: []const u8, key: []const u8, scope: MemoryTombstoneScope, session_key: []const u8) ![]u8 {
        const actor_hex = try hex(allocator, actor);
        defer allocator.free(actor_hex);
        const key_hex = try hex(allocator, key);
        defer allocator.free(key_hex);
        const session_hex = try hex(allocator, session_key);
        defer allocator.free(session_hex);
        return std.fmt.allocPrint(allocator, "{s}:agent-memory:tombstone:{s}:{s}:{s}:{s}", .{
            self.prefix,
            actor_hex,
            key_hex,
            if (scope == .all) "all" else "scoped",
            session_hex,
        });
    }

    fn entryId(self: *RedisAgentMemory, allocator: std.mem.Allocator, actor: []const u8, session_id: ?[]const u8, key: []const u8) ![]u8 {
        _ = self;
        var hash_value = std.hash.Wyhash.hash(0, actor);
        hash_value = std.hash.Wyhash.hash(hash_value, session_id orelse "");
        hash_value = std.hash.Wyhash.hash(hash_value, key);
        return std.fmt.allocPrint(allocator, "agm_{x}", .{hash_value});
    }

