const ClickHouseMemoryState = struct {
    entry: domain.AgentMemory,
    event_order: EventOrder,
};

const ClickHouseMessageState = struct {
    message: Message,
    actor_id: []u8,
    session_id: []u8,
    message_id: []u8,
    event_order: EventOrder,
};

const ClickHouseUsageState = struct {
    actor_id: []u8,
    session_id: []u8,
    total_tokens: u64,
    updated_at_ms: i64,
    event_order: EventOrder,
};

pub const ClickHouseAgentMemory = struct {
    allocator: std.mem.Allocator,
    config: ClickHouseConfig,
    table: []u8,
    messages_table: []u8,
    usage_table: []u8,
    tombstones_table: []u8,
    events_table: []u8,
    frontiers_table: []u8,
    feed_meta_table: []u8,

    pub fn init(allocator: std.mem.Allocator, config: ClickHouseConfig) !ClickHouseAgentMemory {
        if (!config.enabled()) return error.MissingClickHouseAgentMemoryUrl;
        try net_security.validateHttpBaseUrl(config.base_url.?, config.allow_insecure_http);
        const table = try clickhouseSafeIdentifier(allocator, config.table);
        errdefer allocator.free(table);
        const messages_table = try clickhouseTableWithSuffix(allocator, table, "_messages");
        errdefer allocator.free(messages_table);
        const usage_table = try clickhouseTableWithSuffix(allocator, table, "_usage");
        errdefer allocator.free(usage_table);
        const tombstones_table = try clickhouseTableWithSuffix(allocator, table, "_tombstones");
        errdefer allocator.free(tombstones_table);
        const events_table = try clickhouseTableWithSuffix(allocator, table, "_events");
        errdefer allocator.free(events_table);
        const frontiers_table = try clickhouseTableWithSuffix(allocator, table, "_frontiers");
        errdefer allocator.free(frontiers_table);
        const feed_meta_table = try clickhouseTableWithSuffix(allocator, table, "_feed_meta");
        errdefer allocator.free(feed_meta_table);
        var self = ClickHouseAgentMemory{
            .allocator = allocator,
            .config = config,
            .table = table,
            .messages_table = messages_table,
            .usage_table = usage_table,
            .tombstones_table = tombstones_table,
            .events_table = events_table,
            .frontiers_table = frontiers_table,
            .feed_meta_table = feed_meta_table,
        };
        errdefer self.deinit();
        try self.ensureSchema();
        return self;
    }

    pub fn deinit(self: *ClickHouseAgentMemory) void {
        self.allocator.free(self.table);
        self.allocator.free(self.messages_table);
        self.allocator.free(self.usage_table);
        self.allocator.free(self.tombstones_table);
        self.allocator.free(self.events_table);
        self.allocator.free(self.frontiers_table);
        self.allocator.free(self.feed_meta_table);
    }

    pub fn store(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, input: Input) !domain.AgentMemory {
        const request_actor = try access.requiredActorId(input.actor_id);
        const owner_actor = try access.agentMemoryOwner(allocator, request_actor, input.scope);
        defer allocator.free(owner_actor);
        const writer_actor = input.writer_actor_id orelse request_actor;
        const scope = try access.agentMemoryScope(allocator, owner_actor, input.session_id, input.scope);
        defer allocator.free(scope);
        const permissions = try access.agentMemoryPermissions(allocator, owner_actor, input.scope, input.permissions_json);
        defer allocator.free(permissions);
        if (input.event_order) |order| {
            if (try self.tombstoneBlocksPut(allocator, "agent_memory", input.key, input.session_id, owner_actor, order)) {
                if (try self.get(allocator, input.key, input.session_id, owner_actor)) |existing| return existing;
                return ignoredAgentMemory(allocator, input, owner_actor, writer_actor);
            }
        }
        var existing_state = try self.getMemoryState(allocator, input.key, input.session_id, owner_actor);
        defer if (existing_state) |*state| freeClickHouseMemoryState(allocator, state);
        if (input.event_order) |order| {
            if (existing_state) |state| {
                if (compareEventOrder(order, state.event_order.timestamp_ms, state.event_order.origin_instance_id, state.event_order.origin_sequence) <= 0) {
                    const result = try cloneAgentMemory(allocator, state.entry);
                    return result;
                }
            }
        }
        const reduced_content = try agent_memory_reducer.reduceContent(allocator, input.operation, if (existing_state) |state| state.entry.content else null, input.content);
        defer allocator.free(reduced_content);
        const status = if (existing_state) |state| state.entry.status else domain.defaultMemoryStatus("agent", scope);
        const entry_id = try memoryEntryId(allocator, owner_actor, input.session_id, input.key);
        defer allocator.free(entry_id);
        try self.insertMemoryRow(.{
            .id = entry_id,
            .key = input.key,
            .content = reduced_content,
            .category = input.category,
            .session_id = input.session_id,
            .actor_id = owner_actor,
            .writer_actor_id = writer_actor,
            .scope = scope,
            .permissions_json = permissions,
            .status = status,
            .timestamp_ms = eventTimestampMs(input),
            .event_order = input.event_order,
            .deleted = false,
        });
        const result = (try self.get(allocator, input.key, input.session_id, owner_actor)) orelse return error.AgentMemoryStorageUnavailable;
        errdefer {
            var cleanup = result;
            freeAgentMemory(allocator, &cleanup);
        }
        if (!input.suppress_feed and !domain.isInternalMemoryEntryKeyOrContent(result.key, result.content)) {
            try self.appendAgentMemoryFeedEvent(result, input.operation, input.content, input.event_order);
        }
        return result;
    }

    pub fn getByInput(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, input: GetInput) !?domain.AgentMemory {
        const normalized_session_id = access.normalizeSessionId(input.session_id);
        if (input.scopes_json) |scopes_json| {
            const actor_id = input.actor_id orelse return error.InvalidAgentMemoryRuntimeRequest;
            if (input.any_session) return self.getAnyVisible(allocator, input.key, actor_id, scopes_json);
            return self.getVisible(allocator, input.key, normalized_session_id, actor_id, scopes_json);
        }
        return self.get(allocator, input.key, normalized_session_id, input.actor_id);
    }

    fn get(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8) !?domain.AgentMemory {
        var state = try self.getMemoryState(allocator, key, session_id, actor_id orelse return null);
        if (state == null) return null;
        const result = try cloneAgentMemory(allocator, state.?.entry);
        freeClickHouseMemoryState(allocator, &state.?);
        return result;
    }

    fn getVisible(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8) !?domain.AgentMemory {
        return self.getVisibleByKey(allocator, key, session_id, false, actor_id, scopes_json);
    }

    fn getAnyVisible(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, key: []const u8, actor_id: []const u8, scopes_json: []const u8) !?domain.AgentMemory {
        return self.getVisibleByKey(allocator, key, null, true, actor_id, scopes_json);
    }

    fn getVisibleByKey(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, include_sessions: bool, actor_id: []const u8, scopes_json: []const u8) !?domain.AgentMemory {
        var candidates = try visibleOwnerCandidatesFromScopes(allocator, actor_id, scopes_json);
        defer candidates.deinit(allocator);
        if (!candidates.requires_global_scan) return self.getVisibleByKeyFromOwnerCandidates(allocator, &candidates, key, session_id, include_sessions, actor_id, scopes_json);

        var where_clause: std.ArrayListUnmanaged(u8) = .empty;
        defer where_clause.deinit(allocator);
        try appendClickHouseMemoryListWhere(allocator, &where_clause, null, session_id, include_sessions, null);
        try where_clause.appendSlice(allocator, " AND key = ");
        try clickhouse_contracts.appendStringLiteral(allocator, &where_clause, key);
        return self.getVisibleByKeyWhere(allocator, where_clause.items, actor_id, scopes_json, false);
    }

    fn getVisibleByKeyFromOwnerCandidates(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, candidates: *const VisibleOwnerCandidates, key: []const u8, session_id: ?[]const u8, include_sessions: bool, actor_id: []const u8, scopes_json: []const u8) !?domain.AgentMemory {
        if (!include_sessions) return self.getVisibleByKeyFromOwnerDirectCandidates(allocator, candidates, key, session_id, actor_id, scopes_json);

        var matches: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        defer matches.deinit(allocator);
        errdefer for (matches.items) |*entry| freeAgentMemory(allocator, entry);

        for (candidates.owners.items) |owner| {
            var where_clause: std.ArrayListUnmanaged(u8) = .empty;
            defer where_clause.deinit(allocator);
            try appendClickHouseMemoryListWhere(allocator, &where_clause, null, session_id, include_sessions, owner);
            try where_clause.appendSlice(allocator, " AND key = ");
            try clickhouse_contracts.appendStringLiteral(allocator, &where_clause, key);
            var maybe_entry = try self.getVisibleByKeyWhere(allocator, where_clause.items, actor_id, scopes_json, true);
            if (maybe_entry) |*entry| {
                var entry_owned = true;
                errdefer if (entry_owned) freeAgentMemory(allocator, entry);
                try matches.append(allocator, entry.*);
                entry_owned = false;
            }
        }

        sortAgentMemoryForVisibleGet(matches.items, actor_id);
        if (matches.items.len == 0) return null;
        const result = matches.items[0];
        for (matches.items[1..]) |*entry| freeAgentMemory(allocator, entry);
        return result;
    }

    fn getVisibleByKeyFromOwnerDirectCandidates(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, candidates: *const VisibleOwnerCandidates, key: []const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8) !?domain.AgentMemory {
        var matches: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        defer matches.deinit(allocator);
        errdefer for (matches.items) |*entry| freeAgentMemory(allocator, entry);

        for (candidates.owners.items) |owner| {
            var maybe_state = try self.getMemoryState(allocator, key, session_id, owner);
            defer if (maybe_state) |*state| freeClickHouseMemoryState(allocator, state);
            if (maybe_state) |state| {
                if (!try entryVisible(allocator, state.entry, actor_id, scopes_json)) continue;
                try matches.append(allocator, try cloneAgentMemory(allocator, state.entry));
            }
        }

        sortAgentMemoryForVisibleGet(matches.items, actor_id);
        if (matches.items.len == 0) return null;
        const result = matches.items[0];
        for (matches.items[1..]) |*entry| freeAgentMemory(allocator, entry);
        return result;
    }

    fn getVisibleByKeyWhere(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, where_clause: []const u8, actor_id: []const u8, scopes_json: []const u8, stop_after_first_visible: bool) !?domain.AgentMemory {
        var matches: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        defer matches.deinit(allocator);
        errdefer for (matches.items) |*entry| freeAgentMemory(allocator, entry);

        const scan_limit = clickhouseVisibleKeyScanLimit();
        const fetch_limit = clickhouseMemoryWindowFetchLimit(1);
        var raw_offset: usize = 0;
        var scanned: usize = 0;
        while (scanned < scan_limit) {
            const remaining = scan_limit - scanned;
            const batch_limit = @min(fetch_limit, remaining);
            const states = try self.queryMemoryStatesWindow(allocator, where_clause, batch_limit, raw_offset);
            const fetched = states.len;
            defer {
                for (states) |*state| freeClickHouseMemoryState(allocator, state);
                allocator.free(states);
            }
            if (fetched == 0) break;

            for (states) |state| {
                scanned += 1;
                if (!try entryVisible(allocator, state.entry, actor_id, scopes_json)) continue;
                try matches.append(allocator, try cloneAgentMemory(allocator, state.entry));
            }

            if ((stop_after_first_visible and matches.items.len > 0) or fetched < batch_limit) break;
            raw_offset = runtimePageOffsetAfterFetch(raw_offset, fetched);
        }

        sortAgentMemoryForVisibleGet(matches.items, actor_id);
        if (matches.items.len == 0) return null;
        const result = matches.items[0];
        for (matches.items[1..]) |*entry| freeAgentMemory(allocator, entry);
        return result;
    }

    pub fn listByInput(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, input: ListInput) ![]domain.AgentMemory {
        const normalized_session_id = access.normalizeSessionId(input.session_id);
        if (input.limit) |limit| {
            if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
            if (input.scopes_json) |scopes_json| {
                const actor_id = input.actor_id orelse return error.InvalidAgentMemoryRuntimeRequest;
                if (input.any_session) return self.listAnyVisibleWindow(allocator, input.category, actor_id, scopes_json, limit, input.offset);
                return self.listVisibleWindow(allocator, input.category, normalized_session_id, actor_id, scopes_json, limit, input.offset);
            }
            return self.listWindow(allocator, input.category, normalized_session_id, input.actor_id, limit, input.offset);
        }
        if (input.scopes_json) |scopes_json| {
            const actor_id = input.actor_id orelse return error.InvalidAgentMemoryRuntimeRequest;
            if (input.any_session) return self.listAnyVisible(allocator, input.category, actor_id, scopes_json);
            return self.listVisible(allocator, input.category, normalized_session_id, actor_id, scopes_json);
        }
        return self.list(allocator, input.category, normalized_session_id, input.actor_id);
    }

    fn list(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: ?[]const u8) ![]domain.AgentMemory {
        return self.listInternal(allocator, category, session_id, false, actor_id, null, false);
    }

    fn listWindow(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: ?[]const u8, limit: usize, offset: usize) ![]domain.AgentMemory {
        return self.listInternalWindow(allocator, category, session_id, false, actor_id, null, false, limit, offset);
    }

    fn listVisible(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8) ![]domain.AgentMemory {
        var candidates = try visibleOwnerCandidatesFromScopes(allocator, actor_id, scopes_json);
        defer candidates.deinit(allocator);
        if (!candidates.requires_global_scan) return self.listVisibleFromOwnerCandidatesWindow(allocator, &candidates, category, session_id, false, actor_id, scopes_json, std.math.maxInt(usize), 0);

        return self.listInternal(allocator, category, session_id, false, null, .{ .actor_id = actor_id, .scopes_json = scopes_json }, true);
    }

    fn listVisibleWindow(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, limit: usize, offset: usize) ![]domain.AgentMemory {
        var candidates = try visibleOwnerCandidatesFromScopes(allocator, actor_id, scopes_json);
        defer candidates.deinit(allocator);
        if (!candidates.requires_global_scan) return self.listVisibleFromOwnerCandidatesWindow(allocator, &candidates, category, session_id, false, actor_id, scopes_json, limit, offset);

        return self.listInternalWindow(allocator, category, session_id, false, null, .{ .actor_id = actor_id, .scopes_json = scopes_json }, true, limit, offset);
    }

    fn listAnyVisible(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, actor_id: []const u8, scopes_json: []const u8) ![]domain.AgentMemory {
        var candidates = try visibleOwnerCandidatesFromScopes(allocator, actor_id, scopes_json);
        defer candidates.deinit(allocator);
        if (!candidates.requires_global_scan) return self.listVisibleFromOwnerCandidatesWindow(allocator, &candidates, category, null, true, actor_id, scopes_json, std.math.maxInt(usize), 0);

        return self.listInternal(allocator, category, null, true, null, .{ .actor_id = actor_id, .scopes_json = scopes_json }, true);
    }

    fn listAnyVisibleWindow(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, limit: usize, offset: usize) ![]domain.AgentMemory {
        var candidates = try visibleOwnerCandidatesFromScopes(allocator, actor_id, scopes_json);
        defer candidates.deinit(allocator);
        if (!candidates.requires_global_scan) return self.listVisibleFromOwnerCandidatesWindow(allocator, &candidates, category, null, true, actor_id, scopes_json, limit, offset);

        return self.listInternalWindow(allocator, category, null, true, null, .{ .actor_id = actor_id, .scopes_json = scopes_json }, true, limit, offset);
    }

    pub fn searchByInput(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, input: SearchInput) ![]domain.AgentMemory {
        if (input.limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        const normalized_session_id = access.normalizeSessionId(input.session_id);
        if (input.any_session) return self.searchAnyVisible(allocator, input.query, input.limit, input.scopes_json, input.actor_id);
        return self.search(allocator, input.query, input.limit, normalized_session_id, input.scopes_json, input.actor_id);
    }

    fn search(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, search_query: []const u8, limit: usize, session_id: ?[]const u8, scopes_json: []const u8, actor_id: ?[]const u8) ![]domain.AgentMemory {
        const actor = actor_id orelse return allocator.alloc(domain.AgentMemory, 0);
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        var candidates = try visibleOwnerCandidatesFromScopes(allocator, actor, scopes_json);
        defer candidates.deinit(allocator);
        if (!candidates.requires_global_scan) return self.searchVisibleOwnerCandidates(allocator, &candidates, search_query, limit, session_id, false, .{ .actor_id = actor, .scopes_json = scopes_json });

        return self.searchInternal(allocator, search_query, limit, session_id, false, .{ .actor_id = actor, .scopes_json = scopes_json });
    }

    fn searchAnyVisible(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, search_query: []const u8, limit: usize, scopes_json: []const u8, actor_id: ?[]const u8) ![]domain.AgentMemory {
        const actor = actor_id orelse return allocator.alloc(domain.AgentMemory, 0);
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        var candidates = try visibleOwnerCandidatesFromScopes(allocator, actor, scopes_json);
        defer candidates.deinit(allocator);
        if (!candidates.requires_global_scan) return self.searchVisibleOwnerCandidates(allocator, &candidates, search_query, limit, null, true, .{ .actor_id = actor, .scopes_json = scopes_json });

        return self.searchInternal(allocator, search_query, limit, null, true, .{ .actor_id = actor, .scopes_json = scopes_json });
    }

    fn listVisibleFromOwnerCandidatesWindow(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, candidates: *const VisibleOwnerCandidates, category: ?[]const u8, session_id: ?[]const u8, include_sessions: bool, actor_id: []const u8, scopes_json: []const u8, limit: usize, offset: usize) ![]domain.AgentMemory {
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        const keep_limit = agentMemoryWindowKeepLimit(limit, offset);
        var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (out.items) |*entry| freeAgentMemory(allocator, entry);
            out.deinit(allocator);
        }
        const filter = VisibleFilter{ .actor_id = actor_id, .scopes_json = scopes_json };
        for (candidates.owners.items) |owner| {
            const entries = try self.listInternalWindow(allocator, category, session_id, include_sessions, owner, filter, true, keep_limit, 0);
            defer {
                for (entries) |*entry| freeAgentMemory(allocator, entry);
                allocator.free(entries);
            }
            for (entries) |*entry| {
                try out.append(allocator, entry.*);
                detachAgentMemory(entry);
            }
        }
        sortAgentMemory(out.items);
        const owned = try out.toOwnedSlice(allocator);
        return pageAgentMemorySlice(allocator, owned, limit, offset);
    }

    fn searchVisibleOwnerCandidates(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, candidates: *const VisibleOwnerCandidates, search_query: []const u8, limit: usize, session_id: ?[]const u8, include_sessions: bool, visible: VisibleFilter) ![]domain.AgentMemory {
        const capped = runtimeAgentMemorySearchResultLimit(limit);
        var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (out.items) |*entry| freeAgentMemory(allocator, entry);
            out.deinit(allocator);
        }
        for (candidates.owners.items) |owner| {
            const entries = try self.searchInternalForOwner(allocator, search_query, capped, session_id, include_sessions, visible, owner);
            defer {
                for (entries) |*entry| freeAgentMemory(allocator, entry);
                allocator.free(entries);
            }
            for (entries) |*entry| {
                try out.append(allocator, entry.*);
                detachAgentMemory(entry);
                sortAgentMemory(out.items);
                trimAgentMemorySearchResults(allocator, &out, capped);
            }
        }
        return out.toOwnedSlice(allocator);
    }

    fn searchInternal(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, search_query: []const u8, limit: usize, session_id: ?[]const u8, include_sessions: bool, visible: VisibleFilter) ![]domain.AgentMemory {
        return self.searchInternalForOwner(allocator, search_query, limit, session_id, include_sessions, visible, null);
    }

    fn searchInternalForOwner(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, search_query: []const u8, limit: usize, session_id: ?[]const u8, include_sessions: bool, visible: VisibleFilter, owner_id: ?[]const u8) ![]domain.AgentMemory {
        const capped = runtimeAgentMemorySearchResultLimit(limit);
        const scan_limit = runtimeAgentMemorySearchScanLimit(capped);
        const fetch_limit = clickhouseMemoryWindowFetchLimit(capped);
        var where_clause: std.ArrayListUnmanaged(u8) = .empty;
        defer where_clause.deinit(allocator);
        try appendClickHouseMemoryListWhere(allocator, &where_clause, null, session_id, include_sessions, owner_id);
        var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (out.items) |*entry| freeAgentMemory(allocator, entry);
            out.deinit(allocator);
        }
        var raw_offset: usize = 0;
        var scanned: usize = 0;
        while (scanned < scan_limit) {
            const remaining = scan_limit - scanned;
            const batch_limit = @min(fetch_limit, remaining);
            var fetched: usize = 0;
            {
                const states = try self.queryMemoryStatesWindow(allocator, where_clause.items, batch_limit, raw_offset);
                fetched = states.len;
                defer {
                    for (states) |*state| freeClickHouseMemoryState(allocator, state);
                    allocator.free(states);
                }
                if (fetched == 0) break;
                for (states) |state| {
                    scanned += 1;
                    if (!try entryVisible(allocator, state.entry, visible.actor_id, visible.scopes_json)) continue;
                    var entry = try cloneAgentMemory(allocator, state.entry);
                    var entry_owned = true;
                    errdefer if (entry_owned) freeAgentMemory(allocator, &entry);
                    const score = scoreText(search_query, entry.key) + scoreText(search_query, entry.content);
                    try appendRuntimeScoredAgentMemoryCandidate(allocator, &out, search_query, capped, entry, score);
                    entry_owned = false;
                }
            }
            if ((search_query.len == 0 and out.items.len >= capped) or fetched < batch_limit) break;
            raw_offset = runtimePageOffsetAfterFetch(raw_offset, fetched);
        }
        return out.toOwnedSlice(allocator);
    }

    pub fn deleteByInput(self: *ClickHouseAgentMemory, input: DeleteInput) !bool {
        const normalized_session_id = access.normalizeSessionId(input.session_id);
        const log_feed = !input.suppress_feed;
        if (input.all_owners) {
            return self.deleteAllOrderedInternal(input.key, input.actor_id, input.writer_actor_id, input.event_order, log_feed);
        }
        return self.deleteInternal(input.key, normalized_session_id, input.actor_id, input.writer_actor_id, log_feed, input.event_order);
    }

    fn deleteInternal(self: *ClickHouseAgentMemory, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, log_feed: bool, event_order: ?EventOrder) !bool {
        const owner = actor_id orelse return false;
        if (event_order) |order| try self.upsertTombstone("agent_memory", key, owner, .scoped, session_id, order);
        var existing = try self.getMemoryState(self.allocator, key, session_id, owner);
        defer if (existing) |*state| freeClickHouseMemoryState(self.allocator, state);
        const state = existing orelse return false;
        if (event_order) |order| {
            if (compareEventOrder(order, state.event_order.timestamp_ms, state.event_order.origin_instance_id, state.event_order.origin_sequence) < 0) return false;
        }
        try self.insertMemoryRow(.{
            .id = state.entry.id,
            .key = state.entry.key,
            .content = state.entry.content,
            .category = state.entry.category,
            .session_id = state.entry.session_id,
            .actor_id = state.entry.actor_id,
            .writer_actor_id = writer_actor_id orelse owner,
            .scope = state.entry.scope,
            .permissions_json = state.entry.permissions_json,
            .status = state.entry.status,
            .timestamp_ms = if (event_order) |order| order.timestamp_ms else ids.nowMs(),
            .event_order = event_order,
            .deleted = true,
        });
        if (log_feed) try self.appendAgentMemoryDeleteFeedEvent(key, session_id, owner, writer_actor_id orelse owner, state.entry.scope, state.entry.permissions_json, "delete", event_order);
        return true;
    }

    fn deleteAllOrderedInternal(self: *ClickHouseAgentMemory, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, event_order: ?EventOrder, log_feed: bool) !bool {
        const owner = actor_id orelse return false;
        if (event_order) |order| try self.upsertTombstone("agent_memory", key, owner, .all, null, order);
        const entries = try self.listInternal(self.allocator, null, null, true, owner, null, false);
        defer {
            for (entries) |*entry| freeAgentMemory(self.allocator, entry);
            self.allocator.free(entries);
        }
        var changed = false;
        var first_scope: ?[]const u8 = null;
        var first_permissions: ?[]const u8 = null;
        for (entries) |entry| {
            if (!std.mem.eql(u8, entry.key, key)) continue;
            if (first_scope == null) first_scope = entry.scope;
            if (first_permissions == null) first_permissions = entry.permissions_json;
            _ = try self.deleteInternal(key, entry.session_id, owner, writer_actor_id, false, event_order);
            changed = true;
        }
        if (changed and log_feed) {
            const fallback_scope = try access.agentMemoryScope(self.allocator, owner, null, null);
            defer self.allocator.free(fallback_scope);
            const fallback_permissions = if (first_permissions == null) try domain.actorGrantJson(self.allocator, owner) else null;
            defer if (fallback_permissions) |permissions| self.allocator.free(permissions);
            try self.appendAgentMemoryDeleteFeedEvent(key, null, owner, writer_actor_id orelse owner, first_scope orelse fallback_scope, first_permissions orelse fallback_permissions.?, "delete_all", event_order);
        }
        return changed;
    }

    pub fn patchStatusByInput(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, input: PatchStatusInput) !bool {
        return self.patchStatusOrdered(allocator, input.key, access.normalizeSessionId(input.session_id), input.actor_id, input.status, input.writer_actor_id, input.event_order);
    }

    fn patchStatus(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, status: []const u8, writer_actor_id: ?[]const u8) !bool {
        return self.patchStatusOrdered(allocator, key, session_id, actor_id, status, writer_actor_id, null);
    }

    fn patchStatusOrdered(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, status: []const u8, writer_actor_id: ?[]const u8, event_order: ?EventOrder) !bool {
        return self.patchStatusOrderedInternal(allocator, key, session_id, actor_id, status, writer_actor_id, event_order, true);
    }

    fn patchStatusOrderedSuppressFeed(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, status: []const u8, writer_actor_id: ?[]const u8, event_order: ?EventOrder) !bool {
        return self.patchStatusOrderedInternal(allocator, key, session_id, actor_id, status, writer_actor_id, event_order, false);
    }

    fn patchStatusOrderedInternal(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, status: []const u8, writer_actor_id: ?[]const u8, event_order: ?EventOrder, log_feed: bool) !bool {
        const owner = actor_id orelse return false;
        var existing = try self.getMemoryState(allocator, key, session_id, owner);
        defer if (existing) |*state| freeClickHouseMemoryState(allocator, state);
        const state = existing orelse return false;
        if (event_order) |order| {
            if (compareEventOrder(order, state.event_order.timestamp_ms, state.event_order.origin_instance_id, state.event_order.origin_sequence) <= 0) return false;
        }
        const hide = !domain.isDefaultVisibleStatus(status);
        if (hide) {
            const order = event_order orelse EventOrder{ .timestamp_ms = ids.nowMs(), .origin_instance_id = "clickhouse", .origin_sequence = 0 };
            try self.upsertTombstone("agent_memory", key, owner, .scoped, session_id, order);
        }
        try self.insertMemoryRow(.{
            .id = state.entry.id,
            .key = state.entry.key,
            .content = state.entry.content,
            .category = state.entry.category,
            .session_id = state.entry.session_id,
            .actor_id = state.entry.actor_id,
            .writer_actor_id = writer_actor_id orelse owner,
            .scope = state.entry.scope,
            .permissions_json = state.entry.permissions_json,
            .status = status,
            .timestamp_ms = if (event_order) |order| order.timestamp_ms else ids.nowMs(),
            .event_order = event_order,
            .deleted = hide,
        });
        if (log_feed) try self.appendAgentMemoryLifecycleFeedEvent(state.entry, writer_actor_id orelse owner, status, event_order);
        return true;
    }

    pub fn tombstoneBlocksReplayByInput(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, input: TombstoneBlocksReplayInput) !bool {
        return self.tombstoneBlocksReplay(allocator, input.key, input.session_id, input.actor_id, input.event_order);
    }

    fn tombstoneBlocksReplay(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, event_order: EventOrder) !bool {
        return self.tombstoneBlocksPut(allocator, "agent_memory", key, session_id, actor_id orelse return false, event_order);
    }

    pub fn countByInput(self: *ClickHouseAgentMemory, input: CountInput) !usize {
        return self.count(input.actor_id, input.scopes_json);
    }

    fn count(self: *ClickHouseAgentMemory, actor_id: ?[]const u8, scopes_json: []const u8) !usize {
        if (actor_id) |actor| {
            var candidates = try visibleOwnerCandidatesFromScopes(self.allocator, actor, scopes_json);
            defer candidates.deinit(self.allocator);
            if (candidates.requires_global_scan) return self.countVisibleByWhere("deleted = 0", actor, scopes_json);

            var total: usize = 0;
            for (candidates.owners.items) |owner| {
                var where_clause: std.ArrayListUnmanaged(u8) = .empty;
                defer where_clause.deinit(self.allocator);
                try where_clause.appendSlice(self.allocator, "deleted = 0 AND actor_id = ");
                try clickhouse_contracts.appendStringLiteral(self.allocator, &where_clause, owner);
                total = runtimeCountAdd(total, try self.countVisibleByWhere(where_clause.items, actor, scopes_json));
            }
            return total;
        }
        const query_sql = try std.fmt.allocPrint(self.allocator, "SELECT count() FROM {s} FINAL WHERE deleted = 0 FORMAT TSV", .{self.table});
        defer self.allocator.free(query_sql);
        const body = try self.query(query_sql);
        defer self.allocator.free(body);
        return try clickhouse_contracts.parseTsvUsize(body);
    }

    fn countVisibleByWhere(self: *ClickHouseAgentMemory, where_clause: []const u8, actor_id: []const u8, scopes_json: []const u8) !usize {
        const batch_limit: usize = 1000;
        var raw_offset: usize = 0;
        var visible_count: usize = 0;
        while (true) {
            const states = try self.queryMemoryStatesWindow(self.allocator, where_clause, batch_limit, raw_offset);
            const fetched = states.len;
            defer {
                for (states) |*state| freeClickHouseMemoryState(self.allocator, state);
                self.allocator.free(states);
            }
            if (fetched == 0) break;
            for (states) |state| {
                if (try entryVisible(self.allocator, state.entry, actor_id, scopes_json)) visible_count = runtimeCountIncrement(visible_count);
            }
            if (fetched < batch_limit) break;
            raw_offset = runtimePageOffsetAfterFetch(raw_offset, fetched);
        }
        return visible_count;
    }

