    fn saveMessageAtOrdered(self: *ClickHouseAgentMemory, session_id: []const u8, role: []const u8, content: []const u8, created_at_ms: i64, actor_id: ?[]const u8, event_order: ?EventOrder) !void {
        return self.saveMessageAtOrderedInternal(session_id, role, content, created_at_ms, actor_id, event_order, true);
    }

    fn saveMessageAtOrderedInternal(self: *ClickHouseAgentMemory, session_id: []const u8, role: []const u8, content: []const u8, created_at_ms: i64, actor_id: ?[]const u8, event_order: ?EventOrder, log_feed: bool) !void {
        const actor = try access.requiredActorId(actor_id);
        if (event_order) |order| {
            if (try self.tombstoneBlocksPut(self.allocator, "agent_session_message", session_id, session_id, actor, order)) return;
        }
        const message_id = try clickhouseMessageId(self.allocator, actor, session_id, role, content, created_at_ms);
        defer self.allocator.free(message_id);
        try self.insertMessageRow(.{
            .message_id = message_id,
            .actor_id = actor,
            .session_id = session_id,
            .role = role,
            .content = content,
            .created_at_ms = created_at_ms,
            .event_order = event_order,
            .deleted = false,
        });
        if (log_feed and sessionMessageShouldEmitFeed(role)) try self.appendSessionMessageFeedEvent(session_id, role, content, created_at_ms, actor, event_order);
    }

    pub fn loadMessagesByInput(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, input: LoadMessagesInput) ![]Message {
        return self.loadMessages(allocator, input.session_id, input.actor_id);
    }

    fn loadMessages(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, session_id: []const u8, actor_id: ?[]const u8) ![]Message {
        const actor = actor_id orelse return allocator.alloc(Message, 0);
        const states = try self.listMessageStates(allocator, actor, session_id, false);
        defer {
            for (states) |*state| freeClickHouseMessageState(allocator, state);
            allocator.free(states);
        }
        var out: std.ArrayListUnmanaged(Message) = .empty;
        errdefer {
            for (out.items) |*message| freeMessage(allocator, message);
            out.deinit(allocator);
        }
        for (states) |state| {
            try out.append(allocator, .{
                .role = try allocator.dupe(u8, state.message.role),
                .content = try allocator.dupe(u8, state.message.content),
                .created_at_ms = state.message.created_at_ms,
            });
        }
        const messages = try out.toOwnedSlice(allocator);
        sortMessages(messages);
        return messages;
    }

