    }

    fn clearMessagesOrdered(self: *ClickHouseAgentMemory, session_id: []const u8, actor_id: ?[]const u8, event_order: ?EventOrder) !void {
        return self.clearMessagesOrderedInternal(session_id, actor_id, event_order, true);
    }

    fn clearMessagesOrderedInternal(self: *ClickHouseAgentMemory, session_id: []const u8, actor_id: ?[]const u8, event_order: ?EventOrder, log_feed: bool) !void {
        const actor = actor_id orelse return;
        if (event_order) |order| try self.upsertTombstone("agent_session_message", session_id, actor, .scoped, session_id, order);
        var where_clause: std.ArrayListUnmanaged(u8) = .empty;
        defer where_clause.deinit(self.allocator);
        try where_clause.appendSlice(self.allocator, "deleted = 0 AND actor_id = ");
        try clickhouse_contracts.appendStringLiteral(self.allocator, &where_clause, actor);
        try where_clause.appendSlice(self.allocator, " AND session_id = ");
        try clickhouse_contracts.appendStringLiteral(self.allocator, &where_clause, session_id);
        if (event_order) |order| try appendClickHouseEventOrderCeiling(self.allocator, &where_clause, order);

        const fetch_limit = clickhouseMessageWindowFetchLimit();
        var deleted_any = false;
        while (true) {
            const states = try self.queryMessageStatesWindow(self.allocator, where_clause.items, fetch_limit, 0);
            defer {
                for (states) |*state| freeClickHouseMessageState(self.allocator, state);
                self.allocator.free(states);
            }
            if (states.len == 0) break;
            for (states) |state| {
                try self.insertMessageRow(.{
                    .message_id = state.message_id,
                    .actor_id = actor,
                    .session_id = session_id,
                    .role = state.message.role,
                    .content = state.message.content,
                    .created_at_ms = state.message.created_at_ms,
                    .event_order = event_order,
                    .deleted = true,
                });
            }
            deleted_any = true;
            if (states.len < fetch_limit) break;
        }
        if (deleted_any and log_feed) try self.appendSessionMessageDeleteFeedEvent(session_id, actor, "delete_all", event_order);
        _ = try self.deleteUsageOrderedInternal(session_id, actor, event_order, log_feed);
    }

    pub fn clearAutoSavedByInput(self: *ClickHouseAgentMemory, input: ClearAutoSavedInput) !void {
        return self.clearAutoSavedInternal(input.session_id, input.actor_id, !input.suppress_feed);
