    fn saveUsageOrderedInternal(self: *ClickHouseAgentMemory, session_id: []const u8, total_tokens: u64, actor_id: ?[]const u8, event_order: ?EventOrder, log_feed: bool) !void {
        const actor = try access.requiredActorId(actor_id);
        if (event_order) |order| {
            if (try self.tombstoneBlocksPut(self.allocator, "agent_session_usage", session_id, session_id, actor, order)) return;
        }
        var existing = try self.getUsageState(self.allocator, session_id, actor);
        defer if (existing) |*state| freeClickHouseUsageState(self.allocator, state);
        if (event_order) |order| {
            if (existing) |state| {
                if (compareEventOrder(order, state.event_order.timestamp_ms, state.event_order.origin_instance_id, state.event_order.origin_sequence) <= 0) return;
            }
        }
        try self.insertUsageRow(.{
            .actor_id = actor,
            .session_id = session_id,
            .total_tokens = total_tokens,
            .updated_at_ms = if (event_order) |order| order.timestamp_ms else ids.nowMs(),
            .event_order = event_order,
            .deleted = false,
        });
        if (log_feed) try self.appendSessionUsagePutFeedEvent(session_id, total_tokens, actor, event_order);
    }

