    fn deleteUsageOrderedInternal(self: *ClickHouseAgentMemory, session_id: []const u8, actor_id: ?[]const u8, event_order: ?EventOrder, log_feed: bool) !bool {
        const actor = actor_id orelse return false;
        if (event_order) |order| try self.upsertTombstone("agent_session_usage", session_id, actor, .scoped, session_id, order);
        var existing = try self.getUsageState(self.allocator, session_id, actor);
        defer if (existing) |*state| freeClickHouseUsageState(self.allocator, state);
        const state = existing orelse return false;
        if (event_order) |order| {
            if (compareEventOrder(order, state.event_order.timestamp_ms, state.event_order.origin_instance_id, state.event_order.origin_sequence) < 0) return false;
        }
        try self.insertUsageRow(.{
            .actor_id = actor,
            .session_id = session_id,
            .total_tokens = state.total_tokens,
            .updated_at_ms = if (event_order) |order| order.timestamp_ms else ids.nowMs(),
            .event_order = event_order,
            .deleted = true,
        });
        if (log_feed) try self.appendSessionUsageDeleteFeedEvent(session_id, actor, event_order);
        return true;
    }

