    pub fn listSessionsByInput(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, input: ListSessionsInput) !HistoryList {
        return self.listSessions(allocator, input.limit, input.offset, input.actor_id);
    }

    fn listSessions(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, limit: usize, offset: usize, actor_id: ?[]const u8) !HistoryList {
        const actor = actor_id orelse return .{ .total = 0, .sessions = try allocator.alloc(SessionInfo, 0) };
        var where_clause: std.ArrayListUnmanaged(u8) = .empty;
        defer where_clause.deinit(allocator);
        try where_clause.appendSlice(allocator, "deleted = 0 AND actor_id = ");
        try clickhouse_contracts.appendStringLiteral(allocator, &where_clause, actor);
        try where_clause.appendSlice(allocator, " AND role <> ");
        try clickhouse_contracts.appendStringLiteral(allocator, &where_clause, domain.runtime_command_role);

        const total_sql = try std.fmt.allocPrint(
            allocator,
            "SELECT count() FROM (SELECT session_id FROM {s} FINAL WHERE {s} GROUP BY session_id) FORMAT TSV",
            .{ self.messages_table, where_clause.items },
        );
        defer allocator.free(total_sql);
        const total_body = try self.query(total_sql);
        defer self.allocator.free(total_body);
        const total = try clickhouse_contracts.parseTsvU64(total_body);
        if (limit == 0 or offset >= total) return .{ .total = total, .sessions = try allocator.alloc(SessionInfo, 0) };

        const sessions_sql = try std.fmt.allocPrint(
            allocator,
            "SELECT session_id,count() AS message_count,min(created_at_ms) AS first_message_at,max(created_at_ms) AS last_message_at FROM {s} FINAL WHERE {s} GROUP BY session_id ORDER BY last_message_at DESC, session_id ASC LIMIT {d} OFFSET {d} FORMAT JSONEachRow",
            .{ self.messages_table, where_clause.items, @max(@as(usize, 1), @min(limit, 10_000)), offset },
        );
        defer allocator.free(sessions_sql);
        const sessions_body = try self.query(sessions_sql);
        defer self.allocator.free(sessions_body);
        const sessions = try parseClickHouseSessionInfos(allocator, sessions_body);
        return .{ .total = total, .sessions = sessions };
    }

    pub fn historyByInput(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, input: HistoryInput) !HistoryShow {
        return self.history(allocator, input.session_id, input.limit, input.offset, input.actor_id);
    }

    fn history(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, session_id: []const u8, limit: usize, offset: usize, actor_id: ?[]const u8) !HistoryShow {
        const actor = actor_id orelse return .{ .total = 0, .messages = try allocator.alloc(Message, 0) };
        var where_clause: std.ArrayListUnmanaged(u8) = .empty;
        defer where_clause.deinit(allocator);
        try where_clause.appendSlice(allocator, "deleted = 0 AND actor_id = ");
        try clickhouse_contracts.appendStringLiteral(allocator, &where_clause, actor);
        try where_clause.appendSlice(allocator, " AND session_id = ");
        try clickhouse_contracts.appendStringLiteral(allocator, &where_clause, session_id);

        var total: usize = 0;
        var out: std.ArrayListUnmanaged(Message) = .empty;
        errdefer {
            for (out.items) |*message| freeMessage(allocator, message);
            out.deinit(allocator);
        }

        const fetch_limit = clickhouseMessageWindowFetchLimit();
        var raw_offset: usize = 0;
        while (true) {
            const states = try self.queryMessageStatesWindow(allocator, where_clause.items, fetch_limit, raw_offset);
            const fetched = states.len;
            defer {
                for (states) |*state| freeClickHouseMessageState(allocator, state);
                allocator.free(states);
            }
            if (fetched == 0) break;

            for (states) |state| {
                if (!domain.sessionMessageVisibleInHistory(state.message.role)) continue;
                if (total >= offset and out.items.len < limit) {
                    try out.append(allocator, .{
                        .role = try allocator.dupe(u8, state.message.role),
                        .content = try allocator.dupe(u8, state.message.content),
                        .created_at_ms = state.message.created_at_ms,
                    });
                }
                total = runtimeCountIncrement(total);
            }

            if (fetched < fetch_limit) break;
            raw_offset = runtimePageOffsetAfterFetch(raw_offset, fetched);
        }
        return .{ .total = runtimeCountToU64(total), .messages = try out.toOwnedSlice(allocator) };
    }

    pub fn listFeedEventsByInput(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, input: ListFeedEventsInput) ![]FeedEvent {
        return self.listFeedEvents(allocator, input.since_id, input.limit, input.actor_id, input.scopes_json);
    }

    fn listFeedEvents(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, since_id: i64, limit: usize, actor_id: ?[]const u8, scopes_json: []const u8) ![]FeedEvent {
        const floor = try self.feedCursorFloor();
        if (since_id < floor) return error.CursorExpired;
        const target_limit = runtimeFeedEventTargetLimit(limit);
        const fetch_limit = runtimeFeedEventFetchLimit(target_limit);
        var where_clause: std.ArrayListUnmanaged(u8) = .empty;
        defer where_clause.deinit(allocator);
        try where_clause.print(allocator, "id > {d} AND compacted_at_ms IS NULL", .{since_id});
        const events = try self.queryFeedEventsInternal(allocator, where_clause.items, fetch_limit);
        defer {
            for (events) |*event| event.deinit(allocator);
            allocator.free(events);
        }
        var out: std.ArrayListUnmanaged(FeedEvent) = .empty;
        errdefer {
            for (out.items) |*event| event.deinit(allocator);
            out.deinit(allocator);
        }
        for (events) |event| {
            if (!self.feedEventVisible(event, actor_id, scopes_json)) continue;
            try out.append(allocator, try event.clone(allocator));
            if (out.items.len >= target_limit) break;
        }
        return out.toOwnedSlice(allocator);
    }

    pub fn feedStatusByInput(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, input: FeedStatusInput) !FeedStatus {
        return self.feedStatus(allocator, input.actor_id, input.scopes_json);
    }

    fn feedStatus(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, actor_id: ?[]const u8, scopes_json: []const u8) !FeedStatus {
        const floor = try self.feedCursorFloor();
        const max_event_id = try self.lastFeedEventId();
        const events = try self.queryFeedEventsInternal(allocator, "compacted_at_ms IS NULL", 100_000);
        defer {
            for (events) |*event| event.deinit(allocator);
            allocator.free(events);
        }
        var visible: usize = 0;
        var pending: usize = 0;
        var applying: usize = 0;
        var applied: usize = 0;
        for (events) |event| {
            if (!self.feedEventVisible(event, actor_id, scopes_json)) continue;
            visible = runtimeCountIncrement(visible);
            if (std.mem.eql(u8, event.status, "pending")) {
                pending = runtimeCountIncrement(pending);
            } else if (std.mem.eql(u8, event.status, "applying")) {
                applying = runtimeCountIncrement(applying);
            } else if (std.mem.eql(u8, event.status, "applied")) {
                applied = runtimeCountIncrement(applied);
            }
        }
        const instance_id = try self.feedInstanceId(allocator);
        errdefer allocator.free(instance_id);
        const next_local_origin_sequence = runtimeNextLocalOriginSequenceFromFrontier(try self.originFrontier(instance_id), max_event_id);
        return .{
            .instance_id = instance_id,
            .storage_kind = try allocator.dupe(u8, "clickhouse"),
            .supports_compaction = true,
            .cursor_floor = floor,
            .compacted_through_sequence = floor,
            .oldest_available_sequence = runtimeFeedSequenceAfter(floor),
            .max_event_id = max_event_id,
            .last_sequence = max_event_id,
            .next_local_origin_sequence = next_local_origin_sequence,
            .visible_events = visible,
            .pending_events = pending,
            .applying_events = applying,
            .applied_events = applied,
        };
    }

    pub fn compactFeedByInput(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, input: CompactFeedInput) !FeedCompactResult {
        return self.compactFeed(allocator, input.actor_id, input.scopes_json, input.before_id);
    }

    fn compactFeed(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, actor_id: ?[]const u8, scopes_json: []const u8, before_id: ?i64) !FeedCompactResult {
        _ = actor_id;
        _ = scopes_json;
        const before = before_id orelse try self.lastFeedEventId();
        const where_clause = try std.fmt.allocPrint(allocator, "id <= {d} AND compacted_at_ms IS NULL", .{before});
        defer allocator.free(where_clause);
        const events = try self.queryFeedEventsInternal(allocator, where_clause, 100_000);
        defer {
            for (events) |*event| event.deinit(allocator);
            allocator.free(events);
        }
        const now = ids.nowMs();
        for (events) |event| {
            var copy = try event.clone(allocator);
            defer copy.deinit(allocator);
            copy.compacted_at_ms = now;
            try self.insertFeedEvent(copy);
        }
        try self.setFeedCursorFloor(before);
        const max_event_id = try self.lastFeedEventId();
        const floor = try self.feedCursorFloor();
        return .{
            .cursor_floor = floor,
            .compacted_through_sequence = floor,
            .max_event_id = max_event_id,
            .compacted_events = events.len,
        };
    }

    pub fn exportFeedCheckpointByInput(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, input: ExportFeedCheckpointInput) ![]u8 {
        return self.exportFeedCheckpoint(allocator, input.since_id, input.limit, input.actor_id, input.scopes_json);
    }

    fn exportFeedCheckpoint(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, since_id: ?i64, limit: ?usize, actor_id: ?[]const u8, scopes_json: []const u8) ![]u8 {
        const after = since_id orelse 0;
        const target_limit = @max(@as(usize, 1), @min(limit orelse 500, 1000));
        const events = try self.listFeedEvents(allocator, after, target_limit, actor_id, scopes_json);
        defer {
            for (events) |*event| event.deinit(allocator);
            allocator.free(events);
        }
        const floor = try self.feedCursorFloor();
        const max_event_id = try self.lastFeedEventId();
        const instance_id = try self.feedInstanceId(allocator);
        defer allocator.free(instance_id);
        var out: std.ArrayListUnmanaged(u8) = .empty;
        errdefer out.deinit(allocator);
        try out.appendSlice(allocator, "{\"instance_id\":");
        try json.appendString(&out, allocator, instance_id);
        try out.appendSlice(allocator, ",\"feed_object_types\":");
        try out.appendSlice(allocator, feed_object_types_json);
        try out.appendSlice(allocator, ",\"lifecycle_object_types\":");
        try out.appendSlice(allocator, lifecycle_object_types_json);
        try out.appendSlice(allocator, ",\"cursor_floor\":");
        try out.print(allocator, "{d},\"compacted_through_sequence\":{d},\"max_event_id\":{d},\"last_sequence\":{d},\"frontiers\":[", .{ floor, floor, max_event_id, max_event_id });
        try self.appendCheckpointFrontiersJson(allocator, &out);
        try out.appendSlice(allocator, "],\"events\":[");
        for (events, 0..) |event, i| {
            if (i > 0) try out.append(allocator, ',');
            try event.writeJson(allocator, &out);
        }
        try out.appendSlice(allocator, "]}");
        return out.toOwnedSlice(allocator);
    }

    pub fn restoreFeedCheckpointByInput(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, input: RestoreFeedCheckpointInput) !void {
        return self.restoreFeedCheckpoint(allocator, input.checkpoint_json, input.actor_id, input.scopes_json);
    }

    fn restoreFeedCheckpoint(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, checkpoint_json: []const u8, actor_id: ?[]const u8, scopes_json: []const u8) !void {
        var parsed = std.json.parseFromSlice(std.json.Value, allocator, checkpoint_json, .{}) catch return error.AgentMemoryStorageUnavailable;
        defer parsed.deinit();
        if (parsed.value != .object) return error.AgentMemoryStorageUnavailable;
        const events_value = runtimeCheckpointEventsValue(parsed.value.object) orelse return error.AgentMemoryStorageUnavailable;
        if (events_value != .array) return error.AgentMemoryStorageUnavailable;
        try validateRuntimeCheckpointShape(allocator, parsed.value.object, actor_id, scopes_json);
        for (events_value.array.items) |item| {
            if (item != .object) return error.AgentMemoryStorageUnavailable;
            try self.applyFeedEventObject(allocator, item.object, actor_id, scopes_json);
        }
        try self.restoreCheckpointFrontiers(allocator, parsed.value.object);
        const floor = try runtimeCheckpointCompactedThrough(parsed.value.object);
        if (floor > 0) try self.setFeedCursorFloor(floor);
    }

    pub fn applyFeedEventByInput(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, input: ApplyFeedEventInput) !void {
        return self.applyFeedEventJson(allocator, input.event_json, input.actor_id, input.scopes_json);
    }

    fn applyFeedEventJson(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, event_json: []const u8, actor_id: ?[]const u8, scopes_json: []const u8) !void {
        var parsed = std.json.parseFromSlice(std.json.Value, allocator, event_json, .{}) catch return error.AgentMemoryStorageUnavailable;
        defer parsed.deinit();
        if (parsed.value != .object) return error.AgentMemoryStorageUnavailable;
        if (runtimeCheckpointEventsValue(parsed.value.object) != null) return self.restoreFeedCheckpoint(allocator, event_json, actor_id, scopes_json);
        return self.applyFeedEventObject(allocator, parsed.value.object, actor_id, scopes_json);
    }

