    fn appendLocalFeedEvent(
        self: *ClickHouseAgentMemory,
        event_type: []const u8,
        operation: []const u8,
        object_type: []const u8,
        object_id: []const u8,
        scope: []const u8,
        permissions_json: []const u8,
        actor_id: ?[]const u8,
        payload_json: []const u8,
        event_order: ?EventOrder,
    ) !void {
        if (event_order) |order| {
            if (try self.feedEventOriginExists(order.origin_instance_id, order.origin_sequence, event_type, object_type, object_id)) return;
        }
        const id: i64 = @intCast(clickhouseVersion());
        const created_at_ms = if (event_order) |order| order.timestamp_ms else ids.nowMs();
        const local_origin_instance_id = if (event_order == null) try self.feedInstanceId(self.allocator) else null;
        defer if (local_origin_instance_id) |value| self.allocator.free(value);
        var event = FeedEvent{
            .id = id,
            .sequence = id,
            .event_type = try self.allocator.dupe(u8, event_type),
            .origin_instance_id = if (event_order) |order| try self.allocator.dupe(u8, order.origin_instance_id) else try self.allocator.dupe(u8, local_origin_instance_id.?),
            .origin_sequence = if (event_order) |order| order.origin_sequence else id,
            .operation = try self.allocator.dupe(u8, operation),
            .object_type = try self.allocator.dupe(u8, object_type),
            .object_id = try self.allocator.dupe(u8, object_id),
            .scope = try self.allocator.dupe(u8, scope),
            .permissions_json = try self.allocator.dupe(u8, permissions_json),
            .actor_id = if (actor_id) |actor| try self.allocator.dupe(u8, actor) else null,
            .dedupe_key = null,
            .causality_json = try self.allocator.dupe(u8, "{}"),
            .payload_json = try self.allocator.dupe(u8, payload_json),
            .status = try self.allocator.dupe(u8, "applied"),
            .created_at_ms = created_at_ms,
            .applied_at_ms = created_at_ms,
            .compacted_at_ms = null,
        };
        defer event.deinit(self.allocator);
        try self.insertFeedEvent(event);
        try self.advanceOriginFrontier(event.origin_instance_id, event.origin_sequence);
    }

    fn appendAgentMemoryFeedEvent(self: *ClickHouseAgentMemory, entry: domain.AgentMemory, operation: domain.AgentMemoryOperation, operation_content: []const u8, event_order: ?EventOrder) !void {
        const payload = try feed_contract.agentMemoryWrite(self.allocator, "clickhouse", entry, operation, operation_content);
        defer self.allocator.free(payload);
        const event_type = switch (operation) {
            .put => "agent_memory.runtime_put",
            .merge_object => "agent_memory.runtime_merge_object",
            .merge_string_set => "agent_memory.runtime_merge_string_set",
        };
        try self.appendLocalFeedEvent(
            event_type,
            operation.name(),
            "agent_memory",
            entry.id,
            entry.scope,
            entry.permissions_json,
            if (entry.writer_actor_id.len > 0) entry.writer_actor_id else entry.actor_id,
            payload,
            event_order,
        );
    }

    fn appendAgentMemoryDeleteFeedEvent(self: *ClickHouseAgentMemory, key: []const u8, session_id: ?[]const u8, owner_actor_id: []const u8, writer_actor_id: []const u8, scope: []const u8, permissions_json: []const u8, operation: []const u8, event_order: ?EventOrder) !void {
        const payload = try feed_contract.agentMemoryDelete(self.allocator, "clickhouse", key, session_id, owner_actor_id, scope, permissions_json);
        defer self.allocator.free(payload);
        const event_type = if (std.mem.eql(u8, operation, "delete_all")) "agent_memory.runtime_delete_all" else "agent_memory.runtime_delete";
        try self.appendLocalFeedEvent(event_type, operation, "agent_memory", key, scope, permissions_json, writer_actor_id, payload, event_order);
    }

    fn appendAgentMemoryLifecycleFeedEvent(self: *ClickHouseAgentMemory, entry: domain.AgentMemory, writer_actor_id: []const u8, status: []const u8, event_order: ?EventOrder) !void {
        const operation = feed_contract.agentMemoryLifecycleOperationForStatus(status);
        const payload = try self.agentMemoryLifecyclePayloadJson(entry, status);
        defer self.allocator.free(payload);
        const event_type = try std.fmt.allocPrint(self.allocator, "agent_memory.runtime_{s}", .{operation});
        defer self.allocator.free(event_type);
        try self.appendLocalFeedEvent(event_type, operation, "agent_memory", entry.id, entry.scope, entry.permissions_json, writer_actor_id, payload, event_order);
    }

    fn agentMemoryLifecyclePayloadJson(self: *ClickHouseAgentMemory, entry: domain.AgentMemory, status: []const u8) ![]u8 {
        var out: std.ArrayListUnmanaged(u8) = .empty;
        errdefer out.deinit(self.allocator);
        try out.appendSlice(self.allocator, "{\"store\":\"clickhouse\",\"key\":");
        try json.appendString(&out, self.allocator, entry.key);
        try out.appendSlice(self.allocator, ",\"session_id\":");
        try json.appendNullableString(&out, self.allocator, entry.session_id);
        try out.appendSlice(self.allocator, ",\"scope\":");
        try json.appendString(&out, self.allocator, entry.scope);
        try out.appendSlice(self.allocator, ",\"permissions\":");
        try json.appendRawJsonArray(&out, self.allocator, entry.permissions_json);
