    fn applyFeedEventObject(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, obj: std.json.ObjectMap, actor_id: ?[]const u8, scopes_json: []const u8) !void {
        var event = try parseLooseFeedEventValue(allocator, obj, actor_id);
        defer event.deinit(allocator);
        if (!self.feedEventVisible(event, actor_id, scopes_json)) return error.Forbidden;
        if (try self.originAlreadyApplied(event.origin_instance_id, event.origin_sequence)) return;
        if (try self.feedEventOriginExists(event.origin_instance_id, event.origin_sequence, event.event_type, event.object_type, event.object_id)) {
            try self.advanceOriginFrontier(event.origin_instance_id, event.origin_sequence);
            return;
        }
        const suppress_feed = json.boolField(obj, "suppress_feed") orelse false;
        const order = EventOrder{
            .timestamp_ms = event.created_at_ms,
            .origin_instance_id = event.origin_instance_id,
            .origin_sequence = event.origin_sequence,
        };
        if (std.mem.eql(u8, event.object_type, "agent_memory")) {
            try self.applyAgentMemoryFeedEvent(allocator, event, order, actor_id, suppress_feed);
        } else if (std.mem.eql(u8, event.object_type, "agent_session_message")) {
            try self.applySessionMessageFeedEvent(allocator, event, order, actor_id, suppress_feed);
        } else if (std.mem.eql(u8, event.object_type, "agent_session_usage")) {
            try self.applySessionUsageFeedEvent(allocator, event, order, actor_id, suppress_feed);
        } else {
            return error.NotSupported;
        }
        try self.advanceOriginFrontier(event.origin_instance_id, event.origin_sequence);
    }

    fn applyAgentMemoryFeedEvent(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, event: FeedEvent, order: EventOrder, fallback_actor_id: ?[]const u8, suppress_feed: bool) !void {
        var payload = try std.json.parseFromSlice(std.json.Value, allocator, event.payload_json, .{});
        defer payload.deinit();
        if (payload.value != .object) return error.AgentMemoryStorageUnavailable;
        const obj = payload.value.object;
        const key = jsonStringishField(obj, &.{"key"}) orelse event.object_id;
        const session_id = access.normalizeSessionId(jsonStringishField(obj, &.{ "session_id", "session" }));
        const owner_actor = jsonStringishField(obj, &.{ "owner_id", "actor_id" }) orelse event.actor_id orelse fallback_actor_id orelse return error.MissingActorId;
        if (feed_contract.isDeleteAllOperation(event.operation)) {
            _ = try self.deleteByInput(.{
                .key = key,
                .actor_id = owner_actor,
                .writer_actor_id = event.actor_id orelse owner_actor,
                .event_order = order,
                .all_owners = true,
                .suppress_feed = suppress_feed,
            });
            return;
        }
        if (feed_contract.isDeleteOperation(event.operation) or feed_contract.isDeleteScopedOperation(event.operation)) {
            _ = try self.deleteByInput(.{
                .key = key,
                .session_id = session_id,
                .actor_id = owner_actor,
                .writer_actor_id = event.actor_id orelse owner_actor,
                .event_order = order,
                .suppress_feed = suppress_feed,
            });
            return;
        }
        if (feed_contract.isLifecycleOperation(event.operation)) {
            const status = feed_contract.statusFromLifecycleOperation(event.operation, obj);
            _ = if (suppress_feed)
                try self.patchStatusOrderedSuppressFeed(allocator, key, session_id, owner_actor, status, event.actor_id orelse owner_actor, order)
            else
                try self.patchStatusOrdered(allocator, key, session_id, owner_actor, status, event.actor_id orelse owner_actor, order);
            return;
        }
        const memory_operation = domain.AgentMemoryOperation.parse(event.operation);
        const content = try runtimeAgentMemoryOperationContent(allocator, obj, memory_operation);
        defer allocator.free(content);
        const permissions_json = try jsonRawArrayField(allocator, obj, &.{ "permissions", "permissions_json" }, "[]");
        defer allocator.free(permissions_json);
        var entry = try self.store(allocator, .{
            .key = key,
            .content = content,
            .category = jsonStringishField(obj, &.{"category"}) orelse "core",
            .session_id = session_id,
            .scope = jsonStringishField(obj, &.{"scope"}),
            .permissions_json = permissions_json,
            .actor_id = owner_actor,
            .writer_actor_id = event.actor_id orelse owner_actor,
            .operation = memory_operation,
            .suppress_feed = suppress_feed,
            .event_order = order,
        });
        defer freeAgentMemory(allocator, &entry);
    }

    fn applySessionMessageFeedEvent(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, event: FeedEvent, order: EventOrder, fallback_actor_id: ?[]const u8, suppress_feed: bool) !void {
        var payload = try std.json.parseFromSlice(std.json.Value, allocator, event.payload_json, .{});
        defer payload.deinit();
        if (payload.value != .object) return error.AgentMemoryStorageUnavailable;
        const obj = payload.value.object;
        const actor = jsonStringishField(obj, &.{"actor_id"}) orelse event.actor_id orelse fallback_actor_id orelse return error.MissingActorId;
        if (std.mem.eql(u8, event.operation, "delete_autosaved")) {
            try self.clearAutoSavedByInput(.{
                .session_id = try optionalJsonNullableStringField(obj, "session_id"),
                .actor_id = actor,
                .suppress_feed = suppress_feed,
            });
            return;
        }
        const session_id = try requiredJsonStringField(obj, "session_id");
        if (feed_contract.isAgentSessionDeleteOperation(event.operation)) {
            try self.clearMessagesByInput(.{
                .session_id = session_id,
                .actor_id = actor,
                .event_order = order,
                .suppress_feed = suppress_feed,
            });
            return;
        }
        const message = try runtimeSessionMessagePayload(obj, event, fallback_actor_id);
        try self.saveMessageByInput(.{
            .session_id = message.session_id,
            .role = message.role,
            .content = message.content,
            .created_at_ms = message.created_at_ms,
            .actor_id = message.actor_id,
            .event_order = order,
            .suppress_feed = suppress_feed,
        });
    }

    fn applySessionUsageFeedEvent(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, event: FeedEvent, order: EventOrder, fallback_actor_id: ?[]const u8, suppress_feed: bool) !void {
        var payload = try std.json.parseFromSlice(std.json.Value, allocator, event.payload_json, .{});
        defer payload.deinit();
        if (payload.value != .object) return error.AgentMemoryStorageUnavailable;
        const obj = payload.value.object;
        const actor = jsonStringishField(obj, &.{"actor_id"}) orelse event.actor_id orelse fallback_actor_id orelse return error.MissingActorId;
        const session_id = try requiredJsonStringField(obj, "session_id");
        if (feed_contract.isAgentSessionDeleteOperation(event.operation)) {
            _ = try self.deleteUsageByInput(.{
                .session_id = session_id,
                .actor_id = actor,
                .event_order = order,
                .suppress_feed = suppress_feed,
            });
            return;
        }
        const usage = try runtimeSessionUsagePayload(obj, event, fallback_actor_id);
        try self.saveUsageByInput(.{
            .session_id = usage.session_id,
            .total_tokens = usage.total_tokens,
            .actor_id = usage.actor_id,
            .event_order = order,
            .suppress_feed = suppress_feed,
        });
    }

    fn queryFeedEventsInternal(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, where_clause: []const u8, limit: usize) ![]FeedEvent {
        const query_sql = try std.fmt.allocPrint(
            allocator,
            "SELECT id,sequence,event_type,origin_instance_id,origin_sequence,operation,object_type,object_id,scope,permissions_json,actor_id,dedupe_key,causality_json,payload_json,status,created_at_ms,applied_at_ms,compacted_at_ms FROM {s} FINAL WHERE {s} ORDER BY id ASC LIMIT {d} FORMAT JSONEachRow",
            .{ self.events_table, where_clause, @max(@as(usize, 1), @min(limit, 100_000)) },
        );
        defer allocator.free(query_sql);
        const body = try self.query(query_sql);
        defer self.allocator.free(body);
        return parseClickHouseFeedEvents(allocator, body);
    }

    fn insertFeedEvent(self: *ClickHouseAgentMemory, event: FeedEvent) !void {
        var body: std.ArrayListUnmanaged(u8) = .empty;
        defer body.deinit(self.allocator);
        try body.print(self.allocator, "{{\"id\":{d},\"sequence\":{d},\"event_type\":", .{ event.id, event.sequence });
        try json.appendString(&body, self.allocator, event.event_type);
        try body.appendSlice(self.allocator, ",\"origin_instance_id\":");
        try json.appendString(&body, self.allocator, event.origin_instance_id);
        try body.print(self.allocator, ",\"origin_sequence\":{d},\"operation\":", .{event.origin_sequence});
        try json.appendString(&body, self.allocator, event.operation);
        try body.appendSlice(self.allocator, ",\"object_type\":");
        try json.appendString(&body, self.allocator, event.object_type);
        try body.appendSlice(self.allocator, ",\"object_id\":");
        try json.appendString(&body, self.allocator, event.object_id);
        try body.appendSlice(self.allocator, ",\"scope\":");
        try json.appendString(&body, self.allocator, event.scope);
        try body.appendSlice(self.allocator, ",\"permissions_json\":");
        try json.appendString(&body, self.allocator, event.permissions_json);
        try body.appendSlice(self.allocator, ",\"actor_id\":");
        try json.appendNullableString(&body, self.allocator, event.actor_id);
        try body.appendSlice(self.allocator, ",\"dedupe_key\":");
        try json.appendNullableString(&body, self.allocator, event.dedupe_key);
        try body.appendSlice(self.allocator, ",\"causality_json\":");
        try json.appendString(&body, self.allocator, event.causality_json);
        try body.appendSlice(self.allocator, ",\"payload_json\":");
        try json.appendString(&body, self.allocator, event.payload_json);
        try body.appendSlice(self.allocator, ",\"status\":");
        try json.appendString(&body, self.allocator, event.status);
        try body.print(self.allocator, ",\"created_at_ms\":{d},\"applied_at_ms\":", .{event.created_at_ms});
        if (event.applied_at_ms) |value| try body.print(self.allocator, "{d}", .{value}) else try body.appendSlice(self.allocator, "null");
        try body.appendSlice(self.allocator, ",\"compacted_at_ms\":");
        if (event.compacted_at_ms) |value| try body.print(self.allocator, "{d}", .{value}) else try body.appendSlice(self.allocator, "null");
        try body.print(self.allocator, ",\"version\":{d}}}\n", .{clickhouseVersion()});
        const query_sql = try std.fmt.allocPrint(self.allocator, "INSERT INTO {s} FORMAT JSONEachRow", .{self.events_table});
        defer self.allocator.free(query_sql);
        try self.insert(query_sql, body.items);
    }

