    fn lastFeedEventId(self: *ClickHouseAgentMemory) !i64 {
        const query_sql = try std.fmt.allocPrint(self.allocator, "SELECT ifNull(max(id), 0) FROM {s} FINAL FORMAT TSV", .{self.events_table});
        defer self.allocator.free(query_sql);
