        try clickhouse_contracts.appendStringLiteral(self.allocator, &where_clause, name);
        const query_sql = try std.fmt.allocPrint(self.allocator, "SELECT value FROM {s} FINAL WHERE {s} LIMIT 1 FORMAT TSV", .{ self.feed_meta_table, where_clause.items });
        defer self.allocator.free(query_sql);
        const body = try self.query(query_sql);
        defer self.allocator.free(body);
        return try clickhouseTsvI64OrDefaultZero(body);
    }

    fn setFeedMetaAtLeast(self: *ClickHouseAgentMemory, name: []const u8, value: i64) !void {
        const current = try self.feedMetaValue(name);
        if (value <= current) return;
        var body: std.ArrayListUnmanaged(u8) = .empty;
        defer body.deinit(self.allocator);
        try body.appendSlice(self.allocator, "{\"name\":");
        try json.appendString(&body, self.allocator, name);
        try body.print(self.allocator, ",\"value\":{d},\"version\":{d}}}\n", .{ value, clickhouseVersion() });
        const query_sql = try std.fmt.allocPrint(self.allocator, "INSERT INTO {s} FORMAT JSONEachRow", .{self.feed_meta_table});
        defer self.allocator.free(query_sql);
        try self.insert(query_sql, body.items);
    }

