    fn originAlreadyApplied(self: *ClickHouseAgentMemory, origin_instance_id: []const u8, origin_sequence: i64) !bool {
        return origin_sequence > 0 and origin_sequence <= try self.originFrontier(origin_instance_id);
    }

    fn advanceOriginFrontier(self: *ClickHouseAgentMemory, origin_instance_id: []const u8, origin_sequence: i64) !void {
        if (origin_instance_id.len == 0 or origin_sequence <= 0) return;
        const current = try self.originFrontier(origin_instance_id);
        if (origin_sequence <= current) return;
        var body: std.ArrayListUnmanaged(u8) = .empty;
        defer body.deinit(self.allocator);
        try body.appendSlice(self.allocator, "{\"origin_instance_id\":");
        try json.appendString(&body, self.allocator, origin_instance_id);
        try body.print(self.allocator, ",\"origin_sequence\":{d},\"version\":{d}}}\n", .{ origin_sequence, clickhouseVersion() });
        const query_sql = try std.fmt.allocPrint(self.allocator, "INSERT INTO {s} FORMAT JSONEachRow", .{self.frontiers_table});
        defer self.allocator.free(query_sql);
        try self.insert(query_sql, body.items);
    }

    fn appendCheckpointFrontiersJson(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8)) !void {
        const query_sql = try std.fmt.allocPrint(allocator, "SELECT origin_instance_id,origin_sequence FROM {s} FINAL ORDER BY origin_instance_id ASC FORMAT JSONEachRow", .{self.frontiers_table});
        defer allocator.free(query_sql);
        const body = try self.query(query_sql);
        defer self.allocator.free(body);
        const array_json = try clickhouse_contracts.jsonEachRowsToArray(allocator, body);
        defer allocator.free(array_json);
        var parsed = try std.json.parseFromSlice(std.json.Value, allocator, array_json, .{});
        defer parsed.deinit();
        if (parsed.value != .array) return;
        var written: usize = 0;
        for (parsed.value.array.items) |item| {
            if (item != .object) return error.AgentMemoryStorageUnavailable;
            const frontier = try runtimeCheckpointFrontierFields(item.object);
            if (written > 0) try out.append(allocator, ',');
            try appendRuntimeCheckpointFrontierJson(allocator, out, frontier.origin_instance_id, frontier.origin_sequence);
            written += 1;
        }
    }

    fn restoreCheckpointFrontiers(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, obj: std.json.ObjectMap) !void {
        const frontiers = runtimeCheckpointFrontiersValue(obj) orelse return;
        if (frontiers != .array) return error.AgentMemoryStorageUnavailable;
        const instance_id = try self.feedInstanceId(allocator);
        defer allocator.free(instance_id);
        for (frontiers.array.items) |frontier_value| {
            if (frontier_value != .object) return error.AgentMemoryStorageUnavailable;
            const frontier = try runtimeCheckpointFrontierFields(frontier_value.object);
            try self.advanceOriginFrontier(frontier.origin_instance_id, frontier.origin_sequence);
            if (std.mem.eql(u8, frontier.origin_instance_id, instance_id)) try self.setFeedMetaAtLeast("local_sequence", frontier.origin_sequence);
        }
    }

    fn feedEventOriginExists(self: *ClickHouseAgentMemory, origin_instance_id: []const u8, origin_sequence: i64, event_type: []const u8, object_type: []const u8, object_id: []const u8) !bool {
        if (origin_instance_id.len == 0 or origin_sequence <= 0) return false;
        var where_clause: std.ArrayListUnmanaged(u8) = .empty;
        defer where_clause.deinit(self.allocator);
        try where_clause.appendSlice(self.allocator, "origin_instance_id = ");
        try clickhouse_contracts.appendStringLiteral(self.allocator, &where_clause, origin_instance_id);
        try where_clause.print(self.allocator, " AND origin_sequence = {d} AND event_type = ", .{origin_sequence});
        try clickhouse_contracts.appendStringLiteral(self.allocator, &where_clause, event_type);
        try where_clause.appendSlice(self.allocator, " AND object_type = ");
        try clickhouse_contracts.appendStringLiteral(self.allocator, &where_clause, object_type);
        try where_clause.appendSlice(self.allocator, " AND object_id = ");
        try clickhouse_contracts.appendStringLiteral(self.allocator, &where_clause, object_id);
        const query_sql = try std.fmt.allocPrint(self.allocator, "SELECT count() FROM {s} FINAL WHERE {s} FORMAT TSV", .{ self.events_table, where_clause.items });
        defer self.allocator.free(query_sql);
        const body = try self.query(query_sql);
        defer self.allocator.free(body);
        return (try clickhouse_contracts.parseTsvU64(body)) > 0;
    }

    fn ensureSchema(self: *ClickHouseAgentMemory) !void {
        const memory_sql = try std.fmt.allocPrint(
            self.allocator,
            "CREATE TABLE IF NOT EXISTS {s} (id String, actor_id String, writer_actor_id String, key String, session_key String, session_id Nullable(String), content String, category String, scope String, permissions_json String, status String, timestamp_ms Int64, event_timestamp_ms Int64, origin_instance_id String, origin_sequence Int64, deleted UInt8, version UInt64) ENGINE = ReplacingMergeTree(version) ORDER BY (actor_id, key, session_key)",
            .{self.table},
        );
        defer self.allocator.free(memory_sql);
        try self.exec(memory_sql);

        const messages_sql = try std.fmt.allocPrint(
            self.allocator,
            "CREATE TABLE IF NOT EXISTS {s} (actor_id String, session_id String, message_id String, role String, content String, created_at_ms Int64, event_timestamp_ms Int64, origin_instance_id String, origin_sequence Int64, deleted UInt8, version UInt64) ENGINE = ReplacingMergeTree(version) ORDER BY (actor_id, session_id, message_id)",
            .{self.messages_table},
        );
        defer self.allocator.free(messages_sql);
        try self.exec(messages_sql);

        const usage_sql = try std.fmt.allocPrint(
            self.allocator,
            "CREATE TABLE IF NOT EXISTS {s} (actor_id String, session_id String, total_tokens UInt64, updated_at_ms Int64, event_timestamp_ms Int64, origin_instance_id String, origin_sequence Int64, deleted UInt8, version UInt64) ENGINE = ReplacingMergeTree(version) ORDER BY (actor_id, session_id)",
            .{self.usage_table},
        );
        defer self.allocator.free(usage_sql);
        try self.exec(usage_sql);

        const tombstones_sql = try std.fmt.allocPrint(
            self.allocator,
            "CREATE TABLE IF NOT EXISTS {s} (object_type String, key String, actor_id String, tombstone_scope String, session_key String, session_id Nullable(String), event_timestamp_ms Int64, origin_instance_id String, origin_sequence Int64, version UInt64) ENGINE = ReplacingMergeTree(version) ORDER BY (object_type, actor_id, key, tombstone_scope, session_key)",
            .{self.tombstones_table},
        );
        defer self.allocator.free(tombstones_sql);
        try self.exec(tombstones_sql);

        const events_sql = try std.fmt.allocPrint(
            self.allocator,
            "CREATE TABLE IF NOT EXISTS {s} (id Int64, sequence Int64, event_type String, origin_instance_id String, origin_sequence Int64, operation String, object_type String, object_id String, scope String, permissions_json String, actor_id Nullable(String), dedupe_key Nullable(String), causality_json String, payload_json String, status String, created_at_ms Int64, applied_at_ms Nullable(Int64), compacted_at_ms Nullable(Int64), version UInt64) ENGINE = ReplacingMergeTree(version) ORDER BY (id)",
            .{self.events_table},
        );
        defer self.allocator.free(events_sql);
        try self.exec(events_sql);

        const frontiers_sql = try std.fmt.allocPrint(
            self.allocator,
            "CREATE TABLE IF NOT EXISTS {s} (origin_instance_id String, origin_sequence Int64, version UInt64) ENGINE = ReplacingMergeTree(version) ORDER BY (origin_instance_id)",
            .{self.frontiers_table},
        );
        defer self.allocator.free(frontiers_sql);
        try self.exec(frontiers_sql);

        const feed_meta_sql = try std.fmt.allocPrint(
            self.allocator,
            "CREATE TABLE IF NOT EXISTS {s} (name String, value Int64, version UInt64) ENGINE = ReplacingMergeTree(version) ORDER BY (name)",
            .{self.feed_meta_table},
        );
        defer self.allocator.free(feed_meta_sql);
        try self.exec(feed_meta_sql);
    }

    fn getMemoryState(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor: []const u8) !?ClickHouseMemoryState {
        const session_key = clickhouseSessionKey(session_id);
        var where_clause: std.ArrayListUnmanaged(u8) = .empty;
        defer where_clause.deinit(allocator);
        try where_clause.appendSlice(allocator, "deleted = 0 AND actor_id = ");
        try clickhouse_contracts.appendStringLiteral(allocator, &where_clause, actor);
        try where_clause.appendSlice(allocator, " AND key = ");
        try clickhouse_contracts.appendStringLiteral(allocator, &where_clause, key);
        try where_clause.appendSlice(allocator, " AND session_key = ");
        try clickhouse_contracts.appendStringLiteral(allocator, &where_clause, session_key);
        const rows = try self.queryMemoryStates(allocator, where_clause.items, 1);
        if (rows.len == 0) {
            allocator.free(rows);
            return null;
        }
        const first = rows[0];
        allocator.free(rows);
        return first;
    }

    fn listInternal(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, include_sessions: bool, actor_id: ?[]const u8, visible: ?VisibleFilter, visible_only: bool) ![]domain.AgentMemory {
        var where_clause: std.ArrayListUnmanaged(u8) = .empty;
        defer where_clause.deinit(allocator);
        try appendClickHouseMemoryListWhere(allocator, &where_clause, category, session_id, include_sessions, actor_id);
        const states = try self.queryMemoryStates(allocator, where_clause.items, 5000);
        defer {
            for (states) |*state| freeClickHouseMemoryState(allocator, state);
            allocator.free(states);
        }
        var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (out.items) |*entry| freeAgentMemory(allocator, entry);
            out.deinit(allocator);
        }
        for (states) |state| {
            if (visible_only) {
                const filter = visible orelse continue;
                if (!try entryVisible(allocator, state.entry, filter.actor_id, filter.scopes_json)) continue;
            }
            try out.append(allocator, try cloneAgentMemory(allocator, state.entry));
        }
        sortAgentMemory(out.items);
        return out.toOwnedSlice(allocator);
    }

    fn listInternalWindow(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, include_sessions: bool, actor_id: ?[]const u8, visible: ?VisibleFilter, visible_only: bool, limit: usize, offset: usize) ![]domain.AgentMemory {
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        var where_clause: std.ArrayListUnmanaged(u8) = .empty;
        defer where_clause.deinit(allocator);
        try appendClickHouseMemoryListWhere(allocator, &where_clause, category, session_id, include_sessions, actor_id);

        if (!visible_only) {
            const states = try self.queryMemoryStatesWindow(allocator, where_clause.items, limit, offset);
            defer {
                for (states) |*state| freeClickHouseMemoryState(allocator, state);
                allocator.free(states);
            }
            return cloneClickHouseMemoryStates(allocator, states);
        }

        var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (out.items) |*entry| freeAgentMemory(allocator, entry);
            out.deinit(allocator);
        }

        const filter = visible orelse return allocator.alloc(domain.AgentMemory, 0);
        const fetch_limit = clickhouseMemoryWindowFetchLimit(limit);
        var raw_offset: usize = 0;
        var visible_offset_seen: usize = 0;
        while (true) {
            const states = try self.queryMemoryStatesWindow(allocator, where_clause.items, fetch_limit, raw_offset);
            const fetched = states.len;
            defer {
                for (states) |*state| freeClickHouseMemoryState(allocator, state);
                allocator.free(states);
            }
            if (fetched == 0) break;

            for (states) |state| {
                if (!try entryVisible(allocator, state.entry, filter.actor_id, filter.scopes_json)) continue;
                if (visible_offset_seen < offset) {
                    visible_offset_seen += 1;
                    continue;
                }
                if (out.items.len >= limit) continue;
                try out.append(allocator, try cloneAgentMemory(allocator, state.entry));
            }

            if (out.items.len >= limit or fetched < fetch_limit) break;
            raw_offset = runtimePageOffsetAfterFetch(raw_offset, fetched);
        }

        return out.toOwnedSlice(allocator);
    }

    fn queryMemoryStates(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, where_clause: []const u8, limit: usize) ![]ClickHouseMemoryState {
        return self.queryMemoryStatesWindow(allocator, where_clause, limit, 0);
    }

    fn queryMemoryStatesWindow(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, where_clause: []const u8, limit: usize, offset: usize) ![]ClickHouseMemoryState {
        const query_sql = try std.fmt.allocPrint(
            allocator,
            "SELECT id,actor_id,writer_actor_id,key,session_id,content,category,scope,permissions_json,status,timestamp_ms,event_timestamp_ms,origin_instance_id,origin_sequence FROM {s} FINAL WHERE {s} ORDER BY timestamp_ms DESC, key ASC LIMIT {d} OFFSET {d} FORMAT JSONEachRow",
            .{ self.table, where_clause, @max(@as(usize, 1), @min(limit, 10_000)), offset },
        );
        defer allocator.free(query_sql);
        const body = try self.query(query_sql);
        defer self.allocator.free(body);
        return parseClickHouseMemoryStates(allocator, body);
    }

    fn appendClickHouseMemoryListWhere(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), category: ?[]const u8, session_id: ?[]const u8, include_sessions: bool, actor_id: ?[]const u8) !void {
        try out.appendSlice(allocator, "deleted = 0");
        if (actor_id) |actor| {
            try out.appendSlice(allocator, " AND actor_id = ");
            try clickhouse_contracts.appendStringLiteral(allocator, out, actor);
        }
        if (category) |cat| {
            try out.appendSlice(allocator, " AND category = ");
            try clickhouse_contracts.appendStringLiteral(allocator, out, cat);
        }
        if (session_id) |sid| {
            try out.appendSlice(allocator, " AND session_key = ");
            try clickhouse_contracts.appendStringLiteral(allocator, out, clickhouseSessionKey(sid));
        } else if (!include_sessions) {
            try out.appendSlice(allocator, " AND session_key = ");
            try clickhouse_contracts.appendStringLiteral(allocator, out, clickhouseGlobalSessionKey);
        }
    }

    fn appendClickHouseAutosaveRoleFilter(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8)) !void {
        try out.appendSlice(allocator, " AND (role = ");
        try clickhouse_contracts.appendStringLiteral(allocator, out, "autosave_user");
        try out.appendSlice(allocator, " OR role = ");
        try clickhouse_contracts.appendStringLiteral(allocator, out, "autosave_assistant");
        try out.append(allocator, ')');
    }

    fn appendClickHouseEventOrderCeiling(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), order: EventOrder) !void {
        try out.print(allocator, " AND (event_timestamp_ms < {d} OR (event_timestamp_ms = {d} AND (origin_instance_id < ", .{ order.timestamp_ms, order.timestamp_ms });
        try clickhouse_contracts.appendStringLiteral(allocator, out, order.origin_instance_id);
        try out.appendSlice(allocator, " OR (origin_instance_id = ");
        try clickhouse_contracts.appendStringLiteral(allocator, out, order.origin_instance_id);
        try out.print(allocator, " AND origin_sequence <= {d}))))", .{order.origin_sequence});
    }

    fn cloneClickHouseMemoryStates(allocator: std.mem.Allocator, states: []const ClickHouseMemoryState) ![]domain.AgentMemory {
        var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (out.items) |*entry| freeAgentMemory(allocator, entry);
            out.deinit(allocator);
        }
        for (states) |state| try out.append(allocator, try cloneAgentMemory(allocator, state.entry));
        return out.toOwnedSlice(allocator);
    }

    fn clickhouseMemoryWindowFetchLimit(limit: usize) usize {
        if (limit == 0) return 0;
        if (limit == std.math.maxInt(usize)) return 1000;
        return @min(@as(usize, 1000), @max(@as(usize, 128), limit));
    }

    fn clickhouseVisibleKeyScanLimit() usize {
        return 5000;
    }

    fn clickhouseMessageWindowFetchLimit() usize {
        return 128;
    }

    fn insertMemoryRow(self: *ClickHouseAgentMemory, row: InsertMemoryRow) !void {
        var body: std.ArrayListUnmanaged(u8) = .empty;
        defer body.deinit(self.allocator);
        try body.appendSlice(self.allocator, "{\"id\":");
        try json.appendString(&body, self.allocator, row.id);
        try body.appendSlice(self.allocator, ",\"actor_id\":");
        try json.appendString(&body, self.allocator, row.actor_id);
        try body.appendSlice(self.allocator, ",\"writer_actor_id\":");
        try json.appendString(&body, self.allocator, row.writer_actor_id);
        try body.appendSlice(self.allocator, ",\"key\":");
        try json.appendString(&body, self.allocator, row.key);
        try body.appendSlice(self.allocator, ",\"session_key\":");
        try json.appendString(&body, self.allocator, clickhouseSessionKey(row.session_id));
        try body.appendSlice(self.allocator, ",\"session_id\":");
        try json.appendNullableString(&body, self.allocator, row.session_id);
        try body.appendSlice(self.allocator, ",\"content\":");
        try json.appendString(&body, self.allocator, row.content);
        try body.appendSlice(self.allocator, ",\"category\":");
        try json.appendString(&body, self.allocator, row.category);
        try body.appendSlice(self.allocator, ",\"scope\":");
        try json.appendString(&body, self.allocator, row.scope);
        try body.appendSlice(self.allocator, ",\"permissions_json\":");
        try json.appendString(&body, self.allocator, row.permissions_json);
        try body.appendSlice(self.allocator, ",\"status\":");
        try json.appendString(&body, self.allocator, row.status);
        const event_timestamp_ms = if (row.event_order) |order| order.timestamp_ms else row.timestamp_ms;
        const origin_instance_id = if (row.event_order) |order| order.origin_instance_id else "";
        const origin_sequence = if (row.event_order) |order| order.origin_sequence else 0;
        try body.print(self.allocator, ",\"timestamp_ms\":{d},\"event_timestamp_ms\":{d},\"origin_instance_id\":", .{ row.timestamp_ms, event_timestamp_ms });
        try json.appendString(&body, self.allocator, origin_instance_id);
        try body.print(self.allocator, ",\"origin_sequence\":{d},\"deleted\":{d},\"version\":{d}}}\n", .{ origin_sequence, @intFromBool(row.deleted), clickhouseVersion() });
        const query_sql = try std.fmt.allocPrint(self.allocator, "INSERT INTO {s} FORMAT JSONEachRow", .{self.table});
        defer self.allocator.free(query_sql);
        try self.insert(query_sql, body.items);
    }

    fn tombstoneBlocksPut(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, object_type: []const u8, key: []const u8, session_id: ?[]const u8, actor: []const u8, event_order: EventOrder) !bool {
        const session_key = clickhouseSessionKey(session_id);
        var where_clause: std.ArrayListUnmanaged(u8) = .empty;
        defer where_clause.deinit(allocator);
        try where_clause.appendSlice(allocator, "object_type = ");
        try clickhouse_contracts.appendStringLiteral(allocator, &where_clause, object_type);
        try where_clause.appendSlice(allocator, " AND actor_id = ");
        try clickhouse_contracts.appendStringLiteral(allocator, &where_clause, actor);
        try where_clause.appendSlice(allocator, " AND key = ");
        try clickhouse_contracts.appendStringLiteral(allocator, &where_clause, key);
        try where_clause.appendSlice(allocator, " AND ((tombstone_scope = 'scoped' AND session_key = ");
        try clickhouse_contracts.appendStringLiteral(allocator, &where_clause, session_key);
        try where_clause.appendSlice(allocator, ") OR (tombstone_scope = 'all' AND session_key = '*'))");
        const query_sql = try std.fmt.allocPrint(
            allocator,
            "SELECT event_timestamp_ms,origin_instance_id,origin_sequence FROM {s} FINAL WHERE {s} LIMIT 20 FORMAT JSONEachRow",
            .{ self.tombstones_table, where_clause.items },
        );
        defer allocator.free(query_sql);
        const body = try self.query(query_sql);
        defer self.allocator.free(body);
        return clickhouseTombstoneRowsBlockEventOrder(allocator, body, event_order);
    }

    fn upsertTombstone(self: *ClickHouseAgentMemory, object_type: []const u8, key: []const u8, actor: []const u8, scope: MemoryTombstoneScope, session_id: ?[]const u8, event_order: EventOrder) !void {
        const session_key = if (scope == .all) "*" else clickhouseSessionKey(session_id);
        var body: std.ArrayListUnmanaged(u8) = .empty;
        defer body.deinit(self.allocator);
        try body.appendSlice(self.allocator, "{\"object_type\":");
        try json.appendString(&body, self.allocator, object_type);
        try body.appendSlice(self.allocator, ",\"key\":");
        try json.appendString(&body, self.allocator, key);
        try body.appendSlice(self.allocator, ",\"actor_id\":");
        try json.appendString(&body, self.allocator, actor);
        try body.appendSlice(self.allocator, ",\"tombstone_scope\":");
        try json.appendString(&body, self.allocator, if (scope == .all) "all" else "scoped");
        try body.appendSlice(self.allocator, ",\"session_key\":");
        try json.appendString(&body, self.allocator, session_key);
        try body.appendSlice(self.allocator, ",\"session_id\":");
        try json.appendNullableString(&body, self.allocator, session_id);
        try body.print(self.allocator, ",\"event_timestamp_ms\":{d},\"origin_instance_id\":", .{event_order.timestamp_ms});
        try json.appendString(&body, self.allocator, event_order.origin_instance_id);
        try body.print(self.allocator, ",\"origin_sequence\":{d},\"version\":{d}}}\n", .{ event_order.origin_sequence, clickhouseVersion() });
        const query_sql = try std.fmt.allocPrint(self.allocator, "INSERT INTO {s} FORMAT JSONEachRow", .{self.tombstones_table});
        defer self.allocator.free(query_sql);
        try self.insert(query_sql, body.items);
    }

    fn insertMessageRow(self: *ClickHouseAgentMemory, row: InsertMessageRow) !void {
        var body: std.ArrayListUnmanaged(u8) = .empty;
        defer body.deinit(self.allocator);
        const event_timestamp_ms = if (row.event_order) |order| order.timestamp_ms else row.created_at_ms;
        const origin_instance_id = if (row.event_order) |order| order.origin_instance_id else "";
        const origin_sequence = if (row.event_order) |order| order.origin_sequence else 0;
        try body.appendSlice(self.allocator, "{\"actor_id\":");
        try json.appendString(&body, self.allocator, row.actor_id);
        try body.appendSlice(self.allocator, ",\"session_id\":");
        try json.appendString(&body, self.allocator, row.session_id);
        try body.appendSlice(self.allocator, ",\"message_id\":");
        try json.appendString(&body, self.allocator, row.message_id);
        try body.appendSlice(self.allocator, ",\"role\":");
        try json.appendString(&body, self.allocator, row.role);
        try body.appendSlice(self.allocator, ",\"content\":");
        try json.appendString(&body, self.allocator, row.content);
        try body.print(self.allocator, ",\"created_at_ms\":{d},\"event_timestamp_ms\":{d},\"origin_instance_id\":", .{ row.created_at_ms, event_timestamp_ms });
        try json.appendString(&body, self.allocator, origin_instance_id);
        try body.print(self.allocator, ",\"origin_sequence\":{d},\"deleted\":{d},\"version\":{d}}}\n", .{ origin_sequence, @intFromBool(row.deleted), clickhouseVersion() });
        const query_sql = try std.fmt.allocPrint(self.allocator, "INSERT INTO {s} FORMAT JSONEachRow", .{self.messages_table});
        defer self.allocator.free(query_sql);
        try self.insert(query_sql, body.items);
    }

    fn listMessageStates(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, actor: []const u8, session_id: []const u8, all_sessions: bool) ![]ClickHouseMessageState {
        var where_clause: std.ArrayListUnmanaged(u8) = .empty;
        defer where_clause.deinit(allocator);
        try where_clause.appendSlice(allocator, "deleted = 0 AND actor_id = ");
        try clickhouse_contracts.appendStringLiteral(allocator, &where_clause, actor);
        if (!all_sessions) {
            try where_clause.appendSlice(allocator, " AND session_id = ");
            try clickhouse_contracts.appendStringLiteral(allocator, &where_clause, session_id);
        }
        var out: std.ArrayListUnmanaged(ClickHouseMessageState) = .empty;
        errdefer {
            for (out.items) |*state| freeClickHouseMessageState(allocator, state);
            out.deinit(allocator);
        }
        const fetch_limit = clickhouseMessageWindowFetchLimit();
        var raw_offset: usize = 0;
        while (true) {
            const states = try self.queryMessageStatesWindow(allocator, where_clause.items, fetch_limit, raw_offset);
            const fetched = states.len;
            defer {
                for (states) |*state| freeClickHouseMessageState(allocator, state);
                allocator.free(states);
            }
            if (fetched == 0) break;
            for (states) |*state| {
                try out.append(allocator, state.*);
                detachClickHouseMessageState(state);
            }
            if (fetched < fetch_limit) break;
            raw_offset = runtimePageOffsetAfterFetch(raw_offset, fetched);
        }
        return out.toOwnedSlice(allocator);
    }

    fn queryMessageStatesWindow(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, where_clause: []const u8, limit: usize, offset: usize) ![]ClickHouseMessageState {
        const query_sql = try std.fmt.allocPrint(
            allocator,
            "SELECT actor_id,session_id,message_id,role,content,created_at_ms,event_timestamp_ms,origin_instance_id,origin_sequence FROM {s} FINAL WHERE {s} ORDER BY created_at_ms ASC, role ASC LIMIT {d} OFFSET {d} FORMAT JSONEachRow",
            .{ self.messages_table, where_clause, @max(@as(usize, 1), @min(limit, 10_000)), offset },
        );
        defer allocator.free(query_sql);
        const body = try self.query(query_sql);
        defer self.allocator.free(body);
        return parseClickHouseMessageStates(allocator, body);
    }

    fn insertUsageRow(self: *ClickHouseAgentMemory, row: InsertUsageRow) !void {
        var body: std.ArrayListUnmanaged(u8) = .empty;
        defer body.deinit(self.allocator);
        const event_timestamp_ms = if (row.event_order) |order| order.timestamp_ms else row.updated_at_ms;
        const origin_instance_id = if (row.event_order) |order| order.origin_instance_id else "";
        const origin_sequence = if (row.event_order) |order| order.origin_sequence else 0;
        try body.appendSlice(self.allocator, "{\"actor_id\":");
        try json.appendString(&body, self.allocator, row.actor_id);
        try body.appendSlice(self.allocator, ",\"session_id\":");
        try json.appendString(&body, self.allocator, row.session_id);
        try body.print(self.allocator, ",\"total_tokens\":{d},\"updated_at_ms\":{d},\"event_timestamp_ms\":{d},\"origin_instance_id\":", .{ row.total_tokens, row.updated_at_ms, event_timestamp_ms });
        try json.appendString(&body, self.allocator, origin_instance_id);
        try body.print(self.allocator, ",\"origin_sequence\":{d},\"deleted\":{d},\"version\":{d}}}\n", .{ origin_sequence, @intFromBool(row.deleted), clickhouseVersion() });
        const query_sql = try std.fmt.allocPrint(self.allocator, "INSERT INTO {s} FORMAT JSONEachRow", .{self.usage_table});
        defer self.allocator.free(query_sql);
        try self.insert(query_sql, body.items);
    }

    fn getUsageState(self: *ClickHouseAgentMemory, allocator: std.mem.Allocator, session_id: []const u8, actor: []const u8) !?ClickHouseUsageState {
        var where_clause: std.ArrayListUnmanaged(u8) = .empty;
        defer where_clause.deinit(allocator);
        try where_clause.appendSlice(allocator, "deleted = 0 AND actor_id = ");
        try clickhouse_contracts.appendStringLiteral(allocator, &where_clause, actor);
        try where_clause.appendSlice(allocator, " AND session_id = ");
        try clickhouse_contracts.appendStringLiteral(allocator, &where_clause, session_id);
        const query_sql = try std.fmt.allocPrint(
            allocator,
            "SELECT actor_id,session_id,total_tokens,updated_at_ms,event_timestamp_ms,origin_instance_id,origin_sequence FROM {s} FINAL WHERE {s} LIMIT 1 FORMAT JSONEachRow",
            .{ self.usage_table, where_clause.items },
        );
        defer allocator.free(query_sql);
        const body = try self.query(query_sql);
        defer self.allocator.free(body);
        const values = try parseClickHouseUsageStates(allocator, body);
        if (values.len == 0) {
            allocator.free(values);
            return null;
        }
        const first = values[0];
        allocator.free(values);
        return first;
    }

    fn exec(self: *ClickHouseAgentMemory, sql: []const u8) !void {
        const response = try self.query(sql);
        self.allocator.free(response);
    }

    fn insert(self: *ClickHouseAgentMemory, sql: []const u8, body: []const u8) !void {
        const url = try self.queryUrl(sql);
        defer self.allocator.free(url);
        const response = try clickhousePost(self.allocator, url, self.config.api_key, self.config.timeout_secs, self.config.max_response_bytes, "application/x-ndjson", body);
        defer self.allocator.free(response);
    }

    fn query(self: *ClickHouseAgentMemory, sql: []const u8) ![]u8 {
        const url = try self.queryUrl(sql);
        defer self.allocator.free(url);
        return clickhousePost(self.allocator, url, self.config.api_key, self.config.timeout_secs, self.config.max_response_bytes, "text/plain", "");
    }

    fn queryUrl(self: *ClickHouseAgentMemory, sql: []const u8) ![]u8 {
        return clickhouse_contracts.queryUrl(self.allocator, self.config.base_url.?, sql, self.config.allow_insecure_http);
    }
};

const ApiHttpResponse = struct {
    status: std.http.Status,
    body: []u8,
};

pub const ApiAgentMemory = struct {
    allocator: std.mem.Allocator,
    config: ApiConfig,

    pub fn init(allocator: std.mem.Allocator, config: ApiConfig) !ApiAgentMemory {
        if (config.profile == .byterover) {
            if (std.mem.trim(u8, config.byterover_command, " \t\r\n").len == 0) return error.MissingByteRoverCommand;
            return .{ .allocator = allocator, .config = config };
        }
        const base_url = config.base_url orelse return error.MissingApiBackendUrl;
        if (std.mem.trim(u8, base_url, " \t\r\n").len == 0) return error.MissingApiBackendUrl;
        try net_security.validateHttpBaseUrl(base_url, config.allow_insecure_http);
        return .{ .allocator = allocator, .config = config };
    }

    pub fn deinit(_: *ApiAgentMemory) void {}

    pub fn store(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: Input) !domain.AgentMemory {
        if (self.config.profile == .supermemory) return self.supermemoryStore(allocator, input);
        if (self.config.profile == .openviking) return self.openvikingStore(allocator, input);
        if (self.config.profile == .honcho) return self.honchoStore(allocator, input);
        if (self.config.profile == .mem0) return self.mem0Store(allocator, input);
        if (self.config.profile == .hindsight) return self.hindsightStore(allocator, input);
        if (self.config.profile == .retaindb) return self.retaindbStore(allocator, input);
        if (self.config.profile == .byterover) return self.byteroverStore(allocator, input);
        if (self.config.profile == .zep) return self.zepStore(allocator, input);
        if (self.config.profile == .falkordb) return self.falkordbStore(allocator, input);
        const actor = try access.requiredActorId(input.writer_actor_id orelse input.actor_id);
        if (input.suppress_feed or apiStoreRequiresFeedApply(input, actor)) return self.applyAgentMemoryReducer(allocator, input);
        const scopes = self.scopesForInput(input);
        const encoded_key = try percentEncode(allocator, input.key);
        defer allocator.free(encoded_key);
        const path = try std.fmt.allocPrint(allocator, "/agent-memory/{s}", .{encoded_key});
        defer allocator.free(path);

        const body = try agentMemoryStorePayload(allocator, input);
        defer allocator.free(body);
        const response = try self.requestWithCapabilities(allocator, .PUT, path, "", actor, scopes, self.capabilitiesForInput(input), body);
        defer allocator.free(response.body);
        if (response.status != .ok) return error.AgentMemoryStorageUnavailable;
        return try parseAgentMemoryWrapper(allocator, response.body, "memory");
    }

    fn applyAgentMemoryReducer(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: Input) !domain.AgentMemory {
        const actor = try access.requiredActorId(input.writer_actor_id orelse input.actor_id);
        const scopes = self.scopesForInput(input);
        const body = try agentMemoryApplyPayload(allocator, input, actor);
        defer allocator.free(body);
        const response = try self.requestRuntimeApplyWithCapabilities(allocator, actor, scopes, self.capabilitiesForInput(input), body);
        defer allocator.free(response.body);
        if (response.status != .ok) return error.AgentMemoryStorageUnavailable;
        return (try self.getAppliedMemory(allocator, input, actor)) orelse error.AgentMemoryStorageUnavailable;
    }

    fn getAppliedMemory(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: Input, actor: []const u8) !?domain.AgentMemory {
        const payload_scope = agentMemoryPayloadScope(input);
        const read_actor = if (payload_scope != null) actor else input.actor_id orelse actor;
        return self.getWithCapabilities(allocator, input.key, input.session_id, read_actor, self.scopesForInput(input), self.capabilitiesForInput(input), payload_scope);
    }

    fn scopesForInput(self: *const ApiAgentMemory, input: Input) []const u8 {
        return input.actor_scopes_json orelse self.config.actor_scopes_json;
    }

    fn capabilitiesForInput(self: *const ApiAgentMemory, input: Input) []const u8 {
        return input.actor_capabilities_json orelse self.config.actor_capabilities_json;
    }

    pub fn getByInput(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: GetInput) !?domain.AgentMemory {
        const normalized_session_id = access.normalizeSessionId(input.session_id);
        if (input.scopes_json) |scopes_json| {
            const actor_id = input.actor_id orelse return error.InvalidAgentMemoryRuntimeRequest;
            if (!input.any_session) return self.getWithCapabilities(allocator, input.key, normalized_session_id, actor_id, scopes_json, input.capabilities_json, null);
            if (self.config.profile == .supermemory) return self.supermemoryGet(allocator, input.key, null, actor_id, scopes_json, input.capabilities_json, null);
            if (self.config.profile == .openviking) return self.openvikingGet(allocator, input.key, null, actor_id, scopes_json, input.capabilities_json, null);
            if (self.config.profile == .honcho) return self.honchoGet(allocator, input.key, null, actor_id, scopes_json, input.capabilities_json, null);
            if (self.config.profile == .mem0) return self.mem0Get(allocator, input.key, null, actor_id, scopes_json, input.capabilities_json, null);
            if (self.config.profile == .hindsight) return self.hindsightGet(allocator, input.key, null, actor_id, scopes_json, input.capabilities_json, null);
            if (self.config.profile == .retaindb) return self.retaindbGet(allocator, input.key, null, actor_id, scopes_json, input.capabilities_json, null);
            if (self.config.profile == .byterover) return self.byteroverGetAnyVisible(allocator, input.key, actor_id, scopes_json, input.capabilities_json);
            if (self.config.profile == .zep) return self.zepGet(allocator, input.key, null, actor_id, scopes_json, input.capabilities_json, null);
            if (self.config.profile == .falkordb) return self.falkordbGet(allocator, input.key, null, actor_id, scopes_json, input.capabilities_json, null);
            const encoded_key = try percentEncode(allocator, input.key);
            defer allocator.free(encoded_key);
            const path = try std.fmt.allocPrint(allocator, "/agent-memory/{s}", .{encoded_key});
            defer allocator.free(path);
            const query = try agentMemoryAnyVisibleQuery(allocator);
            defer allocator.free(query);
            const response = try self.requestWithCapabilities(allocator, .GET, path, query, actor_id, scopes_json, input.capabilities_json, "");
            defer allocator.free(response.body);
            if (response.status == .not_found) return null;
            if (response.status != .ok) return error.AgentMemoryStorageUnavailable;
            return try parseAgentMemoryWrapper(allocator, response.body, "memory");
        }
        const actor = input.actor_id orelse return null;
        const scope = sharedScopeFromOwner(actor);
        const scopes = if (scope) |s| try scopesJson(allocator, &.{s}) else try allocator.dupe(u8, "[]");
        defer allocator.free(scopes);
        return self.getWithCapabilities(allocator, input.key, normalized_session_id, actor, scopes, apiEffectiveCapabilities(self.config, input.capabilities_json), scope);
    }

    pub fn listByInput(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: ListInput) ![]domain.AgentMemory {
        const normalized_session_id = access.normalizeSessionId(input.session_id);
        if (input.scopes_json) |scopes_json| {
            const actor_id = input.actor_id orelse return error.InvalidAgentMemoryRuntimeRequest;
            if (input.limit) |limit| {
                return self.listWithCapabilitiesWindow(allocator, input.category, if (input.any_session) null else normalized_session_id, actor_id, scopes_json, input.capabilities_json, null, input.any_session, limit, input.offset);
            }
            return self.listWithCapabilities(allocator, input.category, if (input.any_session) null else normalized_session_id, actor_id, scopes_json, input.capabilities_json, null, input.any_session);
        }
        const actor = input.actor_id orelse return allocator.alloc(domain.AgentMemory, 0);
        const scope = sharedScopeFromOwner(actor);
        const scopes = if (scope) |s| try scopesJson(allocator, &.{s}) else try allocator.dupe(u8, "[]");
        defer allocator.free(scopes);
        const capabilities = apiEffectiveCapabilities(self.config, input.capabilities_json);
        if (input.limit) |limit| {
            return self.listWithCapabilitiesWindow(allocator, input.category, normalized_session_id, actor, scopes, capabilities, scope, false, limit, input.offset);
        }
        return self.listWithCapabilities(allocator, input.category, normalized_session_id, actor, scopes, capabilities, scope, false);
    }

    pub fn searchByInput(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: SearchInput) ![]domain.AgentMemory {
        const actor = input.actor_id orelse return allocator.alloc(domain.AgentMemory, 0);
        if (input.limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        const normalized_session_id = access.normalizeSessionId(input.session_id);
        if (input.any_session) {
            if (self.config.profile == .supermemory) return self.supermemorySearch(allocator, input.query, input.limit, null, input.scopes_json, actor, input.capabilities_json, true, null);
            if (self.config.profile == .openviking) return self.openvikingSearch(allocator, input.query, input.limit, null, input.scopes_json, actor, input.capabilities_json, true, null);
            if (self.config.profile == .honcho) return self.honchoSearch(allocator, input.query, input.limit, null, input.scopes_json, actor, input.capabilities_json, true, null, null);
            if (self.config.profile == .mem0) return self.mem0Search(allocator, input.query, input.limit, null, input.scopes_json, actor, input.capabilities_json, true, null, null);
            if (self.config.profile == .hindsight) return self.hindsightSearch(allocator, input.query, input.limit, null, input.scopes_json, actor, input.capabilities_json, true, null, null);
            if (self.config.profile == .retaindb) return self.retaindbSearch(allocator, input.query, input.limit, null, input.scopes_json, actor, input.capabilities_json, true, null, null);
            if (self.config.profile == .byterover) return self.byteroverSearch(allocator, input.query, input.limit, null, input.scopes_json, actor, input.capabilities_json, true, null, null);
            if (self.config.profile == .zep) return self.zepSearch(allocator, input.query, input.limit, null, input.scopes_json, actor, input.capabilities_json, true, null, null);
            if (self.config.profile == .falkordb) return self.falkordbSearch(allocator, input.query, input.limit, null, input.scopes_json, actor, input.capabilities_json, true, null, null);
            const body = try agentMemorySearchPayload(allocator, input.query, input.limit, null, true, input.scopes_json);
            defer allocator.free(body);
            const response = try self.requestWithCapabilities(allocator, .POST, "/agent-memory/search", "", actor, input.scopes_json, input.capabilities_json, body);
            defer allocator.free(response.body);
            if (response.status != .ok) return error.AgentMemoryStorageUnavailable;
            const out = try parseAgentMemoryArrayWrapper(allocator, response.body, "memories");
            if (out.len > input.limit) {
                for (out[input.limit..]) |*entry| freeAgentMemory(allocator, entry);
                return allocator.realloc(out, input.limit);
            }
            return out;
        }
        if (self.config.profile == .supermemory) return self.supermemorySearch(allocator, input.query, input.limit, normalized_session_id, input.scopes_json, actor, input.capabilities_json, false, null);
        if (self.config.profile == .openviking) return self.openvikingSearch(allocator, input.query, input.limit, normalized_session_id, input.scopes_json, actor, input.capabilities_json, false, null);
        if (self.config.profile == .honcho) return self.honchoSearch(allocator, input.query, input.limit, normalized_session_id, input.scopes_json, actor, input.capabilities_json, false, null, null);
        if (self.config.profile == .mem0) return self.mem0Search(allocator, input.query, input.limit, normalized_session_id, input.scopes_json, actor, input.capabilities_json, false, null, null);
        if (self.config.profile == .hindsight) return self.hindsightSearch(allocator, input.query, input.limit, normalized_session_id, input.scopes_json, actor, input.capabilities_json, false, null, null);
        if (self.config.profile == .retaindb) return self.retaindbSearch(allocator, input.query, input.limit, normalized_session_id, input.scopes_json, actor, input.capabilities_json, false, null, null);
        if (self.config.profile == .byterover) return self.byteroverSearch(allocator, input.query, input.limit, normalized_session_id, input.scopes_json, actor, input.capabilities_json, false, null, null);
        if (self.config.profile == .zep) return self.zepSearch(allocator, input.query, input.limit, normalized_session_id, input.scopes_json, actor, input.capabilities_json, false, null, null);
        if (self.config.profile == .falkordb) return self.falkordbSearch(allocator, input.query, input.limit, normalized_session_id, input.scopes_json, actor, input.capabilities_json, false, null, null);
        const body = try agentMemorySearchPayload(allocator, input.query, input.limit, normalized_session_id, false, input.scopes_json);
        defer allocator.free(body);
        const response = try self.requestWithCapabilities(allocator, .POST, "/agent-memory/search", "", actor, input.scopes_json, input.capabilities_json, body);
        defer allocator.free(response.body);
        if (response.status != .ok) return error.AgentMemoryStorageUnavailable;
        const out = try parseAgentMemoryArrayWrapper(allocator, response.body, "memories");
        if (out.len > input.limit) {
            for (out[input.limit..]) |*entry| freeAgentMemory(allocator, entry);
            return allocator.realloc(out, input.limit);
        }
        return out;
    }

    fn listWithScopes(self: *ApiAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, exact_scope: ?[]const u8, include_sessions: bool) ![]domain.AgentMemory {
        return self.listWithCapabilities(allocator, category, session_id, actor_id, scopes_json, null, exact_scope, include_sessions);
    }

    fn listWithCapabilities(self: *ApiAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, exact_scope: ?[]const u8, include_sessions: bool) ![]domain.AgentMemory {
        if (self.config.profile == .supermemory) return self.supermemoryList(allocator, category, session_id, actor_id, scopes_json, capabilities_json, exact_scope, include_sessions, 500, 0);
        if (self.config.profile == .openviking) return self.openvikingList(allocator, category, session_id, actor_id, scopes_json, capabilities_json, exact_scope, include_sessions, 500, 0);
        if (self.config.profile == .honcho) return self.honchoList(allocator, category, session_id, actor_id, scopes_json, capabilities_json, exact_scope, include_sessions, 500, 0);
        if (self.config.profile == .mem0) return self.mem0List(allocator, category, session_id, actor_id, scopes_json, capabilities_json, exact_scope, include_sessions, 500, 0);
        if (self.config.profile == .hindsight) return self.hindsightList(allocator, category, session_id, actor_id, scopes_json, capabilities_json, exact_scope, include_sessions, 500, 0);
        if (self.config.profile == .retaindb) return self.retaindbList(allocator, category, session_id, actor_id, scopes_json, capabilities_json, exact_scope, include_sessions, 500, 0);
        if (self.config.profile == .byterover) return self.byteroverList(allocator, category, session_id, actor_id, scopes_json, capabilities_json, exact_scope, include_sessions, 500, 0);
        if (self.config.profile == .zep) return self.zepList(allocator, category, session_id, actor_id, scopes_json, capabilities_json, exact_scope, include_sessions, 500, 0);
        if (self.config.profile == .falkordb) return self.falkordbList(allocator, category, session_id, actor_id, scopes_json, capabilities_json, exact_scope, include_sessions, 500, 0);
        var all: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (all.items) |*entry| freeAgentMemory(allocator, entry);
            all.deinit(allocator);
        }

        var offset: usize = 0;
        const page_size: usize = 500;
        while (true) {
            const query = try agentMemoryListQuery(allocator, category, session_id, exact_scope, include_sessions, true, page_size, offset);
            defer allocator.free(query);
            const response = try self.requestWithCapabilities(allocator, .GET, "/agent-memory", query, actor_id, scopes_json, capabilities_json, "");
            defer allocator.free(response.body);
            if (response.status != .ok) return error.AgentMemoryStorageUnavailable;
            const page = try parseAgentMemoryArrayWrapper(allocator, response.body, "memories");
            defer allocator.free(page);
            const page_len = page.len;
            for (page) |entry| try all.append(allocator, entry);
            if (page_len < page_size) break;
            offset = runtimeNextPageOffset(offset, page_len) orelse break;
        }
        sortAgentMemory(all.items);
        return all.toOwnedSlice(allocator);
    }

    fn listWithScopesWindow(self: *ApiAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, exact_scope: ?[]const u8, include_sessions: bool, limit: usize, offset: usize) ![]domain.AgentMemory {
