    fn listWithCapabilitiesWindow(self: *ApiAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, exact_scope: ?[]const u8, include_sessions: bool, limit: usize, offset: usize) ![]domain.AgentMemory {
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        if (self.config.profile == .supermemory) return self.supermemoryList(allocator, category, session_id, actor_id, scopes_json, capabilities_json, exact_scope, include_sessions, limit, offset);
        if (self.config.profile == .openviking) return self.openvikingList(allocator, category, session_id, actor_id, scopes_json, capabilities_json, exact_scope, include_sessions, limit, offset);
        if (self.config.profile == .honcho) return self.honchoList(allocator, category, session_id, actor_id, scopes_json, capabilities_json, exact_scope, include_sessions, limit, offset);
        if (self.config.profile == .mem0) return self.mem0List(allocator, category, session_id, actor_id, scopes_json, capabilities_json, exact_scope, include_sessions, limit, offset);
        if (self.config.profile == .hindsight) return self.hindsightList(allocator, category, session_id, actor_id, scopes_json, capabilities_json, exact_scope, include_sessions, limit, offset);
        if (self.config.profile == .retaindb) return self.retaindbList(allocator, category, session_id, actor_id, scopes_json, capabilities_json, exact_scope, include_sessions, limit, offset);
        if (self.config.profile == .byterover) return self.byteroverList(allocator, category, session_id, actor_id, scopes_json, capabilities_json, exact_scope, include_sessions, limit, offset);
        if (self.config.profile == .zep) return self.zepList(allocator, category, session_id, actor_id, scopes_json, capabilities_json, exact_scope, include_sessions, limit, offset);
        if (self.config.profile == .falkordb) return self.falkordbList(allocator, category, session_id, actor_id, scopes_json, capabilities_json, exact_scope, include_sessions, limit, offset);
        const query = try agentMemoryListQuery(allocator, category, session_id, exact_scope, include_sessions, true, limit, offset);
        defer allocator.free(query);
        const response = try self.requestWithCapabilities(allocator, .GET, "/agent-memory", query, actor_id, scopes_json, capabilities_json, "");
        defer allocator.free(response.body);
        if (response.status != .ok) return error.AgentMemoryStorageUnavailable;
        const out = try parseAgentMemoryArrayWrapper(allocator, response.body, "memories");
        return remoteAgentMemoryWindowPage(allocator, out, limit);
    }

    pub fn deleteByInput(self: *ApiAgentMemory, input: DeleteInput) !bool {
        if (input.all_owners) {
            if (self.config.profile.supportsNullPantryRuntimeApi()) {
                if (input.event_order != null or input.suppress_feed) {
                    return self.deleteAllApplyRemote(input.key, input.actor_id, input.writer_actor_id, input.event_order, input.suppress_feed, input.actor_scopes_json, input.actor_capabilities_json);
                }
            }
            return self.deleteAllRemote(input.key, input.actor_id, input.writer_actor_id, input.actor_scopes_json, input.actor_capabilities_json);
        }
        const normalized_session_id = access.normalizeSessionId(input.session_id);
        if (self.config.profile.supportsNullPantryRuntimeApi()) {
            if (input.event_order != null or input.suppress_feed) {
                return self.deleteApplyRemote(input.key, normalized_session_id, input.actor_id, input.writer_actor_id, input.event_order, input.suppress_feed, input.actor_scopes_json, input.actor_capabilities_json);
            }
        }
        return self.deleteExactRemote(input.key, normalized_session_id, input.actor_id, input.writer_actor_id, input.actor_scopes_json, input.actor_capabilities_json);
    }

    fn deleteExactRemote(self: *ApiAgentMemory, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        if (self.config.profile == .supermemory) return self.supermemoryDelete(key, session_id, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json);
        if (self.config.profile == .openviking) return self.openvikingDelete(key, session_id, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json);
        if (self.config.profile == .honcho) return self.honchoDelete(key, session_id, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json);
        if (self.config.profile == .mem0) return self.mem0Delete(key, session_id, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json);
        if (self.config.profile == .hindsight) return self.hindsightDelete(key, session_id, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json);
        if (self.config.profile == .retaindb) return self.retaindbDelete(key, session_id, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json);
        if (self.config.profile == .byterover) return self.byteroverDelete(key, session_id, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json);
        if (self.config.profile == .zep) return self.zepDelete(key, session_id, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json);
        if (self.config.profile == .falkordb) return self.falkordbDelete(key, session_id, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json);
        const actor = writer_actor_id orelse actor_id orelse return false;
        const encoded_key = try percentEncode(self.allocator, key);
        defer self.allocator.free(encoded_key);
        const path = try std.fmt.allocPrint(self.allocator, "/agent-memory/{s}", .{encoded_key});
        defer self.allocator.free(path);
        const scope = if (actor_id) |owner| sharedScopeFromOwner(owner) else null;
        const query = try agentMemoryExactQuery(self.allocator, session_id, scope);
        defer self.allocator.free(query);
        const response = try self.requestWithCapabilities(self.allocator, .DELETE, path, query, actor, apiEffectiveScopes(self.config, actor_scopes_json), apiEffectiveCapabilities(self.config, actor_capabilities_json), "");
        defer self.allocator.free(response.body);
        if (response.status == .not_found) return false;
        if (response.status != .ok and response.status != .no_content) return error.AgentMemoryStorageUnavailable;
        return true;
    }

