            return items.len;
        }
        if (self.config.profile == .zep) {
            const actor = actor_id orelse return 0;
            const items = try self.zepSearch(self.allocator, "nullpantry", 500, null, scopes_json, actor, capabilities_json, true, null, null);
            defer {
                for (items) |*entry| freeAgentMemory(self.allocator, entry);
                self.allocator.free(items);
            }
            return items.len;
        }
        if (self.config.profile == .falkordb) {
            const actor = actor_id orelse return 0;
            const items = try self.falkordbSearch(self.allocator, "nullpantry", 500, null, scopes_json, actor, capabilities_json, true, null, null);
            defer {
                for (items) |*entry| freeAgentMemory(self.allocator, entry);
                self.allocator.free(items);
            }
            return items.len;
        }
        const actor = actor_id orelse "";
        const response = try self.requestWithCapabilities(self.allocator, .GET, "/agent-memory/count", "", actor, scopes_json, capabilities_json, "");
        defer self.allocator.free(response.body);
        if (response.status != .ok) return error.AgentMemoryStorageUnavailable;
        return parseJsonCount(self.allocator, response.body, "count", 0);
    }

