    fn recountRuntimeFeedStatus(self: *ApiAgentMemory, allocator: std.mem.Allocator, status: *FeedStatus, actor_id: ?[]const u8, scopes_json: []const u8, capabilities_json: ?[]const u8) !void {
        status.visible_events = 0;
        status.pending_events = 0;
        status.applying_events = 0;
        status.applied_events = 0;

        var cursor = status.cursor_floor;
        const page_limit: usize = 500;
        while (cursor < status.max_event_id) {
            const query = try feedEventsQuery(allocator, cursor, page_limit);
            defer allocator.free(query);
            const response = try self.requestFeedWithCapabilities(allocator, .GET, "/memory/events", query, actor_id, scopes_json, capabilities_json, "");
            defer allocator.free(response.body);
            try requireApiFeedOk(response.status);
            const events = try parseRuntimeFeedEventsVisibleWrapper(allocator, response.body, actor_id, scopes_json);
            defer {
                for (events) |*event| event.deinit(allocator);
                allocator.free(events);
            }
            if (events.len == 0) break;
            for (events) |event| {
                cursor = @max(cursor, event.id);
                status.visible_events += 1;
                if (std.mem.eql(u8, event.status, "pending")) {
                    status.pending_events += 1;
                } else if (std.mem.eql(u8, event.status, "applying")) {
                    status.applying_events += 1;
                } else if (std.mem.eql(u8, event.status, "applied")) {
                    status.applied_events += 1;
                }
            }
            if (events.len < page_limit) break;
        }
    }

    fn getWithScopes(self: *ApiAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, explicit_scope: ?[]const u8) !?domain.AgentMemory {
