    fn getWithCapabilities(self: *ApiAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, explicit_scope: ?[]const u8) !?domain.AgentMemory {
        if (self.config.profile == .supermemory) return self.supermemoryGet(allocator, key, session_id, actor_id, scopes_json, capabilities_json, explicit_scope);
        if (self.config.profile == .openviking) return self.openvikingGet(allocator, key, session_id, actor_id, scopes_json, capabilities_json, explicit_scope);
        if (self.config.profile == .honcho) return self.honchoGet(allocator, key, session_id, actor_id, scopes_json, capabilities_json, explicit_scope);
        if (self.config.profile == .mem0) return self.mem0Get(allocator, key, session_id, actor_id, scopes_json, capabilities_json, explicit_scope);
        if (self.config.profile == .hindsight) return self.hindsightGet(allocator, key, session_id, actor_id, scopes_json, capabilities_json, explicit_scope);
        if (self.config.profile == .retaindb) return self.retaindbGet(allocator, key, session_id, actor_id, scopes_json, capabilities_json, explicit_scope);
        if (self.config.profile == .byterover) return self.byteroverGet(allocator, key, session_id, actor_id, scopes_json, capabilities_json, explicit_scope);
        if (self.config.profile == .zep) return self.zepGet(allocator, key, session_id, actor_id, scopes_json, capabilities_json, explicit_scope);
        if (self.config.profile == .falkordb) return self.falkordbGet(allocator, key, session_id, actor_id, scopes_json, capabilities_json, explicit_scope);
        const encoded_key = try percentEncode(allocator, key);
        defer allocator.free(encoded_key);
        const path = try std.fmt.allocPrint(allocator, "/agent-memory/{s}", .{encoded_key});
        defer allocator.free(path);
        const query = try agentMemoryExactQuery(allocator, session_id, explicit_scope);
        defer allocator.free(query);
        const response = try self.requestWithCapabilities(allocator, .GET, path, query, actor_id, scopes_json, capabilities_json, "");
        defer allocator.free(response.body);
        if (response.status == .not_found) return null;
        if (response.status != .ok) return error.AgentMemoryStorageUnavailable;
        return try parseAgentMemoryWrapper(allocator, response.body, "memory");
    }

    fn request(self: *ApiAgentMemory, allocator: std.mem.Allocator, method: std.http.Method, path: []const u8, query: []const u8, actor_id: ?[]const u8, scopes_json: ?[]const u8, payload: []const u8) !ApiHttpResponse {
