    fn requestWithCapabilities(self: *ApiAgentMemory, allocator: std.mem.Allocator, method: std.http.Method, path: []const u8, query: []const u8, actor_id: ?[]const u8, scopes_json: ?[]const u8, capabilities_json: ?[]const u8, payload: []const u8) !ApiHttpResponse {
        if (!self.config.profile.supportsNullPantryRuntimeApi()) return error.UnsupportedAgentMemoryRuntimeOperation;
        const routed_query = try apiRemoteStorageQuery(allocator, query, self.config.remote_storage);
        defer allocator.free(routed_query);
        const url = try apiBackendUrl(allocator, self.config.base_url.?, path, routed_query, self.config.allow_insecure_http);
        defer allocator.free(url);
        return requestApiJson(allocator, method, url, self.config, actor_id, scopes_json, capabilities_json, payload);
    }

