    fn supermemoryStore(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: Input) !domain.AgentMemory {
        const actor = try access.requiredActorId(input.writer_actor_id orelse input.actor_id);
        const owner = try externalAgentMemoryOwner(allocator, input.actor_id orelse actor, input.scope);
        defer allocator.free(owner);
        var write_input = input;
        var reduced_content: ?[]u8 = null;
        defer if (reduced_content) |content| allocator.free(content);

        var existing: ?domain.AgentMemory = null;
        defer if (existing) |*entry| freeAgentMemory(allocator, entry);
        if (input.operation != .put) {
            existing = try self.supermemoryGet(allocator, input.key, input.session_id, owner, self.scopesForInput(input), self.capabilitiesForInput(input), input.scope);
            reduced_content = try agent_memory_reducer.reduceContent(allocator, input.operation, if (existing) |entry| entry.content else null, input.content);
            write_input.content = reduced_content.?;
            write_input.operation = .put;
        }

        const mapped_input = supermemory.WriteInput{
            .key = write_input.key,
            .content = write_input.content,
            .category = write_input.category,
            .session_id = write_input.session_id,
            .owner_actor_id = owner,
            .writer_actor_id = actor,
            .requested_scope = write_input.scope,
            .requested_permissions_json = write_input.permissions_json,
            .metadata_json = write_input.metadata_json,
            .timestamp_ms = eventTimestampMs(write_input),
            .status = if (existing) |entry| entry.status else "proposed",
        };
        const body = try supermemory.documentPayload(allocator, mapped_input);
        defer allocator.free(body);
        const response = try self.supermemoryRequest(allocator, .POST, "/v3/documents", "", actor, self.scopesForInput(input), self.capabilitiesForInput(input), body);
        defer allocator.free(response.body);
        if (response.status != .ok and response.status != .created and response.status != .accepted) return error.AgentMemoryStorageUnavailable;
        return try supermemory.agentMemoryFromWriteInput(allocator, mapped_input, response.body);
    }

    fn supermemoryGet(self: *ApiAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, explicit_scope: ?[]const u8) !?domain.AgentMemory {
        const owner = try externalAgentMemoryOwner(allocator, actor_id, explicit_scope);
        defer allocator.free(owner);
        const custom_id = try supermemory.customId(allocator, owner, session_id, key);
        defer allocator.free(custom_id);
        const path = try supermemory.documentPath(allocator, custom_id);
        defer allocator.free(path);
        const response = try self.supermemoryRequest(allocator, .GET, path, "", actor_id, scopes_json, capabilities_json, "");
        defer allocator.free(response.body);
        if (response.status == .not_found) return null;
        if (response.status == .ok) {
            if (try supermemory.agentMemoryFromBody(allocator, response.body, actor_id, scopes_json, key, session_id, false)) |entry| return entry;
        }
        if (response.status != .ok and response.status != .not_found) return error.AgentMemoryStorageUnavailable;
        var found = try self.supermemorySearch(allocator, key, 10, session_id, scopes_json, actor_id, capabilities_json, false, key);
        defer allocator.free(found);
        if (found.len == 0) return null;
        const first = found[0];
        detachAgentMemory(&found[0]);
