    fn supermemorySearch(self: *ApiAgentMemory, allocator: std.mem.Allocator, query_text: []const u8, limit: usize, session_id: ?[]const u8, scopes_json: []const u8, actor_id: []const u8, capabilities_json: ?[]const u8, include_sessions: bool, exact_key: ?[]const u8) ![]domain.AgentMemory {
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        var targets = try supermemory.visibleContainerTags(allocator, actor_id, scopes_json);
        defer targets.deinit(allocator);
        var merged: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (merged.items) |*entry| freeAgentMemory(allocator, entry);
            merged.deinit(allocator);
        }
        const per_tag_limit = @max(limit, 1);
        if (targets.use_global_scan) {
            try self.supermemorySearchContainer(allocator, &merged, query_text, per_tag_limit, null, session_id, scopes_json, actor_id, capabilities_json, include_sessions, exact_key);
        } else {
            for (targets.tags.items) |tag| {
                try self.supermemorySearchContainer(allocator, &merged, query_text, per_tag_limit, tag, session_id, scopes_json, actor_id, capabilities_json, include_sessions, exact_key);
            }
