    fn supermemorySearchContainer(self: *ApiAgentMemory, allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(domain.AgentMemory), query_text: []const u8, limit: usize, container_tag: ?[]const u8, session_id: ?[]const u8, scopes_json: []const u8, actor_id: []const u8, capabilities_json: ?[]const u8, include_sessions: bool, exact_key: ?[]const u8) !void {
