        const response = try self.supermemoryRequest(allocator, .POST, "/v4/search", "", actor_id, scopes_json, capabilities_json, body);
        defer allocator.free(response.body);
        if (response.status != .ok) return error.AgentMemoryStorageUnavailable;
        const parsed = try supermemory.agentMemoryArrayFromBody(allocator, response.body, actor_id, scopes_json, exact_key, session_id, include_sessions);
        defer {
            for (parsed) |*entry| freeAgentMemory(allocator, entry);
            allocator.free(parsed);
        }
        for (parsed) |*entry| {
            try supermemory.appendUniqueAgentMemory(allocator, out, entry.*);
            detachAgentMemory(entry);
        }
    }

    fn supermemoryDelete(self: *ApiAgentMemory, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        const owner = actor_id orelse return false;
        const actor = writer_actor_id orelse owner;
        const scopes_json = apiEffectiveScopes(self.config, actor_scopes_json);
        const capabilities_json = apiEffectiveCapabilities(self.config, actor_capabilities_json);
        const custom_id = try supermemory.customId(self.allocator, owner, session_id, key);
        defer self.allocator.free(custom_id);
        var deleted = try self.supermemoryDeleteDocumentId(custom_id, actor, scopes_json, capabilities_json);
        if (deleted) return true;

        const matches = try self.supermemorySearch(self.allocator, key, 20, session_id, scopes_json, actor, capabilities_json, session_id != null, key);
        defer {
            for (matches) |*entry| freeAgentMemory(self.allocator, entry);
            self.allocator.free(matches);
        }
        for (matches) |entry| {
            if (!std.mem.eql(u8, entry.actor_id, owner)) continue;
            if (session_id) |sid| {
                if (entry.session_id == null or !std.mem.eql(u8, entry.session_id.?, sid)) continue;
            } else if (entry.session_id != null) {
                continue;
            }
            if (std.mem.eql(u8, entry.id, custom_id)) continue;
            if (try self.supermemoryDeleteDocumentId(entry.id, actor, scopes_json, capabilities_json)) deleted = true;
        }
        return deleted;
    }

    fn supermemoryDeleteDocumentId(self: *ApiAgentMemory, document_id: []const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: []const u8) !bool {
        const path = try supermemory.documentPath(self.allocator, document_id);
        defer self.allocator.free(path);
        const response = try self.supermemoryRequest(self.allocator, .DELETE, path, "", actor_id, scopes_json, capabilities_json, "");
        defer self.allocator.free(response.body);
        if (response.status == .not_found) return false;
        if (response.status != .ok and response.status != .no_content and response.status != .accepted) return error.AgentMemoryStorageUnavailable;
        return true;
    }

    fn supermemoryDeleteAll(self: *ApiAgentMemory, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        const owner = actor_id orelse return false;
        var deleted = try self.supermemoryDelete(key, null, owner, writer_actor_id, actor_scopes_json, actor_capabilities_json);
        const actor = writer_actor_id orelse owner;
        const scopes_json = apiEffectiveScopes(self.config, actor_scopes_json);
        const matches = try self.supermemorySearch(self.allocator, key, 100, null, scopes_json, actor, actor_capabilities_json, true, key);
        defer {
            for (matches) |*entry| freeAgentMemory(self.allocator, entry);
            self.allocator.free(matches);
        }
        for (matches) |entry| {
            if (!std.mem.eql(u8, entry.actor_id, owner)) continue;
            if (entry.session_id) |sid| {
                if (try self.supermemoryDelete(key, sid, owner, writer_actor_id, actor_scopes_json, actor_capabilities_json)) deleted = true;
            }
        }
        return deleted;
    }

    fn supermemoryPatchStatus(self: *ApiAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, status: []const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        const owner = actor_id orelse return false;
        const actor = writer_actor_id orelse owner;
        if (std.mem.eql(u8, status, "deleted")) return self.supermemoryDelete(key, session_id, owner, actor, actor_scopes_json, actor_capabilities_json);
        const scopes_json = apiEffectiveScopes(self.config, actor_scopes_json);
        var entry = (try self.supermemoryGet(allocator, key, session_id, owner, scopes_json, actor_capabilities_json, sharedScopeFromOwner(owner))) orelse return false;
        defer freeAgentMemory(allocator, &entry);
        const mapped_input = supermemory.WriteInput{
            .key = entry.key,
            .content = entry.content,
            .category = entry.category,
            .session_id = entry.session_id,
            .owner_actor_id = entry.actor_id,
            .writer_actor_id = actor,
            .requested_scope = entry.scope,
            .requested_permissions_json = entry.permissions_json,
            .metadata_json = "{}",
            .timestamp_ms = ids.nowMs(),
            .status = status,
            .remote_id = entry.id,
        };
        const body = try supermemory.documentPayload(allocator, mapped_input);
        defer allocator.free(body);
        const response = try self.supermemoryRequest(allocator, .POST, "/v3/documents", "", actor, scopes_json, apiEffectiveCapabilities(self.config, actor_capabilities_json), body);
        defer allocator.free(response.body);
        if (response.status != .ok and response.status != .created and response.status != .accepted) return error.AgentMemoryStorageUnavailable;
        return true;
    }

