    fn openvikingStore(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: Input) !domain.AgentMemory {
        const actor = try access.requiredActorId(input.writer_actor_id orelse input.actor_id);
        const owner = try externalAgentMemoryOwner(allocator, input.actor_id orelse actor, input.scope);
        defer allocator.free(owner);
        var write_input = input;
        var reduced_content: ?[]u8 = null;
        defer if (reduced_content) |content| allocator.free(content);

        if (input.operation != .put) {
            var existing = try self.openvikingGet(allocator, input.key, input.session_id, owner, self.scopesForInput(input), self.capabilitiesForInput(input), input.scope);
            defer if (existing) |*entry| freeAgentMemory(allocator, entry);
            reduced_content = try agent_memory_reducer.reduceContent(allocator, input.operation, if (existing) |entry| entry.content else null, input.content);
            write_input.content = reduced_content.?;
            write_input.operation = .put;
        }

        const uri = try openviking.memoryUri(allocator, owner, write_input.session_id, write_input.key);
        defer allocator.free(uri);
        const mapped_input = openviking.WriteInput{
            .key = write_input.key,
            .content = write_input.content,
            .category = write_input.category,
            .session_id = write_input.session_id,
            .owner_actor_id = owner,
            .writer_actor_id = actor,
            .requested_scope = write_input.scope,
            .requested_permissions_json = write_input.permissions_json,
            .metadata_json = write_input.metadata_json,
            .timestamp_ms = eventTimestampMs(write_input),
            .status = "proposed",
        };
        const content = try openviking.contentPayload(allocator, mapped_input, uri);
        defer allocator.free(content);
        try self.openvikingWriteContent(allocator, uri, content, actor, self.scopesForInput(input), self.capabilitiesForInput(input));
        return try openviking.agentMemoryFromWriteInput(allocator, mapped_input, uri);
    }

    fn openvikingGet(self: *ApiAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, explicit_scope: ?[]const u8) !?domain.AgentMemory {
