        if (try self.openvikingReadMemory(allocator, uri, actor_id, scopes_json, capabilities_json, key, session_id)) |entry| return entry;
        var found = try self.openvikingSearch(allocator, key, 10, session_id, scopes_json, actor_id, capabilities_json, false, key);
        defer allocator.free(found);
        if (found.len == 0) return null;
        const first = found[0];
        detachAgentMemory(&found[0]);
        for (found[1..]) |*entry| freeAgentMemory(allocator, entry);
        return first;
    }

    fn openvikingList(self: *ApiAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, exact_scope: ?[]const u8, include_sessions: bool, limit: usize, offset: usize) ![]domain.AgentMemory {
