        var filtered: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (filtered.items) |*entry| freeAgentMemory(allocator, entry);
            filtered.deinit(allocator);
        }
        defer allocator.free(results);
        for (results) |entry| {
            var candidate = entry;
            if (category) |cat| {
                if (!std.mem.eql(u8, candidate.category, cat)) {
                    freeAgentMemory(allocator, &candidate);
                    continue;
                }
            }
            if (exact_scope) |scope| {
                if (!std.mem.eql(u8, candidate.scope, scope)) {
                    freeAgentMemory(allocator, &candidate);
                    continue;
                }
            }
