    fn openvikingSearch(self: *ApiAgentMemory, allocator: std.mem.Allocator, query_text: []const u8, limit: usize, session_id: ?[]const u8, scopes_json: []const u8, actor_id: []const u8, capabilities_json: ?[]const u8, include_sessions: bool, exact_key: ?[]const u8) ![]domain.AgentMemory {
        _ = include_sessions;
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        var roots = try openviking.visibleTargetUris(allocator, actor_id, scopes_json);
        defer {
            for (roots.items) |root| allocator.free(root);
            roots.deinit(allocator);
        }
        var merged: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (merged.items) |*entry| freeAgentMemory(allocator, entry);
            merged.deinit(allocator);
        }
        const per_root_limit = @max(limit, 1);
        for (roots.items) |root_uri| {
            const body = try openviking.searchPayload(allocator, query_text, per_root_limit, root_uri);
            defer allocator.free(body);
            const response = try self.openvikingRequest(allocator, .POST, "/search/find", "", actor_id, scopes_json, capabilities_json, body);
            defer allocator.free(response.body);
            if (response.status != .ok) return error.AgentMemoryStorageUnavailable;
            const hits = try openviking.searchHitsFromBody(allocator, response.body);
            defer {
                for (hits) |*hit| hit.deinit(allocator);
                allocator.free(hits);
            }
            for (hits) |hit| {
                var entry = (try self.openvikingReadMemory(allocator, hit.uri, actor_id, scopes_json, capabilities_json, exact_key, session_id)) orelse continue;
                entry.score = hit.score;
                try openviking.appendUniqueAgentMemory(allocator, &merged, entry);
            }
        }
        const owned = try merged.toOwnedSlice(allocator);
        sortAgentMemory(owned);
        return pageAgentMemorySlice(allocator, owned, limit, 0);
    }

    fn openvikingDelete(self: *ApiAgentMemory, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        const owner = actor_id orelse return false;
        const actor = writer_actor_id orelse owner;
        const uri = try openviking.memoryUri(self.allocator, owner, session_id, key);
        defer self.allocator.free(uri);
        return self.openvikingDeleteUri(uri, actor, apiEffectiveScopes(self.config, actor_scopes_json), apiEffectiveCapabilities(self.config, actor_capabilities_json));
    }

    fn openvikingDeleteAll(self: *ApiAgentMemory, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        const owner = actor_id orelse return false;
