    fn openvikingReadMemory(self: *ApiAgentMemory, allocator: std.mem.Allocator, uri: []const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, exact_key: ?[]const u8, session_id: ?[]const u8) !?domain.AgentMemory {
        const query = try openviking.uriQuery(allocator, uri, true);
        defer allocator.free(query);
