    }

    fn openvikingWriteContent(self: *ApiAgentMemory, allocator: std.mem.Allocator, uri: []const u8, content: []const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: []const u8) !void {
        const create_body = try openviking.writePayload(allocator, uri, content, "create");
        defer allocator.free(create_body);
        {
            const response = try self.openvikingRequest(allocator, .POST, "/content/write", "", actor_id, scopes_json, capabilities_json, create_body);
            defer allocator.free(response.body);
            if (response.status == .ok or response.status == .created or response.status == .accepted) return;
            if (response.status != .conflict) return error.AgentMemoryStorageUnavailable;
        }

        const replace_body = try openviking.writePayload(allocator, uri, content, "replace");
        defer allocator.free(replace_body);
        const response = try self.openvikingRequest(allocator, .POST, "/content/write", "", actor_id, scopes_json, capabilities_json, replace_body);
        defer allocator.free(response.body);
        if (response.status != .ok and response.status != .created and response.status != .accepted) return error.AgentMemoryStorageUnavailable;
    }

