        const query_text = category orelse "nullpantry agent memory";
        const search_limit = agentMemoryWindowKeepLimit(limit, offset);
        const results = try self.honchoSearch(allocator, query_text, @max(search_limit, limit), session_id, scopes_json, actor_id, capabilities_json, true, null, null);
        var filtered: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (filtered.items) |*entry| freeAgentMemory(allocator, entry);
            filtered.deinit(allocator);
        }
        defer allocator.free(results);
        for (results) |entry| {
            var candidate = entry;
            if (category) |cat| {
                if (!std.mem.eql(u8, candidate.category, cat)) {
                    freeAgentMemory(allocator, &candidate);
                    continue;
                }
            }
            if (exact_scope) |scope| {
                if (!std.mem.eql(u8, candidate.scope, scope)) {
                    freeAgentMemory(allocator, &candidate);
                    continue;
                }
            }
            try filtered.append(allocator, candidate);
        }
        const owned = try filtered.toOwnedSlice(allocator);
        sortAgentMemory(owned);
        return pageAgentMemorySlice(allocator, owned, limit, offset);
    }

    fn honchoSearch(self: *ApiAgentMemory, allocator: std.mem.Allocator, query_text: []const u8, limit: usize, session_id: ?[]const u8, scopes_json: []const u8, actor_id: []const u8, capabilities_json: ?[]const u8, include_sessions: bool, exact_key: ?[]const u8, exact_owner: ?[]const u8) ![]domain.AgentMemory {
        _ = include_sessions;
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        const workspace_id = honcho.workspaceId(self.config.workspace_id);
        var merged: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (merged.items) |*entry| freeAgentMemory(allocator, entry);
            merged.deinit(allocator);
        }

        if (exact_owner) |owner| {
            try self.honchoSearchOwner(allocator, &merged, workspace_id, owner, query_text, limit, session_id, actor_id, scopes_json, capabilities_json, exact_key);
        } else {
            var owners = try honcho.visibleOwners(allocator, actor_id, scopes_json);
            defer owners.deinit(allocator);
            if (owners.requires_global_scan) {
                const path = try honcho.workspaceSearchPath(allocator, workspace_id);
                defer allocator.free(path);
                try self.honchoSearchPath(allocator, &merged, path, query_text, limit, actor_id, scopes_json, capabilities_json, exact_key, session_id);
            } else {
                for (owners.owners.items) |owner| {
                    try self.honchoSearchOwner(allocator, &merged, workspace_id, owner, query_text, limit, session_id, actor_id, scopes_json, capabilities_json, exact_key);
                }
            }
        }

        const owned = try merged.toOwnedSlice(allocator);
        sortAgentMemory(owned);
        return pageAgentMemorySlice(allocator, owned, limit, 0);
    }

    fn honchoSearchOwner(self: *ApiAgentMemory, allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(domain.AgentMemory), workspace_id: []const u8, owner_actor_id: []const u8, query_text: []const u8, limit: usize, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, exact_key: ?[]const u8) !void {
        if (session_id) |sid| {
            const honcho_session_id = try honcho.sessionId(allocator, owner_actor_id, sid);
            defer allocator.free(honcho_session_id);
            const path = try honcho.sessionSearchPath(allocator, workspace_id, honcho_session_id);
            defer allocator.free(path);
            return self.honchoSearchPath(allocator, out, path, query_text, limit, actor_id, scopes_json, capabilities_json, exact_key, session_id);
        }
        const peer_id = try honcho.peerId(allocator, owner_actor_id);
        defer allocator.free(peer_id);
        const path = try honcho.peerSearchPath(allocator, workspace_id, peer_id);
        defer allocator.free(path);
        return self.honchoSearchPath(allocator, out, path, query_text, limit, actor_id, scopes_json, capabilities_json, exact_key, null);
    }

    fn honchoSearchPath(self: *ApiAgentMemory, allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(domain.AgentMemory), path: []const u8, query_text: []const u8, limit: usize, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, exact_key: ?[]const u8, session_id: ?[]const u8) !void {
        const body = try honcho.searchPayload(allocator, query_text, limit);
        defer allocator.free(body);
        const response = try self.honchoRequest(allocator, .POST, path, "", actor_id, scopes_json, capabilities_json, body);
        defer allocator.free(response.body);
        if (response.status == .not_found) return;
        if (response.status != .ok) return error.AgentMemoryStorageUnavailable;
        const parsed = try honcho.agentMemoryArrayFromBody(allocator, response.body, actor_id, scopes_json, exact_key, session_id);
        defer allocator.free(parsed);
        for (parsed) |entry| try honcho.appendLatestAgentMemory(allocator, out, entry);
    }

    fn honchoDelete(self: *ApiAgentMemory, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        const owner = actor_id orelse return false;
        const actor = writer_actor_id orelse owner;
        const scopes_json = apiEffectiveScopes(self.config, actor_scopes_json);
        var existing = try self.honchoGet(self.allocator, key, session_id, owner, scopes_json, actor_capabilities_json, sharedScopeFromOwner(owner));
        defer if (existing) |*entry| freeAgentMemory(self.allocator, entry);
        const explicit_scope = sharedScopeFromOwner(owner);
        const fallback_permissions = if (existing == null) try fallbackDeletePermissions(self.allocator, owner, explicit_scope) else null;
        defer if (fallback_permissions) |permissions| self.allocator.free(permissions);
        const mapped_input = honcho.WriteInput{
            .key = key,
            .content = if (existing) |entry| entry.content else "",
            .category = if (existing) |entry| entry.category else "core",
            .session_id = session_id,
            .owner_actor_id = owner,
            .writer_actor_id = actor,
            .requested_scope = explicit_scope,
            .requested_permissions_json = if (existing) |entry| entry.permissions_json else fallback_permissions.?,
            .metadata_json = "{}",
            .timestamp_ms = ids.nowMs(),
            .status = "deleted",
        };
        try self.honchoWriteMemory(self.allocator, mapped_input, actor, scopes_json, apiEffectiveCapabilities(self.config, actor_capabilities_json));
        return true;
    }

    fn honchoDeleteAll(self: *ApiAgentMemory, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        const owner = actor_id orelse return false;
        var deleted = try self.honchoDelete(key, null, owner, writer_actor_id, actor_scopes_json, actor_capabilities_json);
        const actor = writer_actor_id orelse owner;
        const scopes_json = apiEffectiveScopes(self.config, actor_scopes_json);
        const matches = try self.honchoSearch(self.allocator, key, 100, null, scopes_json, actor, actor_capabilities_json, true, key, owner);
        defer {
            for (matches) |*entry| freeAgentMemory(self.allocator, entry);
            self.allocator.free(matches);
        }
        for (matches) |entry| {
            if (!std.mem.eql(u8, entry.actor_id, owner)) continue;
            if (entry.session_id) |sid| {
                if (try self.honchoDelete(key, sid, owner, writer_actor_id, actor_scopes_json, actor_capabilities_json)) deleted = true;
            }
        }
        return deleted;
    }

    fn honchoPatchStatus(self: *ApiAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, status: []const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        const owner = actor_id orelse return false;
        const actor = writer_actor_id orelse owner;
        const scopes_json = apiEffectiveScopes(self.config, actor_scopes_json);
        var entry = (try self.honchoGet(allocator, key, session_id, owner, scopes_json, actor_capabilities_json, sharedScopeFromOwner(owner))) orelse return false;
        defer freeAgentMemory(allocator, &entry);
        const mapped_input = honcho.WriteInput{
            .key = entry.key,
            .content = entry.content,
            .category = entry.category,
            .session_id = entry.session_id,
            .owner_actor_id = entry.actor_id,
