        return true;
    }

    fn honchoWriteMemory(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: honcho.WriteInput, actor_id: []const u8, scopes_json: []const u8, capabilities_json: []const u8) !void {
        const workspace_id = honcho.workspaceId(self.config.workspace_id);
        const peer_id = try honcho.peerId(allocator, input.owner_actor_id);
        defer allocator.free(peer_id);
        const session_id = try honcho.sessionId(allocator, input.owner_actor_id, input.session_id);
        defer allocator.free(session_id);
        try self.honchoEnsurePeerSession(allocator, workspace_id, peer_id, session_id, input, actor_id, scopes_json, capabilities_json);

        const path = try honcho.sessionMessagesPath(allocator, workspace_id, session_id);
        defer allocator.free(path);
        const body = try honcho.messagePayload(allocator, input, peer_id);
        defer allocator.free(body);
        const response = try self.honchoRequest(allocator, .POST, path, "", actor_id, scopes_json, capabilities_json, body);
        defer allocator.free(response.body);
        if (response.status != .ok and response.status != .created and response.status != .accepted and response.status != .no_content) return error.AgentMemoryStorageUnavailable;
    }

    fn honchoEnsurePeerSession(self: *ApiAgentMemory, allocator: std.mem.Allocator, workspace_id: []const u8, peer_id: []const u8, session_id: []const u8, input: honcho.WriteInput, actor_id: []const u8, scopes_json: []const u8, capabilities_json: []const u8) !void {
        const peer_path = try honcho.peerPath(allocator, workspace_id, peer_id);
        defer allocator.free(peer_path);
        const peer_body = try honcho.peerPayload(allocator, peer_id, input.owner_actor_id);
        defer allocator.free(peer_body);
        {
            const response = try self.honchoRequest(allocator, .PUT, peer_path, "", actor_id, scopes_json, capabilities_json, peer_body);
            defer allocator.free(response.body);
            if (response.status != .ok and response.status != .created and response.status != .accepted and response.status != .no_content and response.status != .conflict) return error.AgentMemoryStorageUnavailable;
        }

        const session_path = try honcho.sessionPath(allocator, workspace_id, session_id);
        defer allocator.free(session_path);
        const session_body = try honcho.sessionPayload(allocator, session_id, input.owner_actor_id, input.session_id);
        defer allocator.free(session_body);
        {
            const response = try self.honchoRequest(allocator, .PUT, session_path, "", actor_id, scopes_json, capabilities_json, session_body);
            defer allocator.free(response.body);
            if (response.status != .ok and response.status != .created and response.status != .accepted and response.status != .no_content and response.status != .conflict) return error.AgentMemoryStorageUnavailable;
        }

        const peers_path = try honcho.sessionPeersPath(allocator, workspace_id, session_id);
        defer allocator.free(peers_path);
        const peers_body = try honcho.sessionPeerPayload(allocator, peer_id);
        defer allocator.free(peers_body);
        const response = try self.honchoRequest(allocator, .POST, peers_path, "", actor_id, scopes_json, capabilities_json, peers_body);
        defer allocator.free(response.body);
        if (response.status != .ok and response.status != .created and response.status != .accepted and response.status != .no_content and response.status != .conflict and response.status != .not_found) return error.AgentMemoryStorageUnavailable;
    }

    fn honchoRequest(self: *ApiAgentMemory, allocator: std.mem.Allocator, method: std.http.Method, path: []const u8, query: []const u8, actor_id: ?[]const u8, scopes_json: ?[]const u8, capabilities_json: ?[]const u8, payload: []const u8) !ApiHttpResponse {
        const url = try honcho.apiUrl(allocator, self.config.base_url.?, path, query, self.config.allow_insecure_http);
        defer allocator.free(url);
        return requestApiJson(allocator, method, url, self.config, actor_id, scopes_json, capabilities_json, payload);
    }

    fn mem0Store(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: Input) !domain.AgentMemory {
        const actor = try access.requiredActorId(input.writer_actor_id orelse input.actor_id);
        const owner = try externalAgentMemoryOwner(allocator, input.actor_id orelse actor, input.scope);
        defer allocator.free(owner);
        var write_input = input;
        var reduced_content: ?[]u8 = null;
        defer if (reduced_content) |content| allocator.free(content);

        var existing = try self.mem0Get(allocator, input.key, input.session_id, owner, self.scopesForInput(input), self.capabilitiesForInput(input), input.scope);
        defer if (existing) |*entry| freeAgentMemory(allocator, entry);
        if (input.operation != .put) {
            reduced_content = try agent_memory_reducer.reduceContent(allocator, input.operation, if (existing) |entry| entry.content else null, input.content);
            write_input.content = reduced_content.?;
            write_input.operation = .put;
        }

        const mapped_input = mem0.WriteInput{
            .key = write_input.key,
            .content = write_input.content,
            .category = write_input.category,
            .session_id = write_input.session_id,
            .owner_actor_id = owner,
            .writer_actor_id = actor,
            .requested_scope = write_input.scope,
            .requested_permissions_json = write_input.permissions_json,
            .metadata_json = write_input.metadata_json,
            .timestamp_ms = eventTimestampMs(write_input),
            .status = "proposed",
            .remote_id = if (existing) |entry| entry.id else null,
        };
        try self.mem0WriteMemory(allocator, mapped_input, actor, self.scopesForInput(input), self.capabilitiesForInput(input));
        return try mem0.agentMemoryFromWriteInput(allocator, mapped_input);
    }

    fn mem0Get(self: *ApiAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, explicit_scope: ?[]const u8) !?domain.AgentMemory {
        const owner = try externalAgentMemoryOwner(allocator, actor_id, explicit_scope);
        defer allocator.free(owner);
        var found = try self.mem0Search(allocator, key, 10, session_id, scopes_json, actor_id, capabilities_json, false, key, owner);
        defer allocator.free(found);
        if (found.len == 0) return null;
        const first = found[0];
        detachAgentMemory(&found[0]);
        for (found[1..]) |*entry| freeAgentMemory(allocator, entry);
        return first;
    }

    fn mem0List(self: *ApiAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, exact_scope: ?[]const u8, include_sessions: bool, limit: usize, offset: usize) ![]domain.AgentMemory {
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        const search_limit = agentMemoryWindowKeepLimit(limit, offset);
        var merged: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (merged.items) |*entry| freeAgentMemory(allocator, entry);
            merged.deinit(allocator);
        }

        if (exact_scope) |scope| {
            const owner = try externalAgentMemoryOwner(allocator, actor_id, scope);
            defer allocator.free(owner);
            try self.mem0ListOwner(allocator, &merged, owner, category, session_id, include_sessions, @max(search_limit, limit), actor_id, scopes_json, capabilities_json);
        } else {
            var owners = try mem0.visibleOwners(allocator, actor_id, scopes_json);
            defer owners.deinit(allocator);
            if (owners.requires_global_scan) {
                try self.mem0ListOwner(allocator, &merged, null, category, session_id, include_sessions, @max(search_limit, limit), actor_id, scopes_json, capabilities_json);
            } else {
                for (owners.owners.items) |owner| {
                    try self.mem0ListOwner(allocator, &merged, owner, category, session_id, include_sessions, @max(search_limit, limit), actor_id, scopes_json, capabilities_json);
                }
            }
        }

        const owned = try merged.toOwnedSlice(allocator);
        sortAgentMemory(owned);
        return pageAgentMemorySlice(allocator, owned, limit, offset);
    }

    fn mem0Search(self: *ApiAgentMemory, allocator: std.mem.Allocator, query_text: []const u8, limit: usize, session_id: ?[]const u8, scopes_json: []const u8, actor_id: []const u8, capabilities_json: ?[]const u8, include_sessions: bool, exact_key: ?[]const u8, exact_owner: ?[]const u8) ![]domain.AgentMemory {
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
