        } else {
            var owners = try mem0.visibleOwners(allocator, actor_id, scopes_json);
            defer owners.deinit(allocator);
            if (owners.requires_global_scan) {
                try self.mem0SearchOwner(allocator, &merged, null, query_text, limit, session_id, include_sessions, actor_id, scopes_json, capabilities_json, exact_key);
            } else {
                for (owners.owners.items) |owner| {
                    try self.mem0SearchOwner(allocator, &merged, owner, query_text, limit, session_id, include_sessions, actor_id, scopes_json, capabilities_json, exact_key);
                }
