    fn mem0SearchOwner(self: *ApiAgentMemory, allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(domain.AgentMemory), owner_actor_id: ?[]const u8, query_text: []const u8, limit: usize, session_id: ?[]const u8, include_sessions: bool, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, exact_key: ?[]const u8) !void {
        const body = try mem0.searchPayload(allocator, query_text, limit, owner_actor_id, session_id, include_sessions, exact_key);
        defer allocator.free(body);
        const response = try self.mem0Request(allocator, .POST, "/v3/memories/search/", "", actor_id, scopes_json, capabilities_json, body);
        defer allocator.free(response.body);
        if (response.status == .not_found) return;
        if (response.status != .ok) return error.AgentMemoryStorageUnavailable;
        _ = try mem0.appendAgentMemoryPage(allocator, out, response.body, actor_id, scopes_json, exact_key, session_id, include_sessions);
    }

    fn mem0ListOwner(self: *ApiAgentMemory, allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(domain.AgentMemory), owner_actor_id: ?[]const u8, category: ?[]const u8, session_id: ?[]const u8, include_sessions: bool, limit: usize, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8) !void {
        const body = try mem0.listPayload(allocator, owner_actor_id, session_id, include_sessions, null, category);
        defer allocator.free(body);
        const target = @max(limit, 1);
        const plan = mem0.pageFetchPlan(target);
        var page: usize = 1;
        var fetched: usize = 0;
        while (page <= plan.max_pages and fetched < target) : (page += 1) {
            const remaining = target - fetched;
            const request_size = @min(remaining, plan.page_size);
            const parsed_count = blk: {
                const query = try mem0.listQuery(allocator, page, request_size);
                defer allocator.free(query);
                const response = try self.mem0Request(allocator, .POST, "/v3/memories/", query, actor_id, scopes_json, capabilities_json, body);
                defer allocator.free(response.body);
                if (response.status == .not_found) return;
                if (response.status != .ok) return error.AgentMemoryStorageUnavailable;
                break :blk try mem0.appendAgentMemoryPage(allocator, out, response.body, actor_id, scopes_json, null, session_id, include_sessions);
            };
            fetched += parsed_count;
            if (!mem0.shouldContinuePages(parsed_count, request_size)) break;
        }
    }

    fn mem0Delete(self: *ApiAgentMemory, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        const owner = actor_id orelse return false;
        const actor = writer_actor_id orelse owner;
