        var entry = (try self.mem0Get(self.allocator, key, session_id, owner, scopes_json, actor_capabilities_json, sharedScopeFromOwner(owner))) orelse return false;
        defer freeAgentMemory(self.allocator, &entry);
        return self.mem0DeleteId(entry.id, actor, scopes_json, apiEffectiveCapabilities(self.config, actor_capabilities_json));
