    fn mem0DeleteAll(self: *ApiAgentMemory, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
