    fn mem0WriteMemory(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: mem0.WriteInput, actor_id: []const u8, scopes_json: []const u8, capabilities_json: []const u8) !void {
        if (input.remote_id != null) return self.mem0UpdateMemory(allocator, input, actor_id, scopes_json, capabilities_json);
        return self.mem0AddMemory(allocator, input, actor_id, scopes_json, capabilities_json);
    }

    fn mem0AddMemory(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: mem0.WriteInput, actor_id: []const u8, scopes_json: []const u8, capabilities_json: []const u8) !void {
        const body = try mem0.addPayload(allocator, input);
        defer allocator.free(body);
        const response = try self.mem0Request(allocator, .POST, "/v3/memories/add/", "", actor_id, scopes_json, capabilities_json, body);
