    fn retaindbRemoteFetchLimit(limit: usize) usize {
        return remoteAgentMemoryFetchLimit(limit);
    }

    fn retaindbStore(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: Input) !domain.AgentMemory {
        const actor = try access.requiredActorId(input.writer_actor_id orelse input.actor_id);
        const owner = try externalAgentMemoryOwner(allocator, input.actor_id orelse actor, input.scope);
        defer allocator.free(owner);
        var write_input = input;
        var reduced_content: ?[]u8 = null;
        defer if (reduced_content) |content| allocator.free(content);

        var existing = try self.retaindbGet(allocator, input.key, input.session_id, owner, self.scopesForInput(input), self.capabilitiesForInput(input), input.scope);
        defer if (existing) |*entry| freeAgentMemory(allocator, entry);
        if (input.operation != .put) {
            reduced_content = try agent_memory_reducer.reduceContent(allocator, input.operation, if (existing) |entry| entry.content else null, input.content);
            write_input.content = reduced_content.?;
            write_input.operation = .put;
        }

        const resolved_scope = try access.agentMemoryScope(allocator, owner, write_input.session_id, write_input.scope);
        defer allocator.free(resolved_scope);
        const status = if (existing) |entry| entry.status else domain.defaultMemoryStatus("agent", resolved_scope);
        const mapped_input = retaindb.WriteInput{
            .key = write_input.key,
            .content = write_input.content,
            .category = write_input.category,
            .session_id = write_input.session_id,
            .owner_actor_id = owner,
            .writer_actor_id = actor,
            .requested_scope = write_input.scope,
            .requested_permissions_json = write_input.permissions_json,
            .metadata_json = write_input.metadata_json,
            .timestamp_ms = eventTimestampMs(write_input),
            .status = status,
            .remote_id = if (existing) |entry| entry.id else null,
        };
        try self.retaindbWriteMemory(allocator, mapped_input, actor, self.scopesForInput(input), self.capabilitiesForInput(input));
        return try retaindb.agentMemoryFromWriteInput(allocator, mapped_input);
    }

    fn retaindbGet(self: *ApiAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, explicit_scope: ?[]const u8) !?domain.AgentMemory {
        const owner = try externalAgentMemoryOwner(allocator, actor_id, explicit_scope);
        defer allocator.free(owner);
        var found = try self.retaindbSearch(allocator, key, 10, session_id, scopes_json, actor_id, capabilities_json, false, key, owner);
        defer allocator.free(found);
        if (found.len == 0) return null;
        sortAgentMemoryForVisibleGet(found, actor_id);
        const first = found[0];
        detachAgentMemory(&found[0]);
        for (found[1..]) |*entry| freeAgentMemory(allocator, entry);
        return first;
    }

    fn retaindbList(self: *ApiAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, exact_scope: ?[]const u8, include_sessions: bool, limit: usize, offset: usize) ![]domain.AgentMemory {
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        const search_limit = retaindbRemoteFetchLimit(agentMemoryWindowKeepLimit(limit, offset));
        var merged: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (merged.items) |*entry| freeAgentMemory(allocator, entry);
            merged.deinit(allocator);
        }

        if (exact_scope) |scope| {
            const owner = try externalAgentMemoryOwner(allocator, actor_id, scope);
            defer allocator.free(owner);
            try self.retaindbListOwner(allocator, &merged, owner, category, session_id, include_sessions, search_limit, actor_id, scopes_json, capabilities_json);
        } else {
            var owners = try retaindb.visibleOwners(allocator, actor_id, scopes_json);
            defer owners.deinit(allocator);
            if (owners.requires_global_scan) {
                try self.retaindbListOwner(allocator, &merged, null, category, session_id, include_sessions, search_limit, actor_id, scopes_json, capabilities_json);
            } else {
                for (owners.owners.items) |owner| {
                    try self.retaindbListOwner(allocator, &merged, owner, category, session_id, include_sessions, search_limit, actor_id, scopes_json, capabilities_json);
                }
            }
        }

        const owned = try merged.toOwnedSlice(allocator);
        sortAgentMemory(owned);
        return pageAgentMemorySlice(allocator, owned, limit, offset);
    }

    fn retaindbSearch(self: *ApiAgentMemory, allocator: std.mem.Allocator, query_text: []const u8, limit: usize, session_id: ?[]const u8, scopes_json: []const u8, actor_id: []const u8, capabilities_json: ?[]const u8, include_sessions: bool, exact_key: ?[]const u8, exact_owner: ?[]const u8) ![]domain.AgentMemory {
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        const search_limit = retaindbRemoteFetchLimit(limit);
        var merged: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (merged.items) |*entry| freeAgentMemory(allocator, entry);
            merged.deinit(allocator);
        }

        if (exact_owner) |owner| {
            try self.retaindbSearchOwner(allocator, &merged, owner, query_text, search_limit, session_id, include_sessions, actor_id, scopes_json, capabilities_json, exact_key);
        } else {
            var owners = try retaindb.visibleOwners(allocator, actor_id, scopes_json);
            defer owners.deinit(allocator);
            if (owners.requires_global_scan) {
                try self.retaindbSearchOwner(allocator, &merged, null, query_text, search_limit, session_id, include_sessions, actor_id, scopes_json, capabilities_json, exact_key);
            } else {
                for (owners.owners.items) |owner| {
                    try self.retaindbSearchOwner(allocator, &merged, owner, query_text, search_limit, session_id, include_sessions, actor_id, scopes_json, capabilities_json, exact_key);
                }
            }
        }

        const owned = try merged.toOwnedSlice(allocator);
        sortAgentMemory(owned);
        return pageAgentMemorySlice(allocator, owned, limit, 0);
    }

    fn retaindbSearchOwner(self: *ApiAgentMemory, allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(domain.AgentMemory), owner_actor_id: ?[]const u8, query_text: []const u8, limit: usize, session_id: ?[]const u8, include_sessions: bool, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, exact_key: ?[]const u8) !void {
        const body = try retaindb.searchPayload(allocator, retaindb.projectId(self.config.workspace_id), query_text, owner_actor_id, session_id, include_sessions, exact_key, limit);
        defer allocator.free(body);
        const response = try self.retaindbRequest(allocator, .POST, "/memory/search", "", actor_id, scopes_json, capabilities_json, body);
        defer allocator.free(response.body);
        if (response.status == .not_found) return;
        if (response.status != .ok) return error.AgentMemoryStorageUnavailable;
        _ = try retaindb.appendAgentMemoryPage(allocator, out, response.body, actor_id, scopes_json, exact_key, session_id, include_sessions);
    }

    fn retaindbListOwner(self: *ApiAgentMemory, allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(domain.AgentMemory), owner_actor_id: ?[]const u8, category: ?[]const u8, session_id: ?[]const u8, include_sessions: bool, limit: usize, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8) !void {
        const query_text = category orelse "nullpantry agent memory";
        const body = try retaindb.searchPayload(allocator, retaindb.projectId(self.config.workspace_id), query_text, owner_actor_id, session_id, include_sessions, null, limit);
        defer allocator.free(body);
        const response = try self.retaindbRequest(allocator, .POST, "/memory/search", "", actor_id, scopes_json, capabilities_json, body);
        defer allocator.free(response.body);
        if (response.status == .not_found) return;
        if (response.status != .ok) return error.AgentMemoryStorageUnavailable;
        const parsed = try retaindb.agentMemoryArrayFromBody(allocator, response.body, actor_id, scopes_json, null, session_id, include_sessions);
        defer {
            for (parsed) |*entry| freeAgentMemory(allocator, entry);
            allocator.free(parsed);
        }
        for (parsed) |*entry| {
            if (category) |cat| {
                if (!std.mem.eql(u8, entry.category, cat)) continue;
            }
            try retaindb.appendLatestAgentMemory(allocator, out, entry.*);
            detachAgentMemory(entry);
        }
    }

    fn retaindbDelete(self: *ApiAgentMemory, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        const owner = actor_id orelse return false;
        const actor = writer_actor_id orelse owner;
        const scopes_json = apiEffectiveScopes(self.config, actor_scopes_json);
        var entry = (try self.retaindbGet(self.allocator, key, session_id, owner, scopes_json, actor_capabilities_json, sharedScopeFromOwner(owner))) orelse return false;
        defer freeAgentMemory(self.allocator, &entry);
        try self.retaindbPatchEntryStatus(self.allocator, entry, actor, scopes_json, apiEffectiveCapabilities(self.config, actor_capabilities_json), "deleted");
        return true;
    }

    fn retaindbDeleteAll(self: *ApiAgentMemory, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        const owner = actor_id orelse return false;
        const actor = writer_actor_id orelse owner;
        const scopes_json = apiEffectiveScopes(self.config, actor_scopes_json);
        const matches = try self.retaindbSearch(self.allocator, key, 100, null, scopes_json, actor, actor_capabilities_json, true, key, owner);
        defer {
            for (matches) |*entry| freeAgentMemory(self.allocator, entry);
            self.allocator.free(matches);
        }
        var deleted = false;
        for (matches) |entry| {
            if (!std.mem.eql(u8, entry.actor_id, owner)) continue;
            try self.retaindbPatchEntryStatus(self.allocator, entry, actor, scopes_json, apiEffectiveCapabilities(self.config, actor_capabilities_json), "deleted");
            deleted = true;
        }
        return deleted;
    }

    fn retaindbPatchStatus(self: *ApiAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, status: []const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        const owner = actor_id orelse return false;
        const actor = writer_actor_id orelse owner;
        const scopes_json = apiEffectiveScopes(self.config, actor_scopes_json);
        var entry = (try self.retaindbGet(allocator, key, session_id, owner, scopes_json, actor_capabilities_json, sharedScopeFromOwner(owner))) orelse return false;
        defer freeAgentMemory(allocator, &entry);
        try self.retaindbPatchEntryStatus(allocator, entry, actor, scopes_json, apiEffectiveCapabilities(self.config, actor_capabilities_json), status);
        return true;
    }

    fn retaindbPatchEntryStatus(self: *ApiAgentMemory, allocator: std.mem.Allocator, entry: domain.AgentMemory, writer_actor_id: []const u8, scopes_json: []const u8, capabilities_json: []const u8, status: []const u8) !void {
        try self.retaindbUpdateMemory(allocator, retaindbEntryWriteInput(entry, writer_actor_id, status), writer_actor_id, scopes_json, capabilities_json);
    }

    fn retaindbEntryWriteInput(entry: domain.AgentMemory, writer_actor_id: []const u8, status: []const u8) retaindb.WriteInput {
        return .{
            .key = entry.key,
            .content = entry.content,
            .category = entry.category,
            .session_id = entry.session_id,
            .owner_actor_id = entry.actor_id,
            .writer_actor_id = writer_actor_id,
            .requested_scope = entry.scope,
            .requested_permissions_json = entry.permissions_json,
            .metadata_json = "{}",
            .timestamp_ms = ids.nowMs(),
            .status = status,
            .remote_id = entry.id,
        };
    }

    fn retaindbWriteMemory(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: retaindb.WriteInput, actor_id: []const u8, scopes_json: []const u8, capabilities_json: []const u8) !void {
        if (input.remote_id != null) return self.retaindbUpdateMemory(allocator, input, actor_id, scopes_json, capabilities_json);
        return self.retaindbCreateMemory(allocator, input, actor_id, scopes_json, capabilities_json);
    }

    fn retaindbCreateMemory(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: retaindb.WriteInput, actor_id: []const u8, scopes_json: []const u8, capabilities_json: []const u8) !void {
        const body = try retaindb.createPayload(allocator, retaindb.projectId(self.config.workspace_id), input);
        defer allocator.free(body);
        const response = try self.retaindbRequest(allocator, .POST, "/memory", "", actor_id, scopes_json, capabilities_json, body);
        defer allocator.free(response.body);
        if (response.status != .ok and response.status != .created and response.status != .accepted and response.status != .no_content) return error.AgentMemoryStorageUnavailable;
    }

    fn retaindbUpdateMemory(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: retaindb.WriteInput, actor_id: []const u8, scopes_json: []const u8, capabilities_json: []const u8) !void {
        const remote_id = input.remote_id orelse return self.retaindbCreateMemory(allocator, input, actor_id, scopes_json, capabilities_json);
        const encoded = try percentEncode(allocator, remote_id);
        defer allocator.free(encoded);
        const path = try std.fmt.allocPrint(allocator, "/memory/{s}", .{encoded});
        defer allocator.free(path);
        const body = try retaindb.updatePayload(allocator, retaindb.projectId(self.config.workspace_id), input);
        defer allocator.free(body);
        const response = try self.retaindbRequest(allocator, .PUT, path, "", actor_id, scopes_json, capabilities_json, body);
        defer allocator.free(response.body);
        if (response.status == .not_found) return self.retaindbCreateMemory(allocator, .{
            .key = input.key,
            .content = input.content,
            .category = input.category,
            .session_id = input.session_id,
            .owner_actor_id = input.owner_actor_id,
            .writer_actor_id = input.writer_actor_id,
            .requested_scope = input.requested_scope,
            .requested_permissions_json = input.requested_permissions_json,
            .metadata_json = input.metadata_json,
            .timestamp_ms = input.timestamp_ms,
            .status = input.status,
            .remote_id = null,
        }, actor_id, scopes_json, capabilities_json);
        if (response.status != .ok and response.status != .created and response.status != .accepted and response.status != .no_content) return error.AgentMemoryStorageUnavailable;
    }

    fn retaindbRequest(self: *ApiAgentMemory, allocator: std.mem.Allocator, method: std.http.Method, path: []const u8, query: []const u8, actor_id: ?[]const u8, scopes_json: ?[]const u8, capabilities_json: ?[]const u8, payload: []const u8) !ApiHttpResponse {
