    fn hindsightStore(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: Input) !domain.AgentMemory {
        const actor = try access.requiredActorId(input.writer_actor_id orelse input.actor_id);
        const owner = try externalAgentMemoryOwner(allocator, input.actor_id orelse actor, input.scope);
        defer allocator.free(owner);
        var write_input = input;
        var reduced_content: ?[]u8 = null;
        defer if (reduced_content) |content| allocator.free(content);

        var existing = try self.hindsightGet(allocator, input.key, input.session_id, owner, self.scopesForInput(input), self.capabilitiesForInput(input), input.scope);
        defer if (existing) |*entry| freeAgentMemory(allocator, entry);
        if (input.operation != .put) {
            reduced_content = try agent_memory_reducer.reduceContent(allocator, input.operation, if (existing) |entry| entry.content else null, input.content);
            write_input.content = reduced_content.?;
            write_input.operation = .put;
        }

        const mapped_input = hindsight.WriteInput{
            .key = write_input.key,
            .content = write_input.content,
            .category = write_input.category,
            .session_id = write_input.session_id,
            .owner_actor_id = owner,
            .writer_actor_id = actor,
            .requested_scope = write_input.scope,
            .requested_permissions_json = write_input.permissions_json,
            .metadata_json = write_input.metadata_json,
            .timestamp_ms = eventTimestampMs(write_input),
            .status = "proposed",
        };
        try self.hindsightWriteMemory(allocator, mapped_input, actor, self.scopesForInput(input), self.capabilitiesForInput(input));
        return try hindsight.agentMemoryFromWriteInput(allocator, mapped_input);
    }

    fn hindsightGet(self: *ApiAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, explicit_scope: ?[]const u8) !?domain.AgentMemory {
        const owner = try externalAgentMemoryOwner(allocator, actor_id, explicit_scope);
        defer allocator.free(owner);
        var events: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        defer events.deinit(allocator);
        errdefer {
            for (events.items) |*entry| freeAgentMemory(allocator, entry);
        }

        try self.hindsightListOwner(allocator, &events, owner, null, session_id, false, 100, actor_id, scopes_json, capabilities_json, key, key);
        const owned = try events.toOwnedSlice(allocator);
        if (owned.len > 0) {
            sortAgentMemoryForVisibleGet(owned, actor_id);
            const active = try hindsight.activeAgentMemoryPage(allocator, owned, 1, 0);
            defer allocator.free(active);
            if (active.len == 0) return null;
            const first = active[0];
            detachAgentMemory(&active[0]);
            return first;
        }
        allocator.free(owned);

        var found = try self.hindsightSearch(allocator, key, 20, session_id, scopes_json, actor_id, capabilities_json, false, key, owner);
        defer allocator.free(found);
        if (found.len == 0) return null;
        sortAgentMemoryForVisibleGet(found, actor_id);
        const first = found[0];
        detachAgentMemory(&found[0]);
        for (found[1..]) |*entry| freeAgentMemory(allocator, entry);
        return first;
    }

    fn hindsightList(self: *ApiAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, exact_scope: ?[]const u8, include_sessions: bool, limit: usize, offset: usize) ![]domain.AgentMemory {
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        const search_limit = agentMemoryWindowKeepLimit(limit, offset);
        var merged: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (merged.items) |*entry| freeAgentMemory(allocator, entry);
            merged.deinit(allocator);
        }

        if (exact_scope) |scope| {
            const owner = try externalAgentMemoryOwner(allocator, actor_id, scope);
            defer allocator.free(owner);
            try self.hindsightListOwner(allocator, &merged, owner, category, session_id, include_sessions, @max(search_limit, limit), actor_id, scopes_json, capabilities_json, null, category);
        } else {
            var owners = try hindsight.visibleOwners(allocator, actor_id, scopes_json);
            defer owners.deinit(allocator);
            if (owners.requires_global_scan) {
                try self.hindsightListOwner(allocator, &merged, null, category, session_id, include_sessions, @max(search_limit, limit), actor_id, scopes_json, capabilities_json, null, category);
            } else {
                for (owners.owners.items) |owner| {
                    try self.hindsightListOwner(allocator, &merged, owner, category, session_id, include_sessions, @max(search_limit, limit), actor_id, scopes_json, capabilities_json, null, category);
                }
            }
        }

        const owned = try merged.toOwnedSlice(allocator);
        sortAgentMemory(owned);
        return hindsight.activeAgentMemoryPage(allocator, owned, limit, offset);
    }

    fn hindsightSearch(self: *ApiAgentMemory, allocator: std.mem.Allocator, query_text: []const u8, limit: usize, session_id: ?[]const u8, scopes_json: []const u8, actor_id: []const u8, capabilities_json: ?[]const u8, include_sessions: bool, exact_key: ?[]const u8, exact_owner: ?[]const u8) ![]domain.AgentMemory {
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        var merged: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (merged.items) |*entry| freeAgentMemory(allocator, entry);
            merged.deinit(allocator);
        }

        if (exact_owner) |owner| {
            try self.hindsightSearchOwner(allocator, &merged, owner, query_text, limit, session_id, include_sessions, actor_id, scopes_json, capabilities_json, exact_key);
        } else {
            var owners = try hindsight.visibleOwners(allocator, actor_id, scopes_json);
            defer owners.deinit(allocator);
            if (owners.requires_global_scan) {
                try self.hindsightSearchOwner(allocator, &merged, null, query_text, limit, session_id, include_sessions, actor_id, scopes_json, capabilities_json, exact_key);
            } else {
                for (owners.owners.items) |owner| {
                    try self.hindsightSearchOwner(allocator, &merged, owner, query_text, limit, session_id, include_sessions, actor_id, scopes_json, capabilities_json, exact_key);
                }
            }
        }

        const owned = try merged.toOwnedSlice(allocator);
        sortAgentMemory(owned);
        return hindsight.activeAgentMemoryPage(allocator, owned, limit, 0);
    }

    fn hindsightSearchOwner(self: *ApiAgentMemory, allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(domain.AgentMemory), owner_actor_id: ?[]const u8, query_text: []const u8, limit: usize, session_id: ?[]const u8, include_sessions: bool, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, exact_key: ?[]const u8) !void {
        const body = try hindsight.recallPayload(allocator, query_text, owner_actor_id, session_id, include_sessions, exact_key, limit);
        defer allocator.free(body);
        const response = try self.hindsightRequest(allocator, .POST, "/memories/recall", "", actor_id, scopes_json, capabilities_json, body);
        defer allocator.free(response.body);
        if (response.status == .not_found) return;
        if (response.status != .ok) return error.AgentMemoryStorageUnavailable;
        _ = try hindsight.appendAgentMemoryPage(allocator, out, response.body, actor_id, scopes_json, exact_key, session_id, include_sessions);
    }

    fn hindsightListOwner(self: *ApiAgentMemory, allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(domain.AgentMemory), owner_actor_id: ?[]const u8, category: ?[]const u8, session_id: ?[]const u8, include_sessions: bool, limit: usize, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, exact_key: ?[]const u8, query_hint: ?[]const u8) !void {
        const target = @max(limit, 1);
        const plan = hindsight.pageFetchPlan(target);
        var page_offset: usize = 0;
        var fetched: usize = 0;
        var pages: usize = 0;
        while (pages < plan.max_pages and fetched < target) : (pages += 1) {
            const remaining = target - fetched;
            const request_size = @min(remaining, plan.page_size);
            const parsed_count = blk: {
                const query = try hindsight.listQuery(allocator, query_hint, request_size, page_offset);
                defer allocator.free(query);
                const response = try self.hindsightRequest(allocator, .GET, "/memories/list", query, actor_id, scopes_json, capabilities_json, "");
                defer allocator.free(response.body);
                if (response.status == .not_found) return;
                if (response.status != .ok) return error.AgentMemoryStorageUnavailable;
                const raw_count = try hindsight.rawMemoryItemCountFromBody(allocator, response.body);
                const parsed = try hindsight.agentMemoryEventArrayFromBody(allocator, response.body, actor_id, scopes_json, exact_key, session_id, include_sessions);
                defer allocator.free(parsed);
                for (parsed) |entry| {
                    if (owner_actor_id) |owner| {
                        if (!std.mem.eql(u8, entry.actor_id, owner)) {
                            var cleanup = entry;
                            freeAgentMemory(allocator, &cleanup);
                            continue;
                        }
                    }
                    if (category) |cat| {
                        if (!std.mem.eql(u8, entry.category, cat)) {
                            var cleanup = entry;
                            freeAgentMemory(allocator, &cleanup);
                            continue;
                        }
                    }
                    try hindsight.appendLatestAgentMemory(allocator, out, entry);
                }
                break :blk raw_count;
            };
            fetched = runtimeCountAdd(fetched, parsed_count);
            if (!hindsight.shouldContinuePages(parsed_count, request_size)) break;
            page_offset = runtimeNextPageOffset(page_offset, request_size) orelse break;
        }
    }

    fn hindsightDelete(self: *ApiAgentMemory, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        const owner = actor_id orelse return false;
        const actor = writer_actor_id orelse owner;
        const scopes_json = apiEffectiveScopes(self.config, actor_scopes_json);
        var entry = (try self.hindsightGet(self.allocator, key, session_id, owner, scopes_json, actor_capabilities_json, sharedScopeFromOwner(owner))) orelse return false;
        defer freeAgentMemory(self.allocator, &entry);
        const mapped_input = hindsight.WriteInput{
            .key = entry.key,
            .content = entry.content,
            .category = entry.category,
            .session_id = entry.session_id,
            .owner_actor_id = entry.actor_id,
            .writer_actor_id = actor,
            .requested_scope = entry.scope,
            .requested_permissions_json = entry.permissions_json,
            .metadata_json = "{}",
            .timestamp_ms = ids.nowMs(),
            .status = "deleted",
        };
        try self.hindsightWriteMemory(self.allocator, mapped_input, actor, scopes_json, apiEffectiveCapabilities(self.config, actor_capabilities_json));
        return true;
    }

    fn hindsightDeleteAll(self: *ApiAgentMemory, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        const owner = actor_id orelse return false;
        const actor = writer_actor_id orelse owner;
        const scopes_json = apiEffectiveScopes(self.config, actor_scopes_json);
        const matches = try self.hindsightSearch(self.allocator, key, 100, null, scopes_json, actor, actor_capabilities_json, true, key, owner);
        defer {
            for (matches) |*entry| freeAgentMemory(self.allocator, entry);
            self.allocator.free(matches);
        }
        var deleted = false;
        for (matches) |entry| {
            if (!std.mem.eql(u8, entry.actor_id, owner)) continue;
            const mapped_input = hindsight.WriteInput{
                .key = entry.key,
                .content = entry.content,
                .category = entry.category,
                .session_id = entry.session_id,
                .owner_actor_id = entry.actor_id,
                .writer_actor_id = actor,
                .requested_scope = entry.scope,
                .requested_permissions_json = entry.permissions_json,
                .metadata_json = "{}",
                .timestamp_ms = ids.nowMs(),
                .status = "deleted",
            };
            try self.hindsightWriteMemory(self.allocator, mapped_input, actor, scopes_json, apiEffectiveCapabilities(self.config, actor_capabilities_json));
            deleted = true;
        }
        return deleted;
    }

