    fn zepStore(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: Input) !domain.AgentMemory {
        const actor = try access.requiredActorId(input.writer_actor_id orelse input.actor_id);
        const owner = try externalAgentMemoryOwner(allocator, input.actor_id orelse actor, input.scope);
        defer allocator.free(owner);
        var write_input = input;
        var reduced_content: ?[]u8 = null;
        defer if (reduced_content) |content| allocator.free(content);

        var existing = try self.zepGet(allocator, input.key, input.session_id, owner, self.scopesForInput(input), self.capabilitiesForInput(input), input.scope);
        defer if (existing) |*entry| freeAgentMemory(allocator, entry);
        if (input.operation != .put) {
            reduced_content = try agent_memory_reducer.reduceContent(allocator, input.operation, if (existing) |entry| entry.content else null, input.content);
            write_input.content = reduced_content.?;
            write_input.operation = .put;
        }

        const mapped_input = zep.WriteInput{
            .key = write_input.key,
            .content = write_input.content,
            .category = write_input.category,
            .session_id = write_input.session_id,
            .owner_actor_id = owner,
            .writer_actor_id = actor,
            .requested_scope = write_input.scope,
            .requested_permissions_json = write_input.permissions_json,
            .metadata_json = write_input.metadata_json,
            .timestamp_ms = eventTimestampMs(write_input),
            .status = if (existing) |entry| entry.status else "proposed",
        };
        try self.zepWriteMemory(allocator, mapped_input, actor, self.scopesForInput(input), self.capabilitiesForInput(input));
        return try zep.agentMemoryFromWriteInput(allocator, mapped_input);
    }

    fn zepGet(self: *ApiAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, explicit_scope: ?[]const u8) !?domain.AgentMemory {
        const owner = try externalAgentMemoryOwner(allocator, actor_id, explicit_scope);
        defer allocator.free(owner);
        var found = try self.zepSearch(allocator, key, 20, session_id, scopes_json, actor_id, capabilities_json, false, key, owner);
        defer allocator.free(found);
        if (found.len == 0) return null;
        sortAgentMemoryForVisibleGet(found, actor_id);
        const first = found[0];
        detachAgentMemory(&found[0]);
        for (found[1..]) |*entry| freeAgentMemory(allocator, entry);
        return first;
    }

    fn zepList(self: *ApiAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, exact_scope: ?[]const u8, include_sessions: bool, limit: usize, offset: usize) ![]domain.AgentMemory {
        const query_text = category orelse "nullpantry agent memory";
        const search_limit = agentMemoryWindowKeepLimit(limit, offset);
        const results = try self.zepSearch(allocator, query_text, @max(search_limit, limit), session_id, scopes_json, actor_id, capabilities_json, include_sessions, null, null);
        defer allocator.free(results);
        var filtered: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (filtered.items) |*entry| freeAgentMemory(allocator, entry);
            filtered.deinit(allocator);
        }
        for (results) |entry| {
            var candidate = entry;
            if (category) |cat| {
                if (!std.mem.eql(u8, candidate.category, cat)) {
                    freeAgentMemory(allocator, &candidate);
                    continue;
                }
            }
            if (exact_scope) |scope| {
                if (!std.mem.eql(u8, candidate.scope, scope)) {
                    freeAgentMemory(allocator, &candidate);
                    continue;
                }
            }
            try filtered.append(allocator, candidate);
        }
        const owned = try filtered.toOwnedSlice(allocator);
        sortAgentMemory(owned);
        return pageAgentMemorySlice(allocator, owned, limit, offset);
    }

    fn zepSearch(self: *ApiAgentMemory, allocator: std.mem.Allocator, query_text: []const u8, limit: usize, session_id: ?[]const u8, scopes_json: []const u8, actor_id: []const u8, capabilities_json: ?[]const u8, include_sessions: bool, exact_key: ?[]const u8, exact_owner: ?[]const u8) ![]domain.AgentMemory {
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        var merged: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (merged.items) |*entry| freeAgentMemory(allocator, entry);
            merged.deinit(allocator);
        }
        if (exact_owner) |owner| {
            try self.zepSearchOwner(allocator, &merged, owner, query_text, limit, session_id, actor_id, scopes_json, capabilities_json, include_sessions, exact_key);
        } else {
            var owners = try zep.visibleOwners(allocator, actor_id, scopes_json);
            defer owners.deinit(allocator);
            const owner_slice = owners.owners.items;
            for (owner_slice) |owner| {
                try self.zepSearchOwner(allocator, &merged, owner, query_text, limit, session_id, actor_id, scopes_json, capabilities_json, include_sessions, exact_key);
            }
        }
        const owned = try merged.toOwnedSlice(allocator);
        sortAgentMemory(owned);
        return zep.activeAgentMemoryPage(allocator, owned, limit, 0);
    }

    fn zepSearchOwner(self: *ApiAgentMemory, allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(domain.AgentMemory), owner_actor_id: []const u8, query_text: []const u8, limit: usize, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, include_sessions: bool, exact_key: ?[]const u8) !void {
        const body = try zep.searchPayload(allocator, query_text, owner_actor_id, limit);
        defer allocator.free(body);
        const response = try self.zepRequest(allocator, .POST, "/graph/search", "", actor_id, scopes_json, capabilities_json, body);
        defer allocator.free(response.body);
        if (response.status != .ok) return error.AgentMemoryStorageUnavailable;
        const parsed = try zep.agentMemoryArrayFromBody(allocator, response.body, actor_id, scopes_json, exact_key, session_id, include_sessions);
        defer allocator.free(parsed);
        for (parsed) |entry| try zep.appendLatestAgentMemory(allocator, out, entry);
    }

    fn zepDelete(self: *ApiAgentMemory, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        return self.zepPatchStatus(self.allocator, key, session_id, actor_id, "deleted", writer_actor_id, actor_scopes_json, actor_capabilities_json);
    }

    fn zepDeleteAll(self: *ApiAgentMemory, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
