    fn zepPatchStatus(self: *ApiAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, status: []const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        const owner_input = actor_id orelse return false;
        const actor = writer_actor_id orelse owner_input;
        const scopes_json = apiEffectiveScopes(self.config, actor_scopes_json);
        const owner = try externalAgentMemoryOwner(allocator, owner_input, sharedScopeFromOwner(owner_input));
        defer allocator.free(owner);
        var entry = try self.zepGet(allocator, key, session_id, owner, scopes_json, actor_capabilities_json, sharedScopeFromOwner(owner));
        defer if (entry) |*value| freeAgentMemory(allocator, value);
        const mapped_input = zep.WriteInput{
            .key = key,
            .content = if (entry) |value| value.content else "",
            .category = if (entry) |value| value.category else "core",
            .session_id = session_id,
            .owner_actor_id = owner,
            .writer_actor_id = actor,
            .requested_scope = sharedScopeFromOwner(owner),
            .requested_permissions_json = if (entry) |value| value.permissions_json else try fallbackDeletePermissions(allocator, owner, sharedScopeFromOwner(owner)),
            .metadata_json = "{}",
            .timestamp_ms = ids.nowMs(),
            .status = status,
        };
        defer if (entry == null) allocator.free(mapped_input.requested_permissions_json);
        try self.zepWriteMemory(allocator, mapped_input, actor, scopes_json, apiEffectiveCapabilities(self.config, actor_capabilities_json));
        return true;
    }

    fn zepWriteMemory(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: zep.WriteInput, actor_id: []const u8, scopes_json: []const u8, capabilities_json: []const u8) !void {
