        if (response.status != .ok) return error.AgentMemoryStorageUnavailable;
        const parsed = try falkordb.agentMemoryArrayFromBody(allocator, response.body, actor_id, scopes_json, exact_key, session_id, include_sessions);
        defer allocator.free(parsed);
        for (parsed) |entry| try falkordb.appendLatestAgentMemory(allocator, out, entry);
    }

    fn falkordbDelete(self: *ApiAgentMemory, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        return self.falkordbPatchStatus(self.allocator, key, session_id, actor_id, "deleted", writer_actor_id, actor_scopes_json, actor_capabilities_json);
    }

    fn falkordbDeleteAll(self: *ApiAgentMemory, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        return self.falkordbDelete(key, null, actor_id, writer_actor_id, actor_scopes_json, actor_capabilities_json);
    }

    fn falkordbPatchStatus(self: *ApiAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, status: []const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        const owner_input = actor_id orelse return false;
        const actor = writer_actor_id orelse owner_input;
        const scopes_json = apiEffectiveScopes(self.config, actor_scopes_json);
        const owner = try externalAgentMemoryOwner(allocator, owner_input, sharedScopeFromOwner(owner_input));
        defer allocator.free(owner);
        var entry = try self.falkordbGet(allocator, key, session_id, owner, scopes_json, actor_capabilities_json, sharedScopeFromOwner(owner));
        defer if (entry) |*value| freeAgentMemory(allocator, value);
        const mapped_input = falkordb.WriteInput{
            .key = key,
            .content = if (entry) |value| value.content else "",
            .category = if (entry) |value| value.category else "core",
            .session_id = session_id,
            .owner_actor_id = owner,
            .writer_actor_id = actor,
            .requested_scope = sharedScopeFromOwner(owner),
            .requested_permissions_json = if (entry) |value| value.permissions_json else try fallbackDeletePermissions(allocator, owner, sharedScopeFromOwner(owner)),
            .metadata_json = "{}",
            .timestamp_ms = ids.nowMs(),
            .status = status,
        };
        defer if (entry == null) allocator.free(mapped_input.requested_permissions_json);
        try self.falkordbWriteMemory(allocator, mapped_input, actor, scopes_json, apiEffectiveCapabilities(self.config, actor_capabilities_json));
        return true;
    }

    fn falkordbWriteMemory(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: falkordb.WriteInput, actor_id: []const u8, scopes_json: []const u8, capabilities_json: []const u8) !void {
        const query = try falkordb.upsertQuery(allocator, input);
        defer allocator.free(query);
        const response = try self.falkordbRequestQuery(allocator, query, actor_id, scopes_json, capabilities_json);
        defer allocator.free(response.body);
        if (response.status != .ok and response.status != .created and response.status != .accepted and response.status != .no_content) return error.AgentMemoryStorageUnavailable;
    }

    fn falkordbRequestQuery(self: *ApiAgentMemory, allocator: std.mem.Allocator, query: []const u8, actor_id: ?[]const u8, scopes_json: ?[]const u8, capabilities_json: ?[]const u8) !ApiHttpResponse {
        const timeout_ms = std.math.cast(u32, time_math.secondsToMs(@max(self.config.timeout_secs, 1))) orelse std.math.maxInt(u32);
        const url = try falkordb.apiUrl(allocator, self.config.base_url.?, falkordb.graphName(self.config.workspace_id), query, timeout_ms, self.config.allow_insecure_http);
        defer allocator.free(url);
        return requestApiJson(allocator, .GET, url, self.config, actor_id, scopes_json, capabilities_json, "");
    }

    fn byteroverRemoteFetchLimit(limit: usize) usize {
        return remoteAgentMemoryFetchLimit(limit);
    }

    fn byteroverStore(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: Input) !domain.AgentMemory {
        const actor = try access.requiredActorId(input.writer_actor_id orelse input.actor_id);
        const owner = try externalAgentMemoryOwner(allocator, input.actor_id orelse actor, input.scope);
        defer allocator.free(owner);
        var write_input = input;
        var reduced_content: ?[]u8 = null;
        defer if (reduced_content) |content| allocator.free(content);

        var existing = try self.byteroverGet(allocator, input.key, input.session_id, owner, self.scopesForInput(input), self.capabilitiesForInput(input), input.scope);
        defer if (existing) |*entry| freeAgentMemory(allocator, entry);
        if (input.operation != .put) {
            reduced_content = try agent_memory_reducer.reduceContent(allocator, input.operation, if (existing) |entry| entry.content else null, input.content);
            write_input.content = reduced_content.?;
            write_input.operation = .put;
        }

        const resolved_scope = try access.agentMemoryScope(allocator, owner, write_input.session_id, write_input.scope);
        defer allocator.free(resolved_scope);
        const status = if (existing) |entry| entry.status else domain.defaultMemoryStatus("agent", resolved_scope);
        const mapped_input = byterover.WriteInput{
            .key = write_input.key,
            .content = write_input.content,
            .category = write_input.category,
            .session_id = write_input.session_id,
            .owner_actor_id = owner,
            .writer_actor_id = actor,
            .requested_scope = write_input.scope,
            .requested_permissions_json = write_input.permissions_json,
            .metadata_json = write_input.metadata_json,
            .timestamp_ms = eventTimestampMs(write_input),
            .status = status,
        };
        try self.byteroverWriteMemory(allocator, mapped_input);
        return try byterover.agentMemoryFromWriteInput(allocator, mapped_input);
    }

    fn byteroverGet(self: *ApiAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, explicit_scope: ?[]const u8) !?domain.AgentMemory {
        _ = capabilities_json;
        const owner = try externalAgentMemoryOwner(allocator, actor_id, explicit_scope);
        defer allocator.free(owner);
        var found = try self.byteroverSearch(allocator, key, 20, session_id, scopes_json, actor_id, null, false, key, owner);
        defer allocator.free(found);
        if (found.len == 0) return null;
        sortAgentMemoryForVisibleGet(found, actor_id);
        const first = found[0];
        detachAgentMemory(&found[0]);
        for (found[1..]) |*entry| freeAgentMemory(allocator, entry);
        return first;
    }

    fn byteroverGetAnyVisible(self: *ApiAgentMemory, allocator: std.mem.Allocator, key: []const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8) !?domain.AgentMemory {
        var found = try self.byteroverSearch(allocator, key, 20, null, scopes_json, actor_id, capabilities_json, true, key, null);
        defer allocator.free(found);
        if (found.len == 0) return null;
        sortAgentMemoryForVisibleGet(found, actor_id);
        const first = found[0];
        detachAgentMemory(&found[0]);
        for (found[1..]) |*entry| freeAgentMemory(allocator, entry);
        return first;
    }

    fn byteroverList(self: *ApiAgentMemory, allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, actor_id: []const u8, scopes_json: []const u8, capabilities_json: ?[]const u8, exact_scope: ?[]const u8, include_sessions: bool, limit: usize, offset: usize) ![]domain.AgentMemory {
        _ = capabilities_json;
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        const search_limit = byteroverRemoteFetchLimit(agentMemoryWindowKeepLimit(limit, offset));
        var merged: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (merged.items) |*entry| freeAgentMemory(allocator, entry);
            merged.deinit(allocator);
        }

        if (exact_scope) |scope| {
            const owner = try externalAgentMemoryOwner(allocator, actor_id, scope);
            defer allocator.free(owner);
            try self.byteroverSearchOwner(allocator, &merged, owner, category orelse "nullpantry agent memory", search_limit, session_id, include_sessions, actor_id, scopes_json, null, category);
        } else {
            var owners = try byterover.visibleOwners(allocator, actor_id, scopes_json);
            defer owners.deinit(allocator);
            if (owners.requires_global_scan) {
                try self.byteroverSearchOwner(allocator, &merged, null, category orelse "nullpantry agent memory", search_limit, session_id, include_sessions, actor_id, scopes_json, null, category);
            } else {
                for (owners.owners.items) |owner| {
                    try self.byteroverSearchOwner(allocator, &merged, owner, category orelse "nullpantry agent memory", search_limit, session_id, include_sessions, actor_id, scopes_json, null, category);
                }
            }
        }

        const owned = try merged.toOwnedSlice(allocator);
        sortAgentMemory(owned);
        return byterover.activeAgentMemoryPage(allocator, owned, limit, offset);
    }

    fn byteroverSearch(self: *ApiAgentMemory, allocator: std.mem.Allocator, query_text: []const u8, limit: usize, session_id: ?[]const u8, scopes_json: []const u8, actor_id: []const u8, capabilities_json: ?[]const u8, include_sessions: bool, exact_key: ?[]const u8, exact_owner: ?[]const u8) ![]domain.AgentMemory {
        _ = capabilities_json;
        if (limit == 0) return allocator.alloc(domain.AgentMemory, 0);
        const search_limit = byteroverRemoteFetchLimit(limit);
        var merged: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
        errdefer {
            for (merged.items) |*entry| freeAgentMemory(allocator, entry);
            merged.deinit(allocator);
        }

        if (exact_owner) |owner| {
            try self.byteroverSearchOwner(allocator, &merged, owner, query_text, search_limit, session_id, include_sessions, actor_id, scopes_json, exact_key, null);
        } else {
            var owners = try byterover.visibleOwners(allocator, actor_id, scopes_json);
            defer owners.deinit(allocator);
            if (owners.requires_global_scan) {
                try self.byteroverSearchOwner(allocator, &merged, null, query_text, search_limit, session_id, include_sessions, actor_id, scopes_json, exact_key, null);
            } else {
                for (owners.owners.items) |owner| {
                    try self.byteroverSearchOwner(allocator, &merged, owner, query_text, search_limit, session_id, include_sessions, actor_id, scopes_json, exact_key, null);
                }
            }
        }

        const owned = try merged.toOwnedSlice(allocator);
        sortAgentMemory(owned);
        return byterover.activeAgentMemoryPage(allocator, owned, limit, 0);
    }

    fn byteroverSearchOwner(self: *ApiAgentMemory, allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(domain.AgentMemory), owner_actor_id: ?[]const u8, query_text: []const u8, limit: usize, session_id: ?[]const u8, include_sessions: bool, actor_id: []const u8, scopes_json: []const u8, exact_key: ?[]const u8, category: ?[]const u8) !void {
        const prompt = try byterover.queryPrompt(allocator, query_text, owner_actor_id, session_id, include_sessions, exact_key, category, limit);
        defer allocator.free(prompt);
        const output = try self.byteroverQuery(allocator, prompt, limit);
        defer allocator.free(output);
        const parsed = try byterover.agentMemoryArrayFromCliOutput(allocator, output, actor_id, scopes_json, exact_key, session_id, include_sessions);
        defer {
            for (parsed) |*entry| freeAgentMemory(allocator, entry);
            allocator.free(parsed);
        }
        for (parsed) |*entry| {
            if (owner_actor_id) |owner| {
                if (!std.mem.eql(u8, entry.actor_id, owner)) continue;
            }
            if (category) |cat| {
                if (!std.mem.eql(u8, entry.category, cat)) continue;
            }
            try byterover.appendLatestAgentMemory(allocator, out, entry.*);
            detachAgentMemory(entry);
        }
    }

    fn byteroverDelete(self: *ApiAgentMemory, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        const owner = actor_id orelse return false;
        const actor = writer_actor_id orelse owner;
        const scopes_json = apiEffectiveScopes(self.config, actor_scopes_json);
        var entry = (try self.byteroverGet(self.allocator, key, session_id, owner, scopes_json, actor_capabilities_json, sharedScopeFromOwner(owner))) orelse return false;
        defer freeAgentMemory(self.allocator, &entry);
        try self.byteroverWriteMemory(self.allocator, byteroverEntryWriteInput(entry, actor, "deleted"));
        return true;
    }

    fn byteroverDeleteAll(self: *ApiAgentMemory, key: []const u8, actor_id: ?[]const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        const owner = actor_id orelse return false;
        const actor = writer_actor_id orelse owner;
        const scopes_json = apiEffectiveScopes(self.config, actor_scopes_json);
        const matches = try self.byteroverSearch(self.allocator, key, 100, null, scopes_json, actor, actor_capabilities_json, true, key, owner);
        defer {
            for (matches) |*entry| freeAgentMemory(self.allocator, entry);
            self.allocator.free(matches);
        }
        var deleted = false;
        for (matches) |entry| {
            if (!std.mem.eql(u8, entry.actor_id, owner)) continue;
            try self.byteroverWriteMemory(self.allocator, byteroverEntryWriteInput(entry, actor, "deleted"));
            deleted = true;
        }
        return deleted;
    }

    fn byteroverPatchStatus(self: *ApiAgentMemory, allocator: std.mem.Allocator, key: []const u8, session_id: ?[]const u8, actor_id: ?[]const u8, status: []const u8, writer_actor_id: ?[]const u8, actor_scopes_json: ?[]const u8, actor_capabilities_json: ?[]const u8) !bool {
        const owner = actor_id orelse return false;
        const actor = writer_actor_id orelse owner;
        const scopes_json = apiEffectiveScopes(self.config, actor_scopes_json);
        var entry = (try self.byteroverGet(allocator, key, session_id, owner, scopes_json, actor_capabilities_json, sharedScopeFromOwner(owner))) orelse return false;
        defer freeAgentMemory(allocator, &entry);
        try self.byteroverWriteMemory(allocator, byteroverEntryWriteInput(entry, actor, status));
        return true;
    }

    fn byteroverEntryWriteInput(entry: domain.AgentMemory, writer_actor_id: []const u8, status: []const u8) byterover.WriteInput {
        return .{
            .key = entry.key,
            .content = entry.content,
            .category = entry.category,
            .session_id = entry.session_id,
            .owner_actor_id = entry.actor_id,
            .writer_actor_id = writer_actor_id,
            .requested_scope = entry.scope,
            .requested_permissions_json = entry.permissions_json,
            .metadata_json = "{}",
            .timestamp_ms = ids.nowMs(),
            .status = status,
        };
    }

    fn byteroverWriteMemory(self: *ApiAgentMemory, allocator: std.mem.Allocator, input: byterover.WriteInput) !void {
        const text = try byterover.curateText(allocator, input);
        defer allocator.free(text);
        const output = try self.byteroverCurate(allocator, text);
        defer allocator.free(output);
        if (!byterover.cliOutputSucceeded(allocator, output)) return error.AgentMemoryStorageUnavailable;
    }

    fn byteroverCurate(self: *ApiAgentMemory, allocator: std.mem.Allocator, text: []const u8) ![]u8 {
        if (self.config.byterover_use_swarm) {
            const argv = [_][]const u8{ self.config.byterover_command, "swarm", "curate", text, "--format", "json" };
            return self.byteroverRun(allocator, &argv);
        }
        const argv = [_][]const u8{ self.config.byterover_command, "curate", text, "--format", "json" };
        return self.byteroverRun(allocator, &argv);
    }

    fn byteroverQuery(self: *ApiAgentMemory, allocator: std.mem.Allocator, prompt: []const u8, limit: usize) ![]u8 {
        if (self.config.byterover_use_swarm) {
            const limit_text = try std.fmt.allocPrint(allocator, "{d}", .{@max(limit, 1)});
            defer allocator.free(limit_text);
            const argv = [_][]const u8{ self.config.byterover_command, "swarm", "query", prompt, "--format", "json", "-n", limit_text };
            return self.byteroverRun(allocator, &argv);
        }
        const argv = [_][]const u8{ self.config.byterover_command, "query", prompt, "--format", "json" };
        return self.byteroverRun(allocator, &argv);
    }

    fn byteroverRun(self: *ApiAgentMemory, allocator: std.mem.Allocator, argv: []const []const u8) ![]u8 {
        const cwd: std.process.Child.Cwd = if (self.config.byterover_project_dir) |dir| .{ .path = dir } else .inherit;
        var process_io = compat.process.childProcessIo(allocator);
        defer process_io.deinit();
        var child_env = try compat.process.sanitizedChildEnv(allocator);
        defer child_env.deinit();
        const result = try std.process.run(allocator, process_io.io(), .{
            .argv = argv,
            .cwd = cwd,
            .environ_map = &child_env,
            .stdout_limit = .limited(self.config.max_response_bytes),
            .stderr_limit = .limited(64 * 1024),
            .timeout = .{ .duration = .{
                .raw = std.Io.Duration.fromSeconds(self.config.timeout_secs),
                .clock = .awake,
            } },
        });
        defer allocator.free(result.stderr);
        switch (result.term) {
            .exited => |code| if (code == 0) return result.stdout,
            else => {},
        }
        allocator.free(result.stdout);
        return error.AgentMemoryStorageUnavailable;
    }
};

fn externalApiBackendUrl(allocator: std.mem.Allocator, base_url: []const u8, path: []const u8, query: []const u8, allow_insecure_http: bool) ![]u8 {
    return agentMemoryHttpUrl(allocator, base_url, null, path, query, allow_insecure_http);
}

fn requireApiFeedOk(status: std.http.Status) !void {
    if (status == .ok) return;
    if (status == .gone) return error.CursorExpired;
    return error.AgentMemoryStorageUnavailable;
}

fn normalizeApiRuntimeFeedStatus(allocator: std.mem.Allocator, status: *FeedStatus) !void {
    if (std.mem.eql(u8, status.storage_kind, "api")) return;
    const owned = try allocator.dupe(u8, "api");
    allocator.free(status.storage_kind);
    status.storage_kind = owned;
}

fn apiEffectiveScopes(config: ApiConfig, actor_scopes_json: ?[]const u8) []const u8 {
    return actor_scopes_json orelse config.actor_scopes_json;
}

fn apiEffectiveCapabilities(config: ApiConfig, actor_capabilities_json: ?[]const u8) []const u8 {
    return actor_capabilities_json orelse config.actor_capabilities_json;
}

fn apiStoreRequiresFeedApply(input: Input, writer_actor_id: []const u8) bool {
    if (input.operation != .put) return true;
    if (input.event_order != null) return true;
    if (input.actor_id) |owner_actor_id| {
        if (!std.mem.eql(u8, owner_actor_id, writer_actor_id)) return true;
    }
    return false;
}

fn agentMemoryPayloadScope(input: Input) ?[]const u8 {
    if (input.scope) |scope| return scope;
    if (input.actor_id) |owner_actor_id| return sharedScopeFromOwner(owner_actor_id);
    return null;
}

fn agentMemoryStorePayload(allocator: std.mem.Allocator, input: Input) ![]u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    const payload_scope = agentMemoryPayloadScope(input);
    try out.appendSlice(allocator, "{\"content\":");
    try json.appendString(&out, allocator, input.content);
    try out.appendSlice(allocator, ",\"category\":");
    try json.appendString(&out, allocator, input.category);
    try out.appendSlice(allocator, ",\"session_id\":");
    try json.appendNullableString(&out, allocator, input.session_id);
    try out.appendSlice(allocator, ",\"scope\":");
    try json.appendNullableString(&out, allocator, payload_scope);
    try out.appendSlice(allocator, ",\"permissions\":");
    try json.appendRawJsonArray(&out, allocator, input.permissions_json);
    try out.appendSlice(allocator, ",\"metadata\":");
    try json.appendRawJsonObject(&out, allocator, input.metadata_json);
    try out.append(allocator, '}');
    return out.toOwnedSlice(allocator);
}

fn agentMemoryApplyPayload(allocator: std.mem.Allocator, input: Input, actor_id: []const u8) ![]u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.appendSlice(allocator, "{\"event_type\":\"agent_memory.");
    try out.appendSlice(allocator, input.operation.name());
    try out.appendSlice(allocator, "\",\"operation\":\"");
    try out.appendSlice(allocator, input.operation.name());
    try out.appendSlice(allocator, "\",\"object_type\":\"agent_memory\",\"actor_id\":");
    try json.appendString(&out, allocator, actor_id);
    try appendEventOrderFields(allocator, &out, input.event_order);
    if (input.suppress_feed) try out.appendSlice(allocator, ",\"suppress_feed\":true");
    try out.appendSlice(allocator, ",\"payload\":{\"key\":");
    try json.appendString(&out, allocator, input.key);
    if (input.actor_id) |owner_actor_id| {
        try out.appendSlice(allocator, ",\"owner_id\":");
        try json.appendString(&out, allocator, owner_actor_id);
    }
    try out.appendSlice(allocator, ",\"category\":");
    try json.appendString(&out, allocator, input.category);
    try out.appendSlice(allocator, ",\"session_id\":");
    try json.appendNullableString(&out, allocator, input.session_id);
    try out.appendSlice(allocator, ",\"scope\":");
    try json.appendNullableString(&out, allocator, agentMemoryPayloadScope(input));
    try out.appendSlice(allocator, ",\"permissions\":");
    try json.appendRawJsonArray(&out, allocator, input.permissions_json);
    try out.appendSlice(allocator, ",\"metadata\":");
    try json.appendRawJsonObject(&out, allocator, input.metadata_json);
    switch (input.operation) {
        .put => {
            try out.appendSlice(allocator, ",\"content\":");
            try json.appendString(&out, allocator, input.content);
        },
        .merge_string_set => {
            try out.appendSlice(allocator, ",\"values\":");
            try appendStringSetMergePayload(&out, allocator, input.content);
        },
        .merge_object => {
            try out.appendSlice(allocator, ",\"object\":");
            try appendObjectMergePayload(&out, allocator, input.content);
        },
    }
    try out.appendSlice(allocator, "}}");
    return out.toOwnedSlice(allocator);
}

fn appendEventOrderFields(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), event_order: ?EventOrder) !void {
    const order = event_order orelse return;
    try out.print(allocator, ",\"timestamp_ms\":{d},\"origin_instance_id\":", .{order.timestamp_ms});
    try json.appendString(out, allocator, order.origin_instance_id);
    try out.print(allocator, ",\"origin_sequence\":{d}", .{order.origin_sequence});
}

fn appendStringSetMergePayload(out: *std.ArrayListUnmanaged(u8), allocator: std.mem.Allocator, content: []const u8) !void {
    var parsed = std.json.parseFromSlice(std.json.Value, allocator, content, .{}) catch {
        try json.appendString(out, allocator, content);
        return;
    };
    defer parsed.deinit();

    switch (parsed.value) {
        .string => |value| try json.appendString(out, allocator, value),
        .array => |array| {
            for (array.items) |item| {
                if (item != .string) return error.InvalidPayload;
            }
            const value_json = try json.jsonFromValue(allocator, parsed.value);
            defer allocator.free(value_json);
            try out.appendSlice(allocator, value_json);
        },
        else => return error.InvalidPayload,
    }
}

fn appendObjectMergePayload(out: *std.ArrayListUnmanaged(u8), allocator: std.mem.Allocator, content: []const u8) !void {
    var parsed = std.json.parseFromSlice(std.json.Value, allocator, content, .{}) catch return error.InvalidPayload;
    defer parsed.deinit();
    if (parsed.value != .object) return error.InvalidPayload;
    const value_json = try json.jsonFromValue(allocator, parsed.value);
    defer allocator.free(value_json);
    try out.appendSlice(allocator, value_json);
}

