    return out.toOwnedSlice(allocator);
}

test "agent memory API payloads enforce raw metadata roots" {
    const allocator = std.testing.allocator;

    const store_payload = try agentMemoryStorePayload(allocator, .{
        .key = "pref.lang",
        .content = "zig",
        .permissions_json = "[\"team:alpha\"]",
        .metadata_json = "{\"source\":\"test\"}",
    });
    defer allocator.free(store_payload);
    var store_parsed = try std.json.parseFromSlice(std.json.Value, allocator, store_payload, .{});
    defer store_parsed.deinit();
    try std.testing.expectEqualStrings("team:alpha", store_parsed.value.object.get("permissions").?.array.items[0].string);
    try std.testing.expectEqualStrings("test", store_parsed.value.object.get("metadata").?.object.get("source").?.string);
    try std.testing.expectError(error.InvalidRawJson, agentMemoryStorePayload(allocator, .{
        .key = "pref.lang",
        .content = "zig",
        .permissions_json = "{\"scope\":\"team:alpha\"}",
    }));
    try std.testing.expectError(error.InvalidRawJson, agentMemoryStorePayload(allocator, .{
        .key = "pref.lang",
        .content = "zig",
        .metadata_json = "[\"not-object\"]",
    }));

    const apply_payload = try agentMemoryApplyPayload(allocator, .{
        .key = "pref.lang",
        .content = "zig",
        .permissions_json = "[\"team:alpha\"]",
        .metadata_json = "{\"source\":\"test\"}",
        .operation = .put,
    }, "agent:a");
    defer allocator.free(apply_payload);
    var apply_parsed = try std.json.parseFromSlice(std.json.Value, allocator, apply_payload, .{});
    defer apply_parsed.deinit();
    const payload = apply_parsed.value.object.get("payload").?.object;
    try std.testing.expectEqualStrings("team:alpha", payload.get("permissions").?.array.items[0].string);
    try std.testing.expectEqualStrings("test", payload.get("metadata").?.object.get("source").?.string);
    try std.testing.expectError(error.InvalidRawJson, agentMemoryApplyPayload(allocator, .{
        .key = "pref.lang",
        .content = "zig",
        .permissions_json = "{\"scope\":\"team:alpha\"}",
        .operation = .put,
    }, "agent:a"));
    try std.testing.expectError(error.InvalidRawJson, agentMemoryApplyPayload(allocator, .{
        .key = "pref.lang",
        .content = "zig",
        .metadata_json = "[\"not-object\"]",
        .operation = .put,
    }, "agent:a"));

    const search_payload = try agentMemorySearchPayload(allocator, "zig", 10, "session-1", true, "[\"team:alpha\"]");
    defer allocator.free(search_payload);
    var search_parsed = try std.json.parseFromSlice(std.json.Value, allocator, search_payload, .{});
    defer search_parsed.deinit();
    try std.testing.expectEqualStrings("team:alpha", search_parsed.value.object.get("scopes").?.array.items[0].string);
    try std.testing.expectEqualStrings("session-1", search_parsed.value.object.get("session_id").?.string);
    try std.testing.expect(search_parsed.value.object.get("include_sessions").?.bool);
    try std.testing.expectError(error.InvalidRawJson, agentMemorySearchPayload(allocator, "zig", 10, null, false, "{\"scope\":\"team:alpha\"}"));
}

fn agentMemoryListQuery(allocator: std.mem.Allocator, category: ?[]const u8, session_id: ?[]const u8, scope: ?[]const u8, include_sessions: bool, include_internal: bool, limit: usize, offset: usize) ![]u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    var first = true;
    try appendQueryUsize(allocator, &out, &first, "limit", limit);
    try appendQueryUsize(allocator, &out, &first, "offset", offset);
    if (category) |value| try appendQueryString(allocator, &out, &first, "category", value);
    if (session_id) |value| try appendQueryString(allocator, &out, &first, "session_id", value);
    if (scope) |value| try appendQueryString(allocator, &out, &first, "scope", value);
    if (include_sessions) try appendQueryString(allocator, &out, &first, "include_sessions", "true");
    if (include_internal) try appendQueryString(allocator, &out, &first, "include_internal", "true");
    return out.toOwnedSlice(allocator);
}

