fn sessionPath(allocator: std.mem.Allocator, session_id: []const u8, suffix: []const u8) ![]u8 {
    const encoded = try percentEncode(allocator, session_id);
    defer allocator.free(encoded);
    return std.fmt.allocPrint(allocator, "/agent-sessions/{s}{s}", .{ encoded, suffix });
}

fn sharedScopeFromOwner(actor_id: []const u8) ?[]const u8 {
    const prefix = "shared:";
    if (!std.mem.startsWith(u8, actor_id, prefix)) return null;
    return actor_id[prefix.len..];
}

fn fallbackDeletePermissions(allocator: std.mem.Allocator, owner_actor_id: []const u8, explicit_scope: ?[]const u8) ![]u8 {
    if (explicit_scope) |scope| return scopesJson(allocator, &.{scope});
    return domain.actorGrantJson(allocator, owner_actor_id);
}

fn externalAgentMemoryOwner(allocator: std.mem.Allocator, actor_id: []const u8, requested_scope: ?[]const u8) ![]const u8 {
    return access.agentMemoryOwner(allocator, actor_id, requested_scope);
}

fn scopesJson(allocator: std.mem.Allocator, scopes: []const []const u8) ![]u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.append(allocator, '[');
    for (scopes, 0..) |scope, i| {
        if (i > 0) try out.append(allocator, ',');
        try json.appendString(&out, allocator, scope);
    }
    try out.append(allocator, ']');
    return out.toOwnedSlice(allocator);
}

fn sessionScopesJson(allocator: std.mem.Allocator, session_id: []const u8, write: bool) ![]u8 {
    const read_scope = try std.fmt.allocPrint(allocator, "session:{s}", .{session_id});
    defer allocator.free(read_scope);
    if (!write) return scopesJson(allocator, &.{read_scope});
    const write_scope = try std.fmt.allocPrint(allocator, "write:session:{s}", .{session_id});
    defer allocator.free(write_scope);
    return scopesJson(allocator, &.{ read_scope, write_scope });
}

fn allocatorSessionAllScopesJson(allocator: std.mem.Allocator, write: bool) ![]u8 {
    return if (write) scopesJson(allocator, &.{ "session:*", "write:session:*" }) else scopesJson(allocator, &.{"session:*"});
}

fn appendQueryUsize(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), first: *bool, name: []const u8, value: usize) !void {
    if (!first.*) try out.append(allocator, '&');
    first.* = false;
    try out.print(allocator, "{s}={d}", .{ name, value });
}

fn appendQueryI64(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), first: *bool, name: []const u8, value: i64) !void {
    if (!first.*) try out.append(allocator, '&');
    first.* = false;
    try out.print(allocator, "{s}={d}", .{ name, value });
}

fn appendQueryString(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), first: *bool, name: []const u8, value: []const u8) !void {
    const encoded = try percentEncode(allocator, value);
    defer allocator.free(encoded);
    if (!first.*) try out.append(allocator, '&');
    first.* = false;
    try out.appendSlice(allocator, name);
    try out.append(allocator, '=');
    try out.appendSlice(allocator, encoded);
}

fn apiRemoteStorageQuery(allocator: std.mem.Allocator, query: []const u8, remote_storage: ?[]const u8) ![]u8 {
    const storage = apiEffectiveRemoteStorage(remote_storage);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    var first = true;
    if (query.len > 0) {
        var it = std.mem.splitScalar(u8, query, '&');
        while (it.next()) |part| {
            if (part.len == 0) continue;
            const eq = std.mem.indexOfScalar(u8, part, '=') orelse part.len;
            if (storage_routes.isSelectorField(part[0..eq])) continue;
            if (!first) try out.append(allocator, '&');
            first = false;
            try out.appendSlice(allocator, part);
        }
    }
    const field = storage_routes.canonicalQueryFieldForValue(storage);
    try appendQueryString(allocator, &out, &first, field, storage);
    return out.toOwnedSlice(allocator);
}

fn apiRemoteRuntimeFeedQuery(allocator: std.mem.Allocator, query: []const u8, remote_storage: ?[]const u8) ![]u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    var first = true;
    if (query.len > 0) {
        var it = std.mem.splitScalar(u8, query, '&');
        while (it.next()) |part| {
            if (part.len == 0) continue;
            const eq = std.mem.indexOfScalar(u8, part, '=') orelse part.len;
            if (apiRemoteFeedSelectorParam(part[0..eq])) continue;
            if (!first) try out.append(allocator, '&');
            first = false;
            try out.appendSlice(allocator, part);
        }
    }
    try appendQueryString(allocator, &out, &first, "feed_backend", "runtime");
    const storage = apiEffectiveRemoteStorage(remote_storage);
    const field = storage_routes.canonicalQueryFieldForValue(storage);
    try appendQueryString(allocator, &out, &first, field, storage);
    return out.toOwnedSlice(allocator);
}

fn apiEffectiveRemoteStorage(remote_storage: ?[]const u8) []const u8 {
    if (remote_storage) |raw| {
        const trimmed = std.mem.trim(u8, raw, " \t\r\n");
        if (trimmed.len > 0) return trimmed;
    }
    return "runtime";
}

fn apiRemoteFeedSelectorParam(name: []const u8) bool {
    return storage_routes.isSelectorField(name) or
        std.mem.eql(u8, name, "feed_backend") or
        std.mem.eql(u8, name, "runtime_feed") or
        std.mem.eql(u8, name, "native_runtime_feed");
}

fn apiBackendUrl(allocator: std.mem.Allocator, base_url: []const u8, path: []const u8, query: []const u8, allow_insecure_http: bool) ![]u8 {
    return agentMemoryHttpUrl(allocator, base_url, "/v1", path, query, allow_insecure_http);
}

fn agentMemoryHttpUrl(allocator: std.mem.Allocator, base_url: []const u8, version_prefix: ?[]const u8, path: []const u8, query: []const u8, allow_insecure_http: bool) ![]u8 {
    var end = base_url.len;
    while (end > 0 and base_url[end - 1] == '/') : (end -= 1) {}
    const trimmed = base_url[0..end];
    const prefix = if (version_prefix) |version| if (std.mem.endsWith(u8, trimmed, version)) "" else version else "";
    const separator = if (path.len > 0 and path[0] == '/') "" else "/";
    var suffix: std.ArrayListUnmanaged(u8) = .empty;
    defer suffix.deinit(allocator);
    try suffix.appendSlice(allocator, prefix);
    try suffix.appendSlice(allocator, separator);
    try suffix.appendSlice(allocator, path);
    if (query.len > 0) {
        try suffix.append(allocator, '?');
        try suffix.appendSlice(allocator, query);
    }
    return net_security.joinHttpBaseUrl(allocator, base_url, suffix.items, allow_insecure_http);
}

const api_request_header_capacity: usize = 4;

const ApiRequestHeaders = struct {
    headers: [api_request_header_capacity]std.http.Header = undefined,
    count: usize = 0,
    auth_header: ?[]u8 = null,

    fn slice(self: *const ApiRequestHeaders) []const std.http.Header {
        return self.headers[0..self.count];
    }

    fn append(self: *ApiRequestHeaders, header: std.http.Header) !void {
        if (self.count >= self.headers.len) return error.TooManyApiRequestHeaders;
        self.headers[self.count] = header;
        self.count += 1;
    }

    fn deinit(self: *ApiRequestHeaders, allocator: std.mem.Allocator) void {
        if (self.auth_header) |header| allocator.free(header);
        self.* = .{};
    }
};

fn buildApiRequestHeaders(allocator: std.mem.Allocator, cfg: ApiConfig, actor_id: ?[]const u8, scopes_json: ?[]const u8, capabilities_json: ?[]const u8) !ApiRequestHeaders {
    var out: ApiRequestHeaders = .{};
    errdefer out.deinit(allocator);

    if (cfg.token) |token| {
        try net_security.validateHttpHeaderValue(token);
        switch (cfg.profile.authScheme()) {
            .bearer => {
                out.auth_header = try std.fmt.allocPrint(allocator, "Bearer {s}", .{token});
                try out.append(.{ .name = "Authorization", .value = out.auth_header.? });
            },
            .token => {
                out.auth_header = try std.fmt.allocPrint(allocator, "Token {s}", .{token});
                try out.append(.{ .name = "Authorization", .value = out.auth_header.? });
            },
            .x_api_key => {
                try out.append(.{ .name = "X-API-Key", .value = token });
            },
        }
    }
    if (actor_id) |actor| {
        if (actor.len > 0) {
            try net_security.validateHttpHeaderValue(actor);
            try out.append(.{ .name = "X-NullPantry-Actor-Id", .value = actor });
        }
    }
    const scopes_header = scopes_json orelse cfg.actor_scopes_json;
    try net_security.validateHttpHeaderValue(scopes_header);
    try out.append(.{ .name = "X-NullPantry-Actor-Scopes", .value = scopes_header });
    const capabilities_header = capabilities_json orelse cfg.actor_capabilities_json;
    try net_security.validateHttpHeaderValue(capabilities_header);
    try out.append(.{ .name = "X-NullPantry-Actor-Capabilities", .value = capabilities_header });
    return out;
}

fn findHttpHeader(headers: []const std.http.Header, name: []const u8) ?[]const u8 {
    for (headers) |header| {
        if (std.ascii.eqlIgnoreCase(header.name, name)) return header.value;
    }
    return null;
}

fn requestApiJson(allocator: std.mem.Allocator, method: std.http.Method, url: []const u8, cfg: ApiConfig, actor_id: ?[]const u8, scopes_json: ?[]const u8, capabilities_json: ?[]const u8, payload: []const u8) !ApiHttpResponse {
    var request_headers = try buildApiRequestHeaders(allocator, cfg, actor_id, scopes_json, capabilities_json);
    defer request_headers.deinit(allocator);

    var client: std.http.Client = .{ .allocator = allocator, .io = compat.io() };
    defer client.deinit();

    const uri = std.Uri.parse(url) catch return error.AgentMemoryStorageUnavailable;
    var req = client.request(method, uri, .{
        .redirect_behavior = .unhandled,
        .keep_alive = false,
        .headers = .{
            .content_type = .{ .override = "application/json" },
            .accept_encoding = .omit,
            .connection = .{ .override = "close" },
        },
        .extra_headers = request_headers.slice(),
    }) catch return error.AgentMemoryStorageUnavailable;
    defer req.deinit();

    net_security.applyHttpSocketTimeout(req.connection, cfg.timeout_secs);

    if (method.requestHasBody()) {
        req.transfer_encoding = .{ .content_length = payload.len };
        var body_writer = req.sendBodyUnflushed(&.{}) catch return error.AgentMemoryStorageUnavailable;
        body_writer.writer.writeAll(payload) catch return error.AgentMemoryStorageUnavailable;
        body_writer.end() catch return error.AgentMemoryStorageUnavailable;
        net_security.flushHttpConnection(req.connection) catch return error.AgentMemoryStorageUnavailable;
    } else {
        req.sendBodiless() catch return error.AgentMemoryStorageUnavailable;
    }

    var response = req.receiveHead(&.{}) catch return error.AgentMemoryStorageUnavailable;
    const reader = response.reader(&.{});
    const body = net_security.readBoundedResponse(allocator, reader, cfg.max_response_bytes) catch |err| switch (err) {
        error.StreamTooLong => return error.AgentMemoryResponseTooLarge,
        else => return error.AgentMemoryStorageUnavailable,
    };
    return .{ .status = response.head.status, .body = body };
}

fn parseAgentMemoryWrapper(allocator: std.mem.Allocator, body: []const u8, field: []const u8) !domain.AgentMemory {
    const parsed = std.json.parseFromSlice(std.json.Value, allocator, body, .{}) catch return error.AgentMemoryStorageUnavailable;
    defer parsed.deinit();
    if (parsed.value != .object) return error.AgentMemoryStorageUnavailable;
    const value = parsed.value.object.get(field) orelse return error.AgentMemoryStorageUnavailable;
    return agentMemoryFromJsonValue(allocator, value);
}

fn parseAgentMemoryArrayWrapper(allocator: std.mem.Allocator, body: []const u8, field: []const u8) ![]domain.AgentMemory {
    const parsed = std.json.parseFromSlice(std.json.Value, allocator, body, .{}) catch return error.AgentMemoryStorageUnavailable;
    defer parsed.deinit();
    if (parsed.value != .object) return error.AgentMemoryStorageUnavailable;
    const value = parsed.value.object.get(field) orelse return error.AgentMemoryStorageUnavailable;
    if (value != .array) return error.AgentMemoryStorageUnavailable;
    var out: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
    errdefer {
        for (out.items) |*entry| freeAgentMemory(allocator, entry);
        out.deinit(allocator);
    }
    for (value.array.items) |item| {
        try out.append(allocator, try agentMemoryFromJsonValue(allocator, item));
    }
    return out.toOwnedSlice(allocator);
}

fn agentMemoryFromJsonValue(allocator: std.mem.Allocator, value: std.json.Value) !domain.AgentMemory {
    if (value != .object) return error.AgentMemoryStorageUnavailable;
    const obj = value.object;
    const id_value = try requiredJsonStringAliasField(obj, &.{"id"});
    const key_value = try requiredJsonStringAliasField(obj, &.{"key"});
    const owner_value = try requiredJsonStringAliasField(obj, &.{"owner_id"});
    const id_value_owned = try allocator.dupe(u8, id_value);
    errdefer allocator.free(id_value_owned);
    const key = try allocator.dupe(u8, key_value);
    errdefer allocator.free(key);
    const content = try allocator.dupe(u8, try requiredJsonStringAliasField(obj, &.{"content"}));
    errdefer allocator.free(content);
    const category = try allocator.dupe(u8, try requiredJsonStringAliasField(obj, &.{"category"}));
    errdefer allocator.free(category);
    const timestamp = try allocator.dupe(u8, try requiredJsonStringAliasField(obj, &.{"timestamp"}));
    errdefer allocator.free(timestamp);
    const session_id = try requiredJsonNullableStringAliasField(allocator, obj, &.{"session_id"});
    errdefer if (session_id) |sid| allocator.free(sid);
    const owner = try allocator.dupe(u8, owner_value);
    errdefer allocator.free(owner);
    const writer = try allocator.dupe(u8, try requiredJsonStringAliasField(obj, &.{"created_by_actor_id"}));
    errdefer allocator.free(writer);
    const scope = try allocator.dupe(u8, try requiredJsonStringAliasField(obj, &.{"scope"}));
    errdefer allocator.free(scope);
    const permissions = try requiredJsonArrayRawField(allocator, obj, "permissions");
    errdefer allocator.free(permissions);
    const status = try allocator.dupe(u8, try requiredJsonStringAliasField(obj, &.{"status"}));
    errdefer allocator.free(status);
    const store = try optionalJsonStringAliasField(allocator, obj, &.{storage_routes.store_field}) orelse try allocator.dupe(u8, "");
    errdefer allocator.free(store);
    return .{
        .id = id_value_owned,
        .key = key,
        .content = content,
        .category = category,
        .timestamp = timestamp,
        .session_id = session_id,
        .actor_id = owner,
        .writer_actor_id = writer,
        .scope = scope,
        .permissions_json = permissions,
        .status = status,
        .store = store,
        .score = json.floatField(obj, "score"),
    };
}

fn parseMessagesWrapper(allocator: std.mem.Allocator, body: []const u8) ![]Message {
