fn parseFeedEventsWrapper(allocator: std.mem.Allocator, body: []const u8) ![]FeedEvent {
    const parsed = std.json.parseFromSlice(std.json.Value, allocator, body, .{}) catch return error.AgentMemoryStorageUnavailable;
    defer parsed.deinit();
    if (parsed.value != .object) return error.AgentMemoryStorageUnavailable;
    const events_value = responseEventsValue(parsed.value.object) orelse return error.AgentMemoryStorageUnavailable;
    if (events_value != .array) return error.AgentMemoryStorageUnavailable;

    var out: std.ArrayListUnmanaged(FeedEvent) = .empty;
    errdefer {
        for (out.items) |*event| event.deinit(allocator);
        out.deinit(allocator);
    }
    for (events_value.array.items) |item| {
        if (item != .object) return error.AgentMemoryStorageUnavailable;
        try out.ensureUnusedCapacity(allocator, 1);
        out.appendAssumeCapacity(try parseFeedEventValue(allocator, item.object));
    }
    return out.toOwnedSlice(allocator);
}

fn parseRuntimeFeedEventsWrapper(allocator: std.mem.Allocator, body: []const u8) ![]FeedEvent {
    const events = try parseFeedEventsWrapper(allocator, body);
    defer {
        for (events) |*event| event.deinit(allocator);
        allocator.free(events);
    }

    var out: std.ArrayListUnmanaged(FeedEvent) = .empty;
    errdefer {
        for (out.items) |*event| event.deinit(allocator);
        out.deinit(allocator);
    }
    for (events) |event| {
        if (!runtimeFeedObjectTypeSupported(event.object_type)) continue;
        try out.append(allocator, try event.clone(allocator));
    }
    return out.toOwnedSlice(allocator);
}

fn parseRuntimeFeedEventsVisibleWrapper(allocator: std.mem.Allocator, body: []const u8, actor_id: ?[]const u8, scopes_json: []const u8) ![]FeedEvent {
    const events = try parseFeedEventsWrapper(allocator, body);
    defer {
        for (events) |*event| event.deinit(allocator);
        allocator.free(events);
    }

    var out: std.ArrayListUnmanaged(FeedEvent) = .empty;
    errdefer {
        for (out.items) |*event| event.deinit(allocator);
        out.deinit(allocator);
    }
    for (events) |event| {
        if (!runtimeFeedObjectTypeSupported(event.object_type)) continue;
        if (!runtimeFeedEventVisible(allocator, event, actor_id, scopes_json)) continue;
        try out.append(allocator, try event.clone(allocator));
    }
    return out.toOwnedSlice(allocator);
}

fn parseFeedEventValue(allocator: std.mem.Allocator, obj: std.json.ObjectMap) !FeedEvent {
    const id = try requiredJsonI64Field(obj, "id");
    const sequence = try requiredJsonI64Field(obj, "sequence");
    const event_type = try requiredJsonStringField(obj, "event_type");
    const origin_instance_id = try requiredJsonStringField(obj, "origin_instance_id");
    const origin_sequence = try requiredJsonI64Field(obj, "origin_sequence");
    const operation = try requiredJsonStringField(obj, "operation");
    const object_type = try requiredJsonStringField(obj, "object_type");
    const object_id = try requiredJsonStringField(obj, "object_id");
    const scope = try requiredJsonStringField(obj, "scope");
    const actor_id = try optionalJsonNullableStringField(obj, "actor_id");
    const dedupe_key = try optionalJsonNullableStringField(obj, "dedupe_key");
    const status = try requiredJsonStringField(obj, "status");
    const created_at_ms = try requiredJsonI64Field(obj, "created_at_ms");
    const applied_at_ms = try optionalJsonNullableI64Field(obj, "applied_at_ms");
    const compacted_at_ms = try optionalJsonNullableI64Field(obj, "compacted_at_ms");

    const permissions_json = try requiredJsonArrayRawField(allocator, obj, "permissions");
    errdefer allocator.free(permissions_json);
    const causality_json = try optionalJsonObjectRawField(allocator, obj, "causality", "{}");
    errdefer allocator.free(causality_json);
    const payload_json = try requiredJsonObjectRawField(allocator, obj, "payload");
    errdefer allocator.free(payload_json);

    const event_type_copy = try allocator.dupe(u8, event_type);
    errdefer allocator.free(event_type_copy);
    const origin_instance_id_copy = try allocator.dupe(u8, origin_instance_id);
    errdefer allocator.free(origin_instance_id_copy);
    const operation_copy = try allocator.dupe(u8, operation);
    errdefer allocator.free(operation_copy);
    const object_type_copy = try allocator.dupe(u8, object_type);
    errdefer allocator.free(object_type_copy);
    const object_id_copy = try allocator.dupe(u8, object_id);
    errdefer allocator.free(object_id_copy);
    const scope_copy = try allocator.dupe(u8, scope);
    errdefer allocator.free(scope_copy);
    const actor_id_copy = if (actor_id) |value| try allocator.dupe(u8, value) else null;
    errdefer if (actor_id_copy) |value| allocator.free(value);
    const dedupe_key_copy = if (dedupe_key) |value| try allocator.dupe(u8, value) else null;
    errdefer if (dedupe_key_copy) |value| allocator.free(value);
    const status_copy = try allocator.dupe(u8, status);
    errdefer allocator.free(status_copy);

    return .{
        .id = id,
        .sequence = sequence,
        .event_type = event_type_copy,
        .origin_instance_id = origin_instance_id_copy,
        .origin_sequence = origin_sequence,
        .operation = operation_copy,
        .object_type = object_type_copy,
        .object_id = object_id_copy,
        .scope = scope_copy,
        .permissions_json = permissions_json,
        .actor_id = actor_id_copy,
        .dedupe_key = dedupe_key_copy,
        .causality_json = causality_json,
        .payload_json = payload_json,
        .status = status_copy,
        .created_at_ms = created_at_ms,
        .applied_at_ms = applied_at_ms,
        .compacted_at_ms = compacted_at_ms,
    };
}

const RuntimeCheckpointFrontier = struct {
    origin_instance_id: []const u8,
    origin_sequence: i64,
};

const RuntimeCheckpointSequenceMetadata = struct {
    max_event_id: i64,
    last_sequence: i64,
};

fn runtimeCheckpointFrontierFields(obj: std.json.ObjectMap) !RuntimeCheckpointFrontier {
    const origin_instance_id = try requiredJsonStringField(obj, "origin_instance_id");
    if (origin_instance_id.len == 0) return error.AgentMemoryStorageUnavailable;
    return .{
        .origin_instance_id = origin_instance_id,
        .origin_sequence = try requiredJsonNonNegativeI64Field(obj, "origin_sequence"),
    };
}

fn filterRuntimeCheckpointJson(allocator: std.mem.Allocator, body: []const u8, actor_id: ?[]const u8, scopes_json: []const u8) ![]u8 {
    var parsed = std.json.parseFromSlice(std.json.Value, allocator, body, .{}) catch return error.AgentMemoryStorageUnavailable;
    defer parsed.deinit();
    if (parsed.value != .object) return error.AgentMemoryStorageUnavailable;
    const root = parsed.value.object;
    const checkpoint = checkpointObjectValue(root);
    const events_value = runtimeCheckpointEventsValue(root) orelse return error.AgentMemoryStorageUnavailable;
    if (events_value != .array) return error.AgentMemoryStorageUnavailable;

    var events: std.ArrayListUnmanaged(FeedEvent) = .empty;
    defer {
        for (events.items) |*event| event.deinit(allocator);
        events.deinit(allocator);
    }
    var computed_frontiers: std.StringHashMapUnmanaged(i64) = .empty;
    defer deinitRuntimeCheckpointFrontiers(allocator, &computed_frontiers);

    var max_included_event_id: i64 = 0;
    for (events_value.array.items) |item| {
        if (item != .object) return error.AgentMemoryStorageUnavailable;
        var event = try parseLooseFeedEventValue(allocator, item.object, actor_id);
        var event_owned = true;
        defer if (event_owned) event.deinit(allocator);
        if (!runtimeFeedObjectTypeSupported(event.object_type)) continue;
        try validateRuntimeCheckpointEventShape(allocator, item.object, actor_id, scopes_json);
        try advanceRuntimeCheckpointFrontier(allocator, &computed_frontiers, event.origin_instance_id, event.origin_sequence);
        max_included_event_id = @max(max_included_event_id, event.id);
        try events.ensureUnusedCapacity(allocator, 1);
        events.appendAssumeCapacity(event);
        event_owned = false;
    }

    const cursor_floor = try runtimeCheckpointCompactedThrough(root);
    const sequence = try runtimeCheckpointSequenceMetadata(checkpoint, cursor_floor, max_included_event_id);
    const preserve_frontiers = checkpointAdvertisesRuntimeOnly(checkpoint);
    if (preserve_frontiers) try mergeRuntimeCheckpointFrontiers(allocator, &computed_frontiers, root);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.appendSlice(allocator, "{\"instance_id\":");
    try json.appendString(&out, allocator, jsonStringishField(checkpoint, &.{"instance_id"}) orelse "api");
    try out.appendSlice(allocator, ",\"storage_kind\":\"api\",\"feed_object_types\":");
    try out.appendSlice(allocator, feed_object_types_json);
    try out.appendSlice(allocator, ",\"lifecycle_object_types\":");
    try out.appendSlice(allocator, lifecycle_object_types_json);
    try out.print(allocator, ",\"cursor_floor\":{d},\"compacted_through_sequence\":{d},\"max_event_id\":{d},\"last_sequence\":{d},\"frontiers\":[", .{ cursor_floor, cursor_floor, sequence.max_event_id, sequence.last_sequence });
    try appendComputedRuntimeCheckpointFrontiers(allocator, &out, computed_frontiers);
    try out.appendSlice(allocator, "],\"events\":[");
    for (events.items, 0..) |event, i| {
        if (i > 0) try out.append(allocator, ',');
        try event.writeJson(allocator, &out);
    }
    try out.appendSlice(allocator, "]}");
    return out.toOwnedSlice(allocator);
}

fn checkpointObjectValue(obj: std.json.ObjectMap) std.json.ObjectMap {
    const first = responseObjectValue(obj, &.{ "checkpoint", "feed", "memory_feed", "result" }) orelse return obj;
    return responseObjectValue(first, &.{ "checkpoint", "feed", "memory_feed", "result" }) orelse first;
}

fn checkpointAdvertisesRuntimeOnly(obj: std.json.ObjectMap) bool {
    const value = obj.get("feed_object_types") orelse return false;
    if (value != .array) return false;
    if (value.array.items.len == 0) return false;
    for (value.array.items) |item| {
        if (item != .string) return false;
        if (!runtimeFeedObjectTypeSupported(item.string)) return false;
    }
    return true;
}

fn advanceRuntimeCheckpointFrontier(allocator: std.mem.Allocator, frontiers: *std.StringHashMapUnmanaged(i64), origin_instance_id: []const u8, origin_sequence: i64) !void {
    if (origin_instance_id.len == 0 or origin_sequence <= 0) return;
    if (frontiers.getPtr(origin_instance_id)) |current| {
        current.* = @max(current.*, origin_sequence);
        return;
    }
    const owned = try allocator.dupe(u8, origin_instance_id);
    errdefer allocator.free(owned);
    try frontiers.put(allocator, owned, origin_sequence);
}

fn deinitRuntimeCheckpointFrontiers(allocator: std.mem.Allocator, frontiers: *std.StringHashMapUnmanaged(i64)) void {
    var it = frontiers.iterator();
    while (it.next()) |kv| allocator.free(kv.key_ptr.*);
    frontiers.deinit(allocator);
}

fn appendComputedRuntimeCheckpointFrontiers(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), frontiers: std.StringHashMapUnmanaged(i64)) !void {
    var items = try allocator.alloc(RuntimeCheckpointFrontier, frontiers.count());
    defer allocator.free(items);
    var it = frontiers.iterator();
    var i: usize = 0;
    while (it.next()) |kv| : (i += 1) {
        items[i] = .{ .origin_instance_id = kv.key_ptr.*, .origin_sequence = kv.value_ptr.* };
    }
    std.mem.sort(RuntimeCheckpointFrontier, items, {}, struct {
        fn lessThan(_: void, a: RuntimeCheckpointFrontier, b: RuntimeCheckpointFrontier) bool {
            return std.mem.lessThan(u8, a.origin_instance_id, b.origin_instance_id);
        }
    }.lessThan);
    for (items, 0..) |frontier, index| {
        if (index > 0) try out.append(allocator, ',');
        try appendRuntimeCheckpointFrontierJson(allocator, out, frontier.origin_instance_id, frontier.origin_sequence);
    }
}

fn mergeRuntimeCheckpointFrontiers(allocator: std.mem.Allocator, out_frontiers: *std.StringHashMapUnmanaged(i64), obj: std.json.ObjectMap) !void {
    const frontiers_value = runtimeCheckpointFrontiersValue(obj) orelse return;
    if (frontiers_value != .array) return error.AgentMemoryStorageUnavailable;
    for (frontiers_value.array.items) |frontier_value| {
        if (frontier_value != .object) return error.AgentMemoryStorageUnavailable;
        const frontier = try runtimeCheckpointFrontierFields(frontier_value.object);
        try advanceRuntimeCheckpointFrontier(allocator, out_frontiers, frontier.origin_instance_id, frontier.origin_sequence);
    }
}

pub fn parseLooseFeedEventValue(allocator: std.mem.Allocator, obj: std.json.ObjectMap, fallback_actor_id: ?[]const u8) !FeedEvent {
    const event_type = jsonStringishField(obj, &.{"event_type"}) orelse "agent_memory.put";
    const operation = jsonStringishField(obj, &.{"operation"}) orelse feed_contract.operationFromEventType(event_type);
    const object_type = jsonStringishField(obj, &.{"object_type"}) orelse "agent_memory";
    const payload_json = try looseFeedPayloadJson(allocator, obj, object_type);
    errdefer allocator.free(payload_json);
    var payload_parsed = std.json.parseFromSlice(std.json.Value, allocator, payload_json, .{}) catch return error.AgentMemoryStorageUnavailable;
    defer payload_parsed.deinit();
    if (payload_parsed.value != .object) return error.AgentMemoryStorageUnavailable;
    const payload_obj = payload_parsed.value.object;
    const object_id = jsonStringishField(obj, &.{"object_id"}) orelse payloadObjectId(payload_obj, object_type, operation) orelse object_type;
    const scope = try requiredLooseFeedScope(obj, payload_obj);
    const status = jsonStringishField(obj, &.{"status"}) orelse "applied";
    const actor_id = try jsonNullableStringishField(allocator, obj, &.{"actor_id"});
    errdefer if (actor_id) |value| allocator.free(value);
    const event_actor = actor_id orelse jsonStringishField(payload_obj, &.{ "writer_actor_id", "actor_id", "owner_id" }) orelse fallback_actor_id;
    const payload_permissions = try jsonRawArrayField(allocator, payload_obj, &.{ "permissions", "permissions_json" }, "[]");
    defer allocator.free(payload_permissions);
    const event_type_copy = try allocator.dupe(u8, event_type);
    errdefer allocator.free(event_type_copy);
    const origin_instance_id_copy = try allocator.dupe(u8, jsonStringishField(obj, &.{"origin_instance_id"}) orelse "external");
    errdefer allocator.free(origin_instance_id_copy);
    const operation_copy = try allocator.dupe(u8, operation);
    errdefer allocator.free(operation_copy);
    const object_type_copy = try allocator.dupe(u8, object_type);
    errdefer allocator.free(object_type_copy);
    const object_id_copy = try allocator.dupe(u8, object_id);
    errdefer allocator.free(object_id_copy);
    const scope_copy = try allocator.dupe(u8, scope);
    errdefer allocator.free(scope_copy);
    const permissions_json = try jsonRawArrayField(allocator, obj, &.{ "permissions", "permissions_json" }, payload_permissions);
    errdefer allocator.free(permissions_json);
    const actor_id_copy = if (actor_id == null) blk: {
        break :blk if (event_actor) |value| try allocator.dupe(u8, value) else null;
    } else actor_id;
    errdefer if (actor_id == null) if (actor_id_copy) |value| allocator.free(value);
    const dedupe_key = try jsonNullableStringishField(allocator, obj, &.{"dedupe_key"});
    errdefer if (dedupe_key) |value| allocator.free(value);
    const causality_json = try jsonRawObjectField(allocator, obj, &.{ "causality", "causality_json" }, "{}");
    errdefer allocator.free(causality_json);
    const status_copy = try allocator.dupe(u8, status);
    errdefer allocator.free(status_copy);
    var event = FeedEvent{
        .id = jsonI64Field(obj, "id", jsonI64Field(obj, "sequence", 0)),
        .sequence = jsonI64Field(obj, "sequence", jsonI64Field(obj, "id", 0)),
        .event_type = event_type_copy,
        .origin_instance_id = origin_instance_id_copy,
        .origin_sequence = jsonI64Field(obj, "origin_sequence", jsonI64Field(obj, "sequence", jsonI64Field(obj, "id", 0))),
        .operation = operation_copy,
        .object_type = object_type_copy,
        .object_id = object_id_copy,
        .scope = scope_copy,
        .permissions_json = permissions_json,
        .actor_id = actor_id_copy,
        .dedupe_key = dedupe_key,
        .causality_json = causality_json,
        .payload_json = payload_json,
        .status = status_copy,
        .created_at_ms = jsonI64Field(obj, "created_at_ms", jsonI64Field(obj, "timestamp_ms", ids.nowMs())),
        .applied_at_ms = jsonOptionalI64Field(obj, "applied_at_ms") orelse jsonI64Field(obj, "created_at_ms", jsonI64Field(obj, "timestamp_ms", ids.nowMs())),
        .compacted_at_ms = jsonOptionalI64Field(obj, "compacted_at_ms"),
    };
    if (event.sequence <= 0) event.sequence = event.origin_sequence;
    if (event.id <= 0) event.id = event.sequence;
    if (event.origin_sequence <= 0) event.origin_sequence = event.sequence;
    return event;
}

fn looseFeedPayloadJson(allocator: std.mem.Allocator, obj: std.json.ObjectMap, object_type: []const u8) ![]u8 {
    if (obj.get("payload") != null or obj.get("payload_json") != null) {
        return jsonRawObjectField(allocator, obj, &.{ "payload", "payload_json" }, "{}");
    }
    if (!looseFeedTopLevelPayloadSupported(obj, object_type)) return allocator.dupe(u8, "{}");

    const payload_fields = [_][]const u8{
        "key",
        "content",
        "text",
        "value",
        "values",
        "object",
        "category",
        "session_id",
        "session",
        "scope",
        "permissions",
        "permissions_json",
        "owner_id",
        "actor_id",
        "writer_actor_id",
        storage_routes.store_field,
        storage_routes.legacy_storage_field,
        storage_routes.stores_field,
        "value_kind",
        "role",
        "total_tokens",
    };
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.append(allocator, '{');
    var first = true;
    for (&payload_fields) |field| {
        const value = obj.get(field) orelse continue;
        if (!first) try out.append(allocator, ',');
        first = false;
        try json.appendString(&out, allocator, field);
        try out.append(allocator, ':');
        const raw = try json.jsonFromValue(allocator, value);
        defer allocator.free(raw);
        try out.appendSlice(allocator, raw);
    }
    try out.append(allocator, '}');
    return out.toOwnedSlice(allocator);
}

fn looseFeedTopLevelPayloadSupported(obj: std.json.ObjectMap, object_type: []const u8) bool {
    if (std.mem.eql(u8, object_type, "agent_memory")) return jsonStringishField(obj, &.{"key"}) != null;
    if (std.mem.eql(u8, object_type, "agent_session_message")) return jsonStringishField(obj, &.{ "session_id", "session" }) != null;
    if (std.mem.eql(u8, object_type, "agent_session_usage")) return jsonStringishField(obj, &.{ "session_id", "session" }) != null;
    return false;
}

fn payloadObjectId(obj: std.json.ObjectMap, object_type: []const u8, operation: []const u8) ?[]const u8 {
    if (std.mem.eql(u8, object_type, "agent_memory")) return jsonStringishField(obj, &.{"key"});
    if (std.mem.eql(u8, object_type, "agent_session_message")) return jsonStringishField(obj, &.{"session_id"}) orelse operation;
    if (std.mem.eql(u8, object_type, "agent_session_usage")) return jsonStringishField(obj, &.{"session_id"});
    return null;
}

fn requiredLooseFeedScope(event_obj: std.json.ObjectMap, payload_obj: std.json.ObjectMap) ![]const u8 {
    if (try requiredLooseFeedScopeFromObject(event_obj)) |scope| return scope;
    if (try requiredLooseFeedScopeFromObject(payload_obj)) |scope| return scope;
    return error.AgentMemoryStorageUnavailable;
}

fn requiredLooseFeedScopeFromObject(obj: std.json.ObjectMap) !?[]const u8 {
    const value = obj.get("scope") orelse return null;
    if (value != .string) return error.AgentMemoryStorageUnavailable;
    if (std.mem.trim(u8, value.string, " \t\r\n").len == 0) return error.AgentMemoryStorageUnavailable;
    return value.string;
}

fn parseFeedStatus(allocator: std.mem.Allocator, body: []const u8) !FeedStatus {
    const parsed = std.json.parseFromSlice(std.json.Value, allocator, body, .{}) catch return error.AgentMemoryStorageUnavailable;
    defer parsed.deinit();
    if (parsed.value != .object) return error.AgentMemoryStorageUnavailable;
    const obj = responseObjectValue(parsed.value.object, &.{ "status", "feed_status", "feed", "result" }) orelse parsed.value.object;
    const instance_id = try requiredJsonStringField(obj, "instance_id");
    const storage_kind = try requiredJsonStringField(obj, "storage_kind");
    const cursor_floor = try requiredJsonNonNegativeI64Field(obj, "cursor_floor");
    const compacted = try requiredJsonNonNegativeI64Field(obj, "compacted_through_sequence");
    const oldest_available_sequence = try requiredJsonNonNegativeI64Field(obj, "oldest_available_sequence");
    const max_event_id = try requiredJsonNonNegativeI64Field(obj, "max_event_id");
    const last_sequence = try requiredJsonNonNegativeI64Field(obj, "last_sequence");
    const next_local_origin_sequence = try requiredJsonNonNegativeI64Field(obj, "next_local_origin_sequence");

    const instance_id_copy = try allocator.dupe(u8, instance_id);
    errdefer allocator.free(instance_id_copy);
    const storage_kind_copy = try allocator.dupe(u8, storage_kind);
    errdefer allocator.free(storage_kind_copy);
    return .{
        .instance_id = instance_id_copy,
        .storage_kind = storage_kind_copy,
        .supports_compaction = try requiredJsonBoolField(obj, "supports_compaction"),
        .cursor_floor = cursor_floor,
        .compacted_through_sequence = compacted,
        .oldest_available_sequence = oldest_available_sequence,
        .max_event_id = max_event_id,
        .last_sequence = last_sequence,
        .next_local_origin_sequence = next_local_origin_sequence,
        .visible_events = try requiredJsonCountField(obj, "visible_events"),
        .pending_events = try requiredJsonCountField(obj, "pending_events"),
        .applying_events = try requiredJsonCountField(obj, "applying_events"),
        .applied_events = try requiredJsonCountField(obj, "applied_events"),
    };
}

fn parseFeedCompactResult(allocator: std.mem.Allocator, body: []const u8) !FeedCompactResult {
    const parsed = std.json.parseFromSlice(std.json.Value, allocator, body, .{}) catch return error.AgentMemoryStorageUnavailable;
    defer parsed.deinit();
    if (parsed.value != .object) return error.AgentMemoryStorageUnavailable;
    const obj = responseObjectValue(parsed.value.object, &.{ "compaction", "compact", "feed_compaction", "result" }) orelse parsed.value.object;
    return .{
        .cursor_floor = try requiredJsonNonNegativeI64Field(obj, "cursor_floor"),
        .compacted_through_sequence = try requiredJsonNonNegativeI64Field(obj, "compacted_through_sequence"),
        .max_event_id = try requiredJsonNonNegativeI64Field(obj, "max_event_id"),
        .compacted_events = try requiredJsonCountField(obj, "compacted_events"),
    };
}

fn responseEventsValue(obj: std.json.ObjectMap) ?std.json.Value {
    if (obj.get("events")) |events| return events;
    const wrappers = [_][]const u8{ "feed", "memory_feed", "checkpoint", "result" };
    for (&wrappers) |name| {
        if (obj.get(name)) |value| {
            if (value == .object) {
                if (value.object.get("events")) |events| return events;
            }
        }
    }
    return null;
}

fn responseObjectValue(obj: std.json.ObjectMap, names: []const []const u8) ?std.json.ObjectMap {
    for (names) |name| {
        if (obj.get(name)) |value| {
            if (value == .object) return value.object;
        }
    }
    return null;
}

fn runtimeCheckpointFrontiersValue(obj: std.json.ObjectMap) ?std.json.Value {
    return checkpointObjectValue(obj).get("frontiers");
}

pub fn runtimeCheckpointEventsValue(obj: std.json.ObjectMap) ?std.json.Value {
    return checkpointObjectValue(obj).get("events");
}

fn validateRuntimeCheckpointShape(allocator: std.mem.Allocator, obj: std.json.ObjectMap, actor_id: ?[]const u8, scopes_json: []const u8) !void {
    const events_value = runtimeCheckpointEventsValue(obj) orelse return error.AgentMemoryStorageUnavailable;
    if (events_value != .array) return error.AgentMemoryStorageUnavailable;
    for (events_value.array.items) |event_value| {
        if (event_value != .object) return error.AgentMemoryStorageUnavailable;
        try validateRuntimeCheckpointEventShape(allocator, event_value.object, actor_id, scopes_json);
    }
    try validateRuntimeCheckpointFrontiersShape(obj);
}

fn validateRuntimeFeedApplyPayload(allocator: std.mem.Allocator, body: []const u8, actor_id: ?[]const u8, scopes_json: []const u8) !void {
    var parsed = std.json.parseFromSlice(std.json.Value, allocator, body, .{}) catch return error.AgentMemoryStorageUnavailable;
    defer parsed.deinit();
    if (parsed.value != .object) return error.AgentMemoryStorageUnavailable;
    if (runtimeCheckpointEventsValue(parsed.value.object) != null) {
        try validateRuntimeCheckpointShape(allocator, parsed.value.object, actor_id, scopes_json);
        return;
    }
    try validateRuntimeCheckpointEventShape(allocator, parsed.value.object, actor_id, scopes_json);
}

fn validateRuntimeCheckpointEventShape(allocator: std.mem.Allocator, obj: std.json.ObjectMap, actor_id: ?[]const u8, scopes_json: []const u8) !void {
    var event = try parseLooseFeedEventValue(allocator, obj, actor_id);
    defer event.deinit(allocator);
    if (!runtimeFeedObjectTypeSupported(event.object_type)) return error.NotSupported;
    if (event.origin_instance_id.len == 0 or event.origin_sequence <= 0) return error.AgentMemoryStorageUnavailable;
    if (!runtimeFeedEventVisible(allocator, event, actor_id, scopes_json)) return error.Forbidden;
    var payload = try runtimeCheckpointPayloadObject(allocator, event.payload_json);
    defer payload.deinit(allocator);
    if (std.mem.eql(u8, event.object_type, "agent_memory")) {
        try validateRuntimeAgentMemoryPayloadShape(allocator, obj, payload.object, event, actor_id);
    } else if (std.mem.eql(u8, event.object_type, "agent_session_message")) {
        try validateRuntimeSessionMessagePayloadShape(payload.object, event, actor_id);
    } else if (std.mem.eql(u8, event.object_type, "agent_session_usage")) {
        try validateRuntimeSessionUsagePayloadShape(payload.object, event, actor_id);
    }
}

fn runtimeFeedObjectTypeSupported(object_type: []const u8) bool {
    return feed_contract.objectTypeUsesAgentMemoryStorageRoute(object_type);
}

fn runtimeFeedEventVisible(allocator: std.mem.Allocator, event: FeedEvent, actor_id: ?[]const u8, scopes_json: []const u8) bool {
    if (!domain.scopeVisible(event.scope, scopes_json)) return false;
    if (!access.permissionsVisibleForActor(allocator, event.permissions_json, scopes_json, actor_id)) return false;
    return runtimeFeedPayloadVisible(allocator, event, actor_id, scopes_json) catch false;
}

fn runtimeFeedPayloadVisible(allocator: std.mem.Allocator, event: FeedEvent, actor_id: ?[]const u8, scopes_json: []const u8) !bool {
    var payload = try runtimeCheckpointPayloadObject(allocator, event.payload_json);
    defer payload.deinit(allocator);
    const obj = payload.object;

    if (jsonStringishField(obj, &.{"scope"})) |scope| {
        if (!domain.scopeVisible(scope, scopes_json)) return false;
    }
    if (obj.get("permissions") != null or obj.get("permissions_json") != null) {
        const permissions_json = try jsonRawArrayField(allocator, obj, &.{ "permissions", "permissions_json" }, "[]");
        defer allocator.free(permissions_json);
        if (!access.permissionsVisibleForActor(allocator, permissions_json, scopes_json, actor_id)) return false;
    }

    if (std.mem.eql(u8, event.object_type, "agent_memory")) {
        if (!try runtimeAgentMemoryOwnerVisible(allocator, obj, event, actor_id, scopes_json)) return false;
        if (access.normalizeSessionId(jsonStringishField(obj, &.{ "session_id", "session" }))) |session_id| {
            if (!access.sessionVisibleForScopes(allocator, session_id, scopes_json)) return false;
        }
    } else if (feed_contract.isAgentSessionObject(event.object_type)) {
        if (!try runtimeSessionActorVisible(allocator, obj, event, actor_id, scopes_json)) return false;
        if (access.normalizeSessionId(jsonStringishField(obj, &.{ "session_id", "session" }))) |session_id| {
            if (!access.sessionVisibleForScopes(allocator, session_id, scopes_json)) return false;
        } else if (jsonBoolField(obj, "delete_autosaved", false) or jsonBoolField(obj, "autosave_only", false)) {
            if (!domain.scopeVisible("session:*", scopes_json)) return false;
        } else {
            return false;
        }
    }
    return true;
}

const RuntimeAgentMemoryRequestedOwner = struct {
    owner: []const u8,
    explicit: bool,
};

fn runtimeAgentMemoryRequestedOwner(payload_obj: std.json.ObjectMap, event: FeedEvent, actor_id: ?[]const u8) !RuntimeAgentMemoryRequestedOwner {
    const explicit_owner = jsonStringishField(payload_obj, &.{"owner_id"});
    const legacy_actor_owner = jsonStringishField(payload_obj, &.{"actor_id"});
    if (explicit_owner) |owner| {
        if (legacy_actor_owner) |legacy| {
            if (!std.mem.eql(u8, owner, legacy)) return error.Forbidden;
        }
        return .{ .owner = owner, .explicit = true };
    }
    if (legacy_actor_owner) |owner| return .{ .owner = owner, .explicit = true };
    return .{ .owner = event.actor_id orelse actor_id orelse return error.MissingActorId, .explicit = false };
}

fn runtimeActorGrantVisible(allocator: std.mem.Allocator, owner: []const u8, actor_id: ?[]const u8, scopes_json: []const u8) !bool {
    if (actor_id) |caller_actor| {
        if (std.mem.eql(u8, caller_actor, owner)) return true;
    }
    const actor_grant = try domain.actorGrant(allocator, owner);
    defer allocator.free(actor_grant);
    return domain.scopeVisible(actor_grant, scopes_json);
}

fn runtimeAgentMemoryOwnerVisible(allocator: std.mem.Allocator, payload_obj: std.json.ObjectMap, event: FeedEvent, actor_id: ?[]const u8, scopes_json: []const u8) !bool {
    const requested = try runtimeAgentMemoryRequestedOwner(payload_obj, event, actor_id);
    const requested_scope = jsonStringishField(payload_obj, &.{"scope"});
    const effective_owner = try access.agentMemoryOwner(allocator, requested.owner, requested_scope);
    defer allocator.free(effective_owner);
    if (requested.explicit and !std.mem.eql(u8, requested.owner, effective_owner)) {
        const owner_is_event_actor = if (event.actor_id) |event_actor| std.mem.eql(u8, requested.owner, event_actor) else false;
        const owner_is_caller_actor = if (actor_id) |caller_actor| std.mem.eql(u8, requested.owner, caller_actor) else false;
        if (!owner_is_event_actor and !owner_is_caller_actor) return false;
    }
    if (sharedScopeFromOwner(effective_owner)) |scope| return domain.scopeVisible(scope, scopes_json);
    return runtimeActorGrantVisible(allocator, effective_owner, actor_id, scopes_json);
}

fn runtimeAgentMemoryOperationContent(allocator: std.mem.Allocator, payload_obj: std.json.ObjectMap, operation: domain.AgentMemoryOperation) ![]u8 {
    return switch (operation) {
        .put => try agent_memory_reducer.canonicalizePutContent(
            allocator,
            try requiredJsonStringField(payload_obj, "content"),
            jsonStringishField(payload_obj, &.{"value_kind"}),
        ),
        .merge_object => try agent_memory_reducer.objectPatchFromObject(allocator, payload_obj),
        .merge_string_set => try agent_memory_reducer.stringSetPatchFromObject(allocator, payload_obj),
    };
}

fn runtimeSessionPayloadActor(payload_obj: std.json.ObjectMap, event: FeedEvent, actor_id: ?[]const u8) ![]const u8 {
    if (jsonStringishField(payload_obj, &.{"actor_id"})) |payload_actor| {
        if (event.actor_id) |event_actor| {
            if (!std.mem.eql(u8, payload_actor, event_actor)) return error.Forbidden;
        }
        return payload_actor;
    }
    return event.actor_id orelse actor_id orelse return error.MissingActorId;
}

const RuntimeSessionMessagePayload = struct {
    actor_id: []const u8,
    session_id: []const u8,
    role: []const u8,
    content: []const u8,
    created_at_ms: i64,
};

const RuntimeSessionUsagePayload = struct {
    actor_id: []const u8,
    session_id: []const u8,
    total_tokens: u64,
};

fn runtimeSessionMessagePayload(payload_obj: std.json.ObjectMap, event: FeedEvent, actor_id: ?[]const u8) !RuntimeSessionMessagePayload {
    const role = try requiredJsonStringField(payload_obj, "role");
    if (domain.isRuntimeCommandRole(role)) return error.AgentMemoryStorageUnavailable;
    return .{
        .actor_id = try runtimeSessionPayloadActor(payload_obj, event, actor_id),
        .session_id = try requiredJsonStringField(payload_obj, "session_id"),
        .role = role,
        .content = try requiredJsonStringField(payload_obj, "content"),
        .created_at_ms = try requiredJsonNonNegativeI64Field(payload_obj, "created_at_ms"),
    };
}

fn runtimeSessionUsagePayload(payload_obj: std.json.ObjectMap, event: FeedEvent, actor_id: ?[]const u8) !RuntimeSessionUsagePayload {
    return .{
        .actor_id = try runtimeSessionPayloadActor(payload_obj, event, actor_id),
        .session_id = try requiredJsonStringField(payload_obj, "session_id"),
        .total_tokens = try requiredJsonU64Field(payload_obj, "total_tokens"),
    };
}

fn runtimeSessionActorVisible(allocator: std.mem.Allocator, payload_obj: std.json.ObjectMap, event: FeedEvent, actor_id: ?[]const u8, scopes_json: []const u8) !bool {
    const session_actor = try runtimeSessionPayloadActor(payload_obj, event, actor_id);
    return runtimeActorGrantVisible(allocator, session_actor, actor_id, scopes_json);
}

const RuntimeCheckpointPayloadObject = struct {
    object: std.json.ObjectMap,
    parsed: ?std.json.Parsed(std.json.Value) = null,

    fn deinit(self: *RuntimeCheckpointPayloadObject, allocator: std.mem.Allocator) void {
        _ = allocator;
        if (self.parsed) |*parsed| parsed.deinit();
        self.parsed = null;
    }
};

fn runtimeCheckpointPayloadObject(allocator: std.mem.Allocator, payload_json: []const u8) !RuntimeCheckpointPayloadObject {
    var parsed = std.json.parseFromSlice(std.json.Value, allocator, payload_json, .{}) catch return error.AgentMemoryStorageUnavailable;
    errdefer parsed.deinit();
    if (parsed.value != .object) return error.AgentMemoryStorageUnavailable;
    return .{ .object = parsed.value.object, .parsed = parsed };
}

fn validateRuntimeAgentMemoryPayloadShape(allocator: std.mem.Allocator, event_obj: std.json.ObjectMap, payload_obj: std.json.ObjectMap, event: FeedEvent, actor_id: ?[]const u8) !void {
    const key = jsonStringishField(payload_obj, &.{"key"}) orelse jsonStringishField(event_obj, &.{"object_id"}) orelse return error.AgentMemoryStorageUnavailable;
    if (domain.isInternalMemoryKey(key)) return error.AgentMemoryStorageUnavailable;
    _ = try runtimeAgentMemoryRequestedOwner(payload_obj, event, actor_id);
    if (feed_contract.isAgentMemoryDeleteOperation(event.operation) or feed_contract.isLifecycleOperation(event.operation)) {
        return;
    }
    const memory_operation = domain.AgentMemoryOperation.parse(event.operation);
    const content = try runtimeAgentMemoryOperationContent(allocator, payload_obj, memory_operation);
    allocator.free(content);
}

fn validateRuntimeSessionMessagePayloadShape(payload_obj: std.json.ObjectMap, event: FeedEvent, actor_id: ?[]const u8) !void {
    _ = try runtimeSessionPayloadActor(payload_obj, event, actor_id);
    if (std.mem.eql(u8, event.operation, "delete_autosaved")) return;
    _ = try requiredJsonStringField(payload_obj, "session_id");
    if (feed_contract.isAgentSessionDeleteOperation(event.operation)) return;
    _ = try runtimeSessionMessagePayload(payload_obj, event, actor_id);
}

fn validateRuntimeSessionUsagePayloadShape(payload_obj: std.json.ObjectMap, event: FeedEvent, actor_id: ?[]const u8) !void {
    _ = try runtimeSessionPayloadActor(payload_obj, event, actor_id);
    _ = try requiredJsonStringField(payload_obj, "session_id");
    if (feed_contract.isAgentSessionDeleteOperation(event.operation)) return;
    _ = try runtimeSessionUsagePayload(payload_obj, event, actor_id);
}

fn validateRuntimeCheckpointFrontiersShape(obj: std.json.ObjectMap) !void {
    const frontiers = runtimeCheckpointFrontiersValue(obj) orelse return;
    if (frontiers != .array) return error.AgentMemoryStorageUnavailable;
    for (frontiers.array.items) |frontier_value| {
        if (frontier_value != .object) return error.AgentMemoryStorageUnavailable;
        _ = try runtimeCheckpointFrontierFields(frontier_value.object);
    }
}

fn runtimeCheckpointCompactedThrough(obj: std.json.ObjectMap) !i64 {
    const checkpoint = checkpointObjectValue(obj);
    const compacted = try optionalJsonNonNegativeI64Field(checkpoint, "compacted_through_sequence");
    const cursor = try optionalJsonNonNegativeI64Field(checkpoint, "cursor_floor");
    if (compacted) |value| {
        if (cursor) |cursor_value| {
            if (cursor_value != value) return error.AgentMemoryStorageUnavailable;
        }
        return value;
    }
    return cursor orelse 0;
}

fn runtimeCheckpointSequenceMetadata(obj: std.json.ObjectMap, cursor_floor: i64, max_included_event_id: i64) !RuntimeCheckpointSequenceMetadata {
    const floor = @max(cursor_floor, max_included_event_id);
    const max_event_id = try optionalJsonNonNegativeI64Field(obj, "max_event_id");
    const last_sequence = try optionalJsonNonNegativeI64Field(obj, "last_sequence");
    const sequence = max_event_id orelse last_sequence orelse floor;
    if (sequence < floor) return error.AgentMemoryStorageUnavailable;
    if (max_event_id) |value| {
        if (value != sequence) return error.AgentMemoryStorageUnavailable;
    }
    if (last_sequence) |value| {
        if (value != sequence) return error.AgentMemoryStorageUnavailable;
    }
    return .{ .max_event_id = sequence, .last_sequence = sequence };
}

fn appendRuntimeCheckpointFrontierJson(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), origin_instance_id: []const u8, origin_sequence: i64) !void {
    try out.append(allocator, '{');
    try json.appendString(out, allocator, "origin_instance_id");
    try out.append(allocator, ':');
    try json.appendString(out, allocator, origin_instance_id);
    try out.print(allocator, ",\"origin_sequence\":{d}", .{origin_sequence});
    try out.append(allocator, '}');
}

fn parseRemoteSessionInfoValue(allocator: std.mem.Allocator, obj: std.json.ObjectMap) !SessionInfo {
    const session_id = try requiredJsonStringField(obj, "session_id");
    const session_id_copy = try allocator.dupe(u8, session_id);
    errdefer allocator.free(session_id_copy);
    return .{
        .session_id = session_id_copy,
        .message_count = try requiredJsonU64Field(obj, "message_count"),
        .first_message_at = try requiredJsonNonNegativeI64Field(obj, "first_message_at"),
        .last_message_at = try requiredJsonNonNegativeI64Field(obj, "last_message_at"),
    };
}

fn parseRemoteMessageValue(allocator: std.mem.Allocator, obj: std.json.ObjectMap) !Message {
    const role = try requiredJsonStringField(obj, "role");
    const content = try requiredJsonStringField(obj, "content");
    const created_at_ms = try requiredJsonNonNegativeI64Field(obj, "created_at_ms");
    const role_copy = try allocator.dupe(u8, role);
    errdefer allocator.free(role_copy);
    const content_copy = try allocator.dupe(u8, content);
    errdefer allocator.free(content_copy);
    return .{
        .role = role_copy,
        .content = content_copy,
        .created_at_ms = created_at_ms,
    };
}

fn parseMessagesArray(allocator: std.mem.Allocator, value: std.json.Value) ![]Message {
    if (value != .array) return error.AgentMemoryStorageUnavailable;
    var out: std.ArrayListUnmanaged(Message) = .empty;
    errdefer {
        for (out.items) |*message| freeMessage(allocator, message);
        out.deinit(allocator);
    }
    for (value.array.items) |item| {
        if (item != .object) return error.AgentMemoryStorageUnavailable;
        try out.ensureUnusedCapacity(allocator, 1);
        out.appendAssumeCapacity(try parseRemoteMessageValue(allocator, item.object));
    }
    const messages = try out.toOwnedSlice(allocator);
    sortMessages(messages);
    return messages;
}

fn jsonStringishField(obj: std.json.ObjectMap, names: []const []const u8) ?[]const u8 {
    for (names) |name| {
        const value = obj.get(name) orelse continue;
        switch (value) {
            .string => |s| return s,
            .integer, .float, .bool => continue,
            else => continue,
        }
    }
    return null;
}

fn requiredJsonStringField(obj: std.json.ObjectMap, name: []const u8) ![]const u8 {
    const value = obj.get(name) orelse return error.AgentMemoryStorageUnavailable;
    return switch (value) {
        .string => |s| s,
        else => return error.AgentMemoryStorageUnavailable,
    };
}

fn requiredJsonStringAliasField(obj: std.json.ObjectMap, names: []const []const u8) ![]const u8 {
    for (names) |name| {
        const value = obj.get(name) orelse continue;
        return switch (value) {
            .string => |s| s,
            else => error.AgentMemoryStorageUnavailable,
        };
    }
    return error.AgentMemoryStorageUnavailable;
}

fn optionalJsonStringAliasField(allocator: std.mem.Allocator, obj: std.json.ObjectMap, names: []const []const u8) !?[]u8 {
    for (names) |name| {
        const value = obj.get(name) orelse continue;
        return switch (value) {
            .string => |s| try allocator.dupe(u8, s),
            else => error.AgentMemoryStorageUnavailable,
        };
    }
    return null;
}

fn requiredJsonNullableStringAliasField(allocator: std.mem.Allocator, obj: std.json.ObjectMap, names: []const []const u8) !?[]u8 {
    for (names) |name| {
