fn jsonRawField(allocator: std.mem.Allocator, obj: std.json.ObjectMap, names: []const []const u8, fallback: []const u8) ![]u8 {
    for (names) |name| {
        const value = obj.get(name) orelse continue;
        if (value == .null) continue;
        return json.rawJsonFieldValue(allocator, name, value, fallback) catch |err| switch (err) {
            error.InvalidRawJson => error.AgentMemoryStorageUnavailable,
            else => err,
        };
    }
    return json.rawJsonFieldFallback(allocator, if (names.len > 0) names[0] else "", fallback) catch |err| switch (err) {
        error.InvalidRawJson => error.AgentMemoryStorageUnavailable,
        else => err,
    };
}

