fn jsonRawFieldWithRoot(allocator: std.mem.Allocator, obj: std.json.ObjectMap, names: []const []const u8, fallback: []const u8, root: json.RawJsonRoot) ![]u8 {
    const raw = try jsonRawField(allocator, obj, names, fallback);
