fn parseJsonU64(allocator: std.mem.Allocator, body: []const u8, field: []const u8, fallback: u64) u64 {
    const parsed = std.json.parseFromSlice(std.json.Value, allocator, body, .{}) catch return fallback;
    defer parsed.deinit();
    if (parsed.value != .object) return fallback;
    return jsonU64Field(parsed.value.object, field, fallback);
}

fn parseJsonCount(allocator: std.mem.Allocator, body: []const u8, field: []const u8, fallback: usize) usize {
    return runtimeCountFromU64(parseJsonU64(allocator, body, field, runtimeCountToU64(fallback)));
}

fn percentEncode(allocator: std.mem.Allocator, raw: []const u8) ![]u8 {
    return net_security.percentEncodePathSegment(allocator, raw);
}

fn expectRedisSimple(resp: redis.RespValue, expected: []const u8) !void {
    return switch (resp) {
        .simple_string => |value| if (std.mem.eql(u8, value, expected)) {} else error.UnexpectedRedisResponse,
        .err => error.RedisCommandFailed,
        else => error.UnexpectedRedisResponse,
    };
}

const clickhouseGlobalSessionKey = "__nullpantry_global__";
var clickhouse_version_counter: std.atomic.Value(u64) = .init(0);

fn clickhouseSessionKey(session_id: ?[]const u8) []const u8 {
    return session_id orelse clickhouseGlobalSessionKey;
}

fn clickhouseVersion() u64 {
    const millis = bounded_int.nonNegativeI64ToU64(ids.nowMs());
    const seq = clickhouse_version_counter.fetchAdd(1, .monotonic) % 1_000_000;
    return millis * 1_000_000 + seq;
}

fn clickhouseTsvI64OrDefaultZero(raw: []const u8) !i64 {
    const trimmed = std.mem.trim(u8, raw, " \t\r\n");
    if (trimmed.len == 0) return 0;
    return clickhouse_contracts.parseTsvI64(trimmed);
}

fn clickhouseMessageId(allocator: std.mem.Allocator, actor: []const u8, session_id: []const u8, role: []const u8, content: []const u8, created_at_ms: i64) ![]u8 {
    var hash_value = std.hash.Wyhash.hash(0, actor);
    hash_value = std.hash.Wyhash.hash(hash_value, session_id);
    hash_value = std.hash.Wyhash.hash(hash_value, role);
    hash_value = std.hash.Wyhash.hash(hash_value, content);
    var buf: [32]u8 = undefined;
    const ts = try std.fmt.bufPrint(&buf, "{d}", .{created_at_ms});
    hash_value = std.hash.Wyhash.hash(hash_value, ts);
    return std.fmt.allocPrint(allocator, "msg_{x}", .{hash_value});
}

fn clickhouseSafeIdentifier(allocator: std.mem.Allocator, raw: []const u8) ![]u8 {
    if (!clickhouse_contracts.validTableName(raw)) return error.InvalidClickHouseAgentMemoryTable;
    return allocator.dupe(u8, raw);
}

fn clickhouseTableWithSuffix(allocator: std.mem.Allocator, table: []const u8, suffix: []const u8) ![]u8 {
    if (std.mem.lastIndexOfScalar(u8, table, '.')) |dot| {
        return std.fmt.allocPrint(allocator, "{s}.{s}{s}", .{ table[0..dot], table[dot + 1 ..], suffix });
    }
    return std.fmt.allocPrint(allocator, "{s}{s}", .{ table, suffix });
}

fn clickhousePost(allocator: std.mem.Allocator, url: []const u8, api_key: ?[]const u8, timeout_secs: u32, max_response_bytes: usize, content_type: []const u8, body: []const u8) ![]u8 {
    var auth_header: ?[]u8 = null;
    defer if (auth_header) |h| allocator.free(h);
    var extra_headers_buf: [1]std.http.Header = undefined;
    var header_count: usize = 0;
    if (api_key) |key| {
        try net_security.validateHttpHeaderValue(key);
        auth_header = try std.fmt.allocPrint(allocator, "Bearer {s}", .{key});
        extra_headers_buf[header_count] = .{ .name = "Authorization", .value = auth_header.? };
        header_count += 1;
    }
    var client: std.http.Client = .{ .allocator = allocator, .io = compat.io() };
    defer client.deinit();
    const uri = std.Uri.parse(url) catch return error.ClickHouseAgentMemoryUnavailable;
    var req = client.request(.POST, uri, .{
        .redirect_behavior = .unhandled,
        .keep_alive = false,
        .headers = .{
            .content_type = .{ .override = content_type },
            .accept_encoding = .omit,
            .connection = .{ .override = "close" },
        },
        .extra_headers = extra_headers_buf[0..header_count],
    }) catch return error.ClickHouseAgentMemoryUnavailable;
    defer req.deinit();
    net_security.applyHttpSocketTimeout(req.connection, timeout_secs);
    req.transfer_encoding = .{ .content_length = body.len };
    var body_writer = req.sendBodyUnflushed(&.{}) catch return error.ClickHouseAgentMemoryUnavailable;
    body_writer.writer.writeAll(body) catch return error.ClickHouseAgentMemoryUnavailable;
    body_writer.end() catch return error.ClickHouseAgentMemoryUnavailable;
    net_security.flushHttpConnection(req.connection) catch return error.ClickHouseAgentMemoryUnavailable;
    var response = req.receiveHead(&.{}) catch return error.ClickHouseAgentMemoryUnavailable;
    if (response.head.status != .ok) return error.ClickHouseAgentMemoryHttpError;
    const reader = response.reader(&.{});
    const response_body = net_security.readBoundedResponse(allocator, reader, max_response_bytes) catch |err| switch (err) {
        error.StreamTooLong => return error.ClickHouseAgentMemoryResponseTooLarge,
        else => return error.ClickHouseAgentMemoryUnavailable,
    };
    return response_body;
}

fn parseClickHouseFeedEvents(allocator: std.mem.Allocator, body: []const u8) ![]FeedEvent {
    const array_json = try clickhouse_contracts.jsonEachRowsToArray(allocator, body);
    defer allocator.free(array_json);
    var parsed = try std.json.parseFromSlice(std.json.Value, allocator, array_json, .{});
    defer parsed.deinit();
    if (parsed.value != .array) return allocator.alloc(FeedEvent, 0);
    var out: std.ArrayListUnmanaged(FeedEvent) = .empty;
    errdefer {
        for (out.items) |*event| event.deinit(allocator);
        out.deinit(allocator);
    }
    for (parsed.value.array.items) |item| {
        if (item != .object) return error.InvalidClickHouseJsonField;
        const obj = item.object;
        const id = try clickhouse_contracts.jsonRequiredI64Field(obj, "id");
        const sequence = try clickhouse_contracts.jsonRequiredI64Field(obj, "sequence");
        const event_type = try clickhouse_contracts.jsonRequiredStringField(obj, "event_type");
        const origin_instance_id = try clickhouse_contracts.jsonRequiredStringField(obj, "origin_instance_id");
        const origin_sequence = try clickhouse_contracts.jsonRequiredI64Field(obj, "origin_sequence");
        const operation = try clickhouse_contracts.jsonRequiredStringField(obj, "operation");
        const object_type = try clickhouse_contracts.jsonRequiredStringField(obj, "object_type");
        const object_id = try clickhouse_contracts.jsonRequiredStringField(obj, "object_id");
        const scope = try clickhouse_contracts.jsonRequiredStringField(obj, "scope");
        const permissions_json = try clickhouse_contracts.jsonRequiredStringField(obj, "permissions_json");
        const actor_id = try clickhouse_contracts.jsonRequiredNullableStringField(obj, "actor_id");
        const dedupe_key = try clickhouse_contracts.jsonRequiredNullableStringField(obj, "dedupe_key");
        const causality_json = try clickhouse_contracts.jsonRequiredStringField(obj, "causality_json");
        const payload_json = try clickhouse_contracts.jsonRequiredStringField(obj, "payload_json");
        const status = try clickhouse_contracts.jsonRequiredStringField(obj, "status");
        const created_at_ms = try clickhouse_contracts.jsonRequiredI64Field(obj, "created_at_ms");
        const applied_at_ms = try clickhouse_contracts.jsonRequiredNullableI64Field(obj, "applied_at_ms");
        const compacted_at_ms = try clickhouse_contracts.jsonRequiredNullableI64Field(obj, "compacted_at_ms");

        var event_type_copy: ?[]u8 = try allocator.dupe(u8, event_type);
        errdefer if (event_type_copy) |value| allocator.free(value);
        var origin_instance_id_copy: ?[]u8 = try allocator.dupe(u8, origin_instance_id);
        errdefer if (origin_instance_id_copy) |value| allocator.free(value);
        var operation_copy: ?[]u8 = try allocator.dupe(u8, operation);
        errdefer if (operation_copy) |value| allocator.free(value);
        var object_type_copy: ?[]u8 = try allocator.dupe(u8, object_type);
        errdefer if (object_type_copy) |value| allocator.free(value);
        var object_id_copy: ?[]u8 = try allocator.dupe(u8, object_id);
        errdefer if (object_id_copy) |value| allocator.free(value);
        var scope_copy: ?[]u8 = try allocator.dupe(u8, scope);
        errdefer if (scope_copy) |value| allocator.free(value);
        var permissions_json_copy: ?[]u8 = try allocator.dupe(u8, permissions_json);
        errdefer if (permissions_json_copy) |value| allocator.free(value);
        var actor_id_copy: ?[]u8 = if (actor_id) |value| try allocator.dupe(u8, value) else null;
        errdefer if (actor_id_copy) |value| allocator.free(value);
        var dedupe_key_copy: ?[]u8 = if (dedupe_key) |value| try allocator.dupe(u8, value) else null;
        errdefer if (dedupe_key_copy) |value| allocator.free(value);
        var causality_json_copy: ?[]u8 = try allocator.dupe(u8, causality_json);
        errdefer if (causality_json_copy) |value| allocator.free(value);
        var payload_json_copy: ?[]u8 = try allocator.dupe(u8, payload_json);
        errdefer if (payload_json_copy) |value| allocator.free(value);
        var status_copy: ?[]u8 = try allocator.dupe(u8, status);
        errdefer if (status_copy) |value| allocator.free(value);

        const event = FeedEvent{
            .id = id,
            .sequence = sequence,
            .event_type = event_type_copy.?,
            .origin_instance_id = origin_instance_id_copy.?,
            .origin_sequence = origin_sequence,
            .operation = operation_copy.?,
            .object_type = object_type_copy.?,
            .object_id = object_id_copy.?,
            .scope = scope_copy.?,
            .permissions_json = permissions_json_copy.?,
            .actor_id = actor_id_copy,
            .dedupe_key = dedupe_key_copy,
            .causality_json = causality_json_copy.?,
            .payload_json = payload_json_copy.?,
            .status = status_copy.?,
            .created_at_ms = created_at_ms,
            .applied_at_ms = applied_at_ms,
            .compacted_at_ms = compacted_at_ms,
        };
        try out.append(allocator, event);
        event_type_copy = null;
        origin_instance_id_copy = null;
        operation_copy = null;
        object_type_copy = null;
        object_id_copy = null;
        scope_copy = null;
        permissions_json_copy = null;
        actor_id_copy = null;
        dedupe_key_copy = null;
        causality_json_copy = null;
        payload_json_copy = null;
        status_copy = null;
    }
    return out.toOwnedSlice(allocator);
}

fn parseClickHouseMemoryStates(allocator: std.mem.Allocator, body: []const u8) ![]ClickHouseMemoryState {
    const array_json = try clickhouse_contracts.jsonEachRowsToArray(allocator, body);
    defer allocator.free(array_json);
    var parsed = try std.json.parseFromSlice(std.json.Value, allocator, array_json, .{});
    defer parsed.deinit();
    if (parsed.value != .array) return allocator.alloc(ClickHouseMemoryState, 0);
    var out: std.ArrayListUnmanaged(ClickHouseMemoryState) = .empty;
    errdefer {
        for (out.items) |*state| freeClickHouseMemoryState(allocator, state);
        out.deinit(allocator);
    }
    for (parsed.value.array.items) |item| {
        if (item != .object) return error.InvalidClickHouseJsonField;
        const obj = item.object;
        const id = try clickhouse_contracts.jsonRequiredStringField(obj, "id");
        const key = try clickhouse_contracts.jsonRequiredStringField(obj, "key");
        const content = try clickhouse_contracts.jsonRequiredStringField(obj, "content");
        const category = try clickhouse_contracts.jsonRequiredStringField(obj, "category");
        const session_id = try clickhouse_contracts.jsonRequiredNullableStringField(obj, "session_id");
        const actor = try clickhouse_contracts.jsonRequiredStringField(obj, "actor_id");
        const writer_actor_id = try clickhouse_contracts.jsonRequiredStringField(obj, "writer_actor_id");
        const scope = try clickhouse_contracts.jsonRequiredStringField(obj, "scope");
        const permissions_json = try clickhouse_contracts.jsonRequiredStringField(obj, "permissions_json");
        const status = try clickhouse_contracts.jsonRequiredStringField(obj, "status");
        const timestamp_ms = try clickhouse_contracts.jsonRequiredI64Field(obj, "timestamp_ms");
        const event_timestamp_ms = try clickhouse_contracts.jsonRequiredI64Field(obj, "event_timestamp_ms");
        const origin_instance_id = try clickhouse_contracts.jsonRequiredStringField(obj, "origin_instance_id");
        const origin_sequence = try clickhouse_contracts.jsonRequiredI64Field(obj, "origin_sequence");

        const id_copy = try allocator.dupe(u8, id);
        var id_owned = true;
        errdefer if (id_owned) allocator.free(id_copy);
        const key_copy = try allocator.dupe(u8, key);
        var key_owned = true;
        errdefer if (key_owned) allocator.free(key_copy);
        const content_copy = try allocator.dupe(u8, content);
        var content_owned = true;
        errdefer if (content_owned) allocator.free(content_copy);
        const category_copy = try allocator.dupe(u8, category);
        var category_owned = true;
        errdefer if (category_owned) allocator.free(category_copy);
        const timestamp_copy = try std.fmt.allocPrint(allocator, "{d}", .{timestamp_ms});
        var timestamp_owned = true;
        errdefer if (timestamp_owned) allocator.free(timestamp_copy);
        const session_id_copy = if (session_id) |sid| try allocator.dupe(u8, sid) else null;
        var session_id_owned = session_id_copy != null;
        errdefer if (session_id_owned) allocator.free(session_id_copy.?);
        const actor_copy = try allocator.dupe(u8, actor);
        var actor_owned = true;
        errdefer if (actor_owned) allocator.free(actor_copy);
        const writer_actor_id_copy = try allocator.dupe(u8, writer_actor_id);
        var writer_actor_id_owned = true;
        errdefer if (writer_actor_id_owned) allocator.free(writer_actor_id_copy);
        const scope_copy = try allocator.dupe(u8, scope);
        var scope_owned = true;
        errdefer if (scope_owned) allocator.free(scope_copy);
        const permissions_json_copy = try allocator.dupe(u8, permissions_json);
        var permissions_json_owned = true;
        errdefer if (permissions_json_owned) allocator.free(permissions_json_copy);
        const status_copy = try allocator.dupe(u8, status);
        var status_owned = true;
        errdefer if (status_owned) allocator.free(status_copy);
        const store_copy = try allocator.dupe(u8, "clickhouse");
        var store_owned = true;
        errdefer if (store_owned) allocator.free(store_copy);
        const origin_instance_id_copy = try allocator.dupe(u8, origin_instance_id);
        var origin_instance_id_owned = true;
        errdefer if (origin_instance_id_owned) allocator.free(origin_instance_id_copy);

        const entry = domain.AgentMemory{
            .id = id_copy,
            .key = key_copy,
            .content = content_copy,
            .category = category_copy,
            .timestamp = timestamp_copy,
            .session_id = session_id_copy,
            .actor_id = actor_copy,
            .writer_actor_id = writer_actor_id_copy,
            .scope = scope_copy,
            .permissions_json = permissions_json_copy,
            .status = status_copy,
            .store = store_copy,
        };
        try out.append(allocator, .{
            .entry = entry,
            .event_order = .{
                .timestamp_ms = event_timestamp_ms,
                .origin_instance_id = origin_instance_id_copy,
                .origin_sequence = origin_sequence,
            },
        });
        id_owned = false;
        key_owned = false;
        content_owned = false;
        category_owned = false;
        timestamp_owned = false;
        session_id_owned = false;
        actor_owned = false;
        writer_actor_id_owned = false;
        scope_owned = false;
        permissions_json_owned = false;
        status_owned = false;
        store_owned = false;
        origin_instance_id_owned = false;
    }
    return out.toOwnedSlice(allocator);
}

fn clickhouseTombstoneRowsBlockEventOrder(allocator: std.mem.Allocator, body: []const u8, event_order: EventOrder) !bool {
    const array_json = try clickhouse_contracts.jsonEachRowsToArray(allocator, body);
    defer allocator.free(array_json);
    var parsed = try std.json.parseFromSlice(std.json.Value, allocator, array_json, .{});
    defer parsed.deinit();
    if (parsed.value != .array) return error.InvalidClickHouseJsonField;
    for (parsed.value.array.items) |item| {
        if (item != .object) return error.InvalidClickHouseJsonField;
        const obj = item.object;
        const stored_timestamp_ms = try clickhouse_contracts.jsonRequiredI64Field(obj, "event_timestamp_ms");
        const stored_origin_instance_id = try clickhouse_contracts.jsonRequiredStringField(obj, "origin_instance_id");
        const stored_origin_sequence = try clickhouse_contracts.jsonRequiredI64Field(obj, "origin_sequence");
        if (compareEventOrder(event_order, stored_timestamp_ms, stored_origin_instance_id, stored_origin_sequence) <= 0) return true;
    }
    return false;
}

fn parseClickHouseMessageStates(allocator: std.mem.Allocator, body: []const u8) ![]ClickHouseMessageState {
    const array_json = try clickhouse_contracts.jsonEachRowsToArray(allocator, body);
    defer allocator.free(array_json);
    var parsed = try std.json.parseFromSlice(std.json.Value, allocator, array_json, .{});
    defer parsed.deinit();
    if (parsed.value != .array) return allocator.alloc(ClickHouseMessageState, 0);
    var out: std.ArrayListUnmanaged(ClickHouseMessageState) = .empty;
    errdefer {
        for (out.items) |*state| freeClickHouseMessageState(allocator, state);
        out.deinit(allocator);
    }
    for (parsed.value.array.items) |item| {
        if (item != .object) return error.InvalidClickHouseJsonField;
        const obj = item.object;
        const actor = try clickhouse_contracts.jsonRequiredStringField(obj, "actor_id");
        const session_id = try clickhouse_contracts.jsonRequiredStringField(obj, "session_id");
        const message_id = try clickhouse_contracts.jsonRequiredStringField(obj, "message_id");
        const role = try clickhouse_contracts.jsonRequiredStringField(obj, "role");
        const content = try clickhouse_contracts.jsonRequiredStringField(obj, "content");
        const created_at_ms = try clickhouse_contracts.jsonRequiredI64Field(obj, "created_at_ms");
        const event_timestamp_ms = try clickhouse_contracts.jsonRequiredI64Field(obj, "event_timestamp_ms");
        const origin_instance_id = try clickhouse_contracts.jsonRequiredStringField(obj, "origin_instance_id");
        const origin_sequence = try clickhouse_contracts.jsonRequiredI64Field(obj, "origin_sequence");
        const role_copy = try allocator.dupe(u8, role);
        errdefer allocator.free(role_copy);
        const content_copy = try allocator.dupe(u8, content);
        errdefer allocator.free(content_copy);
        const actor_copy = try allocator.dupe(u8, actor);
        errdefer allocator.free(actor_copy);
        const session_id_copy = try allocator.dupe(u8, session_id);
        errdefer allocator.free(session_id_copy);
        const message_id_copy = try allocator.dupe(u8, message_id);
        errdefer allocator.free(message_id_copy);
        const origin_instance_id_copy = try allocator.dupe(u8, origin_instance_id);
        errdefer allocator.free(origin_instance_id_copy);
        try out.append(allocator, .{
            .message = .{
                .role = role_copy,
                .content = content_copy,
                .created_at_ms = created_at_ms,
            },
            .actor_id = actor_copy,
            .session_id = session_id_copy,
            .message_id = message_id_copy,
            .event_order = .{
                .timestamp_ms = event_timestamp_ms,
                .origin_instance_id = origin_instance_id_copy,
                .origin_sequence = origin_sequence,
            },
        });
    }
    return out.toOwnedSlice(allocator);
}

