fn entryVisible(allocator: std.mem.Allocator, entry: domain.AgentMemory, actor_id: []const u8, scopes_json: []const u8) !bool {
    const record_visible = domain.scopeVisible(entry.scope, scopes_json) and
        access.permissionsVisibleForActor(allocator, entry.permissions_json, scopes_json, actor_id);
    return access.agentMemoryVisible(allocator, .{
        .owner_actor_id = entry.actor_id,
        .scope = entry.scope,
        .permissions_json = entry.permissions_json,
        .session_id = entry.session_id,
        .request_actor_id = actor_id,
        .request_scopes_json = scopes_json,
        .record_visible = record_visible,
        .session_visible = if (entry.session_id) |sid| access.sessionVisibleForScopes(allocator, sid, scopes_json) else true,
    });
}

fn redisHashField(fields: []const redis.RespValue, name: []const u8) !?[]const u8 {
    var i: usize = 0;
    while (i + 1 < fields.len) : (i += 2) {
        const key = try redisRequiredStringFromResp(fields[i]);
        const value = try redisRequiredStringFromResp(fields[i + 1]);
        if (std.mem.eql(u8, key, name)) return value;
    }
    return null;
}

fn requiredHashField(fields: []const redis.RespValue, name: []const u8) ![]const u8 {
    return (try redisHashField(fields, name)) orelse error.AgentMemoryStorageUnavailable;
}

fn redisRequiredArrayFromResp(resp: redis.RespValue) ![]const redis.RespValue {
    return switch (resp) {
        .array => |maybe_items| maybe_items orelse return error.AgentMemoryStorageUnavailable,
        else => return error.AgentMemoryStorageUnavailable,
    };
}

fn redisRequiredStringArrayFromResp(resp: redis.RespValue) ![]const redis.RespValue {
    const values = try redisRequiredArrayFromResp(resp);
    for (values) |value| _ = try redisRequiredStringFromResp(value);
    return values;
}

fn redisOptionalHashFieldsFromResp(resp: redis.RespValue) !?[]const redis.RespValue {
    const fields = try redisRequiredArrayFromResp(resp);
    if (fields.len == 0) return null;
    if (fields.len % 2 != 0) return error.AgentMemoryStorageUnavailable;
    var i: usize = 0;
    while (i < fields.len) : (i += 2) {
        _ = try redisRequiredStringFromResp(fields[i]);
        _ = try redisRequiredStringFromResp(fields[i + 1]);
    }
    return fields;
}

fn redisRequiredStringFromResp(resp: redis.RespValue) ![]const u8 {
    return resp.asString() orelse return error.AgentMemoryStorageUnavailable;
}

fn redisOptionalStringFromResp(resp: redis.RespValue) !?[]const u8 {
    return switch (resp) {
        .bulk_string => |maybe_value| maybe_value,
        .simple_string => |value| value,
        else => return error.AgentMemoryStorageUnavailable,
    };
}

fn redisOptionalStringExistsFromResp(resp: redis.RespValue) !bool {
    return (try redisOptionalStringFromResp(resp)) != null;
}

fn redisRequiredCountFromResp(resp: redis.RespValue) !usize {
    return switch (resp) {
        .integer => |value| if (value >= 0) runtimeCountFromSigned(value) else return error.AgentMemoryStorageUnavailable,
        else => return error.AgentMemoryStorageUnavailable,
    };
}

fn redisExecLastIntegerChanged(resp: redis.RespValue) !bool {
    const replies = try redisRequiredArrayFromResp(resp);
    if (replies.len == 0) return error.AgentMemoryStorageUnavailable;
    return redisRequiredIntegerChangedFromResp(replies[replies.len - 1]);
}

fn redisExecAnyIntegerChanged(resp: redis.RespValue) !bool {
    const replies = try redisRequiredArrayFromResp(resp);
    if (replies.len == 0) return error.AgentMemoryStorageUnavailable;
    var changed_any = false;
    for (replies) |reply| {
        if (try redisRequiredIntegerChangedFromResp(reply)) changed_any = true;
    }
    return changed_any;
}

fn redisRequiredIntegerChangedFromResp(resp: redis.RespValue) !bool {
    const value = switch (resp) {
        .integer => |value| value,
        else => return error.AgentMemoryStorageUnavailable,
    };
    if (value < 0) return error.AgentMemoryStorageUnavailable;
    return value > 0;
}

fn redisUsageTotalFromResp(resp: redis.RespValue) !?u64 {
    const value = switch (resp) {
        .bulk_string => |maybe_value| maybe_value orelse return null,
        .simple_string => |value| value,
        else => return error.AgentMemoryStorageUnavailable,
    };
    return std.fmt.parseInt(u64, value, 10) catch return error.AgentMemoryStorageUnavailable;
}

fn redisSessionInfoFromMetaValues(allocator: std.mem.Allocator, session_id: []const u8, values: []const redis.RespValue) !?SessionInfo {
    if (values.len != 3) return error.AgentMemoryStorageUnavailable;
    const count_raw = try redisOptionalStringFromResp(values[0]);
    const first_raw = try redisOptionalStringFromResp(values[1]);
    const last_raw = try redisOptionalStringFromResp(values[2]);
    if (count_raw == null and first_raw == null and last_raw == null) return null;
    const count_text = count_raw orelse return error.AgentMemoryStorageUnavailable;
    const first_text = first_raw orelse return error.AgentMemoryStorageUnavailable;
    const last_text = last_raw orelse return error.AgentMemoryStorageUnavailable;
    const visible_count = std.fmt.parseInt(u64, count_text, 10) catch return error.AgentMemoryStorageUnavailable;
    if (visible_count == 0) return null;
    const first_message_at = std.fmt.parseInt(i64, first_text, 10) catch return error.AgentMemoryStorageUnavailable;
    const last_message_at = std.fmt.parseInt(i64, last_text, 10) catch return error.AgentMemoryStorageUnavailable;
    return .{
        .session_id = try allocator.dupe(u8, session_id),
        .message_count = visible_count,
        .first_message_at = first_message_at,
        .last_message_at = last_message_at,
    };
}

fn redisStoredNonNegativeI64OrDefault(resp: redis.RespValue, default_value: i64) !i64 {
    if (default_value < 0) return error.AgentMemoryStorageUnavailable;
    return (try redisStoredNonNegativeI64FromResp(resp)) orelse default_value;
}

fn redisStoredNonNegativeI64FromResp(resp: redis.RespValue) !?i64 {
    const value = switch (resp) {
        .integer => |value| value,
        .bulk_string => |maybe_value| blk: {
            const raw = maybe_value orelse return null;
            break :blk std.fmt.parseInt(i64, raw, 10) catch return error.AgentMemoryStorageUnavailable;
        },
        .simple_string => |raw| std.fmt.parseInt(i64, raw, 10) catch return error.AgentMemoryStorageUnavailable,
        else => return error.AgentMemoryStorageUnavailable,
    };
    if (value < 0) return error.AgentMemoryStorageUnavailable;
    return value;
}

fn appendRedisCheckpointFrontiersJson(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), resp: redis.RespValue) !void {
    const values = try redisRequiredArrayFromResp(resp);
    if (values.len % 2 != 0) return error.AgentMemoryStorageUnavailable;
    var written: usize = 0;
    var i: usize = 0;
    while (i < values.len) : (i += 2) {
        const origin_instance_id = try redisRequiredStringFromResp(values[i]);
        if (origin_instance_id.len == 0) return error.AgentMemoryStorageUnavailable;
        const origin_sequence_text = try redisRequiredStringFromResp(values[i + 1]);
        const origin_sequence = std.fmt.parseInt(i64, origin_sequence_text, 10) catch return error.AgentMemoryStorageUnavailable;
        if (origin_sequence < 0) return error.AgentMemoryStorageUnavailable;
        if (written > 0) try out.append(allocator, ',');
        try appendRuntimeCheckpointFrontierJson(allocator, out, origin_instance_id, origin_sequence);
        written += 1;
    }
}

fn redisEventOrderFromHash(resp: redis.RespValue) !?EventOrder {
    const fields = (try redisOptionalHashFieldsFromResp(resp)) orelse return null;
    const timestamp_raw = try requiredHashField(fields, "event_timestamp_ms");
    const origin_sequence_raw = try requiredHashField(fields, "origin_sequence");
    return .{
        .timestamp_ms = std.fmt.parseInt(i64, timestamp_raw, 10) catch return error.AgentMemoryStorageUnavailable,
        .origin_instance_id = try requiredHashField(fields, "origin_instance_id"),
        .origin_sequence = std.fmt.parseInt(i64, origin_sequence_raw, 10) catch return error.AgentMemoryStorageUnavailable,
    };
}

fn messagePayload(allocator: std.mem.Allocator, role: []const u8, content: []const u8, created_at_ms: i64) ![]u8 {
    return messagePayloadOrdered(allocator, role, content, created_at_ms, null);
}

fn messagePayloadOrdered(allocator: std.mem.Allocator, role: []const u8, content: []const u8, created_at_ms: i64, event_order: ?EventOrder) ![]u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.appendSlice(allocator, "{\"role\":");
    try json.appendString(&out, allocator, role);
    try out.appendSlice(allocator, ",\"content\":");
    try json.appendString(&out, allocator, content);
    try out.print(allocator, ",\"created_at_ms\":{d}", .{created_at_ms});
    if (event_order) |order| {
        try out.print(allocator, ",\"event_timestamp_ms\":{d},\"origin_instance_id\":", .{order.timestamp_ms});
        try json.appendString(&out, allocator, order.origin_instance_id);
        try out.print(allocator, ",\"origin_sequence\":{d}", .{order.origin_sequence});
    }
    try out.append(allocator, '}');
    return out.toOwnedSlice(allocator);
}

fn redisMessagePayloadNewerThanOrder(allocator: std.mem.Allocator, payload: []const u8, order: EventOrder) !bool {
    var parsed = std.json.parseFromSlice(std.json.Value, allocator, payload, .{}) catch return error.AgentMemoryStorageUnavailable;
    defer parsed.deinit();
    if (parsed.value != .object) return error.AgentMemoryStorageUnavailable;
    const obj = parsed.value.object;
    const timestamp_ms = (try optionalJsonNonNegativeI64Field(obj, "event_timestamp_ms")) orelse
        (try optionalJsonNonNegativeI64Field(obj, "created_at_ms")) orelse return error.AgentMemoryStorageUnavailable;
    const origin_instance_id = (try optionalJsonNullableStringField(obj, "origin_instance_id")) orelse "";
    const origin_sequence = (try optionalJsonNonNegativeI64Field(obj, "origin_sequence")) orelse 0;
    return compareEventOrder(order, timestamp_ms, origin_instance_id, origin_sequence) < 0;
}

fn redisRequiredSingleZsetScore(resp: redis.RespValue) !i64 {
    const items = try redisRequiredArrayFromResp(resp);
    if (items.len != 2) return error.AgentMemoryStorageUnavailable;
    _ = try redisRequiredStringFromResp(items[0]);
    const raw = try redisRequiredStringFromResp(items[1]);
    const score = std.fmt.parseInt(i64, raw, 10) catch blk: {
        const value = std.fmt.parseFloat(f64, raw) catch return error.AgentMemoryStorageUnavailable;
        break :blk json.safeFloatToI64(value) orelse return error.AgentMemoryStorageUnavailable;
    };
    if (score < 0) return error.AgentMemoryStorageUnavailable;
    return score;
}

fn messagesFromResp(allocator: std.mem.Allocator, resp: redis.RespValue) ![]Message {
    const items = try redisRequiredArrayFromResp(resp);
    var out: std.ArrayListUnmanaged(Message) = .empty;
    errdefer {
        for (out.items) |*message| freeMessage(allocator, message);
        out.deinit(allocator);
    }
    for (items) |item| {
        const payload = try redisRequiredStringFromResp(item);
        const parsed = std.json.parseFromSlice(std.json.Value, allocator, payload, .{}) catch return error.AgentMemoryStorageUnavailable;
        defer parsed.deinit();
        if (parsed.value != .object) return error.AgentMemoryStorageUnavailable;
        const obj = parsed.value.object;
        const role = try allocator.dupe(u8, try requiredJsonStringField(obj, "role"));
        errdefer allocator.free(role);
        const content = try allocator.dupe(u8, try requiredJsonStringField(obj, "content"));
        errdefer allocator.free(content);
        try out.append(allocator, .{
            .role = role,
            .content = content,
            .created_at_ms = try requiredJsonNonNegativeI64Field(obj, "created_at_ms"),
        });
    }
    const messages = try out.toOwnedSlice(allocator);
    sortMessages(messages);
    return messages;
}

fn scoreText(query: []const u8, text: []const u8) f64 {
    return retrieval_mod.lexicalScore(query, text);
}

fn sortAgentMemory(items: []domain.AgentMemory) void {
    std.mem.sort(domain.AgentMemory, items, {}, struct {
        fn lessThan(_: void, a: domain.AgentMemory, b: domain.AgentMemory) bool {
            const as = a.score orelse 0;
            const bs = b.score orelse 0;
            if (as != bs) return as > bs;
            return std.mem.order(u8, a.timestamp, b.timestamp) == .gt;
        }
    }.lessThan);
}

fn sortAgentMemoryForVisibleGet(items: []domain.AgentMemory, actor_id: []const u8) void {
    std.mem.sort(domain.AgentMemory, items, actor_id, struct {
        fn priority(request_actor: []const u8, entry: domain.AgentMemory) u8 {
            if (std.mem.eql(u8, entry.actor_id, request_actor)) return 0;
            if (access.isSharedAgentMemoryOwner(entry.actor_id)) return 1;
            return 2;
        }

        fn lessThan(request_actor: []const u8, a: domain.AgentMemory, b: domain.AgentMemory) bool {
            const ap = priority(request_actor, a);
            const bp = priority(request_actor, b);
            if (ap != bp) return ap < bp;
            return std.mem.order(u8, a.timestamp, b.timestamp) == .gt;
        }
    }.lessThan);
}

const VisibleOwnerCandidates = struct {
    owners: std.ArrayListUnmanaged([]u8) = .empty,
    requires_global_scan: bool = false,

    fn deinit(self: *VisibleOwnerCandidates, allocator: std.mem.Allocator) void {
        for (self.owners.items) |owner| allocator.free(owner);
        self.owners.deinit(allocator);
    }

    fn appendOwned(self: *VisibleOwnerCandidates, allocator: std.mem.Allocator, owner: []const u8) !void {
        for (self.owners.items) |existing| {
            if (std.mem.eql(u8, existing, owner)) return;
        }
        try self.owners.append(allocator, try allocator.dupe(u8, owner));
    }

    fn appendSharedScope(self: *VisibleOwnerCandidates, allocator: std.mem.Allocator, scope: []const u8) !void {
        const owner = try access.sharedAgentMemoryOwner(allocator, scope);
        defer allocator.free(owner);
        try self.appendOwned(allocator, owner);
    }
};

fn visibleOwnerCandidatesFromScopes(allocator: std.mem.Allocator, actor_id: []const u8, scopes_json: []const u8) !VisibleOwnerCandidates {
    var result = VisibleOwnerCandidates{};
    errdefer result.deinit(allocator);
    try result.appendOwned(allocator, actor_id);
    try result.appendSharedScope(allocator, "public");
    if (domain.hasActorScope(scopes_json, "admin")) {
        result.requires_global_scan = true;
        return result;
    }

    var parsed = std.json.parseFromSlice(std.json.Value, allocator, scopes_json, .{}) catch {
        result.requires_global_scan = true;
        return result;
    };
    defer parsed.deinit();
    if (parsed.value != .array) return result;
    for (parsed.value.array.items) |item| {
        if (item != .string) continue;
        const scope = item.string;
        if (scope.len == 0) continue;
        if (std.mem.eql(u8, scope, "admin") or std.mem.endsWith(u8, scope, ":*") or std.mem.eql(u8, scope, "*")) {
            result.requires_global_scan = true;
            return result;
        }
        if (std.mem.startsWith(u8, scope, "write:") or
            std.mem.startsWith(u8, scope, "verify:") or
            std.mem.startsWith(u8, scope, "delete:") or
            std.mem.startsWith(u8, scope, "actor:") or
            domain.isActorOwnedAgentMemoryScope(scope, actor_id))
        {
            continue;
        }
        try result.appendSharedScope(allocator, scope);
    }
    return result;
}

fn visibleOwnerCandidatesContain(candidates: VisibleOwnerCandidates, owner: []const u8) bool {
    for (candidates.owners.items) |candidate| {
        if (std.mem.eql(u8, candidate, owner)) return true;
    }
    return false;
}

fn trimAgentMemorySearchResults(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(domain.AgentMemory), limit: usize) void {
    if (out.items.len <= limit) return;
    for (out.items[limit..]) |*entry| freeAgentMemory(allocator, entry);
    out.shrinkRetainingCapacity(limit);
}

const runtime_agent_memory_search_limit_max: usize = 5000;
const runtime_agent_memory_search_scan_multiplier: usize = 20;
const remote_agent_memory_fetch_multiplier: usize = 2;
const remote_agent_memory_fetch_min: usize = 50;
const runtime_feed_event_target_limit_max: usize = 500;
const runtime_feed_event_fetch_multiplier: usize = 8;
const runtime_feed_event_fetch_limit_max: usize = 1000;

fn runtimeAgentMemorySearchResultLimit(raw_limit: usize) usize {
    if (raw_limit == 0) return 0;
    return @max(@as(usize, 1), @min(raw_limit, runtime_agent_memory_search_limit_max));
}

fn remoteAgentMemoryFetchLimit(limit: usize) usize {
    if (limit == 0) return 0;
    const expanded = bounded_int.saturatingUsizeMul(limit, remote_agent_memory_fetch_multiplier);
    return @max(expanded, remote_agent_memory_fetch_min);
}

fn runtimeAgentMemorySearchScanLimit(limit: usize) usize {
    if (limit == 0) return 0;
    const capped = @min(limit, runtime_agent_memory_search_limit_max);
    const expanded = bounded_int.saturatingUsizeMul(capped, runtime_agent_memory_search_scan_multiplier);
    return @max(capped, @min(expanded, runtime_agent_memory_search_limit_max));
}

fn runtimeFeedEventTargetLimit(limit: usize) usize {
    return @max(@as(usize, 1), @min(limit, runtime_feed_event_target_limit_max));
}

fn runtimeFeedEventFetchLimit(target_limit: usize) usize {
    const capped = runtimeFeedEventTargetLimit(target_limit);
    const expanded = bounded_int.saturatingUsizeMul(capped, runtime_feed_event_fetch_multiplier);
    return @max(capped, @min(expanded, runtime_feed_event_fetch_limit_max));
}

fn appendRuntimeScoredAgentMemoryCandidate(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(domain.AgentMemory), query: []const u8, limit: usize, entry: domain.AgentMemory, score: f64) !void {
    var candidate = entry;
    var candidate_owned = true;
    errdefer if (candidate_owned) freeAgentMemory(allocator, &candidate);
    if (score <= 0 and query.len > 0) {
        freeAgentMemory(allocator, &candidate);
        candidate_owned = false;
        return;
    }
    candidate.score = score + 0.5;
    try out.append(allocator, candidate);
    candidate_owned = false;
    sortAgentMemory(out.items);
    trimAgentMemorySearchResults(allocator, out, limit);
}

fn agentMemoryWindowKeepLimit(limit: usize, offset: usize) usize {
    if (limit == 0) return 0;
    return bounded_int.saturatingUsizeAdd(offset, limit);
}

fn runtimePageSize(limit: usize, total: usize, offset: usize) usize {
    if (limit == 0 or offset >= total) return 0;
    return @min(limit, total - offset);
}

const RuntimePageWindow = struct {
    start: usize,
    len: usize,
    end: usize,
};

fn runtimePageWindow(limit: usize, total: usize, offset: usize) RuntimePageWindow {
    const start = @min(offset, total);
    const len = runtimePageSize(limit, total, offset);
    return .{
        .start = start,
        .len = len,
        .end = runtimePageOffsetAfterFetch(start, len),
    };
}

fn runtimePageStopOffset(offset: usize, page_limit: usize) usize {
    if (page_limit == 0) return offset;
    return bounded_int.saturatingUsizeAdd(offset, page_limit - 1);
}

fn runtimePageOffsetAfterFetch(offset: usize, fetched: usize) usize {
    return bounded_int.saturatingUsizeAdd(offset, fetched);
}

fn runtimeNextPageOffset(offset: usize, step: usize) ?usize {
    if (step == 0) return null;
    const next = runtimePageOffsetAfterFetch(offset, step);
    if (next <= offset) return null;
    return next;
}

fn runtimeCountAdd(total: usize, delta: usize) usize {
    return bounded_int.saturatingUsizeAdd(total, delta);
}

fn runtimeCountIncrement(total: usize) usize {
    return runtimeCountAdd(total, 1);
}

fn runtimeCountToU64(total: usize) u64 {
    return bounded_int.usizeToU64Saturating(total);
}

fn runtimeCountFromU64(total: u64) usize {
    return bounded_int.u64ToUsizeSaturating(total);
}

fn runtimeCountFromSigned(total: i64) usize {
    return bounded_int.nonNegativeI64ToUsize(total);
}

const redis_command_header_args: usize = 2;

fn redisCommandArgCount(value_count: usize) !usize {
    return std.math.add(usize, value_count, redis_command_header_args) catch error.OutOfMemory;
}

pub fn pageAgentMemorySlice(allocator: std.mem.Allocator, entries: []domain.AgentMemory, limit: usize, offset: usize) ![]domain.AgentMemory {
    var owned = entries;
    var owned_active = true;
    errdefer if (owned_active) {
        for (owned) |*entry| freeAgentMemory(allocator, entry);
        allocator.free(owned);
    };

    const window = runtimePageWindow(limit, owned.len, offset);
    if (window.len == 0) {
        for (owned) |*entry| freeAgentMemory(allocator, entry);
        allocator.free(owned);
        owned_active = false;
        return allocator.alloc(domain.AgentMemory, 0);
    }

    if (window.start == 0 and window.len == owned.len) {
        owned_active = false;
        return owned;
    }

    const out = try allocator.alloc(domain.AgentMemory, window.len);
    for (owned[0..window.start]) |*entry| freeAgentMemory(allocator, entry);
    for (owned[window.start..window.end], 0..) |*entry, i| {
        out[i] = entry.*;
        detachAgentMemory(entry);
    }
    for (owned[window.end..]) |*entry| freeAgentMemory(allocator, entry);
    allocator.free(owned);
    owned_active = false;
    return out;
}

fn remoteAgentMemoryWindowPage(allocator: std.mem.Allocator, entries: []domain.AgentMemory, limit: usize) ![]domain.AgentMemory {
    return pageAgentMemorySlice(allocator, entries, limit, 0);
}

fn sortSessions(items: []SessionInfo) void {
    std.mem.sort(SessionInfo, items, {}, struct {
        fn lessThan(_: void, a: SessionInfo, b: SessionInfo) bool {
            return a.last_message_at > b.last_message_at;
        }
    }.lessThan);
}

fn detachAgentMemory(entry: *domain.AgentMemory) void {
    entry.id = "";
    entry.key = "";
    entry.content = "";
    entry.category = "";
    entry.timestamp = "";
    entry.session_id = null;
    entry.actor_id = "";
    entry.writer_actor_id = "";
    entry.scope = "";
    entry.permissions_json = "";
    entry.status = "";
    entry.store = "";
}

pub fn freeAgentMemory(allocator: std.mem.Allocator, entry: *domain.AgentMemory) void {
    if (entry.id.len == 0) return;
    if (entry.id.len > 0) allocator.free(entry.id);
    if (entry.key.len > 0) allocator.free(entry.key);
    if (entry.content.len > 0) allocator.free(entry.content);
    if (entry.category.len > 0) allocator.free(entry.category);
    if (entry.timestamp.len > 0) allocator.free(entry.timestamp);
    if (entry.session_id) |sid| allocator.free(sid);
    if (entry.actor_id.len > 0) allocator.free(entry.actor_id);
    if (entry.writer_actor_id.len > 0) allocator.free(entry.writer_actor_id);
    if (entry.scope.len > 0) allocator.free(entry.scope);
    if (entry.permissions_json.len > 0) allocator.free(entry.permissions_json);
    if (entry.status.len > 0) allocator.free(entry.status);
    if (entry.store.len > 0) allocator.free(entry.store);
    detachAgentMemory(entry);
}

fn detachMessage(message: *Message) void {
    message.role = "";
    message.content = "";
    message.created_at_ms = 0;
}

fn freeMessage(allocator: std.mem.Allocator, message: *Message) void {
    if (message.role.len > 0) allocator.free(message.role);
    if (message.content.len > 0) allocator.free(message.content);
    detachMessage(message);
}

fn detachSessionInfo(info: *SessionInfo) void {
    info.session_id = "";
    info.message_count = 0;
    info.first_message_at = 0;
    info.last_message_at = 0;
}

fn freeSessionInfo(allocator: std.mem.Allocator, info: *SessionInfo) void {
    if (info.session_id.len > 0) allocator.free(info.session_id);
    detachSessionInfo(info);
}

fn cloneAgentMemory(allocator: std.mem.Allocator, entry: domain.AgentMemory) !domain.AgentMemory {
    return .{
        .id = try allocator.dupe(u8, entry.id),
        .key = try allocator.dupe(u8, entry.key),
        .content = try allocator.dupe(u8, entry.content),
        .category = try allocator.dupe(u8, entry.category),
        .timestamp = try allocator.dupe(u8, entry.timestamp),
        .session_id = if (entry.session_id) |sid| try allocator.dupe(u8, sid) else null,
        .actor_id = try allocator.dupe(u8, entry.actor_id),
        .writer_actor_id = try allocator.dupe(u8, if (entry.writer_actor_id.len > 0) entry.writer_actor_id else entry.actor_id),
        .scope = try allocator.dupe(u8, entry.scope),
        .permissions_json = try allocator.dupe(u8, entry.permissions_json),
        .status = try allocator.dupe(u8, entry.status),
        .store = try allocator.dupe(u8, entry.store),
        .score = entry.score,
    };
}

fn cloneMemoryEntry(allocator: std.mem.Allocator, entry: MemoryEntry) !MemoryEntry {
    var cloned_entry = try cloneAgentMemory(allocator, entry.entry);
    errdefer freeAgentMemory(allocator, &cloned_entry);
    var cloned_order = if (entry.event_order) |order| try cloneEventOrder(allocator, order) else null;
    errdefer if (cloned_order) |*order| freeEventOrder(allocator, order);
    return .{
        .entry = cloned_entry,
        .event_order = cloned_order,
        .last_access_ms = entry.last_access_ms,
    };
}

fn cloneMemoryTombstone(allocator: std.mem.Allocator, tombstone: MemoryTombstone) !MemoryTombstone {
    const key = try allocator.dupe(u8, tombstone.key);
    errdefer allocator.free(key);
    const actor_id = try allocator.dupe(u8, tombstone.actor_id);
    errdefer allocator.free(actor_id);
    const session_key = try allocator.dupe(u8, tombstone.session_key);
    errdefer allocator.free(session_key);
    const session_id = if (tombstone.session_id) |sid| try allocator.dupe(u8, sid) else null;
    errdefer if (session_id) |sid| allocator.free(sid);
    var event_order = try cloneEventOrder(allocator, tombstone.event_order);
    errdefer freeEventOrder(allocator, &event_order);
    return .{
        .key = key,
        .actor_id = actor_id,
        .scope = tombstone.scope,
        .session_key = session_key,
        .session_id = session_id,
        .event_order = event_order,
    };
}

fn cloneMessageTombstone(allocator: std.mem.Allocator, tombstone: MessageTombstone) !MessageTombstone {
    const actor_id = try allocator.dupe(u8, tombstone.actor_id);
    errdefer allocator.free(actor_id);
    const session_id = try allocator.dupe(u8, tombstone.session_id);
    errdefer allocator.free(session_id);
    var event_order = try cloneEventOrder(allocator, tombstone.event_order);
    errdefer freeEventOrder(allocator, &event_order);
    return .{
        .actor_id = actor_id,
        .session_id = session_id,
        .event_order = event_order,
    };
}

fn cloneUsageTombstone(allocator: std.mem.Allocator, tombstone: UsageTombstone) !UsageTombstone {
    const actor_id = try allocator.dupe(u8, tombstone.actor_id);
    errdefer allocator.free(actor_id);
    const session_id = try allocator.dupe(u8, tombstone.session_id);
    errdefer allocator.free(session_id);
    var event_order = try cloneEventOrder(allocator, tombstone.event_order);
    errdefer freeEventOrder(allocator, &event_order);
    return .{
        .actor_id = actor_id,
        .session_id = session_id,
        .event_order = event_order,
    };
}

fn cloneMemorySessionMessage(allocator: std.mem.Allocator, message: MemorySessionMessage) !MemorySessionMessage {
    const actor_id = try allocator.dupe(u8, message.actor_id);
    errdefer allocator.free(actor_id);
    const session_id = try allocator.dupe(u8, message.session_id);
    errdefer allocator.free(session_id);
    const role = try allocator.dupe(u8, message.role);
    errdefer allocator.free(role);
    const content = try allocator.dupe(u8, message.content);
    errdefer allocator.free(content);
    var event_order = if (message.event_order) |order| try cloneEventOrder(allocator, order) else null;
    errdefer if (event_order) |*order| freeEventOrder(allocator, order);
    return .{
        .actor_id = actor_id,
        .session_id = session_id,
        .role = role,
        .content = content,
        .created_at_ms = message.created_at_ms,
        .event_order = event_order,
        .last_access_ms = message.last_access_ms,
    };
}

fn cloneMemoryUsage(allocator: std.mem.Allocator, usage: MemoryUsage) !MemoryUsage {
    const actor_id = try allocator.dupe(u8, usage.actor_id);
    errdefer allocator.free(actor_id);
    const session_id = try allocator.dupe(u8, usage.session_id);
    errdefer allocator.free(session_id);
    var event_order = if (usage.event_order) |order| try cloneEventOrder(allocator, order) else null;
    errdefer if (event_order) |*order| freeEventOrder(allocator, order);
    return .{
        .actor_id = actor_id,
        .session_id = session_id,
        .total_tokens = usage.total_tokens,
        .updated_at_ms = usage.updated_at_ms,
        .event_order = event_order,
        .last_access_ms = usage.last_access_ms,
    };
}

fn sameOptionalString(a: ?[]const u8, b: ?[]const u8) bool {
    if (a == null and b == null) return true;
    if (a == null or b == null) return false;
    return std.mem.eql(u8, a.?, b.?);
}

fn memoryEntryId(allocator: std.mem.Allocator, actor: []const u8, session_id: ?[]const u8, key: []const u8) ![]u8 {
    var hash_value = std.hash.Wyhash.hash(0, actor);
    hash_value = std.hash.Wyhash.hash(hash_value, session_id orelse "");
    hash_value = std.hash.Wyhash.hash(hash_value, key);
    return std.fmt.allocPrint(allocator, "agm_{x}", .{hash_value});
}

fn parseMemoryTimestamp(raw: []const u8) i64 {
    return std.fmt.parseInt(i64, raw, 10) catch 0;
}

const agent_memory_entry_byte_overhead: usize = 128;
const memory_session_message_byte_overhead: usize = 48;
const memory_usage_byte_overhead: usize = 40;

fn memoryByteSizeAdd(left: usize, right: usize) usize {
    return bounded_int.saturatingUsizeAdd(left, right);
}

fn memoryByteSizeTotal(overhead: usize, fields: []const usize) usize {
    var total = overhead;
    for (fields) |field| total = memoryByteSizeAdd(total, field);
    return total;
}

fn agentMemoryByteSize(entry: domain.AgentMemory) usize {
    return memoryByteSizeTotal(agent_memory_entry_byte_overhead, &.{
        entry.id.len,
        entry.key.len,
        entry.content.len,
        entry.category.len,
        entry.timestamp.len,
        if (entry.session_id) |sid| sid.len else 0,
        entry.actor_id.len,
        entry.writer_actor_id.len,
        entry.scope.len,
        entry.permissions_json.len,
    });
}

fn messageByteSize(message: MemorySessionMessage) usize {
    return memoryByteSizeTotal(memory_session_message_byte_overhead, &.{
        message.actor_id.len,
        message.session_id.len,
        message.role.len,
        message.content.len,
    });
}

fn usageByteSize(usage: MemoryUsage) usize {
    return memoryByteSizeTotal(memory_usage_byte_overhead, &.{
        usage.actor_id.len,
        usage.session_id.len,
    });
}

fn freeMemorySessionMessage(allocator: std.mem.Allocator, message: *MemorySessionMessage) void {
    if (message.actor_id.len > 0) allocator.free(message.actor_id);
    if (message.session_id.len > 0) allocator.free(message.session_id);
    if (message.role.len > 0) allocator.free(message.role);
    if (message.content.len > 0) allocator.free(message.content);
    if (message.event_order) |*order| freeEventOrder(allocator, order);
    message.* = .{ .actor_id = "", .session_id = "", .role = "", .content = "", .created_at_ms = 0, .event_order = null, .last_access_ms = 0 };
}

fn freeMemoryUsage(allocator: std.mem.Allocator, usage: *MemoryUsage) void {
    if (usage.actor_id.len > 0) allocator.free(usage.actor_id);
    if (usage.session_id.len > 0) allocator.free(usage.session_id);
    if (usage.event_order) |*order| freeEventOrder(allocator, order);
    usage.* = .{ .actor_id = "", .session_id = "", .total_tokens = 0, .updated_at_ms = 0, .event_order = null, .last_access_ms = 0 };
}

fn findSessionInfo(items: []const SessionInfo, session_id: []const u8) ?usize {
    for (items, 0..) |item, i| {
        if (std.mem.eql(u8, item.session_id, session_id)) return i;
    }
    return null;
}

fn hexOutputLen(raw_len: usize) !usize {
    return std.math.mul(usize, raw_len, 2) catch return error.OutOfMemory;
}

fn hex(allocator: std.mem.Allocator, raw: []const u8) ![]u8 {
    const out_len = try hexOutputLen(raw.len);
    const out = try allocator.alloc(u8, out_len);
    const digits = "0123456789abcdef";
    for (raw, 0..) |byte, i| {
        out[i * 2] = digits[byte >> 4];
        out[i * 2 + 1] = digits[byte & 0x0f];
    }
    return out;
}

fn feedEventsContainActor(events: []const FeedEvent, event_type: []const u8, key: []const u8, actor_id: []const u8) bool {
    for (events) |event| {
        if (!std.mem.eql(u8, event.event_type, event_type)) continue;
        const event_actor = event.actor_id orelse continue;
        if (!std.mem.eql(u8, event_actor, actor_id)) continue;
        if (std.mem.eql(u8, event.object_id, key) or std.mem.indexOf(u8, event.payload_json, key) != null) return true;
    }
    return false;
}

test "agent memory runtime hex helper checks allocation size overflow" {
    const encoded = try hex(std.testing.allocator, "\x00\x0f\xff");
    defer std.testing.allocator.free(encoded);
    try std.testing.expectEqualStrings("000fff", encoded);

    try std.testing.expectError(error.OutOfMemory, hexOutputLen((std.math.maxInt(usize) / 2) + 1));
}

test "agent memory runtime window helpers use checked sizing" {
    try std.testing.expectEqual(@as(usize, 0), remoteAgentMemoryFetchLimit(0));
    try std.testing.expectEqual(@as(usize, 50), remoteAgentMemoryFetchLimit(1));
    try std.testing.expectEqual(@as(usize, 80), remoteAgentMemoryFetchLimit(40));
    try std.testing.expectEqual(std.math.maxInt(usize), remoteAgentMemoryFetchLimit((std.math.maxInt(usize) / 2) + 1));
    try std.testing.expectEqual(std.math.maxInt(usize), remoteAgentMemoryFetchLimit(std.math.maxInt(usize)));

    try std.testing.expectEqual(@as(usize, 0), runtimeAgentMemorySearchScanLimit(0));
    try std.testing.expectEqual(@as(usize, 20), runtimeAgentMemorySearchScanLimit(1));
    try std.testing.expectEqual(@as(usize, 5000), runtimeAgentMemorySearchScanLimit(250));
    try std.testing.expectEqual(@as(usize, 5000), runtimeAgentMemorySearchScanLimit(10_000));
    try std.testing.expectEqual(@as(usize, 5000), runtimeAgentMemorySearchScanLimit(std.math.maxInt(usize)));

    try std.testing.expectEqual(@as(usize, 1), runtimeFeedEventTargetLimit(0));
    try std.testing.expectEqual(@as(usize, 42), runtimeFeedEventTargetLimit(42));
    try std.testing.expectEqual(@as(usize, runtime_feed_event_target_limit_max), runtimeFeedEventTargetLimit(std.math.maxInt(usize)));
    try std.testing.expectEqual(@as(usize, 8), runtimeFeedEventFetchLimit(1));
    try std.testing.expectEqual(@as(usize, 400), runtimeFeedEventFetchLimit(50));
    try std.testing.expectEqual(@as(usize, runtime_feed_event_fetch_limit_max), runtimeFeedEventFetchLimit(500));
    try std.testing.expectEqual(@as(usize, runtime_feed_event_fetch_limit_max), runtimeFeedEventFetchLimit(std.math.maxInt(usize)));

    try std.testing.expectEqual(@as(usize, 0), agentMemoryWindowKeepLimit(0, 10));
    try std.testing.expectEqual(@as(usize, 15), agentMemoryWindowKeepLimit(5, 10));
    try std.testing.expectEqual(std.math.maxInt(usize), agentMemoryWindowKeepLimit(1, std.math.maxInt(usize)));

    try std.testing.expectEqual(@as(usize, 0), runtimePageSize(0, 10, 0));
    try std.testing.expectEqual(@as(usize, 0), runtimePageSize(5, 10, 10));
    try std.testing.expectEqual(@as(usize, 5), runtimePageSize(5, 10, 0));
    try std.testing.expectEqual(@as(usize, 3), runtimePageSize(5, 10, 7));
    try std.testing.expectEqual(@as(usize, 1), runtimePageSize(5, std.math.maxInt(usize), std.math.maxInt(usize) - 1));

    const first_page = runtimePageWindow(4, 10, 0);
    try std.testing.expectEqual(@as(usize, 0), first_page.start);
    try std.testing.expectEqual(@as(usize, 4), first_page.len);
    try std.testing.expectEqual(@as(usize, 4), first_page.end);

    const tail_page = runtimePageWindow(4, 10, 8);
    try std.testing.expectEqual(@as(usize, 8), tail_page.start);
    try std.testing.expectEqual(@as(usize, 2), tail_page.len);
    try std.testing.expectEqual(@as(usize, 10), tail_page.end);

    const empty_page = runtimePageWindow(4, 10, 12);
    try std.testing.expectEqual(@as(usize, 10), empty_page.start);
    try std.testing.expectEqual(@as(usize, 0), empty_page.len);
    try std.testing.expectEqual(@as(usize, 10), empty_page.end);

    const max_page = runtimePageWindow(std.math.maxInt(usize), std.math.maxInt(usize), std.math.maxInt(usize) - 1);
    try std.testing.expectEqual(std.math.maxInt(usize) - 1, max_page.start);
    try std.testing.expectEqual(@as(usize, 1), max_page.len);
    try std.testing.expectEqual(std.math.maxInt(usize), max_page.end);

    try std.testing.expectEqual(@as(usize, 10), runtimePageStopOffset(10, 1));
    try std.testing.expectEqual(@as(usize, 14), runtimePageStopOffset(10, 5));
    try std.testing.expectEqual(@as(usize, 10), runtimePageStopOffset(10, 0));
    try std.testing.expectEqual(std.math.maxInt(usize), runtimePageStopOffset(std.math.maxInt(usize) - 2, 8));

    try std.testing.expectEqual(@as(usize, 15), runtimePageOffsetAfterFetch(10, 5));
    try std.testing.expectEqual(@as(usize, 10), runtimePageOffsetAfterFetch(10, 0));
    try std.testing.expectEqual(std.math.maxInt(usize), runtimePageOffsetAfterFetch(std.math.maxInt(usize) - 1, 4));

    try std.testing.expectEqual(@as(?usize, 15), runtimeNextPageOffset(10, 5));
    try std.testing.expectEqual(@as(?usize, null), runtimeNextPageOffset(10, 0));
    try std.testing.expectEqual(@as(?usize, std.math.maxInt(usize)), runtimeNextPageOffset(std.math.maxInt(usize) - 1, 4));
    try std.testing.expectEqual(@as(?usize, null), runtimeNextPageOffset(std.math.maxInt(usize), 1));
}

fn runtimeTestOwnedAgentMemory(allocator: std.mem.Allocator, key: []const u8, content: []const u8, timestamp: []const u8) !domain.AgentMemory {
    var entry = domain.AgentMemory{
        .id = "",
        .key = "",
        .content = "",
        .category = "",
        .timestamp = "",
        .session_id = null,
        .actor_id = "",
        .writer_actor_id = "",
        .scope = "",
        .permissions_json = "",
        .status = "",
        .store = "",
    };
    errdefer freeAgentMemory(allocator, &entry);

    entry.id = try std.fmt.allocPrint(allocator, "agm_{s}", .{key});
    entry.key = try allocator.dupe(u8, key);
    entry.content = try allocator.dupe(u8, content);
    entry.category = try allocator.dupe(u8, "core");
    entry.timestamp = try allocator.dupe(u8, timestamp);
    entry.actor_id = try allocator.dupe(u8, "agent:runtime-test");
    entry.writer_actor_id = try allocator.dupe(u8, "agent:runtime-test");
    entry.scope = try allocator.dupe(u8, "agent:agent:runtime-test");
    entry.permissions_json = try allocator.dupe(u8, "[]");
    entry.status = try allocator.dupe(u8, "verified");
    entry.store = try allocator.dupe(u8, "memory");
    return entry;
}

test "agent memory runtime pages owned memory slices with checked windows" {
    const allocator = std.testing.allocator;
    var entries = try allocator.alloc(domain.AgentMemory, 4);
    var entries_active = true;
    var initialized: usize = 0;
    errdefer if (entries_active) {
        for (entries[0..initialized]) |*entry| freeAgentMemory(allocator, entry);
        allocator.free(entries);
    };
    entries[0] = try runtimeTestOwnedAgentMemory(allocator, "a", "first", "1");
    initialized += 1;
    entries[1] = try runtimeTestOwnedAgentMemory(allocator, "b", "second", "2");
    initialized += 1;
    entries[2] = try runtimeTestOwnedAgentMemory(allocator, "c", "third", "3");
    initialized += 1;
    entries[3] = try runtimeTestOwnedAgentMemory(allocator, "d", "fourth", "4");
    initialized += 1;

    initialized = 0;
    entries_active = false;
    const paged = try pageAgentMemorySlice(allocator, entries, 2, 1);
    defer {
        for (paged) |*entry| freeAgentMemory(allocator, entry);
        allocator.free(paged);
    }
    try std.testing.expectEqual(@as(usize, 2), paged.len);
    try std.testing.expectEqualStrings("b", paged[0].key);
    try std.testing.expectEqualStrings("c", paged[1].key);

    var empty_entries = try allocator.alloc(domain.AgentMemory, 1);
    var empty_entries_active = true;
    var empty_initialized: usize = 0;
    errdefer if (empty_entries_active) {
        for (empty_entries[0..empty_initialized]) |*entry| freeAgentMemory(allocator, entry);
        allocator.free(empty_entries);
    };
    empty_entries[0] = try runtimeTestOwnedAgentMemory(allocator, "z", "empty", "5");
    empty_initialized += 1;
    empty_initialized = 0;
    empty_entries_active = false;
    const empty = try pageAgentMemorySlice(allocator, empty_entries, 1, std.math.maxInt(usize));
    defer allocator.free(empty);
    try std.testing.expectEqual(@as(usize, 0), empty.len);
}

