        .{ .bulk_string = "status" },
        .{ .bulk_string = "verified" },
    };
    const missing_content_resp = redis.RespValue{ .array = missing_content_fields[0..] };
    try std.testing.expectError(error.AgentMemoryStorageUnavailable, engine.agentMemoryFromHash(std.testing.allocator, missing_content_resp));

    var odd_fields = [_]redis.RespValue{
        .{ .bulk_string = "id" },
        .{ .bulk_string = "am:agent:a:pref" },
        .{ .bulk_string = "key" },
