test "agent memory runtime count helpers saturate overflow" {
    const max = std.math.maxInt(usize);
    try std.testing.expectEqual(@as(usize, 7), runtimeCountAdd(3, 4));
    try std.testing.expectEqual(max, runtimeCountAdd(max - 1, 4));
    try std.testing.expectEqual(@as(usize, 6), runtimeCountIncrement(5));
    try std.testing.expectEqual(max, runtimeCountIncrement(max));
    try std.testing.expectEqual(@as(u64, 42), runtimeCountToU64(42));
    try std.testing.expectEqual(bounded_int.usizeToU64Saturating(max), runtimeCountToU64(max));
    try std.testing.expectEqual(@as(usize, 42), runtimeCountFromU64(42));
    try std.testing.expectEqual(bounded_int.u64ToUsizeSaturating(std.math.maxInt(u64)), runtimeCountFromU64(std.math.maxInt(u64)));
    try std.testing.expectEqual(@as(usize, 0), runtimeCountFromSigned(-1));
    try std.testing.expectEqual(@as(usize, 42), runtimeCountFromSigned(42));
    try std.testing.expectEqual(bounded_int.nonNegativeI64ToUsize(std.math.maxInt(i64)), runtimeCountFromSigned(std.math.maxInt(i64)));
}

test "memory_lru byte size helpers use saturating estimates" {
    const max = std.math.maxInt(usize);
    try std.testing.expectEqual(max, memoryByteSizeAdd(max - 1, 2));
    try std.testing.expectEqual(max, memoryByteSizeTotal(32, &.{ max - 16, 8 }));

    const entry = domain.AgentMemory{
        .id = "agm_1",
        .key = "memory.key",
        .content = "memory content",
        .category = "core",
        .timestamp = "1234567890",
        .session_id = "session-1",
        .actor_id = "agent:lru",
        .writer_actor_id = "agent:writer",
        .scope = "agent:agent:lru",
        .permissions_json = "[\"actor:agent:lru\"]",
    };
    const expected_entry_size: usize = agent_memory_entry_byte_overhead +
        "agm_1".len +
        "memory.key".len +
        "memory content".len +
        "core".len +
        "1234567890".len +
        "session-1".len +
        "agent:lru".len +
        "agent:writer".len +
        "agent:agent:lru".len +
        "[\"actor:agent:lru\"]".len;
    try std.testing.expectEqual(expected_entry_size, agentMemoryByteSize(entry));

    const message = MemorySessionMessage{
        .actor_id = "agent:lru",
        .session_id = "session-1",
        .role = "user",
        .content = "hello",
        .created_at_ms = 1,
        .last_access_ms = 1,
    };
    const expected_message_size: usize = memory_session_message_byte_overhead +
        "agent:lru".len +
        "session-1".len +
        "user".len +
        "hello".len;
    try std.testing.expectEqual(expected_message_size, messageByteSize(message));

    const usage = MemoryUsage{
        .actor_id = "agent:lru",
        .session_id = "session-1",
        .total_tokens = 42,
        .updated_at_ms = 1,
        .last_access_ms = 1,
    };
    const expected_usage_size: usize = memory_usage_byte_overhead +
        "agent:lru".len +
        "session-1".len;
    try std.testing.expectEqual(expected_usage_size, usageByteSize(usage));
}

test "agent memory runtime integer json helpers reject unsafe floats" {
    var parsed = try std.json.parseFromSlice(
        std.json.Value,
        std.testing.allocator,
        "{\"exact\":42.0,\"fractional\":42.5,\"huge\":1e100,\"negative\":-1.0,\"negative_int\":-1,\"max_int\":9223372036854775807,\"integer\":7,\"text\":\"9\"}",
        .{},
    );
    defer parsed.deinit();

    const obj = parsed.value.object;
    try std.testing.expectEqual(@as(u64, 42), jsonU64Field(obj, "exact", 99));
    try std.testing.expectEqual(@as(u64, 7), jsonU64Field(obj, "integer", 99));
    try std.testing.expectEqual(@as(u64, 9), jsonU64Field(obj, "text", 99));
    try std.testing.expectEqual(@as(u64, 99), jsonU64Field(obj, "fractional", 99));
    try std.testing.expectEqual(@as(u64, 99), jsonU64Field(obj, "huge", 99));
    try std.testing.expectEqual(@as(u64, 99), jsonU64Field(obj, "negative", 99));
    try std.testing.expectEqual(@as(u64, 0), jsonU64Field(obj, "negative_int", 99));
    try std.testing.expectEqual(@as(u64, @intCast(std.math.maxInt(i64))), jsonU64Field(obj, "max_int", 99));
    try std.testing.expectEqual(@as(usize, 7), jsonCountField(obj, "integer"));
    try std.testing.expectEqual(bounded_int.nonNegativeI64ToUsize(std.math.maxInt(i64)), jsonCountField(obj, "max_int"));
    try std.testing.expectEqual(@as(usize, 0), jsonCountField(obj, "missing"));

    try std.testing.expectEqual(@as(i64, 42), jsonI64Field(obj, "exact", -99));
    try std.testing.expectEqual(@as(i64, 7), jsonI64Field(obj, "integer", -99));
    try std.testing.expectEqual(@as(i64, 9), jsonI64Field(obj, "text", -99));
    try std.testing.expectEqual(@as(i64, -99), jsonI64Field(obj, "fractional", -99));
    try std.testing.expectEqual(@as(i64, -99), jsonI64Field(obj, "huge", -99));
    try std.testing.expect(jsonOptionalI64Field(obj, "fractional") == null);
    try std.testing.expect(jsonOptionalI64Field(obj, "huge") == null);
}

