test "agent memory visible owner candidates enumerate exact actor and shared scopes" {
    var candidates = try visibleOwnerCandidatesFromScopes(std.testing.allocator, "agent:a", "[\"agent:agent:a\",\"team:alpha\",\"project:nullpantry\",\"write:team:alpha\"]");
    defer candidates.deinit(std.testing.allocator);

    try std.testing.expect(!candidates.requires_global_scan);
    try std.testing.expect(visibleOwnerCandidatesContain(candidates, "agent:a"));
    try std.testing.expect(visibleOwnerCandidatesContain(candidates, "shared:public"));
    try std.testing.expect(visibleOwnerCandidatesContain(candidates, "shared:team:alpha"));
    try std.testing.expect(visibleOwnerCandidatesContain(candidates, "shared:project:nullpantry"));
    try std.testing.expect(!visibleOwnerCandidatesContain(candidates, "shared:agent:agent:a"));
    try std.testing.expect(!visibleOwnerCandidatesContain(candidates, "shared:write:team:alpha"));

    var wildcard = try visibleOwnerCandidatesFromScopes(std.testing.allocator, "agent:a", "[\"team:*\"]");
    defer wildcard.deinit(std.testing.allocator);
    try std.testing.expect(wildcard.requires_global_scan);

    var malformed = try visibleOwnerCandidatesFromScopes(std.testing.allocator, "agent:a", "not json");
    defer malformed.deinit(std.testing.allocator);
    try std.testing.expect(malformed.requires_global_scan);
}

test "agent memory clickhouse backend helpers validate URLs and tables" {
    try std.testing.expectError(error.InvalidClickHouseAgentMemoryTable, clickhouseSafeIdentifier(std.testing.allocator, "bad table"));
    try std.testing.expectError(error.InvalidClickHouseAgentMemoryTable, clickhouseSafeIdentifier(std.testing.allocator, " agent_memory"));
    try std.testing.expectError(error.InvalidClickHouseAgentMemoryTable, clickhouseSafeIdentifier(std.testing.allocator, ".agent_memory"));
    try std.testing.expectError(error.InvalidClickHouseAgentMemoryTable, clickhouseSafeIdentifier(std.testing.allocator, "np..agent_memory"));
    try std.testing.expectError(error.InvalidClickHouseAgentMemoryTable, clickhouseSafeIdentifier(std.testing.allocator, "agent_memory."));
    const table = try clickhouseSafeIdentifier(std.testing.allocator, "np.agent_memory");
    defer std.testing.allocator.free(table);
    try std.testing.expectEqualStrings("np.agent_memory", table);

    const suffixed = try clickhouseTableWithSuffix(std.testing.allocator, table, "_messages");
    defer std.testing.allocator.free(suffixed);
    try std.testing.expectEqualStrings("np.agent_memory_messages", suffixed);
}

