    defer freeAgentMemory(std.testing.allocator, &visible_pref_a);
    try std.testing.expectEqualStrings("Prefer Zig examples", visible_pref_a.content);
    var visible_pref_c = (try engine.getVisible(std.testing.allocator, "pref.language", null, "agent:c", "[\"team:alpha\"]")).?;
    defer freeAgentMemory(std.testing.allocator, &visible_pref_c);
    try std.testing.expectEqualStrings("Team prefers Rust examples", visible_pref_c.content);
    var any_pref_a = (try engine.getAnyVisible(std.testing.allocator, "pref.language", "agent:a", "[\"team:alpha\"]")).?;
