    try std.testing.expectEqualStrings("agent:a", actor_named_owner);

    const shared_owner = try externalAgentMemoryOwner(std.testing.allocator, "agent:a", "team:alpha");
    defer std.testing.allocator.free(shared_owner);
    try std.testing.expectEqualStrings("shared:team:alpha", shared_owner);

    const precomputed_shared_owner = try externalAgentMemoryOwner(std.testing.allocator, "shared:team:alpha", "team:alpha");
    defer std.testing.allocator.free(precomputed_shared_owner);
    try std.testing.expectEqualStrings("shared:team:alpha", precomputed_shared_owner);

    const direct_owner = try externalAgentMemoryOwner(std.testing.allocator, "agent:a", null);
    defer std.testing.allocator.free(direct_owner);
    try std.testing.expectEqualStrings("agent:a", direct_owner);
}

test "agent memory api backend builds urls and parses memory responses" {
    _ = try ApiAgentMemory.init(std.testing.allocator, .{ .base_url = "https://pantry.example/v1" });
    _ = try ApiAgentMemory.init(std.testing.allocator, .{ .base_url = "http://localhost:8765" });
    try std.testing.expectError(error.InsecureRuntimeUrl, ApiAgentMemory.init(std.testing.allocator, .{ .base_url = "http://pantry.internal:8765" }));
    _ = try ApiAgentMemory.init(std.testing.allocator, .{ .base_url = "http://pantry.internal:8765", .allow_insecure_http = true });

    const url_root = try apiBackendUrl(std.testing.allocator, "https://pantry.example", "/agent-memory/key", "limit=1", false);
    defer std.testing.allocator.free(url_root);
    try std.testing.expectEqualStrings("https://pantry.example/v1/agent-memory/key?limit=1", url_root);

    const url_v1 = try apiBackendUrl(std.testing.allocator, "https://pantry.example/v1/", "/agent-memory/key", "", false);
    defer std.testing.allocator.free(url_v1);
    try std.testing.expectEqualStrings("https://pantry.example/v1/agent-memory/key", url_v1);

    try std.testing.expectError(error.InvalidRuntimeUrl, apiBackendUrl(std.testing.allocator, "https://token@pantry.example", "/agent-memory/key", "", false));
    try std.testing.expectError(error.InvalidRuntimeUrl, apiBackendUrl(std.testing.allocator, "https://pantry.example?token=x", "/agent-memory/key", "", false));
    try std.testing.expectError(error.InsecureRuntimeUrl, apiBackendUrl(std.testing.allocator, "http://pantry.internal", "/agent-memory/key", "", false));
    const insecure_url = try apiBackendUrl(std.testing.allocator, "http://pantry.internal", "/agent-memory/key", "", true);
    defer std.testing.allocator.free(insecure_url);
    try std.testing.expectEqualStrings("http://pantry.internal/v1/agent-memory/key", insecure_url);

    var actor_headers = try buildApiRequestHeaders(std.testing.allocator, .{
        .base_url = "https://pantry.example",
        .token = "secret",
        .actor_scopes_json = "[\"admin\"]",
        .actor_capabilities_json = "[\"read\",\"feed_apply\"]",
    }, "agent:a", "[\"team:alpha\"]", "[\"read\"]");
    defer actor_headers.deinit(std.testing.allocator);
    try std.testing.expectEqual(api_request_header_capacity, actor_headers.slice().len);
    try std.testing.expectEqualStrings("Bearer secret", findHttpHeader(actor_headers.slice(), "authorization").?);
    try std.testing.expectEqualStrings("agent:a", findHttpHeader(actor_headers.slice(), "x-nullpantry-actor-id").?);
    try std.testing.expectEqualStrings("[\"team:alpha\"]", findHttpHeader(actor_headers.slice(), "x-nullpantry-actor-scopes").?);
    try std.testing.expectEqualStrings("[\"read\"]", findHttpHeader(actor_headers.slice(), "x-nullpantry-actor-capabilities").?);

    var default_headers = try buildApiRequestHeaders(std.testing.allocator, .{
        .base_url = "https://pantry.example",
        .actor_scopes_json = "[\"project:nullpantry\"]",
        .actor_capabilities_json = "[\"read\"]",
    }, "", null, null);
    defer default_headers.deinit(std.testing.allocator);
    try std.testing.expect(findHttpHeader(default_headers.slice(), "authorization") == null);
    try std.testing.expect(findHttpHeader(default_headers.slice(), "x-nullpantry-actor-id") == null);
    try std.testing.expectEqualStrings("[\"project:nullpantry\"]", findHttpHeader(default_headers.slice(), "x-nullpantry-actor-scopes").?);
    try std.testing.expectEqualStrings("[\"read\"]", findHttpHeader(default_headers.slice(), "x-nullpantry-actor-capabilities").?);

    var full_headers = ApiRequestHeaders{};
    var i: usize = 0;
    while (i < api_request_header_capacity) : (i += 1) {
        try full_headers.append(.{ .name = "X-Test", .value = "ok" });
    }
    try std.testing.expectEqual(api_request_header_capacity, full_headers.slice().len);
    try std.testing.expectError(error.TooManyApiRequestHeaders, full_headers.append(.{ .name = "X-Test", .value = "overflow" }));

    try std.testing.expectError(error.InvalidHttpHeaderValue, buildApiRequestHeaders(std.testing.allocator, .{
        .base_url = "https://pantry.example",
        .token = "bad\r\nX: y",
