        \\{"memory":{"id":"m1","key":"pref","content":"value","category":"core","timestamp":"42","session_id":null,"actor_id":"agent:a","owner_id":"agent:a","created_by_actor_id":"agent:b","scope":"agent:agent:a","permissions":["agent:a"],"status":"verified","score":0.7}}
    , "memory");
