test "agent memory supermemory profile maps nullpantry memory to vendor documents" {
    if (!build_options.enable_engine_supermemory) return error.SkipZigTest;

    var runtime = try Runtime.init(std.testing.allocator, .{
        .backend = .supermemory,
        .api = .{
            .token = "sm-token",
            .actor_scopes_json = "[\"agent:agent:a\",\"team:alpha\"]",
        },
    });
    defer runtime.deinit();
    try std.testing.expectEqualStrings("supermemory", runtime.backendName());
    try std.testing.expect(!runtime.supportsFeed());

    const url = try externalApiBackendUrl(std.testing.allocator, "https://api.supermemory.ai/", "/v4/search", "", false);
    defer std.testing.allocator.free(url);
    try std.testing.expectEqualStrings("https://api.supermemory.ai/v4/search", url);
    try std.testing.expectError(error.InvalidRuntimeUrl, externalApiBackendUrl(std.testing.allocator, "https://token@api.supermemory.ai", "/v4/search", "", false));

    const payload = try supermemory.documentPayload(std.testing.allocator, .{
        .key = "pref.language",
        .content = "Prefer Zig examples",
        .category = "preference",
        .requested_scope = "team:alpha",
        .requested_permissions_json = "[\"team:alpha\"]",
        .metadata_json = "{\"source\":\"test\"}",
        .owner_actor_id = "shared:team:alpha",
        .writer_actor_id = "agent:a",
        .timestamp_ms = 42,
    });
    defer std.testing.allocator.free(payload);
    try std.testing.expect(std.mem.indexOf(u8, payload, "\"containerTag\":\"team:alpha\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, payload, "\"nullpantry_key\":\"pref.language\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, payload, "\"nullpantry_permissions_json\":\"[\\\"team:alpha\\\"]\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, payload, "\"nullpantry_metadata_json\":\"{\\\"source\\\":\\\"test\\\"}\"") != null);

    const search_payload = try supermemory.searchPayload(std.testing.allocator, "Zig", 10, "team:alpha");
    defer std.testing.allocator.free(search_payload);
    try std.testing.expect(std.mem.indexOf(u8, search_payload, "\"q\":\"Zig\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, search_payload, "\"searchMode\":\"hybrid\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, search_payload, "\"containerTag\":\"team:alpha\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, search_payload, "\"nullpantry_backend\"") != null);

    const global_search_payload = try supermemory.searchPayload(std.testing.allocator, "Zig", 10, null);
    defer std.testing.allocator.free(global_search_payload);
    try std.testing.expect(std.mem.indexOf(u8, global_search_payload, "\"containerTag\"") == null);
}

test "agent memory supermemory parser hydrates metadata and enforces nullpantry visibility" {
    if (!build_options.enable_engine_supermemory) return error.SkipZigTest;

    const body =
        \\{"results":[
        \\  {"id":"sm-1","memory":"Prefer Zig examples","score":0.8,"metadata":{"nullpantry_backend":"supermemory","nullpantry_type":"agent_memory","nullpantry_key":"pref.language","nullpantry_category":"preference","nullpantry_actor_id":"agent:a","nullpantry_writer_actor_id":"agent:a","nullpantry_scope":"agent:agent:a","nullpantry_permissions_json":"[\"actor:agent:a\"]","nullpantry_timestamp_ms":42}},
        \\  {"id":"sm-2","memory":"Team uses Postgres","score":0.7,"metadata":{"nullpantry_backend":"supermemory","nullpantry_type":"agent_memory","nullpantry_key":"team.db","nullpantry_category":"decision","nullpantry_actor_id":"shared:team:alpha","nullpantry_writer_actor_id":"agent:a","nullpantry_scope":"team:alpha","nullpantry_permissions_json":"[\"team:alpha\"]","nullpantry_timestamp_ms":43}}
        \\]}
    ;

    const visible = try supermemory.agentMemoryArrayFromBody(std.testing.allocator, body, "agent:a", "[\"agent:agent:a\",\"team:alpha\"]", null, null, true);
    defer {
        for (visible) |*entry| freeAgentMemory(std.testing.allocator, entry);
        std.testing.allocator.free(visible);
    }
    try std.testing.expectEqual(@as(usize, 2), visible.len);
    try std.testing.expectEqualStrings("supermemory", visible[0].store);

    const isolated = try supermemory.agentMemoryArrayFromBody(std.testing.allocator, body, "agent:b", "[\"agent:agent:b\"]", null, null, true);
    defer {
        for (isolated) |*entry| freeAgentMemory(std.testing.allocator, entry);
        std.testing.allocator.free(isolated);
    }
    try std.testing.expectEqual(@as(usize, 0), isolated.len);

    const exact = try supermemory.agentMemoryArrayFromBody(std.testing.allocator, body, "agent:a", "[\"agent:agent:a\",\"team:alpha\"]", "team.db", null, true);
    defer {
        for (exact) |*entry| freeAgentMemory(std.testing.allocator, entry);
        std.testing.allocator.free(exact);
    }
    try std.testing.expectEqual(@as(usize, 1), exact.len);
    try std.testing.expectEqualStrings("team.db", exact[0].key);
}

