    defer runtime.deinit();
    try std.testing.expectEqualStrings("openviking", runtime.backendName());
    try std.testing.expect(!runtime.supportsFeed());
    try std.testing.expectError(error.NotSupported, testRuntimeSaveMessageAt(&runtime, "session-1", "user", "hello", 1, "agent:a"));
    try std.testing.expectError(error.NotSupported, testRuntimeListFeedEvents(&runtime, std.testing.allocator, 0, 10, "agent:a", "[\"agent:agent:a\"]"));

