    try std.testing.expect(std.mem.indexOf(u8, write_payload, "\"wait\":true") != null);

    const search_payload = try openviking.searchPayload(std.testing.allocator, "Zig", 10, "viking://resources/nullpantry/agent-memory/shared/team_alpha");
