    try std.testing.expect(std.mem.indexOf(u8, search_payload, "\"target_uri\":\"viking://resources/nullpantry/agent-memory/shared/team_alpha\"") != null);

    var headers = try buildApiRequestHeaders(std.testing.allocator, .{
        .profile = .openviking,
        .base_url = "http://localhost:1933",
