    defer {
        for (searched) |*entry| freeAgentMemory(std.testing.allocator, entry);
        std.testing.allocator.free(searched);
    }
    try std.testing.expectEqual(@as(usize, 1), searched.len);

    try std.testing.expect(try runtime.deleteByInput(.{
