fn testingOwnedAgentMemory(allocator: std.mem.Allocator, key: []const u8, timestamp: []const u8) !domain.AgentMemory {
    var entry = domain.AgentMemory{
        .id = "",
        .key = "",
        .content = "",
        .category = "",
        .timestamp = "",
        .session_id = null,
        .actor_id = "",
        .scope = "",
    };
    errdefer freeAgentMemory(allocator, &entry);
    entry.id = try allocator.dupe(u8, key);
    entry.key = try allocator.dupe(u8, key);
    entry.content = try allocator.dupe(u8, "remote content");
    entry.category = try allocator.dupe(u8, "core");
    entry.timestamp = try allocator.dupe(u8, timestamp);
    entry.actor_id = try allocator.dupe(u8, "agent:a");
    entry.writer_actor_id = try allocator.dupe(u8, "agent:a");
    entry.scope = try allocator.dupe(u8, "agent:agent:a");
    entry.permissions_json = try allocator.dupe(u8, "[]");
    entry.status = try allocator.dupe(u8, "verified");
    entry.store = try allocator.dupe(u8, "remote");
    return entry;
}

test "named runtime registry rejects reserved duplicate and native stores" {
    try std.testing.expectError(error.InvalidAgentMemoryStoreName, RuntimeRegistry.init(std.testing.allocator, &.{
        .{ .name = "native", .config = .{ .backend = .memory_lru } },
    }));
    try std.testing.expectError(error.InvalidAgentMemoryStoreName, RuntimeRegistry.init(std.testing.allocator, &.{
        .{ .name = "bad,name", .config = .{ .backend = .memory_lru } },
    }));
    try std.testing.expectError(error.InvalidAgentMemoryStoreName, RuntimeRegistry.init(std.testing.allocator, &.{
        .{ .name = "bad store", .config = .{ .backend = .memory_lru } },
    }));
    try std.testing.expectError(error.InvalidAgentMemoryStoreName, RuntimeRegistry.init(std.testing.allocator, &.{
        .{ .name = ".hidden", .config = .{ .backend = .memory_lru } },
    }));
    try std.testing.expect(!isValidNamedStoreName("memory_lru"));
    try std.testing.expect(!isValidNamedStoreName("none"));
