    try std.testing.expect(!isValidNamedStoreName("http"));
    try std.testing.expect(!isValidNamedStoreName("kg"));
    try std.testing.expect(isValidNamedStoreName("mem0"));
    try std.testing.expect(isValidNamedStoreName("supermemory"));
    try std.testing.expect(isValidNamedStoreName("retaindb"));
    try std.testing.expect(isValidNamedStoreName("byterover"));
    try std.testing.expect(isValidNamedStoreName("team:alpha"));
    try std.testing.expect(isValidNamedStoreName("scratch-1.archive"));
    try std.testing.expectError(error.InvalidAgentMemoryStoreBackend, RuntimeRegistry.init(std.testing.allocator, &.{
        .{ .name = "scratch", .config = .{ .backend = .native } },
    }));
    try std.testing.expectError(error.MissingApiBackendUrl, RuntimeRegistry.init(std.testing.allocator, &.{
        .{ .name = "remote-api", .config = .{ .backend = .api } },
    }));
    try std.testing.expectError(error.MissingClickHouseAgentMemoryUrl, RuntimeRegistry.init(std.testing.allocator, &.{
        .{ .name = "history", .config = .{ .backend = .clickhouse } },
    }));
    try std.testing.expectError(error.DuplicateAgentMemoryStoreName, RuntimeRegistry.init(std.testing.allocator, &.{
        .{ .name = "scratch", .config = .{ .backend = .memory_lru } },
        .{ .name = "scratch", .config = .{ .backend = .memory_lru } },
    }));
}

test "agent memory runtime encodes message payloads" {
    const payload = try messagePayload(std.testing.allocator, "user", "hello", 42);
    defer std.testing.allocator.free(payload);
    const resp = redis.RespValue{ .array = try std.testing.allocator.dupe(redis.RespValue, &[_]redis.RespValue{.{ .bulk_string = payload }}) };
    defer {
        const items = resp.array.?;
        std.testing.allocator.free(items);
    }
    const messages = try messagesFromResp(std.testing.allocator, resp);
    defer {
        for (messages) |*message| freeMessage(std.testing.allocator, message);
        std.testing.allocator.free(messages);
    }
    try std.testing.expectEqual(@as(usize, 1), messages.len);
    try std.testing.expectEqualStrings("user", messages[0].role);
    try std.testing.expectEqualStrings("hello", messages[0].content);
    try std.testing.expectEqual(@as(i64, 42), messages[0].created_at_ms);

    const missing_content = "{\"role\":\"user\",\"created_at_ms\":42}";
    const missing_content_resp = redis.RespValue{ .array = try std.testing.allocator.dupe(redis.RespValue, &[_]redis.RespValue{.{ .bulk_string = missing_content }}) };
    defer std.testing.allocator.free(missing_content_resp.array.?);
    try std.testing.expectError(error.AgentMemoryStorageUnavailable, messagesFromResp(std.testing.allocator, missing_content_resp));

    const bad_json_resp = redis.RespValue{ .array = try std.testing.allocator.dupe(redis.RespValue, &[_]redis.RespValue{.{ .bulk_string = "{\"role\":\"user\"" }}) };
    defer std.testing.allocator.free(bad_json_resp.array.?);
    try std.testing.expectError(error.AgentMemoryStorageUnavailable, messagesFromResp(std.testing.allocator, bad_json_resp));

    const null_payload_resp = redis.RespValue{ .array = try std.testing.allocator.dupe(redis.RespValue, &[_]redis.RespValue{.{ .bulk_string = null }}) };
    defer std.testing.allocator.free(null_payload_resp.array.?);
    try std.testing.expectError(error.AgentMemoryStorageUnavailable, messagesFromResp(std.testing.allocator, null_payload_resp));

    try std.testing.expectError(error.AgentMemoryStorageUnavailable, messagesFromResp(std.testing.allocator, .{ .array = null }));
    try std.testing.expectError(error.AgentMemoryStorageUnavailable, messagesFromResp(std.testing.allocator, .{ .integer = 1 }));
}

test "agent memory runtime redis message payload order rejects malformed metadata" {
    const order: EventOrder = .{
        .timestamp_ms = 10,
        .origin_instance_id = "redis-a",
        .origin_sequence = 2,
    };

    const older_payload = try messagePayloadOrdered(std.testing.allocator, "user", "older", 9, .{
        .timestamp_ms = 9,
        .origin_instance_id = "redis-a",
        .origin_sequence = 1,
    });
    defer std.testing.allocator.free(older_payload);
    try std.testing.expect(!(try redisMessagePayloadNewerThanOrder(std.testing.allocator, older_payload, order)));

    const newer_payload = try messagePayloadOrdered(std.testing.allocator, "user", "newer", 11, .{
        .timestamp_ms = 11,
        .origin_instance_id = "redis-a",
        .origin_sequence = 1,
    });
    defer std.testing.allocator.free(newer_payload);
    try std.testing.expect(try redisMessagePayloadNewerThanOrder(std.testing.allocator, newer_payload, order));

    const legacy_payload = try messagePayload(std.testing.allocator, "user", "legacy", 11);
    defer std.testing.allocator.free(legacy_payload);
    try std.testing.expect(try redisMessagePayloadNewerThanOrder(std.testing.allocator, legacy_payload, order));

    try std.testing.expectError(error.AgentMemoryStorageUnavailable, redisMessagePayloadNewerThanOrder(std.testing.allocator, "{\"role\":\"user\"", order));
    try std.testing.expectError(error.AgentMemoryStorageUnavailable, redisMessagePayloadNewerThanOrder(std.testing.allocator, "[]", order));
    try std.testing.expectError(error.AgentMemoryStorageUnavailable, redisMessagePayloadNewerThanOrder(std.testing.allocator, "{\"role\":\"user\",\"content\":\"missing timestamp\"}", order));
    try std.testing.expectError(error.AgentMemoryStorageUnavailable, redisMessagePayloadNewerThanOrder(std.testing.allocator, "{\"created_at_ms\":-1}", order));
    try std.testing.expectError(error.AgentMemoryStorageUnavailable, redisMessagePayloadNewerThanOrder(std.testing.allocator, "{\"created_at_ms\":11,\"origin_instance_id\":7}", order));
    try std.testing.expectError(error.AgentMemoryStorageUnavailable, redisMessagePayloadNewerThanOrder(std.testing.allocator, "{\"created_at_ms\":11,\"origin_sequence\":\"7\"}", order));
    try std.testing.expectError(error.AgentMemoryStorageUnavailable, redisMessagePayloadNewerThanOrder(std.testing.allocator, "{\"created_at_ms\":11,\"origin_sequence\":-1}", order));
}

