test "memory_lru ordered merge ignores stale writes and tombstone blocks stale replay" {
    var runtime = try Runtime.init(std.testing.allocator, .{ .backend = .memory_lru });
    defer runtime.deinit();
    const actor_id = "agent:ordered";
    const key = "ordered.profile";

    var first = try runtime.store(std.testing.allocator, .{
        .key = key,
        .content = "{\"name\":\"Ada\"}",
        .actor_id = actor_id,
        .operation = .merge_object,
        .event_order = .{ .timestamp_ms = 100, .origin_instance_id = "ordered-runtime", .origin_sequence = 1 },
    });
    defer freeAgentMemory(std.testing.allocator, &first);
    try std.testing.expectEqualStrings("{\"name\":\"Ada\"}", first.content);

    var newer = try runtime.store(std.testing.allocator, .{
        .key = key,
        .content = "{\"language\":\"zig\"}",
        .actor_id = actor_id,
        .operation = .merge_object,
        .event_order = .{ .timestamp_ms = 200, .origin_instance_id = "ordered-runtime", .origin_sequence = 2 },
    });
    defer freeAgentMemory(std.testing.allocator, &newer);
    try std.testing.expectEqualStrings("{\"language\":\"zig\",\"name\":\"Ada\"}", newer.content);

    var stale = try runtime.store(std.testing.allocator, .{
        .key = key,
        .content = "{\"language\":\"rust\",\"stale\":true}",
        .actor_id = actor_id,
        .operation = .merge_object,
        .event_order = .{ .timestamp_ms = 150, .origin_instance_id = "ordered-runtime", .origin_sequence = 3 },
    });
    defer freeAgentMemory(std.testing.allocator, &stale);
    try std.testing.expectEqualStrings("{\"language\":\"zig\",\"name\":\"Ada\"}", stale.content);

    try std.testing.expect(try runtime.patchStatusByInput(std.testing.allocator, .{
        .key = key,
        .status = "deprecated",
        .actor_id = actor_id,
        .event_order = .{ .timestamp_ms = 300, .origin_instance_id = "ordered-runtime", .origin_sequence = 4 },
    }));
    try std.testing.expect((try testRuntimeGet(&runtime, std.testing.allocator, key, null, actor_id)) == null);

    var blocked = try runtime.store(std.testing.allocator, .{
        .key = key,
        .content = "{\"name\":\"stale replay\"}",
        .actor_id = actor_id,
        .operation = .put,
        .event_order = .{ .timestamp_ms = 250, .origin_instance_id = "ordered-runtime", .origin_sequence = 5 },
    });
    defer freeAgentMemory(std.testing.allocator, &blocked);
    try std.testing.expectEqualStrings("ignored", blocked.status);
    try std.testing.expect((try testRuntimeGet(&runtime, std.testing.allocator, key, null, actor_id)) == null);

    var fresh = try runtime.store(std.testing.allocator, .{
        .key = key,
        .content = "{\"name\":\"fresh replay\"}",
        .actor_id = actor_id,
        .operation = .put,
        .event_order = .{ .timestamp_ms = 400, .origin_instance_id = "ordered-runtime", .origin_sequence = 6 },
    });
    defer freeAgentMemory(std.testing.allocator, &fresh);
    try std.testing.expectEqualStrings("{\"name\":\"fresh replay\"}", fresh.content);

    var reread = (try testRuntimeGet(&runtime, std.testing.allocator, key, null, actor_id)).?;
    defer freeAgentMemory(std.testing.allocator, &reread);
    try std.testing.expectEqualStrings("{\"name\":\"fresh replay\"}", reread.content);
}

test "memory_lru tombstone replay boundary is monotonic" {
    var runtime = try Runtime.init(std.testing.allocator, .{ .backend = .memory_lru });
    defer runtime.deinit();
    const actor_id = "agent:tombstone-boundary";
    const key = "tombstone.boundary";

    var stored = try runtime.store(std.testing.allocator, .{
        .key = key,
        .content = "before tombstone",
        .actor_id = actor_id,
        .event_order = .{ .timestamp_ms = 100, .origin_instance_id = "boundary", .origin_sequence = 1 },
    });
    defer freeAgentMemory(std.testing.allocator, &stored);
    try std.testing.expect(try runtime.deleteByInput(.{
        .key = key,
        .actor_id = actor_id,
        .writer_actor_id = actor_id,
        .event_order = .{ .timestamp_ms = 200, .origin_instance_id = "boundary", .origin_sequence = 5 },
    }));

    const cases = [_]struct {
        order: EventOrder,
        blocks: bool,
    }{
        .{ .order = .{ .timestamp_ms = 199, .origin_instance_id = "boundary", .origin_sequence = 99 }, .blocks = true },
        .{ .order = .{ .timestamp_ms = 200, .origin_instance_id = "boundary", .origin_sequence = 5 }, .blocks = true },
        .{ .order = .{ .timestamp_ms = 200, .origin_instance_id = "boundary", .origin_sequence = 6 }, .blocks = false },
        .{ .order = .{ .timestamp_ms = 201, .origin_instance_id = "boundary", .origin_sequence = 1 }, .blocks = false },
    };

    for (cases) |case| {
        try std.testing.expectEqual(case.blocks, try runtime.tombstoneBlocksReplayByInput(std.testing.allocator, .{
            .key = key,
            .actor_id = actor_id,
            .event_order = case.order,
        }));
    }
}

