test "memory_lru checkpoint restore rejects invalid checkpoints atomically" {
    var runtime = try Runtime.init(std.testing.allocator, .{ .backend = .memory_lru });
    defer runtime.deinit();
    const actor_id = "agent:runtime-atomic";
    const scopes = "[\"public\",\"actor:agent:runtime-atomic\"]";

    var existing = try runtime.store(std.testing.allocator, .{ .key = "runtime.atomic.existing", .content = "existing value", .actor_id = actor_id });
    defer freeAgentMemory(std.testing.allocator, &existing);

    const invalid_checkpoint =
        \\{"frontiers":[{"origin_instance_id":"remote-atomic","origin_sequence":2}],"events":[
        \\{"origin_instance_id":"remote-atomic","origin_sequence":1,"event_type":"agent_memory.put","operation":"put","object_type":"agent_memory","object_id":"runtime.atomic.partial","actor_id":"agent:runtime-atomic","scope":"public","payload":{"key":"runtime.atomic.partial","content":"must not partially restore","scope":"public","owner_id":"agent:runtime-atomic"}},
        \\{"origin_instance_id":"remote-atomic","origin_sequence":2,"event_type":"unsupported.put","operation":"put","object_type":"unsupported","object_id":"bad","actor_id":"agent:runtime-atomic","scope":"public","payload":{"content":"bad"}}
        \\]}
    ;
    try std.testing.expectError(error.NotSupported, testRuntimeRestoreFeedCheckpoint(&runtime, std.testing.allocator, invalid_checkpoint, actor_id, scopes));

    var preserved = (try testRuntimeGetVisible(&runtime, std.testing.allocator, "runtime.atomic.existing", null, actor_id, scopes)).?;
    defer freeAgentMemory(std.testing.allocator, &preserved);
    try std.testing.expectEqualStrings("existing value", preserved.content);
    try std.testing.expect((try testRuntimeGetVisible(&runtime, std.testing.allocator, "runtime.atomic.partial", null, actor_id, scopes)) == null);

    var status = try testRuntimeFeedStatus(&runtime, std.testing.allocator, actor_id, scopes);
    defer status.deinit(std.testing.allocator);
    try std.testing.expectEqual(@as(i64, 1), status.max_event_id);

    try testRuntimeApplyFeedEvent(&runtime, std.testing.allocator, "{\"origin_instance_id\":\"remote-atomic\",\"origin_sequence\":1,\"event_type\":\"agent_memory.put\",\"operation\":\"put\",\"object_type\":\"agent_memory\",\"object_id\":\"runtime.atomic.partial\",\"actor_id\":\"agent:runtime-atomic\",\"scope\":\"public\",\"payload\":{\"key\":\"runtime.atomic.partial\",\"content\":\"valid replay after rejected checkpoint\",\"scope\":\"public\",\"owner_id\":\"agent:runtime-atomic\"}}", actor_id, scopes);
    var replayed = (try testRuntimeGetVisible(&runtime, std.testing.allocator, "runtime.atomic.partial", null, actor_id, scopes)).?;
    defer freeAgentMemory(std.testing.allocator, &replayed);
    try std.testing.expectEqualStrings("valid replay after rejected checkpoint", replayed.content);
}

