test "runtime feed suppress flag applies state without echoing feed events" {
    var runtime = try Runtime.init(std.testing.allocator, .{ .backend = .memory_lru });
    defer runtime.deinit();
    const actor_id = "agent:runtime-suppress";
    const scopes = "[\"public\",\"actor:agent:runtime-suppress\",\"session:runtime-suppress-session\"]";

    try testRuntimeApplyFeedEvent(&runtime, std.testing.allocator, "{\"origin_instance_id\":\"suppress-runtime\",\"origin_sequence\":1,\"timestamp_ms\":100,\"key\":\"suppress.normal\",\"content\":\"normal replay event\",\"scope\":\"public\",\"permissions\":[\"public\"]}", actor_id, scopes);
    const normal_feed = try testRuntimeListFeedEvents(&runtime, std.testing.allocator, 0, 10, actor_id, scopes);
    defer {
        for (normal_feed) |*event| event.deinit(std.testing.allocator);
        std.testing.allocator.free(normal_feed);
    }
    try std.testing.expectEqual(@as(usize, 1), normal_feed.len);

    try testRuntimeApplyFeedEvent(&runtime, std.testing.allocator, "{\"origin_instance_id\":\"suppress-runtime\",\"origin_sequence\":2,\"timestamp_ms\":200,\"suppress_feed\":true,\"key\":\"suppress.memory\",\"content\":\"suppressed memory replay\",\"scope\":\"public\",\"permissions\":[\"public\"]}", actor_id, scopes);
    var suppressed_memory = (try testRuntimeGetVisible(&runtime, std.testing.allocator, "suppress.memory", null, actor_id, scopes)).?;
    defer freeAgentMemory(std.testing.allocator, &suppressed_memory);
    try std.testing.expectEqualStrings("suppressed memory replay", suppressed_memory.content);

    try testRuntimeApplyFeedEvent(&runtime, std.testing.allocator, "{\"origin_instance_id\":\"suppress-runtime\",\"origin_sequence\":3,\"timestamp_ms\":300,\"suppress_feed\":true,\"event_type\":\"agent_session_message.put\",\"operation\":\"put\",\"object_type\":\"agent_session_message\",\"object_id\":\"runtime-suppress-session\",\"actor_id\":\"agent:runtime-suppress\",\"scope\":\"public\",\"permissions\":[\"public\"],\"payload\":{\"session_id\":\"runtime-suppress-session\",\"role\":\"user\",\"content\":\"suppressed session replay\",\"created_at_ms\":300,\"actor_id\":\"agent:runtime-suppress\"}}", actor_id, scopes);
    const messages = try testRuntimeLoadMessages(&runtime, std.testing.allocator, "runtime-suppress-session", actor_id);
    defer {
        for (messages) |message| {
            std.testing.allocator.free(message.role);
            std.testing.allocator.free(message.content);
        }
        std.testing.allocator.free(messages);
    }
    try std.testing.expectEqual(@as(usize, 1), messages.len);
    try std.testing.expectEqualStrings("suppressed session replay", messages[0].content);

    try testRuntimeApplyFeedEvent(&runtime, std.testing.allocator, "{\"origin_instance_id\":\"suppress-runtime\",\"origin_sequence\":4,\"timestamp_ms\":400,\"suppress_feed\":true,\"event_type\":\"agent_session_usage.put\",\"operation\":\"put\",\"object_type\":\"agent_session_usage\",\"object_id\":\"runtime-suppress-session\",\"actor_id\":\"agent:runtime-suppress\",\"scope\":\"public\",\"permissions\":[\"public\"],\"payload\":{\"session_id\":\"runtime-suppress-session\",\"total_tokens\":44,\"actor_id\":\"agent:runtime-suppress\"}}", actor_id, scopes);
    try std.testing.expectEqual(@as(?u64, 44), try testRuntimeLoadUsage(&runtime, "runtime-suppress-session", actor_id));

    const delete_body = try std.fmt.allocPrint(std.testing.allocator, "{{\"origin_instance_id\":\"suppress-runtime\",\"origin_sequence\":5,\"timestamp_ms\":500,\"suppress_feed\":true,\"event_type\":\"agent_memory.delete\",\"operation\":\"delete\",\"object_type\":\"agent_memory\",\"object_id\":\"suppress.memory\",\"actor_id\":\"agent:runtime-suppress\",\"scope\":\"public\",\"permissions\":[\"public\"],\"payload\":{{\"key\":\"suppress.memory\",\"scope\":\"public\",\"owner_id\":\"{s}\"}}}}", .{suppressed_memory.actor_id});
    defer std.testing.allocator.free(delete_body);
    try testRuntimeApplyFeedEvent(&runtime, std.testing.allocator, delete_body, actor_id, scopes);
    var deleted_memory = try testRuntimeGetVisible(&runtime, std.testing.allocator, "suppress.memory", null, actor_id, scopes);
    defer if (deleted_memory) |*entry| freeAgentMemory(std.testing.allocator, entry);
    try std.testing.expect(deleted_memory == null);

    const suppressed_feed = try testRuntimeListFeedEvents(&runtime, std.testing.allocator, 0, 10, actor_id, scopes);
    defer {
        for (suppressed_feed) |*event| event.deinit(std.testing.allocator);
        std.testing.allocator.free(suppressed_feed);
    }
    try std.testing.expectEqual(@as(usize, 1), suppressed_feed.len);
    try std.testing.expect(std.mem.indexOf(u8, suppressed_feed[0].payload_json, "normal replay event") != null);
}

