test "runtime feed delete operations clear session message and usage state" {
    var runtime = try Runtime.init(std.testing.allocator, .{ .backend = .memory_lru });
    defer runtime.deinit();
    const actor_id = "agent:runtime-session-delete";
    const scopes = "[\"public\",\"session:runtime-delete\",\"write:session:runtime-delete\",\"actor:agent:runtime-session-delete\"]";

    try testRuntimeSaveMessage(&runtime, "runtime-delete", "user", "message before forget", actor_id);
    try testRuntimeSaveUsage(&runtime, "runtime-delete", 77, actor_id);

    try testRuntimeApplyFeedEvent(&runtime, std.testing.allocator, "{\"origin_instance_id\":\"session-delete-runtime\",\"origin_sequence\":1,\"event_type\":\"agent_session_message.forget\",\"operation\":\"forget\",\"object_type\":\"agent_session_message\",\"object_id\":\"runtime-delete\",\"actor_id\":\"agent:runtime-session-delete\",\"scope\":\"public\",\"permissions\":[\"public\"],\"payload\":{\"session_id\":\"runtime-delete\",\"actor_id\":\"agent:runtime-session-delete\"}}", actor_id, scopes);
    try testRuntimeApplyFeedEvent(&runtime, std.testing.allocator, "{\"origin_instance_id\":\"session-delete-runtime\",\"origin_sequence\":2,\"event_type\":\"agent_session_usage.forget\",\"operation\":\"forget\",\"object_type\":\"agent_session_usage\",\"object_id\":\"runtime-delete\",\"actor_id\":\"agent:runtime-session-delete\",\"scope\":\"public\",\"permissions\":[\"public\"],\"payload\":{\"session_id\":\"runtime-delete\",\"actor_id\":\"agent:runtime-session-delete\"}}", actor_id, scopes);

    const messages = try testRuntimeLoadMessages(&runtime, std.testing.allocator, "runtime-delete", actor_id);
    defer {
        for (messages) |message| {
            std.testing.allocator.free(message.role);
            std.testing.allocator.free(message.content);
        }
        std.testing.allocator.free(messages);
    }
    try std.testing.expectEqual(@as(usize, 0), messages.len);
    try std.testing.expectEqual(@as(?u64, null), try testRuntimeLoadUsage(&runtime, "runtime-delete", actor_id));

    try testRuntimeSaveMessage(&runtime, "runtime-delete", "assistant", "message before delete_all", actor_id);
    try testRuntimeSaveUsage(&runtime, "runtime-delete", 88, actor_id);
    try testRuntimeApplyFeedEvent(&runtime, std.testing.allocator, "{\"origin_instance_id\":\"session-delete-runtime\",\"origin_sequence\":3,\"event_type\":\"agent_session_message.delete_all\",\"operation\":\"delete_all\",\"object_type\":\"agent_session_message\",\"object_id\":\"runtime-delete\",\"actor_id\":\"agent:runtime-session-delete\",\"scope\":\"public\",\"permissions\":[\"public\"],\"payload\":{\"session_id\":\"runtime-delete\",\"actor_id\":\"agent:runtime-session-delete\"}}", actor_id, scopes);
    try testRuntimeApplyFeedEvent(&runtime, std.testing.allocator, "{\"origin_instance_id\":\"session-delete-runtime\",\"origin_sequence\":4,\"event_type\":\"agent_session_usage.delete_all\",\"operation\":\"delete_all\",\"object_type\":\"agent_session_usage\",\"object_id\":\"runtime-delete\",\"actor_id\":\"agent:runtime-session-delete\",\"scope\":\"public\",\"permissions\":[\"public\"],\"payload\":{\"session_id\":\"runtime-delete\",\"actor_id\":\"agent:runtime-session-delete\"}}", actor_id, scopes);

    const messages_after_delete_all = try testRuntimeLoadMessages(&runtime, std.testing.allocator, "runtime-delete", actor_id);
    defer {
        for (messages_after_delete_all) |message| {
            std.testing.allocator.free(message.role);
            std.testing.allocator.free(message.content);
        }
        std.testing.allocator.free(messages_after_delete_all);
    }
    try std.testing.expectEqual(@as(usize, 0), messages_after_delete_all.len);
    try std.testing.expectEqual(@as(?u64, null), try testRuntimeLoadUsage(&runtime, "runtime-delete", actor_id));
}

test "runtime feed rejects cross actor agent memory owner spoofing without explicit delegation" {
    var runtime = try Runtime.init(std.testing.allocator, .{ .backend = .memory_lru });
    defer runtime.deinit();
    const caller_actor = "agent:a";
    const caller_scopes = "[\"public\",\"agent:agent:a\",\"actor:agent:a\"]";

    try std.testing.expectError(error.Forbidden, testRuntimeApplyFeedEvent(&runtime, std.testing.allocator,
        \\{"origin_instance_id":"owner-spoof-runtime","origin_sequence":1,"event_type":"agent_memory.put","operation":"put","object_type":"agent_memory","object_id":"owner-spoof","actor_id":"agent:a","scope":"public","permissions":["public"],"payload":{"key":"owner-spoof","content":"spoofed owner memory","scope":"public","permissions":["public"],"owner_id":"agent:b"}}
    , caller_actor, caller_scopes));
    try std.testing.expectError(error.Forbidden, testRuntimeApplyFeedEvent(&runtime, std.testing.allocator,
        \\{"origin_instance_id":"owner-spoof-runtime","origin_sequence":2,"event_type":"agent_memory.put","operation":"put","object_type":"agent_memory","object_id":"owner-mismatch","actor_id":"agent:a","scope":"agent:agent:b","permissions":["public"],"payload":{"key":"owner-mismatch","content":"mismatched owner aliases","scope":"agent:agent:b","permissions":["public"],"owner_id":"agent:b","actor_id":"agent:c"}}
    , caller_actor, "[\"public\",\"agent:agent:b\",\"actor:agent:b\"]"));

    try std.testing.expect((try testRuntimeGet(&runtime, std.testing.allocator, "owner-spoof", null, "agent:b")) == null);
    try std.testing.expect((try testRuntimeGet(&runtime, std.testing.allocator, "owner-spoof", null, "shared:public")) == null);

    const sync_actor = "agent:sync";
    const sync_scopes = "[\"public\",\"agent:agent:b\",\"actor:agent:b\"]";
    try testRuntimeApplyFeedEvent(&runtime, std.testing.allocator,
        \\{"origin_instance_id":"owner-spoof-runtime","origin_sequence":3,"event_type":"agent_memory.put","operation":"put","object_type":"agent_memory","object_id":"owner-delegated","actor_id":"agent:writer","scope":"agent:agent:b","permissions":["public"],"payload":{"key":"owner-delegated","content":"delegated owner memory","scope":"agent:agent:b","permissions":["public"],"owner_id":"agent:b"}}
    , sync_actor, sync_scopes);

    var delegated = (try testRuntimeGet(&runtime, std.testing.allocator, "owner-delegated", null, "agent:b")).?;
    defer freeAgentMemory(std.testing.allocator, &delegated);
    try std.testing.expectEqualStrings("delegated owner memory", delegated.content);
    try std.testing.expectEqualStrings("agent:b", delegated.actor_id);
    try std.testing.expectEqualStrings("agent:writer", delegated.writer_actor_id);

    try testRuntimeApplyFeedEvent(&runtime, std.testing.allocator,
        \\{"origin_instance_id":"owner-spoof-runtime","origin_sequence":4,"event_type":"agent_memory.put","operation":"put","object_type":"agent_memory","object_id":"owner-shared","actor_id":"agent:writer","scope":"team:alpha","permissions":["team:alpha"],"payload":{"key":"owner-shared","content":"shared owner memory","scope":"team:alpha","permissions":["team:alpha"],"owner_id":"shared:team:alpha"}}
    , sync_actor, "[\"team:alpha\"]");

    var shared = (try testRuntimeGet(&runtime, std.testing.allocator, "owner-shared", null, "shared:team:alpha")).?;
    defer freeAgentMemory(std.testing.allocator, &shared);
    try std.testing.expectEqualStrings("shared owner memory", shared.content);
    try std.testing.expectEqualStrings("shared:team:alpha", shared.actor_id);
    try std.testing.expectEqualStrings("agent:writer", shared.writer_actor_id);
}

test "runtime feed rejects cross actor session spoofing without explicit delegation" {
    var runtime = try Runtime.init(std.testing.allocator, .{ .backend = .memory_lru });
    defer runtime.deinit();
    const caller_actor = "agent:a";
    const caller_scopes = "[\"public\",\"session:session-spoof\",\"actor:agent:a\"]";

    try std.testing.expectError(error.Forbidden, testRuntimeApplyFeedEvent(&runtime, std.testing.allocator,
        \\{"origin_instance_id":"session-spoof-runtime","origin_sequence":1,"event_type":"agent_session_message.put","operation":"put","object_type":"agent_session_message","object_id":"session-spoof","actor_id":"agent:a","scope":"public","permissions":["public"],"payload":{"session_id":"session-spoof","role":"user","content":"spoofed message","created_at_ms":1,"actor_id":"agent:b"}}
    , caller_actor, caller_scopes));
    try std.testing.expectError(error.Forbidden, testRuntimeApplyFeedEvent(&runtime, std.testing.allocator,
        \\{"origin_instance_id":"session-spoof-runtime","origin_sequence":2,"event_type":"agent_session_usage.put","operation":"put","object_type":"agent_session_usage","object_id":"session-spoof","actor_id":"agent:a","scope":"public","permissions":["public"],"payload":{"session_id":"session-spoof","total_tokens":42,"actor_id":"agent:b"}}
    , caller_actor, caller_scopes));

    const victim_messages = try testRuntimeLoadMessages(&runtime, std.testing.allocator, "session-spoof", "agent:b");
    defer {
