    }
    try std.testing.expectEqual(@as(usize, 0), victim_messages.len);
    try std.testing.expectEqual(@as(?u64, null), try testRuntimeLoadUsage(&runtime, "session-spoof", "agent:b"));

    const sync_actor = "agent:sync";
    const sync_scopes = "[\"public\",\"session:session-spoof\",\"actor:agent:b\"]";
    try testRuntimeApplyFeedEvent(&runtime, std.testing.allocator,
        \\{"origin_instance_id":"session-spoof-runtime","origin_sequence":3,"event_type":"agent_session_message.put","operation":"put","object_type":"agent_session_message","object_id":"session-spoof","actor_id":"agent:b","scope":"public","permissions":["public"],"payload":{"session_id":"session-spoof","role":"user","content":"delegated message","created_at_ms":3,"actor_id":"agent:b"}}
    , sync_actor, sync_scopes);
    try testRuntimeApplyFeedEvent(&runtime, std.testing.allocator,
        \\{"origin_instance_id":"session-spoof-runtime","origin_sequence":4,"event_type":"agent_session_usage.put","operation":"put","object_type":"agent_session_usage","object_id":"session-spoof","actor_id":"agent:b","scope":"public","permissions":["public"],"payload":{"session_id":"session-spoof","total_tokens":99,"actor_id":"agent:b"}}
    , sync_actor, sync_scopes);

    const delegated_messages = try testRuntimeLoadMessages(&runtime, std.testing.allocator, "session-spoof", "agent:b");
    defer {
        for (delegated_messages) |*message| freeMessage(std.testing.allocator, message);
        std.testing.allocator.free(delegated_messages);
    }
    try std.testing.expectEqual(@as(usize, 1), delegated_messages.len);
    try std.testing.expectEqualStrings("delegated message", delegated_messages[0].content);
    try std.testing.expectEqual(@as(?u64, 99), try testRuntimeLoadUsage(&runtime, "session-spoof", "agent:b"));

    const sync_messages = try testRuntimeLoadMessages(&runtime, std.testing.allocator, "session-spoof", sync_actor);
    defer {
        for (sync_messages) |*message| freeMessage(std.testing.allocator, message);
        std.testing.allocator.free(sync_messages);
    }
    try std.testing.expectEqual(@as(usize, 0), sync_messages.len);
    try std.testing.expectEqual(@as(?u64, null), try testRuntimeLoadUsage(&runtime, "session-spoof", sync_actor));
}

test "memory_lru accepts wrapped checkpoint restore and apply" {
    var runtime = try Runtime.init(std.testing.allocator, .{ .backend = .memory_lru });
    defer runtime.deinit();
    const actor_id = "agent:wrapped-checkpoint";
    const scopes = "[\"public\",\"actor:agent:wrapped-checkpoint\"]";
    const wrapped_checkpoint =
        \\{"checkpoint":{"cursor_floor":5,"compacted_through_sequence":5,"frontiers":[{"origin_instance_id":"wrapped-runtime","origin_sequence":4}],"events":[{"origin_instance_id":"wrapped-runtime","origin_sequence":4,"event_type":"agent_memory.put","operation":"put","object_type":"agent_memory","object_id":"wrapped.checkpoint.pref","actor_id":"agent:wrapped-checkpoint","scope":"public","payload":{"key":"wrapped.checkpoint.pref","content":"from wrapped checkpoint","scope":"public","owner_id":"agent:wrapped-checkpoint"}}]}}
    ;
    const stale_replay =
        \\{"origin_instance_id":"wrapped-runtime","origin_sequence":4,"event_type":"agent_memory.put","operation":"put","object_type":"agent_memory","object_id":"wrapped.checkpoint.pref","actor_id":"agent:wrapped-checkpoint","scope":"public","payload":{"key":"wrapped.checkpoint.pref","content":"stale wrapped replay","scope":"public","owner_id":"agent:wrapped-checkpoint"}}
    ;

    try testRuntimeApplyFeedEvent(&runtime, std.testing.allocator, wrapped_checkpoint, actor_id, scopes);

    var status = try testRuntimeFeedStatus(&runtime, std.testing.allocator, actor_id, scopes);
    defer status.deinit(std.testing.allocator);
    try std.testing.expectEqual(@as(i64, 5), status.cursor_floor);
    try std.testing.expectEqual(@as(i64, 6), status.next_local_origin_sequence);

    var value = (try testRuntimeGetVisible(&runtime, std.testing.allocator, "wrapped.checkpoint.pref", null, actor_id, scopes)).?;
    defer freeAgentMemory(std.testing.allocator, &value);
    try std.testing.expectEqualStrings("from wrapped checkpoint", value.content);

    try testRuntimeApplyFeedEvent(&runtime, std.testing.allocator, stale_replay, actor_id, scopes);
    var after_stale = (try testRuntimeGetVisible(&runtime, std.testing.allocator, "wrapped.checkpoint.pref", null, actor_id, scopes)).?;
    defer freeAgentMemory(std.testing.allocator, &after_stale);
    try std.testing.expectEqualStrings("from wrapped checkpoint", after_stale.content);
}

test "memory_lru checkpoint export respects cursor floor and compaction" {
    var runtime = try Runtime.init(std.testing.allocator, .{ .backend = .memory_lru });
    defer runtime.deinit();

    const actor_id = "agent:checkpoint";
    const scopes = "[\"agent:agent:checkpoint\"]";
    var first = try runtime.store(std.testing.allocator, .{ .key = "checkpoint.first", .content = "compacted checkpoint memory", .actor_id = actor_id });
    defer freeAgentMemory(std.testing.allocator, &first);
    var first_status = try testRuntimeFeedStatus(&runtime, std.testing.allocator, actor_id, scopes);
    defer first_status.deinit(std.testing.allocator);
    const first_event_id = first_status.max_event_id;
    try std.testing.expect(first_event_id > 0);

    var second = try runtime.store(std.testing.allocator, .{ .key = "checkpoint.second", .content = "available checkpoint memory", .actor_id = actor_id });
    defer freeAgentMemory(std.testing.allocator, &second);
    var second_status = try testRuntimeFeedStatus(&runtime, std.testing.allocator, actor_id, scopes);
    defer second_status.deinit(std.testing.allocator);
    try std.testing.expect(second_status.max_event_id > first_event_id);

    const compacted = try testRuntimeCompactFeed(&runtime, std.testing.allocator, actor_id, scopes, first_event_id);
    try std.testing.expectEqual(first_event_id, compacted.cursor_floor);
    try std.testing.expect(compacted.compacted_events > 0);
    try std.testing.expectError(error.CursorExpired, testRuntimeExportFeedCheckpoint(&runtime, std.testing.allocator, @as(?i64, 0), 100, actor_id, scopes));

    const checkpoint = try testRuntimeExportFeedCheckpoint(&runtime, std.testing.allocator, first_event_id, 100, actor_id, scopes);
    defer std.testing.allocator.free(checkpoint);
    const expected_floor = try std.fmt.allocPrint(std.testing.allocator, "\"cursor_floor\":{d}", .{first_event_id});
    defer std.testing.allocator.free(expected_floor);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint, expected_floor) != null);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint, "checkpoint.second") != null);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint, "checkpoint.first") == null);
}

test "memory_lru feed preserves writer actor for destructive and lifecycle operations" {
    var runtime = try Runtime.init(std.testing.allocator, .{ .backend = .memory_lru });
    defer runtime.deinit();

    var delete_entry = try runtime.store(std.testing.allocator, .{ .key = "writer.delete", .content = "delete me", .actor_id = "agent:owner" });
    defer freeAgentMemory(std.testing.allocator, &delete_entry);
