    var delete_all_global = try runtime.store(std.testing.allocator, .{ .key = "writer.delete_all", .content = "delete all global", .actor_id = "agent:owner" });
    defer freeAgentMemory(std.testing.allocator, &delete_all_global);
    var delete_all_session = try runtime.store(std.testing.allocator, .{ .key = "writer.delete_all", .content = "delete all session", .session_id = "sess", .actor_id = "agent:owner" });
    defer freeAgentMemory(std.testing.allocator, &delete_all_session);
    try std.testing.expect(try testRuntimeDeleteAll(&runtime, "writer.delete_all", "agent:owner", "agent:delete-all"));

    var lifecycle_entry = try runtime.store(std.testing.allocator, .{ .key = "writer.lifecycle", .content = "verify me", .actor_id = "agent:owner" });
    defer freeAgentMemory(std.testing.allocator, &lifecycle_entry);
    try std.testing.expect(try testRuntimePatchStatus(&runtime, std.testing.allocator, "writer.lifecycle", null, "agent:owner", "verified", "agent:verifier"));
    var lifecycle_forget = try runtime.store(std.testing.allocator, .{ .key = "writer.lifecycle.forget", .content = "forget me", .actor_id = "agent:owner" });
    defer freeAgentMemory(std.testing.allocator, &lifecycle_forget);
    try std.testing.expect(try testRuntimePatchStatus(&runtime, std.testing.allocator, "writer.lifecycle.forget", null, "agent:owner", "deprecated", "agent:forgetter"));

    const events = try testRuntimeListFeedEvents(&runtime, std.testing.allocator, 0, 50, "agent:owner", "[\"agent:agent:owner\"]");
    defer {
        for (events) |*event| event.deinit(std.testing.allocator);
        std.testing.allocator.free(events);
    }
    try std.testing.expect(feedEventsContainActor(events, "agent_memory.delete", "writer.delete", "agent:deleter"));
    try std.testing.expect(feedEventsContainActor(events, "agent_memory.delete_all", "writer.delete_all", "agent:delete-all"));
    try std.testing.expect(feedEventsContainActor(events, "agent_memory.verify", "writer.lifecycle", "agent:verifier"));
    try std.testing.expect(feedEventsContainActor(events, "agent_memory.forget", "writer.lifecycle.forget", "agent:forgetter"));
}

test "memory_lru delete_all feed preserves deleted row acl" {
    var runtime = try Runtime.init(std.testing.allocator, .{ .backend = .memory_lru });
    defer runtime.deinit();

    const actor = "agent:feed-delete-all";
    const actor_scopes = "[\"agent:agent:feed-delete-all\"]";
    const key = "runtime.delete_all.feed_acl";

    var root = try runtime.store(std.testing.allocator, .{ .key = key, .content = "root private", .actor_id = actor });
    defer freeAgentMemory(std.testing.allocator, &root);
    var session = try runtime.store(std.testing.allocator, .{ .key = key, .content = "session private", .session_id = "runtime-delete-all-session", .actor_id = actor });
    defer freeAgentMemory(std.testing.allocator, &session);

    try std.testing.expect(try testRuntimeDeleteAll(&runtime, key, actor, actor));

    const events = try testRuntimeListFeedEvents(&runtime, std.testing.allocator, 0, 20, actor, actor_scopes);
    defer {
        for (events) |*event| event.deinit(std.testing.allocator);
        std.testing.allocator.free(events);
    }
    var saw_delete_all = false;
    for (events) |event| {
        if (!std.mem.eql(u8, event.operation, "delete_all") or !std.mem.eql(u8, event.object_id, key)) continue;
        saw_delete_all = true;
        try std.testing.expectEqualStrings("agent:agent:feed-delete-all", event.scope);
        try std.testing.expectEqualStrings("[\"actor:agent:feed-delete-all\"]", event.permissions_json);
        try std.testing.expect(std.mem.indexOf(u8, event.payload_json, "\"permissions\":[\"actor:agent:feed-delete-all\"]") != null);
        try std.testing.expect(std.mem.indexOf(u8, event.payload_json, "\"permissions\":[]") == null);
    }
    try std.testing.expect(saw_delete_all);

    const hidden = try testRuntimeListFeedEvents(&runtime, std.testing.allocator, 0, 20, "agent:feed-delete-other", actor_scopes);
    defer {
        for (hidden) |*event| event.deinit(std.testing.allocator);
