test "memory_lru ttl cutoff is overflow safe" {
    try std.testing.expectEqual(@as(i64, 1_001), memoryTtlCutoffMs(2_001, 1));
    try std.testing.expectEqual(@as(i64, 2_001), memoryTtlCutoffMs(2_001, 0));
    try std.testing.expectEqual(std.math.minInt(i64), memoryTtlCutoffMs(std.math.minInt(i64) + 10, 60));

    const huge_ttl_cutoff = memoryTtlCutoffMs(std.math.maxInt(i64), std.math.maxInt(u32));
    try std.testing.expect(huge_ttl_cutoff < std.math.maxInt(i64));
    try std.testing.expect(huge_ttl_cutoff > 0);
}

