    try std.testing.expectEqual(@as(?u64, 128), try testRuntimeLoadUsage(&runtime, "sess", "agent:a"));
    try testRuntimeClearMessages(&runtime, "sess", "agent:a");
    try std.testing.expectEqual(@as(?u64, null), try testRuntimeLoadUsage(&runtime, "sess", "agent:a"));
    try std.testing.expectEqual(@as(?u64, 256), try testRuntimeLoadUsage(&runtime, "sess", "agent:b"));
    const b_messages_after_clear = try testRuntimeLoadMessages(&runtime, std.testing.allocator, "sess", "agent:b");
    defer {
        for (b_messages_after_clear) |*message| freeMessage(std.testing.allocator, message);
        std.testing.allocator.free(b_messages_after_clear);
    }
    try std.testing.expectEqual(@as(usize, 1), b_messages_after_clear.len);
    try std.testing.expectEqualStrings("hello from b", b_messages_after_clear[0].content);
    try std.testing.expect(try testRuntimeDelete(&runtime, "pref.lang", null, "agent:a", "agent:a"));
    try std.testing.expect((try testRuntimeGet(&runtime, std.testing.allocator, "pref.lang", null, "agent:a")) == null);
    const still_b = (try testRuntimeGet(&runtime, std.testing.allocator, "pref.lang", null, "agent:b")).?;
    defer {
        var copy = still_b;
        freeAgentMemory(std.testing.allocator, &copy);
    }
    try std.testing.expectEqualStrings("agent b private", still_b.content);
}
